-- CDA 25174: Décret du 5 juillet 2000 — Régime des congés (30 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 0, 'Art. 1er', 'Article 1er. - Le présent décret s''applique aux membres du personnel visés par : 
1° l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel 
directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical 
des établissements d''enseignement gardien, primaire, spécialisé, moyen, technique, de 
promotion sociale et artistique de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé de la 
surveillance de ces établissements; 
2° le décret du 1er février 1993 fixant le statut des membres du personnel 
subsidiés de l''enseignement libre subventionné [à l''exception du personnel 
administratif]1; 
3° le décret du 6 juin 1994 fixant le statut des membres du personnel subsidié de 
l''enseignement officiel subventionné [à l''exception du personnel administratif]2; 
4° l''arrêté royal du 15 mai 1928 relatif au règlement concernant l''inspection de 
l''enseignement primaire; 
5° l''arrêté royal du 27 juillet 1979 portant le statut du personnel technique des 
centres psycho-médico-sociaux de la Communauté française, des centres psycho-
médico-sociaux pour l''enseignement spécialisé de la Communauté française ainsi que 
des services d''inspection chargés de la surveillance des centres psycho-médico-sociaux 
et des centres psycho-médico-sociaux pour l''enseignement spécialisé; 
6° l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres de religion, des 
professeurs de religion et des inspecteurs de religion des religions catholique, 
protestante, israélite, orthodoxe et islamique des établissements de la Communauté 
française; 
7° la loi du 7 juillet 1970 relative à la structure générale de l''enseignement 
supérieur; 
8° le décret du 24 juillet 1997 fixant le statut des membres du personnel 
directeur et enseignant et du personnel auxiliaire d''éducation des Hautes Ecoles 
 
1 D. 06/07/2023 
2 D. 06/07/2023 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
organisées ou subventionnées par la Communauté française. 
9° le décret du 2 juin 2006 relatif au cadre organique et au statut des 
puériculteurs des établissements d''enseignement maternel ordinaire organisés et 
subventionnés par la Communauté française ; 
10° le décret du 10 mars 2006 relatif aux statuts des maîtres de religion et 
professeurs de religion. [Inséré par D. 11-04-2014] 
 
 
Modifié par D. 31-03-2022', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '1er', NULL, 'Article 1er du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inspection','spécialisé','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 1, 'Art. 2', 'Article 2. - Pour l''application du présent décret, il faut entendre par : 
- « période scolaire », la période s''étendant du premier jour de l''année scolaire à la 
veille de l''année scolaire suivante et, en ce qui concerne les Hautes Ecoles organisées 
ou subventionnées par la Communauté française, la période s''étendant du 15 
septembre au 14 septembre de l''année suivante; 
- « jours ouvrables », les jours de scolarité et, en ce qui concerne les centres 
psycho-médico-sociaux, les jours de fonctionnement.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '2', NULL, 'Article 2 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 2, 'Art. 3', 'Article 3. - Le membre du personnel absent pour cause de maladie ou d''infirmité 
est soumis à la tutelle du service de santé administratif en ce qui concerne la 
constatation de son éventuelle inaptitude et de l''organisme chargé par le 
Gouvernement de la Communauté française de contrôler les absences pour maladie ou 
infirmité.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '3', NULL, 'Article 3 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 3, 'Art. 4', 'Article 4. - Le membre du personnel dont l''absence est due à un accident causé 
par la faute d''un tiers perçoit son traitement d''activité ou son traitement d''attente à la 
condition de subroger la Communauté française dans ses droits contre l''auteur de 
l''accident jusqu''à concurrence des sommes versées par la Communauté française. 
 
Les jours d''absence couverts comme tels par une indemnité versée par un tiers à 
la Communauté française, ne sont pas pris en considération pour fixer le nombre de 
jours de congé pour cause de maladie ou d''infirmité dont bénéficie le membre du 
personnel en vertu du présent décret. 
 
[Article 4/1. - Le membre du personnel qui veut séjourner à l''étranger pendant 
une absence par suite d''un accident du travail ou d''une maladie professionnelle doit 
recevoir, à cet effet, l''autorisation préalable du service de contrôle médical désigné par 
le Gouvernement. Le membre du personnel doit soumettre une recommandation 
motivée de son médecin traitant qui démontre que le séjour à l''étranger ne met pas en 
danger la guérison et/ou le traitement. Le médecin mentionne également les dates de 
début et de fin de la période de séjour à l''étranger demandée.]3 
 
Modifié par D. 01-07-2005 ; D. 30-04-2009 ; D. 07-02-2019 ; D. 19-07-2021', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '4', NULL, 'Article 4 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inspection','obligation scolaire','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 4, 'Art. 5', 'Article 5. - Jusqu''à la date à laquelle débute le congé de maternité, les jours 
d''absence directement liés à l''état de grossesse du membre du personnel ne sont pas 
pris en considération pour fixer le nombre de jours de congé pour cause de maladie ou 
d''infirmité dont bénéficie le membre du personnel en vertu du présent décret [lorsque 
l’intéressé produit un certificat de son médecin traitant attestant que ces absences 
sont liées à son état de grossesse, en utilisant exclusivement le formulaire dont le 
modèle est déterminé par le Gouvernement de la Communauté française.]4 
 
Les périodes d''absence visées au présent article sont rémunérées et assimilées à 
de l''activité de service. 
 
 
3Inséré par le D. 16-05-2024 
4Remplacé par le décret du 18 janvier 2024 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
Inséré par D. 07-02-2019', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '5', NULL, 'Article 5 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 5, 'Art. 5', 'Article 5/1. - Sont également considérés comme étant une absence liée à la 
grossesse, les 10 jours qui suivent toute fausse-couche avant 180 jours de grossesse et 
dont l''enfant est mort-né. 
 
Les périodes d''absence visées au présent article sont rémunérées et assimilées à 
de l''activité de service. 
 
CHAPITRE II. - Du régime applicable au personnel nommé ou engagé à titre 
définitif ou admis au stage 
 
Section 1re. - Généralités', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '5', NULL, 'Article 5 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inscription','exclusion','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 6, 'Art. 6', 'Article 6. - Les membres du personnel visés à l''article 1er, qui sont nommés ou 
engagés à titre définitif ou admis au stage, bénéficient du régime des congés et de 
disponibilité pour cause de maladie ou d''infirmité défini dans le présent chapitre. 
 
Section 2. - Des congés pour cause de maladie ou d''infirmité 
 
Modifié par D. 31-03-2022', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '6', NULL, 'Article 6 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inscription','exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 7, 'Art. 7', 'Article 7. - Le membre du personnel visé à l''article 6, en activité de service, qui 
est empêché d''exercer normalement ses fonctions par suite de maladie ou d''infirmité, 
peut bénéficier, pendant chaque période scolaire, de congés pour cause de maladie ou 
d''infirmité à raison de quinze jours ouvrables. 
 
Le nombre de jours visés à l''alinéa 1er est réduit à due concurrence lorsque le 
membre du personnel n''acquiert la qualité de définitif qu''après le premier jour de 
l''année scolaire considérée ou qu''après le 15 septembre de l''année académique 
considérée, lorsqu''il ne se trouve en activité de service que durant une partie de la 
période scolaire considérée ou lorsqu''il comptabilise des absences irrégulières durant 
ladite période. Le nombre ainsi obtenu est, le cas échéant, arrondi à l''unité inférieure. 
 
Lorsque le membre du personnel n''acquiert la qualité de définitif qu''après le 
premier jour de l''année scolaire considérée ou qu''après le 15 septembre de l''année 
académique considérée, la réduction à due concurrence visée à l''alinéa précédent est 
opérée en tenant compte de la durée totale des périodes au cours desquelles l''intéressé 
a été désigné ou engagé à titre temporaire depuis cette date jusqu''à la date de sa 
nomination ou de son engagement à titre définitif. 
 
Complété par D. 02-06-2006', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '7', NULL, 'Article 7 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 8, 'Art. 8 § 1', 'Article 8. - § 1er. Le membre du personnel nommé ou engagé à titre définitif ou 
admis au stage à la date du 1er septembre 2000 bénéficie, à cette date, du nombre de 
jours de congé pour cause de maladie ou d''infirmité auquel il pouvait prétendre à la 
veille de l''entrée en vigueur du présent décret. 
 
Le membre du personnel nommé ou engagé à titre définitif ou admis au stage 
après le 1er septembre 2000 bénéficie, à la date de sa nomination ou de son 
engagement à titre définitif, du nombre de jours ouvrables de congé pour cause de 
maladie ou d''infirmité auquel il avait droit, à la veille de sa nomination ou de son 
engagement à titre définitif ou de son admission au stage, en application du chapitre 
III du présent décret. 
 
§ 1erbis. Le puériculteur nommé ou engagé à titre définitif ou à titre provisoire 
en vertu du décret du 2 juin 2006 relatif au cadre organique et au statut des 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
puériculteurs des établissements d''enseignement maternel ordinaire organisés et 
subventionnés par la Communauté française, bénéficie, à la date de sa nomination ou 
de son engagement à titre définitif ou à titre provisoire, de 30 jours ouvrables de 
congés pour cause de maladie ou d''infirmité. 
 
§ 2. A l''issue de chaque période scolaire, le nombre de jours visé au paragraphe 
1er peut être augmenté du solde des jours de congé pour cause de maladie ou 
d''infirmité visés à l''article 7 que l''intéressé n''a pas épuisés, sans que le nombre de 
jours de congé pour cause de maladie ou d''infirmité auquel peut prétendre le membre 
du personnel puisse dépasser cent quatre-vingt-deux jours ouvrables. 
 
Complété par D. 13-12-2007', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '8', '1', 'Article 8 § 1 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inscription','exclusion','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 9, 'Art. 9', 'Article 9. - Les absences pour cause de maladie ou d''infirmité sont imputées 
prioritairement sur le nombre de jours dont peut bénéficier le membre du personnel en 
application de l''article 7. 
 
Lorsque le membre du personnel a bénéficié de jours de congé pour cause de 
maladie ou d''infirmité en application de l''article 8, le nombre maximum de jours de 
congé fixé par cet article peut être reconstitué au cours de la carrière, à raison du solde 
des jours de congé pour cause de maladie ou d''infirmité visé à l''article 7, que 
l''intéressé n''a pas épuisés à la fin de chaque période scolaire. 
 
Dans l''enseignement de promotion sociale et dans l''enseignement secondaire 
artistique à horaire réduit, les absences visées à l''alinéa 1er d''un membre du personnel 
qui ont lieu pendant une période où il accomplit ses prestations dans un établissement 
ouvert 6 jours par semaine sont imputées moyennant un coefficient réducteur de 5/6e. 
 
Dans les cas visés à l''alinéa précédent, lorsque le membre du personnel a 
bénéficié de jours de congé pour cause de maladie ou d''infirmité en application de 
l''article 8, le nombre maximum de jours fixé par cet article peut être reconstitué au 
cours de la carrière, à raison du solde du nombre de jours de congés pour cause de 
maladie ou d''infirmité visé à l''article 7, arrondi à l''unité inférieure, que l''intéressé n''a 
pas épuisés à la fin de chaque période scolaire. 
 
Modifié par D. 19-07-2021', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '9', NULL, 'Article 9 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 10, 'Art. 10', 'Article 10. - Par dérogation aux dispositions qui précèdent, lorsqu''il résulte d''un 
accident du travail, d''un accident sur le chemin du travail ou d''une maladie 
professionnelle, le congé pour cause de maladie ou d''infirmité est accordé sans limite 
de temps:  
- durant la période d''incapacité antérieure à la date de consolidation/durant la 
période d''incapacité temporaire;  
- durant les périodes d''absence postérieures à cette même date de consolidation, 
pour autant qu''il s''agisse d''une nouvelle incapacité liée à l''incapacité initiale mais 
intervenue après une reprise du travail. 
 
Sauf pour l''application de l''article 11, les jours de congé accordés en application 
de l''alinéa précédent ne sont pas pris en considération pour fixer le nombre de jours de 
congé dont bénéficie le membre du personnel en vertu des articles 7 à 9.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '10', NULL, 'Article 10 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 11, 'Art. 11', 'Article 11. - Le membre du personnel ne peut être déclaré définitivement inapte 
pour cause de maladie ou d''infirmité avant qu''il n''ait épuisé la somme de jours de 
congé à laquelle lui donnent droit les articles 7 à 9.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '11', NULL, 'Article 11 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 12, 'Art. 12', 'Article 12. - Les congés pour cause de maladie ou d''infirmité sont assimilés à des 
périodes d''activité de service. 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
Section 3. - De la disponibilité pour maladie ou infirmité', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '12', NULL, 'Article 12 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 13, 'Art. 13', 'Article 13. - Le membre du personnel visé à l''article 6 se trouve de plein droit en 
disponibilité lorsqu''il est absent pour cause de maladie ou d''infirmité après avoir 
épuisé le nombre maximum de jours de congé qui peuvent lui être accordés pour cette 
raison en application des articles 7 à 10.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '13', NULL, 'Article 13 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 14, 'Art. 14', 'Article 14. - Le membre du personnel en disponibilité pour cause de maladie ou 
d''infirmité reçoit un traitement d''attente égal à : 
- 80 p.c. du dernier traitement d''activité, pendant les douze premiers mois de 
disponibilité, au cours de sa carrière; 
- 70 p.c. du dernier traitement d''activité, pendant les douze mois suivants de 
disponibilité; 
- 60 p.c. du dernier traitement d''activité, au-delà de ces vingt-quatre mois de 
disponibilité. 
 
Toutefois, le montant du traitement d''attente visé à l''alinéa 1er ne peut, en aucun 
cas, être inférieur : 
- aux indemnités que l''intéressé obtiendrait dans la même situation si le régime 
de la sécurité sociale lui avait été applicable dès le début de son absence; 
- à la pension que l''intéressé obtiendrait si, à la date de sa mise en disponibilité, 
il avait été admis à la pension prématurée. 
 
Complété par D. 17-12-2003 ; modifié par D. 13-12-2007', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '14', NULL, 'Article 14 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inscription','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 15, 'Art. 15', 'Article 15. - Par dérogation à l''article 14, le membre du personnel en 
disponibilité pour cause de maladie ou d''infirmité a droit à un traitement d''attente 
égal au montant de son traitement d''activité, si l''affection dont il souffre est reconnue 
comme maladie ou infirmité grave et de longue durée. 
 
Le service de santé administratif décide si l''affection dont souffre le membre du 
personnel constitue ou non une telle maladie ou infirmité. Cette décision ne peut en 
tout cas intervenir avant que le membre du personnel n''ait été pour une période 
continue de trois mois au moins en congé ou en disponibilité pour l''affection dont il 
souffre. Toutefois, l''écoulement de la période continue de trois mois au moins n''est pas 
requis pour le membre du personnel qui, suite à une nouvelle absence pour cause de 
maladie ou infirmité, se trouve à nouveau en congé ou en disponibilité pour cause de 
maladie ou infirmité dans les trois années qui suivent la date à laquelle il a fait l''objet 
d''une décision de reconnaissance de maladie grave et de longue durée. 
 
Cette décision entraîne une révision de la situation du membre du personnel avec 
effet pécuniaire à la date du début de la disponibilité.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '15', NULL, 'Article 15 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 16, 'Art. 16', 'Article 16. - Le membre du personnel en disponibilité pour cause de maladie ou 
d''infirmité, conserve ses titres à une nomination à une fonction de promotion, à une 
nomination à une fonction de sélection et à l''avancement de traitement. 
 
Modifié par D. 19-07-2021', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '16', NULL, 'Article 16 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 17, 'Art. 17', 'Article 17. - Le membre du personnel en disponibilité qui bénéficie d''un 
traitement d''attente est tenu de comparaître chaque année devant le service de santé 
administratif au cours du mois correspondant à celui de sa mise en disponibilité, sur 
convocation. 
 
Si le membre du personnel, dûment convoqué, ne comparaît pas devant le service 
de santé administratif à l''époque ainsi fixée, le paiement de son traitement d''attente 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
est suspendu depuis cette époque jusqu''à sa comparution. 
 
Inséré par D. 11-04-2014', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '17', NULL, 'Article 17 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 18, 'Art. 17bis', 'Article 17bis. - La mesure de disponibilité pour maladie prend fin : 
1° soit par la reprise effective des fonctions du membre du personnel dûment 
constatée par le Pouvoir organisateur ou le chef d''établissement; 
2° soit après constatation, par l''organisme de contrôle médical visé par le décret 
du 22 décembre 1994 portant des mesures urgentes en matière d''enseignement, que le 
membre du personnel est apte à reprendre ses fonctions lorsque la reprise effective 
n''est pas possible en raison des vacances d''été 
 
CHAPITRE III. - Du régime applicable au personnel désigné ou engagé à 
titre temporaire', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '17bis', NULL, 'Article 17bis du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 19, 'Art. 18', 'Article 18. - Les membres du personnel visés à l''article 1er qui sont désignés ou 
engagés à titre temporaire bénéficient du régime de congés rémunérés pour cause de 
maladie ou d''infirmité défini dans le présent chapitre.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '18', NULL, 'Article 18 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 20, 'Art. 19 § 2', 'Article 19. - Sans préjudice de l''application des dispositions de l''article 20, §§ 2 
et 3, le membre du personnel désigné ou engagé à titre temporaire pour la durée 
complète d''une année scolaire ou académique et qui est empêché d''exercer 
normalement ses fonctions par suite de maladie ou d''infirmité, peut bénéficier, pour 
l''année scolaire ou académique considérée, de congés pour cause de maladie ou 
d''infirmité à raison de quinze jours ouvrables. 
 
Le nombre de jours visé à l''alinéa 1er est réduit à due concurrence lorsque la 
désignation ou l''engagement à titre temporaire ne couvre pas une année scolaire ou 
académique complète, lorsque le membre du personnel ne se trouve en activité de 
service que durant une partie de la période de désignation ou d''engagement à titre 
temporaire considérée ou lorsqu''il s''absente irrégulièrement. Le nombre ainsi obtenu 
est, le cas échéant, arrondi à l''unité inférieure. 
 
Sans préjudice de l''application de l''article 7, alinéa 3, lorsque le membre du 
personnel a fait l''objet de plusieurs désignations ou engagements à titre temporaire au 
cours d''une année scolaire ou académique, la réduction à due concurrence visée à 
l''alinéa précédent est opérée sur la durée totale des périodes au cours desquelles 
l''intéressé a été désigné ou engagé à titre temporaire pendant l''année scolaire ou 
académique considérée. 
 
Par dérogation à l''alinéa 1er, lorsque le membre du personnel visé par cette 
disposition met fin volontairement à ses fonctions avant le terme de l''année scolaire ou 
académique, son dernier traitement d''activité est diminué d''une somme égale à la 
différence entre la rémunération qu''il a obtenue sur la base de l''alinéa 1er et celle à 
laquelle il aurait pu prétendre en application de l''alinéa 2.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '19', '2', 'Article 19 § 2 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 21, 'Art. 20 § 1', 'Article 20. - § 1er. Le membre du personnel ayant acquis la qualité de temporaire 
avant le 1er septembre 2000 et dont la durée des prestations cumulées avant la date 
d''entrée en vigueur du présent décret, lui a permis de se constituer une réserve d''au 
moins 30 jours ouvrables de congé de maladie ou d''infirmité, bénéficie, à cette date, du 
nombre de jours de congé pour cause de maladie ou d''infirmité auquel il pouvait 
prétendre à la veille de l''entrée en vigueur du présent décret. 
 
A l''issue de chaque année scolaire ou académique, le nombre de jours visé à 
l''alinéa 1er peut être augmenté du solde des jours de congé pour cause de maladie ou 
d''infirmité visé à l''article 19 que l''intéressé n''a pas épuisé, sans que le nombre de jours 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
de congé pour cause de maladie ou d''infirmité auquel peut prétendre le membre du 
personnel puisse dépasser cent quatre-vingt-deux jours ouvrables.  
 
§ 2. Le membre du personnel ayant acquis la qualité de temporaire avant le 1er 
septembre 2000 et dont la durée des prestations cumulées avant la date d''entrée en 
vigueur du présent décret ne lui a pas permis de se constituer une réserve d''au moins 
30 jours ouvrables de congé de maladie ou d''infirmité, voit la réserve de jours de congé 
de maladie ou d''infirmité dont il dispose à la veille de la date d''entrée en vigueur du 
présent décret augmentée d''un nombre de jours ouvrables de congé de maladie ou 
d''infirmité égal à la différence entre : 
- la réserve de jours de congé de maladie ou d''infirmité dont il dispose à la veille 
de la date d''entrée en vigueur du présent décret, d''une part, et 30 jours diminué du 
nombre de jours de congé de maladie ou d''infirmité comptabilisés par l''intéressé au 
cours des années scolaires ou académiques précédentes, d''autre part. 
 
Ce nombre de jours est octroyé au membre du personnel à titre d''avance. 
 
Dès que l''application de l''article 19 lui a permis d''atteindre le nombre de jours lui 
accordé à titre d''avance en application de l''alinéa premier, le membre du personnel 
peut se constituer une réserve de maximum cent quatre-vingt deux jours ouvrables de 
congé pour cause de maladie ou d''infirmité au moyen du solde des jours de congé pour 
cause de maladie ou d''infirmité visé à l''article 19 que l''intéressé n''a pas épuisé à la fin 
de chaque année scolaire ou académique. 
 
§ 3. Le membre du personnel faisant l''objet d''une première désignation ou d''un 
premier engagement à titre temporaire à partir du 1er septembre 2000 bénéficie, à 
titre d''avance, d''une réserve de 30 jours ouvrables de congé de maladie ou d''infirmité. 
Dès que l''application de l''article 19 lui a permis d''atteindre 30 jours ouvrables de 
congé de maladie ou d''infirmité, le membre du personnel peut se constituer une 
réserve de maximum cent quatre-vingt-deux jours ouvrables de congé pour cause de 
maladie ou d''infirmité au moyen du solde des jours de congé pour cause de maladie ou 
d''infirmité visé à l''article 19 que l''intéressé n''a pas épuisé à la fin de chaque année 
scolaire ou académique. 
 
Complété par D. 13-12-2007', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '20', '1', 'Article 20 § 1 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 22, 'Art. 21', 'Article 21. - Les absences pour cause de maladie ou d''infirmité sont imputées 
prioritairement sur le nombre de jours de congé dont peut bénéficier le membre du 
personnel en application de l''article 19. 
 
Lorsque le membre du personnel a bénéficié de jours de congé pour cause de 
maladie ou d''infirmité en application de l''article 20, le nombre maximum de jours de 
congé fixé par cet article peut être reconstitué au cours de la carrière, à raison du solde 
des jours de congé pour cause de maladie ou d''infirmité visé à l''article 19, que 
l''intéressé n''a pas épuisé à la fin de chaque année scolaire ou académique. 
 
Dans l''enseignement de promotion sociale et dans l''enseignement secondaire 
artistique à horaire réduit, les absences visées à l''alinéa 1er, d''un membre du 
personnel qui ont lieu pendant une période où il accomplit ses prestations dans un 
établissement ouvert 6 jours par semaine, sont imputées moyennant un coefficient 
réducteur de 5/6e. 
 
Dans les cas visés à l''alinéa précédent, lorsque le membre du personnel a 
bénéficié de jours de congé pour cause de maladie ou d''infirmité en application de 
l''article 20, le nombre maximum de jours fixé par cet article peut être reconstitué au 
cours de la carrière, à raison du solde du nombre de jours de congés pour cause de 
Statuts /Personnel enseignant/CF/LS/OS/ 
X.A.218 
Lois 25174 
 
D. 05-07-2000 
maladie ou d''infirmité visé à l''article 19, arrondi à l''unité inférieure, que l''intéressé n''a 
pas épuisés à la fin de chaque période scolaire.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '21', NULL, 'Article 21 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 23, 'Art. 22', 'Article 22. - Lorsque l''absence pour cause de maladie ou d''infirmité du membre 
du personnel se prolonge au-delà de la période couverte par la désignation ou 
l''engagement à titre temporaire, l''application des dispositions qui précèdent ne peut 
entraîner l''octroi au membre du personnel d''une rémunération pendant une période 
postérieure à la date à laquelle sa désignation ou son engagement à titre temporaire 
aurait pris fin.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '22', NULL, 'Article 22 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel','obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 24, 'Art. 23', 'Article 23. - Le membre du personnel visé à l''article 18 qui est victime d''un 
accident de travail, d''un accident survenu sur le chemin du travail ou d''une maladie 
professionnelle, bénéficie d''un congé rémunéré durant la période d''incapacité 
consécutive à l''accident ou à la maladie. Ce congé ne peut toutefois lui être accordé au-
delà de la date à laquelle sa désignation à titre temporaire prend fin. 
 
Si la période d''incapacité se prolonge au-delà de la date visée à l''alinéa 1er, il est 
fait application au membre du personnel concerné de l''article 3bis de la loi du 3 juillet 
1967 sur la réparation des dommages résultant des accidents du travail, des accidents 
sur le chemin du travail et des maladies professionnelles dans le secteur public et de 
l''article 22 de la loi du 10 avril 1971 sur les accidents de travail. 
 
CHAPITRE IV. - Dispositions dérogatoire, modificative, abrogatoire et finale', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '23', NULL, 'Article 23 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 25, 'Art. 24', 'Article 24. - Par dérogation à l''article 7, alinéa 1er, le membre du personnel visé 
à l''article 6 qui a atteint l''âge de 51, 52, 53, 54, 55, 56, 57, 58 ou 59 ans et plus à la 
date du 1er septembre 2000, en activité de service et qui est empêché d''exercer 
normalement ses fonctions par suite de maladie ou d''infirmité, peut bénéficier, 
pendant chaque période scolaire, de congés pour cause de maladie ou d''infirmité à 
raison, respectivement, de 16, 17, 18, 19, 20, 21, 22, 23 ou 24 jours ouvrables.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '24', NULL, 'Article 24 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 26, 'Art. 25 § 2', 'Article 25. - Par dérogation à l''article 19, alinéa 1er, et sans préjudice de 
l''application des dispositions de l''article 20, §§ 2 et 3, le membre du personnel désigné 
ou engagé à titre temporaire pour la durée complète d''une année scolaire ou 
académique, qui a atteint l''âge de 51, 52, 53, 54, 55, 56, 57, 58 ou 59 ans et plus à la 
date du 1er septembre 2000 et qui est empêché d''exercer normalement ses fonctions 
par suite de maladie ou d''infirmité, peut bénéficier, pour l''année scolaire ou 
académique considérée, de congés pour cause de maladie ou d''infirmité à raison, 
respectivement, de 16, 17, 18, 19, 20, 21, 22, 23 ou 24 jours ouvrables. 
 
Par dérogation à l''alinéa 1er, lorsque le membre du personnel visé par cette 
disposition met fin volontairement à ses fonctions avant le terme de l''année scolaire ou 
académique, son dernier traitement d''activité est diminué d''une somme égale à la 
différence entre la rémunération qu''il a obtenue sur la base de l''alinéa 1er et celle à 
laquelle il aurait pu prétendre en application de l''article 19, alinéa 2.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '25', '2', 'Article 25 § 2 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 27, 'Art. 26', 'Article 26. - Dans l''article 2 du décret du 22 décembre 1994 portant des mesures 
urgentes en matière d''enseignement, les termes « de l''arrêté royal du 15 mai 1928 
relatif au règlement concernant l''inspection de l''enseignement primaire, du décret du 
24 juillet 1997 fixant le statut des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation des Hautes Ecoles organisées ou subventionnées par 
la Communauté française » sont insérés entre les termes « de l''enseignement 
supérieur » et les termes « ainsi que les membres du personnel contractuel ».', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '26', NULL, 'Article 26 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 28, 'Art. 27', 'Article 27. - Le décret du 4 février 1997 fixant le régime des congés et de 
