INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('25174', 29, 'Art. 28', 'Article 28. - Le présent décret entre en vigueur le 1er septembre 2000. 
 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur belge.', 'Décret du 5 juillet 2000 — Régime des congés', 'Décret congés', '28', NULL, 'Article 28 du Décret du 5 juillet 2000 — Régime des congés (CDA 25174)', NULL, 'commun');

