INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 1, 'Art. 2', 'Article 2. - Pour permettre aux membres du personnel visés à l''article 1er de se 
rendre chaque jour du lieu de leur résidence au lieu de leur travail, et inversement, il 
leur est octroyé une intervention dans les frais de transport en commun public et/ou 
dans l''utilisation de la bicyclette. 
 
L''intervention est à charge : 
- du pouvoir organisateur des établissements d''enseignement maternel, primaire, 
fondamental, secondaire, secondaire artistique à horaire réduit, de promotion sociale, 
des internats, des Hautes Ecoles, des Ecoles supérieures des arts et des Instituts 
supérieurs d''architecture subventionnés par la Communauté française s''il s''agit d''un 
membre du personnel subsidié de l''enseignement subventionné; 
- de l''établissement d''enseignement maternel, primaire, fondamental, secondaire, 
de promotion sociale, des Hautes Ecoles, des internats dépendant de ces 
établissements, des internats autonomes, des homes d''accueil, des Ecoles supérieures 
des arts et de l''Institut supérieur d''architecture organisés par la Communauté 
française s''il s''agit d''un membre du personnel de l''enseignement organisé par la 
Communauté française; 
- du centre psycho-médico-social s''il s''agit d''un membre du personnel des centres 
psycho-médico-sociaux organisés par la Communauté française; 
- du pouvoir organisateur s''il s''agit d''un membre du personnel subsidié des 
centres psycho-médico-sociaux subventionnés par la Communauté française. 
- des centres visés à l''article 1er, 8°, 9°, 10° et 11°, s''il s''agit d''un membre du 
personnel de ces derniers ; 
[- du pôle territorial s''il s''agit du personnel des pôles territoriaux organisés par la 
Communauté française ; 
- du pouvoir organisateur s''il s''agit d''un membre du personnel subsidié des pôles 
territoriaux subventionnés par la Communauté française]2. 
 
Le membre du personnel est tenu d''opter pour la formule de titre de transport la 
 
