INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 2, 'Art. 3', 'Article 3. - Sans préjudice de l''application d''autres dispositions légales et 
réglementaires concernant l''intervention financière de l''employeur dans le prix du 
transport des membres de son personnel, pour le transport organisé par la Société 
nationale des Chemins de fer belge, l''intervention dans le prix de la carte train 
assimilée à l''abonnement social est égale à 100 % de ce montant pour une carte train 
deuxième classe.  
 
L''intervention est aussi égale à 100 % du prix pour les billets de train de 
deuxième classe ou tout autre titre de transport de deuxième classe le moins onéreux. 
 
Inséré par D. 12-12-2008', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '3', NULL, 'Article 3 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 3, 'Art. 3bis', 'Article 3bis. – (…) abrogé par D. 29-11-2012 
 
CHAPITRE IV. - Transports en commun publics autres que le chemin de fer 
 
Complété par D. 12-12-2008; remplacé par D. 29-11-2012 ; complété par D. 08-06-
2017', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '3bis', NULL, 'Article 3bis du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 4, 'Art. 4', 'Article 4. - Pour le transport urbain et suburbain organisé par les sociétés 
régionales de transports publics, l''intervention dans le prix de l''abonnement, qu''il soit 
proportionnel à la distance parcourue ou, à défaut de pouvoir être déterminé en 
fonction de la distance en kilomètres ou en zones, qu''il soit à tarif fixe, est égale à     
100 % de ce prix. 
 
L''intervention est aussi égale à 100 % du prix pour les tickets de bus, de métro ou 
de tram ou tout autre titre de transport public le moins onéreux. 
 
Inséré par D. 12-12-2008', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '4', NULL, 'Article 4 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
