INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 6, 'Art. 5', 'Article 5. - Lorsque le membre du personnel combine plusieurs moyens de 
transport en commun public et qu''un seul titre de transport lui est fourni pour la 
totalité de la distance parcourue, l''intervention est égale à 100 % du prix de la carte 
train assimilée à l''abonnement social. 
 
L''intervention est aussi égale à 100 % du prix pour les tickets de bus, de métro ou 
de tram ou tout autre titre de transport public le moins onéreux. 
  
Inséré par D. 12-12-2008 ; abrogé par D. 29-11-2012

Article 5bis. – (…)  
 
