INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 12, 'Art. 8 § 1', '§ 1er. L''intervention dans les frais de transport en commun public est 
payée contre remise du titre de transport délivré par les sociétés organisant le 
transport en commun public et est subordonnée à la production d''une déclaration 
signée par le membre du personnel, mentionnant que ce moyen de transport est 
 
4 Ajouté par le décret du 20 juillet 2023 
Statuts /Personnel enseignant/CF/LS/OS/NS 
X.A.244 
Lois 27861 
 
D. 17-07-2003 
mis à jour au 13-01-2025 
habituellement utilisé sur cette distance et que cette formule de titre de transport est 
la moins onéreuse. 
 
Dans le cas où le membre du personnel exerce ses fonctions dans plusieurs 
établissements d''enseignement, internats ou homes d''accueil, [pôles territoriaux]5 ou 
plusieurs centres et qu''il peut utiliser son ou ses titre(s) de transport pour se rendre 
vers les établissements d''enseignement, internats, homes d''accueil [pôles territoriaux]6 
ou centres où il travaille, il remet son ou ses titre(s) de transport, selon le cas, au chef 
d''établissement, au pouvoir organisateur ou au directeur du centre où il travaille le 
plus grand nombre d''heures. 
 
A nombre égal d''heures, le membre du personnel remet son ou ses titre(s) de 
transport, selon le cas, au chef d''établissement, au pouvoir organisateur ou au 
directeur du centre où il compte le plus d''ancienneté. 
 
Dans le cas où le membre du personnel exerce ses fonctions dans plusieurs 
établissements d''enseignement, internats, homes d''accueil, [pôles territoriaux]7 ou 
plusieurs centres et qu''il ne peut pas utiliser le(s) même(s) titre(s) de transport, il 
remet à chaque chef d''établissement, pouvoir organisateur ou directeur de centre 
concerné le ou les titre(s) de transport spécifique pour se rendre vers le(s) 
établissement(s) d''enseignement, internats, homes d''accueil ou centre(s) concerné(s). 
 
Toute modification doit être signalée dans le mois de sa date. 
 
Les documents visés à l''alinéa 1 doivent être déposés soit à la fin du mois, soit à 
l''expiration de la validité du titre de transport.', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '8', '1', 'Article 8 § 1 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 13, 'Art. 8 § 2', '§ 2. L''intervention dans l''utilisation de la bicyclette sur le chemin du travail est 
payée contre remise à la fin de chaque mois du formulaire établi selon le modèle établi 
par le Gouvernement. 
 
Sur ce formulaire, le membre du personnel indique le nombre total de kilomètres 
parcourus, arrondi à l''unité supérieur, ainsi que le montant de l''indemnité auquel il 
estime avoir droit. 
 
La première introduction de ce formulaire est accompagnée d''une description de 
l''itinéraire emprunté ainsi que du kilométrage aller et retour que celui-ci comporte. Le 
choix de ce parcours est adapté aux spécificités propres aux déplacements en 
bicyclette, en particulier à celles que requiert la sécurité du cycliste dans la 
circulation. 
 
Toute modification ultérieure de l''itinéraire fait l''objet d''une nouvelle description 
et d''une justification appropriée.', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '8', '2', 'Article 8 § 2 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 14, 'Art. 8 § 3', '§ 3. Si les documents visés aux paragraphes 1er et 2 ne sont pas remis dans le 
