INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 15, 'Art. 9', 'Article 9. - L''intervention, selon le cas, dans les frais de transport en commun 
public supportés par le membre du personnel et/ou dans l''utilisation de la bicyclette 
est payée dans les 2 mois de la date où les documents sont remis conformément à 
l''article 8, § 1er et § 2. 
 
En cas d''utilisation de la bicyclette, l''intervention est payée après vérification du 
formulaire visé à l''article 8, § 2. 
 
modifié par D. 17-12-2003 ; D. 29-11-2012', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '9', NULL, 'Article 9 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 16, 'Art. 10 § 1', 'Article 10. - § 1er. Le coût des interventions pour les membres du personnel des 
Ecoles supérieures des Arts organisées par la Communauté française est à charge de 
la dotation globale qu''elles reçoivent conformément à l''article 3, § 1er, de la loi du 29 
mai 1959 modifiant certaines dispositions de la législation de l''enseignement. 
 
Le coût des interventions pour les membres du personnel des Ecoles supérieures 
des Arts subventionnées est à charge de la subvention de fonctionnement qu''elles 
reçoivent conformément à l''article 32, § 2, de la loi du 29 mai 1959 modifiant certaines 
dispositions de la législation de l''enseignement. [remplacé par D. 29-11-2012] 
 
Le coût des interventions pour les membres du personnel des Hautes Ecoles est à 
charge du solde de l''allocation annuelle globale qu''elles reçoivent chacune 
conformément à l''article 29 du décret du 9 septembre 1996 relatif au financement des 
Hautes Ecoles organisées ou subventionnées par la Communauté française. 
 
Le coût des interventions pour les membres du personnel des centres de 
dépaysement et de plein air de la Communauté française, du Centre d''autoformation 
et de formation continuée de l''enseignement de la Communauté française, du Centre 
technique et pédagogique de l''enseignement de la Communauté française et des 
Centres techniques de la Communauté française de Strée et de Gembloux est à charge 
de la dotation globale qu''ils reçoivent chacun conformément à l''article 3, § 1, de la loi 
du 29 mai 1959 modifiant certaines dispositions de la législation de l''enseignement. 
 
§ 2. Les articles 11 et 12 du présent décret ne sont pas applicables aux Ecoles 
supérieures des arts, aux Hautes Ecoles, aux centres de dépaysement et de plein air de 
la Communauté française, au Centre d''autoformation et de formation continuée de 
l''enseignement de la Communauté française, au Centre technique et pédagogique de 
l''enseignement de la Communauté française et aux Centres techniques de la 
Communauté française de Strée et de Gembloux. 
 
CHAPITRE VIII. - Remboursement de l''intervention par les services du 
Gouvernement 
 
Modifié par D. 17-12-2003 ; D. 13-01-2011', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '10', '1', 'Article 10 § 1 du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 17, 'Art. 11', 'Article 11. - Selon le cas, les pouvoirs organisateurs, les chefs d''établissement, 
 
