INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 18, 'Art. 11bis', 'Article 11bis - Par dérogation aux articles 8 à 11, lorsque le pouvoir 
organisateur a conclu avec la SNCB une convention relative à la délivrance de cartes 
de train 2ème classe diminuées de l''intervention patronale au profit de ses membres 
du personnel ou avec les sociétés STIB, TEC ou De Lijn, une convention relative à la 
délivrance d''abonnements de bus, de métro, et/ou de tram, les règles du présent 
chapitre sont d''application. 
 
Inséré par D. 04-02-2016', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '11bis', NULL, 'Article 11bis du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 19, 'Art. 11ter', 'Article 11ter - L''intervention dans une convention de tiers payant vaut tant 
pour le transport public par chemin de fer que pour le transport public par chemin de 
fer combiné avec un autre transport en commun. 
 
Complémentairement à ce remboursement, le membre du personnel peut 
également obtenir remboursement pour l''utilisation de la bicyclette sur le chemin du 
travail, conformément à l''article 7. 
 
Inséré par D. 04-02-2016 ; complété par D. 08-06-2017', 'Décret du 17 juillet 2003 — Intervention transport en commun', 'Décret transport', '11ter', NULL, 'Article 11ter du Décret du 17 juillet 2003 — Intervention transport en commun (CDA 27861)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 20, 'Art. 11quater', 'Article 11quater - Dans le cas où le membre du personnel exerce ses fonctions 
