INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 21, 'Art. 11quinquies', 'Article 11quinquies - Les modalités de liquidation des factures des conventions 
de tiers-payant sont fixées comme suit : 
1. Le Pouvoir Organisateur ou son délégué informe, lors de la conclusion de la 
convention, les services du Gouvernement de l''existence de ladite convention ; 
2. Le Pouvoir Organisateur ou son délégué fait parvenir une déclaration de 
créance accompagnée de la copie de la facture reçue de la société de transport public 
faisant preuve de l''intervention dans les frais de transport en commun public, selon le 
modèle type établi par le Gouvernement. 
 
Cette déclaration mentionne que le membre du personnel a choisi la formule de 
titre de transport la moins onéreuse. [inséré par D. 08-06-2017] 
 
Dans les trois mois de la réception de la déclaration de créance visée à l''alinéa 1er, 
les services du Gouvernement remboursent le Pouvoir organisateur de l''intervention 
payée. 
 
Sous peine de perte du droit au remboursement, la déclaration de créance visée à 
l''alinéa 1 doit être introduite au plus tard dans les deux mois qui suivent le paiement 
par le Pouvoir organisateur des montants réclamés par la société de transport public 
sur base de la facture. 
 
Par dérogation à l''alinéa précédent, pour l''année scolaire 2016-2017, la 
déclaration de créance visée à l''alinéa 1 doit être introduite au plus tard le 30 
septembre 2017 en ce qui concerne les conventions de tiers payant conclues avec 
d''autres sociétés de transport public que la SNCB. [inséré par D. 08-06-2017] 
 
CHAPITRE IX. - De la mutualisation de la charge des frais de transport 
 
