INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('27861', 31, 'Art. 14', 'Article 14. - A l''article 2 de l''arrêté du Gouvernement de la Communauté 
française relatif à l''intervention de l''employeur dans les frais de transport des 
membres statutaires du personnel scientifique, administratif, technique et ouvrier des 
institutions universitaires organisées par la Communauté française avant les mots «Il 
est accordé une intervention (...)» sont ajoutés les mots : - «Sans préjudice de 
