INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('4329', 22, 'Art. 15 § 3', '§ 3. Un candidat fournit la preuve de sa connaissance fonctionnelle de la langue 
