INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 13, 'Art. 4 § 6', '§ 6. Les Services de l''Inspection visés au paragraphe 1er sont chargés, 
chacun pour ce qui les concerne ou en collaboration entre eux: 
1° d''analyser les programmes d''études visés [à l''article 1.5.1-4 du Code]40 
et de rédiger un avis sur leur conformité avec les référentiels à destination de 
la Commission de pilotage; 
2° de donner des avis et de formuler des propositions, d''initiative ou à la 
demande du Gouvernement, sur tout ce qui relève de leur compétence; 
3° de participer aux groupes de travail, commissions et conseils, en vertu 
des lois, décrets et règlements; 
4° de collaborer avec les établissements d''enseignement supérieur en 
charge de la formation initiale des enseignants dans le cadre et selon les 
conditions fixés par le Gouvernement; 
5° d''exercer toutes autres tâches qui leur sont confiées par ou en vertu 
des lois, décrets et règlements. 
6° en collaboration avec le Service général de pilotage des écoles et des 
Centres psycho-médico-sociaux, de l''organisation de la passation, de la 
correction et du jury externe de l''épreuve externe commune conduisant à la 
délivrance du Certificat d''Etudes de Base au terme de l''enseignement 
primaire, ainsi que de l''organisation, de la correction ou du jury de toutes 
autres épreuves externes certificatives qui leur seraient confiées par le 
Gouvernement. [Inséré par D. 24-02-2022]', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '6', 'Article 4 § 6 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 14, 'Art. 4 § 7', '§ 7. Selon les besoins, les missions visées au présent article sont 
effectuées par un ou plusieurs membres du Service général de l''Inspection. 
 
Ces missions sont assurées de manière complémentaire, pour autant 
qu''une mission d''audit ne soit jamais menée au sein d''un établissement en 
même temps qu''une [mission d’investigation, une]41 mission d''évaluation, une 
mission de contrôle spécifique ou une mission portant sur l''appréciation de 
l''aptitude pédagogique d''un membre du personnel de l''équipe éducative. 
 
Dans le respect de la méthodologie et des objectifs qui sont propres au 
Service général de l''Inspection, et dans le respect du mandat sur la base duquel 
elles sont exécutées, les inspecteurs en charge des missions visées aux 
paragraphes 1er, 2, 3 et 4, ont accès, sous la responsabilité de l''Inspecteur 
général coordonnateur, aux données quantitatives de l''établissement, 
notamment celles relatives aux taux d''échec, de redoublement ou de 
réorientation vers d''autres établissements et aux archives. Ils peuvent fonder 
leurs appréciations sur des faits prélevés notamment en assistant aux cours et 
activités, [en interrogeant les élèves sur les attendus des référentiels et des 
 
38Remplacé par le D. 18-04-2024 
39Inséré par le D. 18-04-2024 
40Remplacé par le D. 18-04-2024 
41Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
programmes,]42 en examinant des préparations, des travaux, des documents 
d’élèves et les résultats obtenus aux évaluations externes non certificatives et 
en analysant les données quantitatives précitées. 
 
[Article 4/1. -', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '7', 'Article 4 § 7 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['redoublement','orientation','évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 15, 'Art. 4 § 1', '§1er. Dans le cadre de leurs compétences relatives aux 
pôles territoriaux, les Services de l''Inspection visés à l''article 3, alinéa 3, 1°, 2° 
et 5°, sont chargés, chacun pour ce qui les concerne ou en collaboration entre 
eux, de missions d''audit portant sur les pôles territoriaux pour lesquels la 
Cellule intermédiaire de coordination valide la demande d''audit formulée par 
un membre du Service général de Pilotage des Ecoles et des Centres psycho-
médico-sociaux ou par le pouvoir organisateur concerné, soit dans le cas de 
refus ou d''incapacité de l''école siège d''un pôle territorial à établir l''annexe 
relative au pôle territorial visée à l''article 6.2.4-1 du Code de l''enseignement 
fondamental et de l''enseignement secondaire, soit à la suite de l''évaluation de 
l''annexe relative au pôle territorial concerné effectuée dans le cadre de 
l''évaluation intermédiaire du contrat d''objectifs de l''école siège du pôle 
territorial. 
 
Le Gouvernement définit la méthodologie générale sur la base de laquelle 
les missions visées à l''alinéa 1er sont exécutées. 
 
Avant toute mission d''audit, la Cellule intermédiaire de coordination fixe 
la portée et les limites du mandat confié au Service général de l''Inspection pour 
les besoins de la mission. L''Inspecteur général coordonnateur, en concertation 
avec la Cellule intermédiaire de coordination, détermine le dispositif et la 
méthodologie spécifique sur la base desquels la mission est réalisée. 
 
Toute mission d''audit donne lieu, dans les quinze jours ouvrables suivant 
sa clôture, à l''établissement d''un diagnostic, repris dans un rapport dont le 
modèle est défini par le Gouvernement, sur proposition de l''Inspecteur général 
coordonnateur, et destiné à la Cellule intermédiaire de coordination ainsi 
qu''au pôle territorial audité. Dans ce cadre, le Service général de l''Inspection 
agit par voie de recommandations. 
 
Si, dans le cadre du mandat d''une mission d''audit, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 3, le rapport visé à l''alinéa 4 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '1', 'Article 4 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection','spécialisé','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 16, 'Art. 4 § 2', '§2. Les Services de l''Inspection visés au paragraphe 1er sont chargés, 
