INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 17, 'Art. 4 § 3', '§3. Les Services de l''Inspection visés au paragraphe 1er sont chargés, 
