INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 18, 'Art. 4 § 2', '§2 bis de la loi du 29 mai 
1959 modifiant certaines dispositions de l''enseignement. 
 
 
 
Docu 46239 
 
D. 10-01-2019  
Le Gouvernement précise les modalités et la méthodologie générale sur 
la base desquelles les missions visées à l''alinéa 1er sont exécutées, en veillant 
notamment à ce que le droit à faire valoir le point de vue des intéressés soit 
garanti. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande du 
Gouvernement ou du fonctionnaire général en charge de la Direction générale 
de l''Enseignement obligatoire ou du fonctionnaire général chargé de la 
Direction générale du Pilotage du Système Educatif. 
 
Avant toute mission visée à l''alinéa 1er, la cellule intermédiaire de 
coordination, le cas échéant élargie au fonctionnaire général chargé de la 
Direction générale de l''Enseignement obligatoire fixe la portée et les limites 
du mandat confié au Service général de l''Inspection pour les besoins de la 
mission. L''Inspecteur général coordonnateur, en concertation avec la cellule 
intermédiaire de coordination, détermine le dispositif et la méthodologie 
spécifique sur la base desquels la mission est réalisée. 
 
Toute mission de contrôle spécifique visée à l''alinéa 1er donne lieu, dans 
les quinze jours ouvrables suivant sa clôture, à l''établissement d''un rapport 
circonstancié dont le modèle est défini par le Gouvernement, sur la proposition 
de l''Inspecteur général coordonnateur. Ce rapport, qui comprend notamment 
des informations et recommandations en lien avec les constats posés dans le 
cadre de cette mission, est transmis par la voie hiérarchique au fonctionnaire 
général désigné par le Gouvernement et au pouvoir organisateur concerné. 
 
Le pouvoir organisateur qui n''envisage pas de réserver de suites à un 
rapport défavorable rédigé par un membre du personnel du Service général de 
l''Inspection en exécution d''une mission visée à l''alinéa 1er, motive cette 
décision auprès du fonctionnaire général visé à l''alinéa 7, dans le mois qui suit 
la date de réception dudit rapport, via le fonctionnaire général en charge de la 
Direction générale du Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '2', 'Article 4 § 2 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 19, 'Art. 4 § 4', '§4. Les Services de l''Inspection visés au paragraphe 1er sont chargés, 
chacun pour ce qui les concerne ou en collaboration entre eux, de missions 
portant sur l''appréciation de l''aptitude pédagogique ou professionnelle d''un 
membre du personnel de l''équipe pluridisciplinaire ou des profils de fonction 
et lettre de missions concernés. 
 
Le Gouvernement précise les modalités et la méthodologie générale sur 
la base desquelles les missions visées à l''alinéa 1er sont exécutées en veillant 
notamment à ce que le droit à faire valoir le point de vue des intéressés soit 
garanti. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande motivée du 
pouvoir organisateur pour les pôles territoriaux subventionnés et à la demande 
du directeur de l''école siège pour les pôles territoriaux organisés par la 
Communauté française, adressée au fonctionnaire général en charge de la 
Direction générale du Pilotage du Système Educatif. 
 
Le fonctionnaire général en charge de la Direction générale du Pilotage 
du Système Educatif, après analyse de la demande visée à l''alinéa 3, marque 
ou non son accord sur l''exécution de la mission et signifie sa décision au 
 
 
Docu 46239 
 
D. 10-01-2019  
directeur dans l''enseignement organisé par la Communauté française ou au 
pouvoir organisateur concerné dans l''enseignement subventionné. 
 
Toute mission visée à l''alinéa 1er donne lieu, dans les quinze jours 
ouvrables suivant sa clôture, à l''établissement d''un rapport circonstancié dont 
le modèle est défini par le Gouvernement, sur la proposition de l''Inspecteur 
général coordonnateur. Ce rapport, qui comprend, notamment, des 
informations et recommandations en lien avec les constats posés dans le cadre 
de cette mission, est transmis par la voie hiérarchique au fonctionnaire général 
désigné par le Gouvernement qui le fait parvenir au directeur de l''école siège 
et au coordonnateur du pôle territorial organisé ou subventionné par la 
Communauté française ou au pouvoir organisateur du pôle territorial 
concerné. Ce dernier le soumet au visa du membre du personnel qui, le cas 
échéant, y joint ses observations. Le rapport, accompagné d''éventuelles 
observations du membre du personnel, est ensuite transmis à l''Inspecteur 
général coordonnateur, via le fonctionnaire général désigné par le 
Gouvernement. 
 
Le pouvoir organisateur du pôle territorial ou son délégué qui n''envisage 
pas de réserver de suites à un rapport défavorable rédigé par le Service général 
de l''Inspection en exécution d''une mission visée à l''alinéa 1er motive cette 
décision auprès du fonctionnaire général visé à l''alinéa 5 dans le mois qui suit 
la date de réception dudit rapport, via le fonctionnaire général en charge de la 
Direction générale du Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '4', 'Article 4 § 4 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','inspection','parents','ROI','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 20, 'Art. 4 § 5', '§5. Les Services de l''Inspection visés au paragraphe 1er sont chargés de 
missions d''expertise à des fins d''appui dans le cadre de : 
 
1° la conception et la mise à la disposition des pôles d''outils 
d''observation ; 
 
2° le recueil et la valorisation des pratiques pertinentes des pôles par 
rapport à leurs missions, dans le respect de l''article 8.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '5', 'Article 4 § 5 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 21, 'Art. 4 § 6', '§6. Les Services de l''Inspection visés au paragraphe 1er sont chargés : 
 
1° de donner des avis et de formuler des propositions, d''initiative ou à la 
demande du Gouvernement, sur tout ce qui relève de leur compétence ; 
 
2° de participer aux groupes de travail, commissions et conseils, en vertu 
des lois, décrets et règlements ; 
 
3° de collaborer avec les établissements d''enseignement supérieur en 
charge de la formation initiale des enseignants dans le cadre et selon les 
conditions fixées par le Gouvernement ; 
 
4° d''exercer toutes autres tâches qui leur sont confiées par ou en vertu 
des lois, décrets et règlements.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '6', 'Article 4 § 6 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 22, 'Art. 4 § 7', '§7. Selon les besoins, les missions visées au présent article sont effectuées 
par un ou plusieurs membres du Service général de l''Inspection. 
 
Ces missions sont assurées de manière complémentaire, pour autant 
qu''une mission d''audit ne soit jamais menée au sein d''un pôle en même temps 
 
 
Docu 46239 
 
D. 10-01-2019  
qu''une mission d''évaluation, une mission de contrôle spécifique, une mission 
portant sur l''appréciation de l''aptitude pédagogique ou professionnelle d''un 
membre du personnel de l''équipe pluridisciplinaire ou une mission 
d''investigation. 
 
Dans le respect de la méthodologie et des objectifs qui leur sont propres, 
et dans le respect du mandat sur la base duquel elles sont exécutées, pour les 
missions visées aux paragraphes 1er, 2, 3 et 4, les membres du Service général 
de l''Inspection ont accès aux données quantitatives et qualitatives du pôle. Ils 
peuvent fonder leurs appréciations sur des faits prélevés notamment en 
examinant des dossiers et en analysant les données précitées]43. 
 
Modifié par D. 24-02-2022', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '4', '7', 'Article 4 § 7 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 23, 'Art. 5 § 1', '§ 1er. Dans le cadre de ses compétences concernant 
l''enseignement de promotion sociale, le Service de l''Inspection visé à l''article 
3, alinéa 3, 3°, est chargé de missions d''audit portant sur les établissements 
pour lesquels la Cellule intermédiaire de coordination valide la demande 
d''audit formulée par les Services du Gouvernement ou par le pouvoir 
organisateur concerné, sur la base d''objectifs généraux définis par le 
Gouvernement en vertu des lois, décrets et règlements de l''enseignement de 
promotion sociale. 
 
Le Gouvernement précise la méthodologie générale sur la base de laquelle 
les missions visées à l''alinéa 1er sont exécutées. Avant toute mission d''audit, 
la Cellule intermédiaire de coordination fixe la portée et les limites du mandat 
confié au Service général de l''Inspection pour les besoins de la mission. 
L''Inspecteur général coordonnateur, en concertation avec la Cellule 
intermédiaire de coordination, détermine le dispositif et la méthodologie 
spécifique sur la base desquels la mission est réalisée. 
 
Toute mission d''audit donne lieu, dans les quinze jours ouvrables suivant 
sa clôture, à l''établissement d''un diagnostic, repris dans un rapport dont le 
modèle est défini par le Gouvernement, sur la proposition de l''Inspecteur 
général coordonnateur, et destiné à la Cellule intermédiaire de coordination 
ainsi qu''à l''établissement audité. Dans ce cadre, le Service général de 
l''Inspection agit par voie de recommandations. [Dans le cadre de l''article 3, 3°, 
du même décret du 22 février 2008 portant diverses mesures relatives à 
l''organisation et au fonctionnement de l''Agence pour l''évaluation de la qualité 
de l''enseignement supérieur organisé ou subventionné par la Communauté 
française, la Cellule intermédiaire de coordination peut transmettre le rapport 
d''audit à la Cellule exécutive de l''Agence dans le respect de la confidentialité 
des audits dans le cadre d''un protocole de coopération entre le Service général 
de l''Inspection et l''Agence pour l''évaluation de la qualité de l''enseignement 
supérieur.]44 
 
Si, dans le cadre du mandat d''une mission d''audit, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 4, le rapport visé à l''alinéa 3 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif. 
 
43 Ajouté par le décret du 20 juillet 2023 
44Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
[Les modalités de suivi de l''audit sont arrêtées par le Gouvernement.]45', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '5', '1', 'Article 5 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 24, 'Art. 5 § 2', '§ 2. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
missions d''évaluation portant sur la mise en oeuvre de dispositifs 
pédagogiques ou éducatifs spécifiques à l''enseignement de promotion sociale 
en application d''une disposition décrétale ou règlementaire ou en application 
d''un dispositif expérimental autorisé par le Gouvernement. 
 
[…]46 
 
Le Gouvernement précise les modalités sur la base desquelles les 
missions visées à l''alinéa 1er sont exécutées. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande du 
Gouvernement, formulée éventuellement sur la proposition du Service général 
de l''Inspection, par la voie de la Cellule intermédiaire de coordination. 
 
Avant toute mission d''évaluation, la Cellule intermédiaire de 
coordination fixe la portée et les limites du mandat confié au Service général 
de l''Inspection pour les besoins de la mission. L''Inspecteur général 
coordonnateur, en concertation avec la Cellule intermédiaire de coordination, 
détermine le dispositif et la méthodologie spécifique sur la base desquels la 
mission est réalisée. 
 
Toute mission d''évaluation donne lieu, dans les trente jours ouvrables 
suivant sa clôture, à l''établissement d''un rapport circonstancié dont le modèle 
est défini par le Gouvernement, sur la proposition de l''Inspecteur général 
coordonnateur, et destiné au Gouvernement via la Cellule intermédiaire de 
coordination. Dans ce cadre, le Service général de l''Inspection agit par voie de 
recommandations. Au terme du plan pluriannuel, un rapport portant sur l''état 
des lieux, l''analyse et la conformité des dispositifs pédagogiques ou éducatifs 
de l''enseignement de promotion sociale évalués est transmis par la voie 
hiérarchique à la Cellule intermédiaire de coordination et au Gouvernement. 
 
Si, dans le cadre du mandat d''une mission d''évaluation, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 4, le rapport visé à l''alinéa 6 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif. 
 
[Dans le cadre de l''article 3, 3°, du décret du 22 février 2008 portant 
diverses mesures relatives à l''organisation et au fonctionnement de l''Agence 
pour l''évaluation de la qualité de l''enseignement supérieur organisé ou 
subventionné par la Communauté française, le Gouvernement peut, sur 
proposition de la Cellule intermédiaire de coordination, transmettre le rapport 
d''évaluation à la Cellule exécutive de l''Agence, laquelle est tenue de respecter 
leur confidentialité.]47 
 
 
45Inséré par le D. 18-04-2024 
46Abrogé par le D. 18-04-2024 
47Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '5', '2', 'Article 5 § 2 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 25, 'Art. 5 § 3', '§ 3. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
missions d''évaluation portant sur la mise en oeuvre de dispositifs 
pédagogiques spécifiques à l''enseignement à distance de la Communauté 
française en e-learning. 
 
Le Gouvernement précise les modalités sur la base desquelles les 
missions visées à l''alinéa 1er sont exécutées. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande du 
Gouvernement, formulée éventuellement sur la proposition du Service général 
de l''Inspection, par la voie de la Cellule intermédiaire de coordination. 
 
Avant toute mission d''évaluation, la Cellule intermédiaire de 
coordination fixe la portée et les limites du mandat confié au Service général 
de l''Inspection pour les besoins de la mission. L''Inspecteur général 
coordonnateur, en concertation avec la Cellule intermédiaire de coordination, 
détermine le dispositif et la méthodologie spécifique sur la base desquels la 
mission est réalisée. 
 
Toute mission d''évaluation donne lieu, dans les [trente]48 jours ouvrables 
suivant sa clôture, à l''établissement d''un rapport circonstancié dont le modèle 
est défini par le Gouvernement, sur proposition de l''Inspecteur général 
coordonnateur, et destiné [au Gouvernement via]49 la Cellule intermédiaire de 
coordination. Dans ce cadre, le Service général de l''Inspection agit par voie de 
recommandations. 
 
Si, dans le cadre du mandat d''une mission d''évaluation, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 4, le rapport visé à l''alinéa 5 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '5', '3', 'Article 5 § 3 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 26, 'Art. 5 § 4', '§ 4. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
missions de contrôle spécifiques dans l''enseignement de promotion sociale 
portant sur: 
1° le niveau des études en référence aux dossiers pédagogiques approuvés 
à titre provisoire ainsi qu''à titre définitif par le Gouvernement, lorsqu''une 
faiblesse ou un enjeu particulier a été repéré et qui nécessite un diagnostic 
externe objectif; 
2° la présomption d''un ou de plusieurs manquements substantiels 
mentionnés dans le rapport rédigé dans le cadre d''une mission visée aux 
paragraphes 1er ou 2 [ou à l''article 7/1]50 ou signalés par le fonctionnaire 
général en charge de la Direction générale de l''Enseignement non obligatoire 
et de la Recherche Scientifique. 
 
Sont substantiels au sens de l''alinéa 1er, 2°, les manquements constatés 
ou dénoncés relativement aux aspects suivants: 
 
48Remplacé par le D. 18-04-2024 
49Remplacé par le D. 18-04-2024 
50Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
1° le respect des articles 7, 8, 10, 11, 13, 14, 26, 31, 34, 36, 37, 40, 42, 53, 
57, 58, 60, 64, 67, 68, 70 et 120 du décret du 16 avril 1991 organisant 
l''enseignement de promotion sociale; 
2° le respect des dossiers pédagogiques ou des programmes approuvés à 
titre provisoire et définitif par le Gouvernement conformément à la 
réglementation en vigueur; 
3° la cohérence des pratiques avec le dossier pédagogique, en ce compris 
les pratiques d''évaluation et de valorisation des acquis; 
4° l''adéquation du matériel didactique, numérique et de l''équipement 
scolaire aux nécessités pédagogiques; 
5° les mécanismes de ségrégation; 
6° le respect de la neutralité, là où cette neutralité s''impose; 
7° le respect du prescrit décrétal en matière de formation en cours de 
carrière. 
 
Dans l''enseignement subventionné par la Communauté française, la 
mission visée à l''alinéa 1er participe du contrôle des conditions d''octroi des 
subventions, tel que prévu à l''article [1.7.3-1,

§2 du Code et à l''article 24,', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '5', '4', 'Article 5 § 4 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','évaluation','personnel','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 27, 'Art. 5 § 2', '§2bis, 
de la loi du 29 mai 1959 modifiant certaines dispositions de l''enseignement]51. 
 
Le Gouvernement précise les modalités et la méthodologie générale sur 
la base desquelles les missions visées à l''alinéa 1er sont exécutées, en veillant 
notamment à ce que le droit à faire valoir le point de vue des intéressés soit 
garanti. 
 
