INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 33, 'Art. 5 § 10', '§ 10. Selon les besoins, les missions visées au présent article sont 
effectuées par un ou plusieurs membres du Service général de l''Inspection. 
 
Ces missions sont assurées de manière complémentaire, pour autant 
qu''une [mission d''investigation, une]64 mission d''audit visée au paragraphe 1er 
ne soit jamais menée au sein d''un établissement en même temps qu''une 
mission d''évaluation, une mission de contrôle spécifique ou une mission 
portant sur l''appréciation de l''aptitude pédagogique d''un membre du personnel 
de l''équipe éducative. 
 
Dans le respect de la méthodologie et des objectifs qui leur sont propres, 
et dans le respect du mandat sur la base duquel elles sont exécutées, pour les 
missions visées aux paragraphes 1er, 2, 4 et 8, les inspecteurs, via l''inspecteur 
coordonnateur, peuvent faire appel à la cellule de pilotage afin de récolter des 
données quantitatives utiles à l''investigation. Ils peuvent fonder leurs 
appréciations sur des faits prélevés, notamment, en assistant aux cours et 
activités, en examinant des préparations, des travaux, des documents 
d''élèves/étudiants et les résultats obtenus aux évaluations externes non 
certificatives et en analysant les données quantitatives précitées. 
 
Dans le respect de la méthodologie et des objectifs qui leur sont propres, 
et dans le respect du mandat sur la base duquel elles sont exécutées, pour les 
missions visées aux paragraphes 3, 5 [, 8 et à l''article 7/1]65, les membres du 
Service général de l''Inspection ont accès aux données quantitatives en 
sollicitant le Conseil de concertation et de pilotage de l''e-learning. Ils peuvent 
fonder leurs appréciations sur des faits prélevés, notamment, en examinant 
des préparations, des travaux, des documents d''élèves/étudiants et les 
résultats obtenus aux évaluations [, en interrogeant les étudiants]66 et en 
analysant les données quantitatives précitées et/ou le résultat d''études 
qualitatives menées. 
 
Modifié par D. 24-02-2022', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '5', '10', 'Article 5 § 10 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 34, 'Art. 6 § 1', '§ 1er. Dans le cadre de ses compétences concernant 
l''enseignement artistique, le Service de l''Inspection visé à l''article 3, alinéa 3, 
4°, est chargé de missions d''évaluation portant sur la mise en oeuvre d''un 
dispositif pédagogique ou éducatif au sein du système scolaire ou éducatif en 
 
64Inséré par le D. 18-04-2024 
65Remplacé par le D. 18-04-2024 
66Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
application d''une disposition décrétale ou règlementaire ou en application d''un 
dispositif expérimental autorisé par le Gouvernement. 
 
Le Gouvernement précise les modalités sur la base desquelles les 
missions visées à l''alinéa 1er sont exécutées. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande du 
Gouvernement, formulée éventuellement sur la proposition du Service général 
de l''Inspection, par la voie de la Cellule intermédiaire de coordination. 
 
Avant toute mission d''évaluation, la Cellule intermédiaire de 
coordination fixe la portée et les limites du mandat confié au Service général 
de l''Inspection pour les besoins de la mission. L''Inspecteur général 
coordonnateur, en concertation avec la Cellule intermédiaire de coordination, 
détermine le dispositif et la méthodologie spécifique sur la base desquels la 
mission est réalisée. 
 
Toute mission d''évaluation donne lieu, dans les trente jours ouvrables 
suivant sa clôture, à l''établissement d''un rapport circonstancié dont le modèle 
est défini par le Gouvernement, sur proposition de l''Inspecteur général 
coordonnateur, et destiné [au Gouvernement via]67 la Cellule intermédiaire de 
coordination. Dans ce cadre, le Service général de l''Inspection agit par voie de 
recommandations. 
 
Si, dans le cadre du mandat d''une mission d''évaluation, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 2, le rapport visé à l''alinéa 5 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '6', '1', 'Article 6 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 35, 'Art. 6 § 2', '§ 2. Le Service de l''Inspection visé au paragraphe 1er est chargé, pour ce 
