INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 40, 'Art. 6 § 1', '§1er, alinéa 1er, du décret du 02 juin 
