INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 41, 'Art. 6 § 6', '§ 6. Selon les besoins, les missions visées au présent article sont 
effectuées par un ou plusieurs membres du Service général de l''Inspection. 
 
Ces missions sont assurées de manière complémentaire. 
 
Dans le respect de la méthodologie et des objectifs qui leur sont propres, 
et dans le respect du mandat sur la base duquel elles sont exécutées, pour les 
missions visées aux paragraphes 1er et 2 [et à l''article 7/1]79, les membres du 
Service général de l''Inspection ont accès aux données quantitatives de 
l''établissement, notamment celles relatives aux taux d''échec, de redoublement 
ou de réorientation et aux archives. Ils peuvent fonder leurs appréciations sur 
des faits prélevés notamment en assistant aux cours et activités en examinant 
des préparations, des travaux, des documents des élèves/étudiants et des 
résultats obtenus aux évaluations externes non certificatives [, en interrogeant 
les élèves/étudiants]80 et en analysant des données quantitatives précitées. 
 
Ce', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '6', '6', 'Article 6 § 6 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['redoublement','orientation','évaluation','inspection'], 'commun');
