INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 43, 'Art. 7 § 1', '§ 1er. Dans le cadre de ses compétences relatives aux Centres 
psycho-médico-sociaux, le Service de l''Inspection visé à l''article 3, alinéa 3, 5°, 
est chargé de missions d''audit portant sur les centres psycho-médico-sociaux 
pour lesquels la Cellule intermédiaire de coordination valide la demande 
d''audit formulée par les Services du Gouvernement ou par le pouvoir 
organisateur concerné sur la base de la mise en oeuvre des missions générales 
et prioritaires définies par le Gouvernement en vertu des lois, décrets et 
règlements relatifs aux centres psycho-médico-sociaux. 
 
Le Gouvernement précise la méthodologie générale sur la base de laquelle 
les missions visées à l''alinéa 1er sont exécutées. 
 
Avant toute mission d''audit, la Cellule intermédiaire de coordination fixe 
la portée et les limites du mandat confié au Service général de l''Inspection pour 
les besoins de la mission. L''Inspecteur général coordonnateur, en concertation 
avec la Cellule intermédiaire de coordination, détermine le dispositif et la 
méthodologie spécifique sur la base desquels la mission est réalisée. 
 
Toute mission d''audit donne lieu, dans les quinze jours ouvrables suivant 
sa clôture, à l''établissement d''un diagnostic, repris dans un rapport dont le 
modèle est défini par le Gouvernement, sur proposition de l''Inspecteur général 
coordonnateur, et destiné à la Cellule intermédiaire de coordination ainsi qu''à 
l''établissement audité. Dans ce cadre, le Service général de l''Inspection agit 
par voie de recommandations. 
 
Si, dans le cadre du mandat d''une mission d''audit, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 3, le rapport visé à l''alinéa 3 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '7', '1', 'Article 7 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 44, 'Art. 7 § 2', '§ 2. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
missions d''évaluation portant sur l''exécution des missions assignées aux 
centres psycho-médico-sociaux et le respect des obligations légales et 
déontologiques. 
 
Le Gouvernement précise les modalités sur la base desquelles les 
missions visées à l''alinéa 1er sont exécutées. 
 
Les missions visées à l''alinéa 1er sont exécutées à la demande du 
Gouvernement, formulée éventuellement sur la proposition du Service général 
de l''Inspection, par la voie de la Cellule intermédiaire de coordination. 
 
Avant toute mission d''évaluation, la Cellule intermédiaire de 
coordination fixe la portée et les limites du mandat confié au Service général 
de l''Inspection pour les besoins de la mission. L''Inspecteur général 
coordonnateur, en concertation avec la Cellule intermédiaire de coordination, 
détermine le dispositif et la méthodologie spécifique sur la base desquels la 
mission est réalisée. 
 
Toute mission d''évaluation donne lieu, dans les trente jours ouvrables 
suivant sa clôture, à l''établissement d''un rapport circonstancié dont le modèle 
 
 
Docu 46239 
 
D. 10-01-2019  
est défini par le Gouvernement, sur proposition de l''Inspecteur général 
coordonnateur, et destiné [au Gouvernement via]81 la Cellule intermédiaire de 
coordination. Dans ce cadre, le Service général de l''Inspection agit par voie de 
recommandations. 
 
Si, dans le cadre du mandat d''une mission d''évaluation, un manquement 
substantiel présumé est relevé, qui serait susceptible de donner lieu à une 
mission visée au paragraphe 3, le rapport visé à l''alinéa 5 en fait mention. Il 
peut faire l''objet d''un rapport distinct, transmis immédiatement, par la voie 
hiérarchique, au fonctionnaire général en charge de la Direction générale du 
Pilotage du Système Educatif.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '7', '2', 'Article 7 § 2 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 45, 'Art. 7 § 3', '§ 3. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
missions et de contrôle spécifiques portant sur un ou plusieurs manquements 
substantiels mentionnés dans le rapport rédigé dans le cadre d''une mission 
visée aux paragraphes 1er et 2 [ou à l''article 7/1]82 ou à la demande du 
fonctionnaire général en charge de la Direction générale de l''Enseignement 
obligatoire. 
 
Sont substantiels au sens de l''alinéa 1er les manquements constatés ou 
dénoncés relativement aux aspects suivants: 
1° le respect des obligations légales et des règles déontologiques; 
2° l''adéquation de l''équipement aux nécessités de la poursuite des 
missions des centres; 
3° la cohérence des pratiques, en ce compris les pratiques d''évaluation; 
4° les mécanismes de ségrégation en ce compris le défaut de détection de 
ces mécanismes; 
5° le respect de la neutralité, là où cette neutralité s''impose; 
6° le respect du prescrit décrétal en matière de formation professionnelle 
continue. [Modifié par D. 17-06-2021] 
 
Dans l''enseignement subventionné par la Communauté française, la 
mission visée à l''alinéa 1er participe du contrôle des conditions d''octroi des 
subventions, tel que prévu à [l''article 1.7.3-1,

§2, du Code,]83 l''article 24 
[…]84', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '7', '3', 'Article 7 § 3 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 46, 'Art. 7 § 2', '§ 2bis, de la loi du 29 mai 1959 modifiant certaines dispositions de 
l''enseignement [t aux articles 13, 21 à 53 de l''arrêté royal organique des 
centres psycho-médico-sociaux du 13 août 1962]85. 
 
Le Gouvernement précise les modalités et la méthodologie générale sur 
