INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 48, 'Art. 7 § 5', '§ 5. Le Service de l''Inspection visé au paragraphe 1er est chargé de 
