INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 54, 'Art. 7 § 3', '§ 3. Le Gouvernement précise les modalités et la méthodologie générale 
