INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 65, 'Art. 17', 'Article 17. – [L'']127 épreuve d''admission [au stage]128. [Elle]129 comprend 
une partie écrite et une partie orale, chacune d''elles étant évaluée sur 50 
points. 
 
Seuls les candidats remplissant les conditions fixées à l''article 13 peuvent 
participer à l''épreuve. 
 
Le Gouvernement fixe le profil de compétences qui définit les 
compétences spécifiques et techniques ainsi que les compétences génériques et 
comportementales attendues [dès l''entrée en stage]130 de l''inspecteur. 
 
Il fixe également les modalités de chacune des parties de l''épreuve 
d''admission et les critères d''évaluation de chacune d''elles sur la base [des]131 
compétences [visées]132 à l''alinéa 3. 
 
La partie écrite de l''épreuve se présente sous la forme d''un questionnaire 
à choix multiples comportant des questions théoriques […]133. 
 
Cette partie de l''épreuve [porte sur des connaissances et des compétences 
spécifiques et techniques visées à l''alinéa 3]134. 
 
[…]135 
 
La partie orale de l''épreuve consiste en un entretien devant l''un des jurys 
visés à l''article 19. 
 
Cette partie de l''épreuve [porte sur la capacité à répondre à des questions 
de jugement situationnel sur la compétence technique de communication orale 
et sur les compétences génériques et comportementales visées à l''alinéa 3]136. 
 
 
