INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 67, 'Art. 20', 'Article 20. - Le ou les jurys de l''épreuve d''admission remettent, 
