INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 68, 'Art. 21', 'Article 21. - Seuls les candidats retenus dans l''un des classements 
