INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 70, 'Art. 25', 'Article 25. - L''épreuve de certification visée à l''article 21 est organisée 
dans les six mois au plus tard du terme de la session de la formation initiale. 
Elle consiste en une production écrite personnelle défendue devant l''un des 
jurys visés à l''article 28.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '25', NULL, 'Article 25 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 71, 'Art. 26', 'Article 26. - La production écrite personnelle visée à l''article 25 consiste 
en un dossier constitué: 
1° de deux études de cas personnel dont l''un au moins porte sur une 
dimension travaillée dans le deuxième volet de la formation initiale; 
2° d''un bilan de compétences du candidat, reprenant ses principaux 
atouts et faiblesses, le candidat les étayant à partir de son parcours 
professionnel et les mettant en lien avec les connaissances et capacités 
supposées développées dans le cadre de chacun des volets de la formation 
initiale. 
 
La défense du dossier devant le jury consiste en la présentation et la 
défense orales de l''un des deux cas personnels étudiés. 
 
Le jury fonde son appréciation de l''épreuve de certification sur les critères 
d''évaluation suivants: 
1° la cohérence entre le bilan de compétences et le reflet de ces 
compétences dans les études de cas défendues par le candidat; 
2° la pertinence des actions proposées par le candidat dans les études de 
cas; 
3° le degré de maîtrise des connaissances et capacités supposées 
développées dans le cadre de chacun des volets de la formation initiale; 
4° la capacité à communiquer par écrit; 
5° la capacité à communiquer oralement. 
 
Le Gouvernement fixe la pondération entre les critères d''évaluation, sans 
pour autant qu''aucun d''entre eux ne dépasse 40 %, ainsi que les modalités 
d''organisation et d''évaluation de l''épreuve. 
 
Modifié par D.  24-02-2022', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '26', NULL, 'Article 26 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 72, 'Art. 27', 'Article 27. - A l''issue de la défense du dossier visée à l''article 26, alinéa 
2, le ou les jurys de l''épreuve de certification statuent, hors la présence du 
candidat, sur la délivrance d''une attestation d''échec ou de réussite. L''épreuve 
est considérée comme réussie si le candidat a obtenu au moins 60 % des points 
au total de l''ensemble de l''épreuve. 
 
Le ou les jurys sont également chargé(s) d''établir un classement, par 
fonction, des candidats pour lesquels une attestation de réussite a été délivrée. 
 
Le classement ainsi établi, par fonction, correspond à une réserve par 
fonction, d''une durée de validité de quatre ans à dater de la date à laquelle le 
classement a été établi pour la fonction concernée. 
 
Complété par D. 09-12-2020 ; modifié par D. 24-02-2022', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '27', NULL, 'Article 27 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 73, 'Art. 28', 'Article 28. - Il est institué un ou plusieurs jurys de l''épreuve de 
certification composés de la manière suivante: 
1° d''un président désigné par le Gouvernement parmi les fonctionnaires 
généraux de rang 15 au moins; 
 
 
Docu 46239 
 
D. 10-01-2019  
2° de deux membres désignés par le Gouvernement parmi les membres 
du personnel de l''Administration générale de l''Enseignement, dont l''un au 
moins représente la Direction générale du Pilotage du Système Educatif; 
3° de deux membres désignés par le Gouvernement parmi les membres 
du personnel définitifs ou exerçant un mandat au sein du Service général de 
l''Inspection; 
4° de deux experts externes désignés par le Gouvernement, ayant une 
compétence spécifique en lien avec les différents volets de la formation initiale. 
 
Pour chaque membre effectif du jury de l''épreuve de certification, le 
Gouvernement désigne un membre suppléant selon les mêmes modalités. 
 
Le mandat des membres du jury est gratuit. Toutefois, une compensation 
financière peut être accordée aux membres experts visés à l''alinéa 1er, 4°, 
selon les modalités fixées par le Gouvernement. 
 
Conformément à l''article 14 de l''arrêté royal du 28 septembre 1984 
portant exécution de la loi du 19 décembre 1974 organisant les relations entre 
les autorités publiques et les syndicats des agents relevant de ces autorités, les 
représentants des organisations syndicales peuvent assister aux réunions de 
ce ou ces jurys en tant qu''observateurs. 
 
Le Gouvernement fixe les modalités de fonctionnement du ou des jurys 
de l''épreuve de certification. 
 
Modifié par D. 24-02-2022', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '28', NULL, 'Article 28 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','personnel','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 74, 'Art. 29', 'Article 29. - Le ou les jurys de l''épreuve de certification remettent, 
d''initiative ou à la demande du Gouvernement, un avis sur l''application du 
présent titre. 
 
TITRE III. - Du statut des membres du personnel du Service général 
de l''Inspection 
 
CHAPITRE Ier. - Dispositions générales', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '29', NULL, 'Article 29 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 75, 'Art. 30', 'Article 30. - Le présent titre s''applique aux membres du personnel du 
Service général de l''Inspection, ci-après dénommés «les membres du 
personnel».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '30', NULL, 'Article 30 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 76, 'Art. 31', 'Article 31. - Pour l''application du présent titre, les délais se calculent 
comme suit: 
1° le jour de l''acte qui en constitue le point de départ n''est pas compris; 
2° le jour de l''échéance est compté dans le délai. Toutefois, lorsque ce jour 
est un samedi, un dimanche ou un jour férié légal, en ce compris les jours fériés 
de ou dans la Communauté française, le jour de l''échéance est reporté au plus 
prochain jour ouvrable.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '31', NULL, 'Article 31 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 77, 'Art. 32', 'Article 32. - Les fonctions de promotion que peuvent exercer les 
membres du personnel du Service général de l''Inspection ainsi que les 
fonctions dont doivent être titulaires les candidats à la fonction sont reprises 
dans l''annexe Ire du présent décret. 
 
 
 
Docu 46239 
 
D. 10-01-2019  
Le Gouvernement établit la liste des fonctions de promotion des membres 
du personnel du Service général de l''Inspection en veillant à les classer au sein 
des catégories suivantes: 
1° Inspecteur; 
2° Inspecteur d''un cours de religion ou du cours de morale non 
confessionnelle; 
3° Inspecteur coordonnateur; 
4° Inspecteur général; 
5° Inspecteur général coordonnateur.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '32', NULL, 'Article 32 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 78, 'Art. 33', 'Article 33. - Le Gouvernement définit le profil de compétences commun 
à l''exercice de la fonction d''inspecteur visée à l''article 32, alinéa 2, 1° et 2°, qui 
définit les compétences spécifiques, les compétences techniques ainsi que les 
compétences génériques et comportementales. 
 
Lors de son entrée en fonction, le membre du personnel nommé à titre 
définitif, admis au stage ou désigné à titre provisoire dans une fonction de 
promotion d''inspecteur, prête serment entre les mains du fonctionnaire 
général désigné par le Gouvernement ou de son délégué. 
 
Le serment s''énonce dans les termes fixés par l''article 2 du décret du 20 
juillet 1831. Acte en est donné au membre du personnel.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '33', NULL, 'Article 33 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inscription','exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 79, 'Art. 34', 'Article 34. - Le Gouvernement détermine les frais pouvant être 
remboursés aux membres du personnel. Il s''agit: 
1° des frais de parcours; 
2° des frais de séjour; 
3° des frais autres, dont notamment les frais relatifs aux communications 
écrites et téléphoniques, à l''Internet et à l''achat de documentation. 
 
Le Gouvernement fixe les limites et modalités du remboursement visé à 
l''alinéa 1er. 
 
CHAPITRE II. - Des devoirs et incompatibilités 
 
SECTION Ire. - Des devoirs', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '34', NULL, 'Article 34 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 80, 'Art. 35', 'Article 35. - Les membres du personnel doivent, en toutes occasions, 
avoir le souci constant des intérêts de la Communauté française, des élèves 
fréquentant les établissements d''enseignement organisés ou subventionnés 
par la Communauté française et des membres du personnel de ces 
établissements. Ils ont également le souci constant des élèves qui satisfont à 
l''obligation scolaire par la dispensation d''un enseignement à domicile [ainsi 
que ceux des centres PMS]157. 
 
Ils s''acquittent de leur mission avec une égale sollicitude vis-à-vis de tous 
les établissements scolaires et en toute indépendance à l''égard des pouvoirs 
organisateurs. 
 
 
157Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '35', NULL, 'Article 35 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 81, 'Art. 36', 'Article 36. - Ils doivent observer les principes de neutralité dans 
l''exercice de leurs fonctions. Ils ne peuvent utiliser les élèves à des fins de 
propagande politique, religieuse, philosophique ou de publicité commerciale. 
 
Les inspecteurs visés à l''article 32, alinéa 2, 2°, ne sont pas tenus 
d''observer les principes de neutralité dans l''exercice de missions étroitement 
liées à l''apprentissage des religions ou de la morale non confessionnelle, aux 
démarches pédagogiques, au respect des référentiels et des programmes des 
cours de religion ou de morale non confessionnelle. Ils s''abstiennent cependant 
de dénigrer les positions exprimées dans les cours parallèles ou par les 
inspecteurs de ces cours.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '36', NULL, 'Article 36 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 82, 'Art. 37', 'Article 37. - Les membres du personnel accomplissent personnellement 
et consciencieusement les obligations qui leur sont imposées par les lois, 
décrets, arrêtés et règlements. 
 
Ils doivent fournir, dans les limites fixées par la réglementation, les 
prestations nécessaires à la bonne marche du service. 
 
Ils exécutent ponctuellement les missions qui leur sont confiées et 
accomplissent leur tâche avec zèle et exactitude. 
 
Ils ne peuvent suspendre l''exercice de leurs fonctions sans autorisation 
préalable de leur supérieur hiérarchique.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '37', NULL, 'Article 37 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 83, 'Art. 38', 'Article 38. - Ils sont tenus à la correction la plus stricte tant dans leurs 
rapports de service que dans leurs rapports avec le public, et doivent 
s''entraider dans la mesure où l''exige l''intérêt du service. 
 
Ils doivent, dans le service comme dans leur vie privée, éviter tout ce qui 
pourrait porter atteinte à la confiance du public ou compromettre l''honneur ou 
la dignité de leur fonction. Ils s''abstiennent de tout acte de harcèlement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '38', NULL, 'Article 38 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 84, 'Art. 39', 'Article 39. - Ils ne peuvent se livrer à aucune activité qui est en 
opposition avec la Constitution et les lois du peuple belge, qui poursuit la 
destruction de l''indépendance du pays ou qui met en danger la défense 
nationale ou l''exécution des engagements de la Belgique en vue d''assurer sa 
sécurité. Ils ne peuvent adhérer, ni prêter leur concours à un mouvement, 
groupement, organisation ou association ayant une activité de même nature.

Article 40. - Ils ne peuvent révéler les faits dont ils auraient eu 
connaissance en raison de leurs fonctions et qui auraient un caractère secret.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '39', NULL, 'Article 39 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 85, 'Art. 41', 'Article 41. - Ils ne peuvent solliciter, exiger ou recevoir, directement ou 
par personne interposée, même en dehors de leurs fonctions, mais en raison de 
celles-ci, des dons, gratifications ou avantages quelconques.

Article 42. - Le Gouvernement peut préciser les devoirs prévus par la 
présente section.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '41', NULL, 'Article 41 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 86, 'Art. 43', 'Article 43. - Sans préjudice de l''application des lois pénales et, s''il y 
échet, de l''article 43 de la loi du 29 mai 1959 modifiant certaines dispositions 
de la législation de l''enseignement, les infractions aux dispositions de la 
 
 
Docu 46239 
 
D. 10-01-2019  
présente section sont punies, suivant le cas, de l''une des sanctions 
disciplinaires prévues à l''article 105 et dans le respect de l''article 110. 
 
SECTION II. - Des incompatibilités', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '43', NULL, 'Article 43 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 87, 'Art. 44', 'Article 44. - Est incompatible avec la qualité de membre du personnel 
du Service général de l''Inspection l''exercice du mandat politique: 
1° de bourgmestre, d''échevin, de conseiller communal, de président du 
conseil de l''aide sociale ou de membre du conseil de l''aide sociale dans une 
commune comprise, en tout ou partie, dans le territoire sur lequel le membre 
du personnel exerce la fonction d''Inspecteur, d''Inspecteur coordonnateur, 
d''Inspecteur général ou d''Inspecteur général coordonnateur; 
2° de député provincial ou de conseiller provincial dans une province qui 
comprend, en tout ou en partie, le territoire sur lequel le membre du personnel 
exerce la fonction d''Inspecteur, d''Inspecteur coordonnateur, d''Inspecteur 
général ou d''Inspecteur général coordonnateur.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '44', NULL, 'Article 44 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 88, 'Art. 45', 'Article 45. - Est incompatible avec la qualité de membre du personnel 
du Service général de l''Inspection l''exercice de tout mandat, en ce compris 
syndical, auprès d''un pouvoir organisateur ou d''une fédération de pouvoirs 
organisateurs dont un ou plusieurs établissement(s) d''enseignement  [ou 
centre(s) PMS]158 est (sont) compris(s) dans le territoire sur lequel le membre 
du personnel exerce la fonction d''inspecteur, d''Inspecteur général ou 
d''Inspecteur général coordonnateur.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '45', NULL, 'Article 45 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 89, 'Art. 46', 'Article 46. - Est incompatible avec la qualité de membre du personnel 
du Service général de l''Inspection toute occupation qui serait de nature à nuire 
à l''accomplissement des devoirs de sa fonction ou contraire à la dignité de celle-
ci. 
 
[Article 46/1. - Sur avis de l''Inspecteur général coordonnateur, le 
Gouvernement, le Ministre compétent ou le fonctionnaire général auquel il a 
délégué ce pouvoir autorise le cumul d''activités professionnelles demandé 
selon les modalités fixées par le Gouvernement aux conditions suivantes : 
 
1° le cumul n''a pas trait à une activité incompatible avec la qualité 
d''inspecteur ; 
 
2° le cumul ne couvre pas des périodes d''activités complémentaires qui 
rendent impossible l''accomplissement normal par l''agent de ses fonctions ; 
 
3° le cumul n''est pas de nature à induire dans le chef du public une 
confusion entre les activités professionnelles concernées de l''agent. 
 
Le refus du cumul d''activités fondé sur une incompatibilité ou une 
circonstance autre que celles visées aux points 2° et 3° de l''alinéa précédent, 
sont décidés par le Gouvernement ou le Ministre auquel il a délégué ce pouvoir 
sur avis de l''Inspecteur général coordonnateur. 
 
 
158Inséré par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
Tous les cinq ans ou en cas de modification des conditions d''exercice ou 
de la nature du cumul, l''agent est tenu d''introduire une nouvelle demande de 
cumul.]159', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '46', NULL, 'Article 46 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 90, 'Art. 47', 'Article 47. - Le Gouvernement constate les incompatibilités visées aux 
articles 44 à 46. Il en informe le membre du personnel concerné dans un délai 
de vingt jours à partir du jour où il constate l''incompatibilité par lettre 
recommandée à la poste sortant ses effets le troisième jour ouvrable suivant la 
date de son expédition.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '47', NULL, 'Article 47 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 91, 'Art. 48', 'Article 48. - En cas de contestation sur l''existence d''une incompatibilité 
mentionnée à l''article 46, le membre du personnel concerné peut introduire, 
par la voie hiérarchique, dans un délai de vingt jours ouvrables à compter de 
la date à laquelle la notification de l''incompatibilité a été faite, une réclamation 
devant la Chambre de recours visée à l''article 116. Celle-ci donne son avis au 
Gouvernement dans un délai de deux mois à partir de la date de réception de 
la réclamation. 
 
Le Gouvernement prend sa décision dans un délai d''un mois à partir de 
la réception de l''avis de la Chambre de recours. 
 
CHAPITRE III. - De l''accès aux fonctions de promotion d''inspecteur 
et d''Inspecteur coordonnateur 
 
SECTION Ire. - De l''admission au stage à la fonction de promotion 
d''inspecteur 
 
[Sous-section 1. - De l''entrée en stage]160', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '48', NULL, 'Article 48 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','inscription'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 92, 'Art. 49', 'Article 49. - Pour être admis au stage à la fonction de promotion 
d''inspecteur, le membre du personnel doit: 
1° satisfaire aux conditions visées à l''article 13; 
2° ne pas avoir été démis de ses fonctions en application de l''article 62 ou 
de l''article 93; 
3° être détenteur de l''attestation de réussite à l''épreuve [d''admission au 
stage]161 en rapport avec la fonction d''inspecteur à conférer, visée à l''article 
[17]162.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '49', NULL, 'Article 49 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inscription'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 93, 'Art. 50', 'Article 50. - En cas de vacance d''un emploi de la fonction de promotion 
