INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 97, 'Art. 53 § 2', '§ 2. A tout moment au cours de la seconde année de stage, le membre du 
personnel peut être à nouveau évalué, selon les mêmes modalités qu''au 
paragraphe 1er. 
 
[En cas de mention « réservée » à la première évaluation visée au 
paragraphe 1er, cette deuxième évaluation est obligatoire, a lieu entre les 
12ème et 14ème mois de stage et aboutit à l''attribution de la mention soit « 
favorable », « réservée » ou « défavorable ». Une troisième évaluation, en fin de 
stage, peut uniquement donner lieu à l''attribution de la mention « favorable » 
ou « défavorable ». 
 
Dans tous les cas, il est mis fin d''office au stage du membre du personnel 
qui obtient la mention « défavorable » à l''issue de la deuxième ou troisième 
évaluation. Dans ce cas, le stage prend fin après l''écoulement d''un délai de 15 
jours et, le cas échéant, le membre du personnel réintègre la fonction et 
l''affectation dans lesquelles il est nommé ou engagé à titre définitif. A défaut, 
ce délai est porté à six semaines. 
 
La mention obtenue par le stagiaire est portée à la connaissance de ce 
dernier soit par envoi recommandé, soit par la remise d''une lettre de la main 
à la main, soit par courriel à l''adresse renseignée, dans tous les cas avec accusé 
de réception.]191', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '53', '2', 'Article 53 § 2 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','évaluation','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 98, 'Art. 53 § 3', '§ 3. Le stagiaire qui se voit attribuer une mention «défavorable» peut 
introduire par envoi recommandé une réclamation écrite contre cette mention, 
par la voie hiérarchique, dans les dix jours de sa notification auprès de la 
Chambre de recours visée à l''article 116. Ce recours est suspensif. 
 
La Chambre de recours remet son avis au Gouvernement dans un délai 
maximum [de deux mois]192 à partir de la date de réception du recours. Le 
Gouvernement prend sa décision et attribue la mention d''évaluation au 
membre du personnel stagiaire dans un délai maximum d''un mois à dater de 
la réception de l''avis. 
 
