INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 102, 'Art. 54 § 3', '§ 3. Sur la base du plan de formation visé au paragraphe 2, la formation 
[…]206 professionnelle est organisée par l''Institut interréseaux de la Formation 
professionnelle continue. 
 
Les formateurs de cette formation […]207 professionnelle sont 
prioritairement issus des Universités, des Hautes Ecoles, des établissements 
d''enseignement de promotion sociale, de l''Institut interréseaux de la 
Formation professionnelle continue, de l''Ecole d''Administration publique ou 
[des Services du Gouvernement, le Service général de l''Inspection et le Service 
général du Pilotage des Ecoles et des Centres psychomédico-sociaux]208. 
 
[Le Gouvernement prend les dispositions nécessaires pour permettre 
l''indemnisation des formateurs qui ne seraient pas visés par l''arrêté du 
Gouvernement de la Communauté française du 25 janvier 2017 fixant les 
modalités de sélection et d''indemnisation des formateurs internes auprès de 
