INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 103, 'Art. 54 § 4', '§ 4. [A l''issue de la formation, le stagiaire présente et défend son portfolio 
devant le ou les jurys.]210 
 
[Le portfolio consiste en un dossier personnel dans lequel il démontre en 
quoi les acquis de la formation et les acquis de l''expérience durant son stage 
lui permettent de rencontrer les exigences du profil de fonction visé à l''article 
33, alinéa 1er, à travers l’analyse réflexive de deux cas en lien avec les missions 
de la fonction d’inspecteur convoitée.]211 
 
[Ce ou ces jurys sont composés : 
 
 
