INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 104, 'Art. 54 § 5', '§ 5. Il est mis fin d''office et sans préavis au stage en cas de non-réussite 
de la formation […]219 professionnelle visée au présent article. Dans ce cas, [le 
stage prend fin après l''écoulement d''un délai de 15 jours et, le cas échéant,]220 
le membre du personnel réintègre à titre définitif sa fonction et son affectation 
d''origine [dans lesquelles il est nommé ou engagé à titre définitif. A défaut, ce 
délai est porté à six semaines]221. 
 
[Le]222 Gouvernement peut [, pour assurer la continuité dans la fonction 
d''inspecteur visée ou afin de ne pas perturber la stabilité des équipes 
pédagogiques,]223 reporter la réintégration du membre du personnel dans sa 
fonction d''origine de [maximum]224 six mois à dater de la décision de non-
réussite de cette formation d''insertion professionnelle. 
 
Le membre du personnel visé à l''alinéa 1er, peut introduire, par envoi 
recommandé, un recours écrit contre la décision de non-réussite du stage, par 
la voie hiérarchique, dans les dix jours de sa notification auprès de la Chambre 
de recours visée à l''article 116. Ce recours est suspensif. 
 
La Chambre de recours remet son avis au Gouvernement dans un délai 
maximum [de deux]225 mois à partir de la date de réception du recours. Le 
Gouvernement prend sa décision […]226 dans un délai maximum d''un mois à 
dater de la réception de l''avis. [Il est mis fin au stage lorsque le Gouvernement 
confirme l''échec.]227', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '54', '5', 'Article 54 § 5 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','exclusion','personnel','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 105, 'Art. 55', 'Article 55. - Tout inspecteur-stagiaire peut solliciter la fin anticipée de 
son stage moyennant un préavis maximum de [six semaines]228. Ce préavis 
peut toutefois être réduit de commun accord. 
 
En cas d''absence de réaction du Gouvernement dans le mois de la 
demande de l''inspecteur-stagiaire, celle-ci est réputée acceptée. 
 
Dans ce cas, le membre du personnel réintègre à titre définitif sa fonction 
d''origine et, sauf circonstances exceptionnelles dûment motivées, il ne pourra 
être désigné pour une nouvelle affectation que dans l''hypothèse où il fera 
 
