INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 116, 'Art. 63 § 4', '§ 4. L''épreuve [d''admission au stage]250 visée au paragraphe 2, 6°, est 
organisée dans les trois mois au plus tard [après l''appel à candidatures]251. 
Elle consiste en la production personnelle d''un dossier écrit défendu devant un 
jury. 
 
Le dossier écrit est constitué: 
1° d''une [étude de cas personnel en lien avec les compétences génériques 
et comportementales du profil de fonction]252 ; 
2° d''un bilan de de compétences du candidat, reprenant ses principaux 
atouts et faiblesses, que le candidat étaye à partir de son parcours 
professionnel […]253. 
 
Le jury fonde son appréciation de l''épreuve [d''admission au stage]254 sur 
les critères d''évaluation suivants: 
1° la cohérence entre le bilan de compétences et le [profil de fonction]255; 
[2° la cohérence entre l''étude de cas et le profil de fonction ;]256 
[3° l''adéquation des actions proposées par rapport au cas soumis ;]257 
[4° la qualité de l''analyse réflexive proposée dans l''étude de cas ;]258 
[5°]259 la capacité à communiquer par écrit; 
[6°]260 la capacité à communiquer oralement. 
 
Le Gouvernement fixe la pondération entre les critères d''évaluation, sans 
pour autant qu''aucun d''entre eux ne dépasse 40 %, ainsi que les modalités 
d''organisation et d''évaluation de l''épreuve. 
 
Le jury est chargé d''examiner le dossier [écrit]261 transmis par le 
candidat, d''auditionner ce dernier et d''évaluer l''ensemble de sa prestation et 
de sanctionner cette évaluation par une attestation de réussite ou d''échec. 
 
Il est également chargé d''établir un classement des candidats ayant 
réussi l''épreuve, par fonction.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '63', '4', 'Article 63 § 4 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inscription','discipline','évaluation','inspection','ROI'], 'commun');
