INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 158, 'Art. 94 § 5', '§ 5. En dehors du temps de prestation du membre du personnel, la 
formation organisée sur la base volontaire n''est pas limitée en nombre de demi-
jours de formation. 
 
Lorsqu''elle se déroule pendant le temps de prestation des membres de 
personnel, elle ne peut dépasser 6 demi-jours par an, sauf dérogation accordée 
par le Gouvernement sur la demande de l''Inspecteur général coordonnateur. 
 
Les formations volontaires sont à la charge du Service général de 
l''Inspection.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '94', '5', 'Article 94 § 5 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 159, 'Art. 94 § 6', '§ 6. Au terme des formations, il est délivré aux membres du Service 
général de l''Inspection une attestation de fréquentation, selon les modalités 
déterminées par le Gouvernement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '94', '6', 'Article 94 § 6 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection','obligation scolaire'], 'commun');
