INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 161, 'Art. 95', 'Article 95. - Les membres du Service général de l''Inspection exerçant 
une fonction de promotion d''Inspecteur général ou d''Inspecteur général 
coordonnateur visées à l''article 32, alinéa 2, 4° et 5°, suivent annuellement une 
formation en cours de carrière de 10 demi-jours au moins, organisée par l''Ecole 
d''Administration publique dont le programme et le développement des 
compétences à poursuivre sont déterminés par le Gouvernement. 
 
La formation peut être étalée sur une période de trois années 
consécutives. 
 
