INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 162, 'Art. 96', 'Article 96. - Les membres du personnel du Service général de 
l''Inspection sont dans l''une des positions administratives suivantes: 
1° l''activité de service; 
2° la non-activité; 
3° la disponibilité. 
 
SECTION II. - De l''activité de service', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '96', NULL, 'Article 96 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 163, 'Art. 97', 'Article 97. - Le membre du personnel du Service général de l''Inspection 
est toujours censé être en activité de service, sauf disposition formelle le 
plaçant dans une autre position administrative. 
 
[remplacé par D. 16-03-2023]', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '97', NULL, 'Article 97 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 164, 'Art. 98 § 1', 'Article 98. - §1er. Le membre du personnel, définitif ou temporaire, 
bénéficie du régime des congés de vacances annuelles défini ci-après : 
- les vacances d''automne (de Toussaint) : une semaine ; 
- les vacances d''hiver (de Noël) : deux semaines ; 
- les vacances de détente (de Carnaval) : une semaine ; 
- les vacances de printemps (de Pâques) : deux semaines ; 
- les vacances d''été : du 6 juillet au 15 août. 
 
Toutefois, lorsque l''année scolaire se termine au-delà du 05 juillet, les 
vacances d''été débutent au premier jour suivant la fin de l''année scolaire. Dans 
ce cas, les jours prestés au-delà du 05 juillet sont reportés immédiatement au-
delà du 15 août. 
 
Les vacances d''hiver (de Noël) et de printemps (de Pâques) correspondent 
aux vacances arrêtées par le Gouvernement en application de l''article 1.9.1-2, 
§2, alinéa 1er, du Code de l''enseignement fondamental et de l''enseignement 
secondaire ou fixées par l''article 223 du décret du 31 mars 2022 relatif à 
l''adaptation des rythmes scolaires annuels dans l''enseignement fondamental 
et secondaire ordinaire, spécialisé, secondaire artistique à horaire réduit et de 
promotion sociale et aux mesures d''accompagnement pour l''accueil temps 
libre. 
 
Les vacances d''automne (de Toussaint) correspondent à la seconde 
semaine des vacances arrêtées ou fixées conformément à l''alinéa précédent. 
 
Les vacances de détente (de Carnaval) correspondent à la première 
semaine des vacances arrêtées ou fixées conformément au deuxième alinéa. 
 
§2. Si ces jours ne tombent pas un samedi ou un dimanche ou durant une 
période de vacances visée au §1er, le membre du personnel, définitif ou 
temporaire, bénéficie également des jours de congé suivants : 
1° le 27 septembre (Fête de la Communauté française) ; 
2° le 1er novembre (Toussaint) ; 
3° le 11 novembre (Commémoration du 11 novembre) ; 
4° le lundi de Pâques ; 
5° le 1er mai (Fête du travail) ; 
6° le jeudi de l''Ascension ; 
7° le lundi de Pentecôte. 
 
§3. Par dérogation aux §§ 1 et 2, les Inspecteurs généraux et l''Inspecteur 
général coordonnateur bénéficient durant leur mandat des congés de vacances 
 
 
Docu 46239 
 
D. 10-01-2019  
annuelles et des jours fériés dont bénéficient les agents des Services du 
Gouvernement. 
 
[inséré par D. 16-03-2023]', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '98', '1', 'Article 98 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','personnel','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 165, 'Art. 98', 'Article 98/1. - Le membre du personnel du Service général de 
l''Inspection a droit à un traitement, à un avancement de traitement ou à 
l''obtention d''un congé autre que ceux mentionnés à l''article 98, aux mêmes 
conditions 
que 
celles 
prévues 
pour 
les 
directions 
d''établissements 
d''enseignement ou des Centres psycho-médico-sociaux de la Communauté 
française qu''il inspecte. 
 
SECTION III. - De la non-activité', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '98', NULL, 'Article 98 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 166, 'Art. 99', 'Article 99. - Le membre du personnel du Service général de l''Inspection 
est dans la position de non-activité: 
1° lorsque, aux conditions fixées par le Gouvernement, il accomplit, en 
temps de paix, certaines prestations militaires ou est affecté à la protection 
civile ou à des tâches d''utilité publique en application de la loi portant le statut 
des objecteurs de conscience; 
2° lorsqu''il est frappé de la sanction de suspension disciplinaire ou de 
mise en non-activité disciplinaire; 
3° lorsque, pour des raisons familiales, il est autorisé à s''absenter pour 
une période de longue durée.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '99', NULL, 'Article 99 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 167, 'Art. 100', 'Article 100. - Le membre du personnel du Service général de l''Inspection 
qui est dans la position de non-activité n''a pas droit au traitement, sauf 
disposition formelle contraire. 
 
S''il se trouve en position de non-activité en raison des dispositions 
prévues à l''article 99, 2°, il n''a pas droit à l''avancement de traitement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '100', NULL, 'Article 100 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 168, 'Art. 101', 'Article 101. - Nul ne peut être mis ou maintenu en non-activité s''il se 
trouve dans les conditions requises pour obtenir une pension de retraite. 
 
SECTION IV. - De la disponibilité', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '101', NULL, 'Article 101 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 169, 'Art. 102', 'Article 102. - Sans préjudice des dispositions de l''article 77, le membre 
du personnel du Service général de l''Inspection peut être mis dans l''une des 
positions de disponibilité suivantes dans les mêmes conditions que les chefs 
des établissements d''enseignement de la Communauté française qu''il inspecte: 
1° pour mission spéciale; 
2° pour maladie ou infirmité n''entrainant pas l''inaptitude définitive au 
service, mais provoquant des absences dont la durée excède celles des congés 
pour cause de maladie ou d''infirmité; 
3° pour convenances personnelles; 
4° pour convenances personnelles précédant la pension de retraite; 
5° par retrait d''emploi dans l''intérêt du service et dans l''intérêt de 
l''enseignement. 
 
Toutefois, en cas de mise en disponibilité pour convenances personnelles, 
l''emploi dont est titulaire le membre du personnel demeure non vacant 
pendant la période de cette mise en disponibilité. 
 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '102', NULL, 'Article 102 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 170, 'Art. 103', 'Article 103. - Nul ne peut être mis ou maintenu en disponibilité après la 
fin du mois où il atteint l''âge auquel il peut prétendre à la pension de retraite. 
 
La disposition de l''alinéa 1er ne s''applique pas aux membres du personnel 
mis en disponibilité pour mission spéciale.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '103', NULL, 'Article 103 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 171, 'Art. 104', 'Article 104. - Des traitements d''attente peuvent être alloués aux 
membres du personnel du Service général de l''Inspection mis en disponibilité 
dans les mêmes conditions que les chefs des établissements d''enseignement de 
la Communauté française qu''ils inspectent. 
 
Ces traitements d''attente, les allocations et indemnités qui sont 
éventuellement alloués à ces membres du personnel, sont soumis au régime de 
mobilité applicable aux rétributions des membres du personnel en activité de 
service. 
 
CHAPITRE VIII. - Du régime disciplinaire 
 
SECTION Ire. - Des sanctions disciplinaires', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '104', NULL, 'Article 104 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 172, 'Art. 105', 'Article 105. - Les sanctions disciplinaires qui peuvent être infligées aux 
membres du personnel du Service général de l''Inspection sont: 
1° le rappel à l''ordre; 
2° la réprimande; 
3° la retenue sur traitement; 
4° la suspension disciplinaire; 
5° la mise en non-activité disciplinaire; 
6° la démission disciplinaire; 
7° la révocation. 
 
En outre, les inspecteurs coordonnateurs peuvent également se voir 
infliger une rétrogradation.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '105', NULL, 'Article 105 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 173, 'Art. 106', 'Article 106. - Pour les membres du personnel nommés à titre définitif 
dans une fonction de promotion d''inspecteur visée à l''article 32, alinéa 2, 1° et 
2°, les sanctions disciplinaires sont proposées par l''Inspecteur général 
coordonnateur. 
 
Pour les membres du personnel nommés à titre définitif dans une fonction 
de promotion d''Inspecteur coordonnateur visée à l''article 63, les sanctions 
disciplinaires sont proposées par l''Inspecteur général coordonnateur. 
 
Pour les Inspecteurs généraux et l''Inspecteur général coordonnateur, les 
sanctions disciplinaires sont proposées par le fonctionnaire général désigné 
par le Gouvernement. 
 
Pour les inspecteurs d''un cours de religion ou du cours de morale non 
confessionnelle, les peines disciplinaires sont proposées après consultation du 
chef du culte concerné ou de l''autorité de morale non confessionnelle. Pour 
autant qu''elle soit démontrée, en cas d''absence ou de vacance d''autorité d''un 
culte ou de la morale non confessionnelle, cette consultation n''est pas requise. 
 
Les sanctions disciplinaires sont prononcées par le Gouvernement. 
 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '106', NULL, 'Article 106 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','discipline','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 174, 'Art. 107', 'Article 107. - La retenue sur traitement ne peut être prononcée pour une 
durée supérieure à trois mois. Elle ne peut dépasser un cinquième du 
traitement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '107', NULL, 'Article 107 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 175, 'Art. 108', 'Article 108. - La suspension disciplinaire ne peut être prononcée pour 
une durée supérieure à un an. Elle entraine la privation de la moitié du 
traitement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '108', NULL, 'Article 108 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 176, 'Art. 109', 'Article 109. - La durée de la mise en non-activité disciplinaire est fixée 
par le Gouvernement: elle ne peut être inférieure à un an, ni dépasser cinq 
ans. 
 
Le membre du personnel bénéficie pendant les deux premières années 
d''un traitement d''attente égal à la moitié du traitement d''activité. Sans 
pouvoir jamais dépasser ce dernier montant, le traitement d''attente est fixé 
ensuite au taux de la pension que l''intéressé obtiendrait s''il était admis 
prématurément à la retraite. 
 
Après avoir subi la moitié de sa sanction, le membre du personnel peut 
demander sa réintégration au sein du Service général de l''Inspection.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '109', NULL, 'Article 109 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inscription','discipline','inspection','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 177, 'Art. 110', 'Article 110. - Aucune sanction ne peut être proposée sans que le membre 
du personnel ait été, au préalable, entendu ou dûment convoqué. 
 
Lors de l''audition, le membre du personnel peut se faire assister par un 
avocat, par un défenseur choisi parmi les membres du personnel du Service 
général de l''Inspection, en activité de service ou retraités, ou par un 
représentant d''une organisation syndicale agréée. La procédure se poursuit 
valablement lorsque le membre du personnel, dûment convoqué, ne se 
présente pas à l''audition ou n''y est pas représenté. 
 
Tout membre du personnel invité à viser une proposition de sanction 
disciplinaire formulée à son encontre a le droit d''introduire, par la voie 
hiérarchique, une réclamation écrite devant la Chambre de recours visé à 
l''article 116, dans le délai de vingt jours ouvrables à compter de la date à 
laquelle la proposition lui a été soumise pour visa. 
 
Si l''intéressé n''a pas introduit de recours dans le délai fixé, la proposition 
de sanction disciplinaire est transmise immédiatement au Gouvernement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '110', NULL, 'Article 110 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 178, 'Art. 111', 'Article 111. - La proposition de sanction disciplinaire et le recours 
introduit par le membre du personnel concerné sont transmis à] la Chambre 
de recours susmentionnée dans le délai d''un mois à compter de la date de la 
réception du recours.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '111', NULL, 'Article 111 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 179, 'Art. 112', 'Article 112. - A moins d''empêchement légitime, le requérant comparaît 
en personne. Il peut se faire assister par un avocat, par un défenseur choisi 
parmi les membres du personnel du Service général de l''Inspection, en activité 
de service ou retraités, ou par un représentant d''une organisation syndicale 
agréée. 
 
Sauf dans les cas de poursuites pénales, la Chambre de recours donne son 
avis au Gouvernement dans un délai maximum de trois mois à compter de la 
date de réception du dossier complet de l''affaire. 
 
 
Docu 46239 
 
D. 10-01-2019  
Toutefois, le Gouvernement peut demander un avis d''urgence. Dans ce 
cas, le délai ne peut cependant être inférieur à un mois. Le Gouvernement 
prend sa décision dans le délai d''un mois à partir de la réception de l''avis de la 
Chambre de recours.

Article 113. - Aucune sanction ne peut produire d''effet pour la période 
qui précède son prononcé.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '112', NULL, 'Article 112 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 180, 'Art. 114', 'Article 114. - L''action pénale relative aux faits qui font l''objet d''une 
procédure disciplinaire est suspensive de la procédure et du prononcé 
disciplinaires. Quel que soit le résultat de l''action pénale, l''autorité 
disciplinaire reste juge de l''application des sanctions disciplinaires. 
 
SECTION II. - De la radiation des sanctions disciplinaires', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '114', NULL, 'Article 114 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 181, 'Art. 115', 'Article 115. - La sanction disciplinaire est effacée d''office au terme d''un 
délai: 
1° d''un an pour le rappel à l''ordre et la réprimande; 
2° de trois ans pour la retenue sur traitement; 
3° de cinq ans pour la suspension disciplinaire; 
4° de sept ans pour la mise en non-activité disciplinaire. 
 
Le délai visé à l''alinéa 1er commence à courir au prononcé de la sanction 
disciplinaire. 
 
Sans préjudice de l''exécution de la sanction disciplinaire, l''effacement a 
pour conséquence que la sanction ne peut plus avoir d''effet, notamment sur les 
droits d''accès à une autre fonction de promotion. 
 
CHAPITRE IX. - De la chambre de recours', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '115', NULL, 'Article 115 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 182, 'Art. 116', 'Article 116. - Il est institué, auprès du Gouvernement, une Chambre de 
recours pour les membres du personnel du Service général de l''Inspection, ci-
après dénommée «la Chambre de recours». 
 
La Chambre de recours élabore son règlement d''ordre intérieur qu''elle 
soumet pour approbation au Gouvernement.

Article 117. - La Chambre de recours traite des recours introduits en 
matière d''incompatibilité, d''évaluation et de sanction disciplinaire.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '116', NULL, 'Article 116 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','évaluation','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 183, 'Art. 118', 'Article 118. - La Chambre de recours est composée: 
1° d''un président désigné par le Gouvernement parmi les fonctionnaires 
généraux de rang 16 au moins; 
2° de trois membres désignés par le Gouvernement parmi les 
fonctionnaires généraux du Ministère de rang 15 au moins; 
3° de trois membres désignés par des organisations syndicales 
représentatives, parmi les membres du Service général de l''Inspection, chaque 
organisation syndicale disposant d''au moins un représentant; 
4° d''un secrétaire désigné par le Gouvernement parmi les agents de 
niveau 2+ au moins des Services du Gouvernement. 
 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '118', NULL, 'Article 118 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 184, 'Art. 119', 'Article 119. - Pour chaque membre effectif, le Gouvernement désigne un 
membre suppléant selon les mêmes modalités que celles visées à l''article 118, 
1°, 2° et 4°.

Article 120. - En cas de remplacement d''un membre, le remplaçant 
achève le mandat de celui à la place duquel il est désigné.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '119', NULL, 'Article 119 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 185, 'Art. 121', 'Article 121. - Les président, président suppléant, membres effectifs et 
membres suppléants sont désignés pour cinq ans. Leur mandat est 
renouvelable.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '121', NULL, 'Article 121 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 186, 'Art. 122', 'Article 122. - La Chambre de recours est présidée par le président et, à 
défaut, par le président suppléant. 
 
Le président a voix délibérative. 
 
Le secrétaire ou le secrétaire suppléant de la Chambre de recours en 
assure le secrétariat. Il n''a pas voix délibérative.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '122', NULL, 'Article 122 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 187, 'Art. 123', 'Article 123. - Aucun recours ne peut faire l''objet de délibérations de la 
Chambre de recours si le requérant n''a été mis à même de faire valoir ses 
moyens de défense et si le dossier ne contient les éléments susceptibles de 
permettre à la Chambre d''émettre un avis en toute connaissance de cause, 
notamment le rapport des enquêteurs, les procès-verbaux des auditions de 
témoins et des confrontations indispensables. 
 
Le requérant peut se faire assister ou représenter par un représentant 
d''une organisation syndicale agréée, par un avocat ou par un défenseur choisi 
parmi les membres du personnel du Service général de l''Inspection, en activité 
de service ou retraités. 
 
Le défaut de comparution du membre du personnel ou de son 
représentant n''empêche pas la Chambre de recours de se prononcer.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '123', NULL, 'Article 123 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 188, 'Art. 124', 'Article 124. - Dès qu''un recours est introduit, le Président communique 
au requérant la liste des membres effectifs et suppléants de la Chambre de 
recours. 
 
Dans les dix jours ouvrables qui suivent la réception de cette liste, le 
requérant peut demander la récusation d''un ou de plusieurs membres, mais 
tout au plus de deux membres désignés sur proposition des organisations 
syndicales et de deux membres désignés directement par le Gouvernement. 
Toutefois, il ne peut récuser un membre effectif et son suppléant. 
 
Tout membre qui se sait cause de récusation est tenu de s''abstenir. 
 
Un membre peut également demander à être déchargé s''il estime avoir 
un intérêt moral en la cause ou s''il croit que l''on puisse douter de son 
impartialité. Le Président décide de la suite à réserver à cette demande. Il peut 
aussi décharger d''office un membre pour les mêmes motifs.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '124', NULL, 'Article 124 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 189, 'Art. 125', 'Article 125. - Les président et président suppléant ne peuvent siéger 
dans une affaire relative à l''un des membres du personnel relevant de leur 
administration. 
 
 
Docu 46239 
 
D. 10-01-2019  
Le président, le président suppléant, les membres effectifs et les membres 
suppléants ne peuvent siéger dans une affaire concernant leur conjoint, leur 
cohabitant, un parent ou un allié, jusqu''au quatrième degré inclusivement.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '125', NULL, 'Article 125 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 190, 'Art. 126', 'Article 126. - La Chambre de recours délibère valablement si le 
président et quatre membres au moins sont présents. 
 
Si le quorum visé à l''alinéa 1er n''est pas atteint, le président convoque 
une nouvelle réunion dans les quinze jours. Au cours de cette réunion, une 
décision pourra être prise, quel que soit le nombre des membres présents.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '126', NULL, 'Article 126 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 191, 'Art. 127', 'Article 127. - Pour chaque affaire, le Gouvernement désigne un 
rapporteur parmi les agents de niveau 1 des Services du Gouvernement qui 
n''ont pas participé à l''enquête. 
 
Le rapporteur expose objectivement à la Chambre de recours les 
rétroactes de l''affaire et les résultats de l''enquête. Il a droit de réplique. Il n''a 
pas voix délibérative.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '127', NULL, 'Article 127 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 192, 'Art. 128', 'Article 128. - La Chambre de recours peut ordonner un complément 
d''enquête, entendre les témoins à charge ou à décharge. Après en avoir 
délibéré, elle transmet au Gouvernement son avis motivé. Cet avis mentionne 
le nombre de votes pour et contre émis.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '128', NULL, 'Article 128 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 193, 'Art. 129', 'Article 129. - L''avis est donné à la majorité simple des voix. 
 
Le vote sur l''avis a lieu au scrutin secret. Les membres désignés 
directement par le Gouvernement et ceux désignés sur proposition des 
organisations syndicales doivent être en nombre égal pour prendre part au 
vote. Le cas échéant, la parité est rétablie par l''élimination d''un ou de plusieurs 
membres après tirage au sort. 
 
En cas de parité des voix, le président décide.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '129', NULL, 'Article 129 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 194, 'Art. 130', 'Article 130. - La décision prise par le Gouvernement fait mention de 
l''avis motivé de la Chambre de recours. Toute décision non conforme à l''avis 
de la Chambre de recours est motivée. 
 
Le Gouvernement notifie sa décision à la Chambre de recours et au 
requérant.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '130', NULL, 'Article 130 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 195, 'Art. 131', 'Article 131. - Le mandat des membres de la Chambre de recours est 
gratuit. Toutefois, des indemnités pour frais de parcours et de séjour peuvent 
leur être accordées suivant les dispositions règlementaires en la matière. 
Aucune indemnité n''est cependant due au président ou au président 
suppléant.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '131', NULL, 'Article 131 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 196, 'Art. 132', 'Article 132. - Les modalités de fonctionnement de la Chambre de recours 
sont fixées par le Gouvernement, dans le respect des droits de la défense et du 
caractère contradictoire des débats. 
 
 
 
Docu 46239 
 
D. 10-01-2019  
CHAPITRE X. - De la suspension préventive: mesure administrative', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '132', NULL, 'Article 132 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 197, 'Art. 133 § 1', 'Article 133. - § 1er. La suspension préventive organisée par le présent 
chapitre est une mesure purement administrative, n''ayant pas le caractère 
d''une sanction. 
 
Elle est prononcée par le Gouvernement et est motivée. Elle a pour effet 
d''écarter le membre du personnel de ses fonctions. 
 
Pendant la durée de la suspension préventive, le membre du personnel 
reste dans la position administrative de l''activité de service. 
 
§ 2. Avant toute mesure de suspension préventive, le membre du 
personnel doit avoir été invité à se faire entendre par le fonctionnaire général 
désigné par le Gouvernement ou l''Inspecteur général coordonnateur qu''il 
délègue à cet effet. 
 
La convocation à l''audition ainsi que les motifs justifiant la suspension 
préventive sont notifiés au membre du personnel trois jours ouvrables au 
moins avant l''audition, soit par lettre recommandée à la poste avec accusé de 
réception portant ses effets trois jours ouvrables après la date de son 
expédition, soit par la remise d''une lettre de la main à la main avec accusé de 
réception portant ses effets à la date figurant sur cet accusé de réception. 
 
Au cours de l''audition, le membre du personnel peut se faire assister ou 
représenter par un représentant d''une organisation syndicale agréée, par un 
avocat ou par un défenseur choisi parmi les membres du personnel du Service 
général de l''Inspection, en activité de service ou retraités. 
 
Dans les dix jours ouvrables qui suivent celui prévu pour l''audition, la 
décision est communiquée au membre du personnel par lettre recommandée à 
la poste, et ce même si le membre du personnel ou son représentant ne se sont 
pas présentés à l''audition sans pouvoir faire valoir des circonstances de force 
majeure de nature à justifier leur absence à l''audition. 
 
Si le membre du personnel ou son représentant peuvent faire valoir des 
circonstances de force majeure de nature à justifier leur absence à l''audition, 
le membre du personnel est convoqué à une nouvelle audition notifiée 
conformément à l''alinéa 2. 
 
Dans ce cas, et même si le membre du personnel ou son représentant ne 
se sont pas présentés à l''audition, la décision est communiquée au membre du 
personnel par lettre recommandée à la poste dans les dix jours ouvrables qui 
suivent celui prévu pour l''audition. 
 
Si la décision conclut à la suspension préventive du membre du personnel, 
elle produit ses effets le troisième jour ouvrable suivant la date de son 
expédition. 
 
§ 3. Par dérogation à l''alinéa 1er du paragraphe 2, le membre du personnel 
peut être écarté de ses fonctions sur-le-champ en cas de faute grave pour 
laquelle il y a flagrant délit ou lorsque les griefs qui lui sont reprochés revêtent 
 
 
Docu 46239 
 
D. 10-01-2019  
un caractère de gravité] tel qu''il est souhaitable, dans l''intérêt du service, que 
le membre du personnel ne soit plus présent au sein du Service. 
 
Dans les dix jours ouvrables qui suivent le jour où la mesure d''écartement 
immédiat a été prise, la procédure de suspension préventive doit être engagée 
conformément aux dispositions du présent article. A défaut, la mesure 
d''écartement immédiat prendra fin au terme du délai précité et le membre du 
personnel ne pourra à nouveau être écarté du service pour la même faute grave 
ou les mêmes griefs que moyennant le respect de la procédure de suspension 
préventive tel que prévu notamment au paragraphe 2. 
 
La 
mesure 
d''écartement 
sur-le-champ 
est 
prononcée 
par 
le 
Gouvernement. Le membre du personnel écarté sur-le-champ reste dans la 
position administrative de l''activité de service.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '133', '1', 'Article 133 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','inspection','obligation scolaire','ROI','DASPA'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 198, 'Art. 134 § 1', 'Article 134. - § 1er. Lorsque l''intérêt du service ou de l''enseignement le 
requiert, une procédure de suspension préventive peut être entamée à l''égard 
d''un membre du personnel du Service général de l''Inspection: 
 
1° s''il fait l''objet de poursuites pénales; 
2° avant l''exercice de poursuites disciplinaires ou s''il fait l''objet de 
poursuites disciplinaires; 
3° dès que le Gouvernement lui notifie, par lettre recommandée à la poste, 
la constatation d''une incompatibilité. 
 
§ 2. Dans le cadre de la constatation d''une incompatibilité ou dans le 
cadre d''une procédure disciplinaire ou avant l''exercice éventuel d''une 
procédure disciplinaire, la durée de la suspension préventive ne peut dépasser 
un an et, dans le cadre d''une procédure disciplinaire, elle expire en tout cas: 
1° après six mois si aucune proposition de sanction disciplinaire n''a été 
formulée et notifiée au membre du personnel dans ce délai; 
2° le troisième jour ouvrable qui suit la notification de la proposition de 
sanction disciplinaire si cette proposition est le rappel à l''ordre, la réprimande 
ou la retenue sur traitement; 
3° pour une proposition de sanction disciplinaire autre que celles visées 
au point 2°, quatre-vingts jours calendrier après la notification de la 
proposition de sanction disciplinaire au membre du personnel si ce dernier n''a 
pas introduit de recours à l''encontre de ladite proposition; 
4° pour une proposition de sanction disciplinaire autre que celles visées 
au point 2°, quatre-vingts jours calendrier après la notification au Ministre de 
l''avis de la Chambre de recours sur la proposition de sanction disciplinaire 
formulée à l''encontre du membre du personnel; 
5° le jour où la sanction disciplinaire sort ses effets. 
 
Dans le cadre de poursuites pénales, la durée de la suspension préventive 
n''est pas limitée à un an. 
 
Lorsqu''une procédure disciplinaire est engagée ou poursuivie après une 
décision judiciaire de condamnation pénale coulée en force de chose jugée, le 
délai d''un an visé à l''alinéa 1er ne commence à courir qu''à dater du prononcé 
de la condamnation définitive. 
 
 
 
Docu 46239 
 
D. 10-01-2019  
§ 3. Dans le cadre d''une procédure disciplinaire ou avant l''exercice 
éventuel d''une procédure disciplinaire, la suspension préventive doit faire 
l''objet d''une confirmation écrite tous les trois mois à dater de la prise d''effet. 
 
Cette confirmation est notifiée à l''intéressé par lettre recommandée à la 
poste. 
 
A défaut de confirmation de la suspension préventive dans les délais 
requis, le membre du personnel concerné peut réintégrer ses fonctions après 
en avoir informé le Gouvernement, par lettre recommandée, au moins dix jours 
ouvrables avant la reprise effective du travail. 
 
Après réception de cette notification, le Gouvernement peut confirmer le 
maintien en suspension préventive selon la procédure décrite à l''alinéa 2.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '134', '1', 'Article 134 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','redoublement','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 199, 'Art. 135', 'Article 135. - Tout membre du personnel suspendu préventivement 
maintient son droit au traitement. 
 
Par dérogation à l''alinéa 1er, est fixé à la moitié de son traitement 
d''activité 
le 
traitement 
de 
tout 
membre 
du 
personnel 
suspendu 
préventivement qui fait l''objet: 
 
 
1° d''une inculpation ou d''une prévention dans le cadre de poursuites 
pénales; 
2° d''une condamnation pénale non définitive contre laquelle le membre 
du personnel a fait usage de ses droits de recours ordinaires; 
3° d''une procédure disciplinaire engagée ou poursuivie à la suite d''une 
condamnation pénale définitive; 
4° de poursuites disciplinaires en raison d''une faute grave pour laquelle 
il y a soit flagrant délit, soit des indices probants et dont l''appréciation 
appartient au Gouvernement; 
d''une proposition de sanction disciplinaire prévue à l''article 105, alinéa 
1er, 4°, 5°, 6° et 7°, ou alinéa 2. 
 
Cette réduction du traitement ne peut avoir pour effet de ramener le 
traitement à un montant inférieur au montant des allocations de chômage 
auquel le membre du personnel aurait droit s''il bénéficiait du régime de 
sécurité sociale des travailleurs salariés. 
 
Pour l''application de l''alinéa 2, 1° et 2°, cette réduction de traitement 
prend effet le premier jour du mois qui suit le jour de l''inculpation ou de la 
prévention ou du prononcé de la condamnation non définitive. 
 
Pour l''application de l''alinéa 2, 3°, cette réduction de traitement déjà 
opérée en vertu de l''alinéa 2, 1° ou 2°, est maintenue au-delà de la 
condamnation définitive si le Ministre notifie au membre du personnel son 
intention de poursuivre ou d''engager la procédure disciplinaire. 
 
Pour l''application de l''alinéa 2, 4°, la réduction de traitement prend effet 
le premier jour du mois qui suit la notification du Ministre au membre du 
personnel de l''application de cet alinéa 2, 4°. 
 
 
 
Docu 46239 
 
D. 10-01-2019  
Pour l''application de l''alinéa 2, 5°, cette réduction de traitement prend 
effet le jour où la proposition de sanction disciplinaire est soumise ou notifiée 
au membre du personnel.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '135', NULL, 'Article 135 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','discipline','redoublement','ROI','DASPA'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 200, 'Art. 136', 'Article 136. - A l''issue de la procédure disciplinaire ou de la procédure 
pénale, la mesure de réduction de traitement est rapportée sauf si: 
1° le Gouvernement inflige au membre du personnel une des sanctions 
prévues à l''article 105, alinéa 1er, 4°, 5°, 6° et 7°, ou alinéa 2; 
2° il est fait application de l''article 137, § 1er, 2°, b), et 5° ; 
3° le membre du personnel fait l''objet d''une condamnation pénale 
définitive suivie ou non d''une procédure disciplinaire. 
 
Lorsque la mesure de réduction de traitement est rapportée en 
application de l''alinéa 1er, le membre du personnel reçoit le complément de son 
traitement initialement retenu augmenté des intérêts de retard calculés au 
taux légal et dus depuis le jour où la réduction a été opérée. 
 
Les sommes perçues par le membre du personnel durant la suspension 
préventive lui restent acquises. 
 
Si le traitement du membre du personnel a été réduit en application de 
l''article 135, alinéa 2, 4° ou 5°, et qu''au terme de la procédure disciplinaire, 
une sanction de suspension disciplinaire est prononcée pour une durée 
inférieure à la durée de la mesure de réduction de traitement, cette dernière 
est rapportée pour la période excédant la durée de la suspension disciplinaire 
et le membre du personnel perçoit dans ce cas le complément de son 
traitement, indûment retenu durant cette période, augmenté des intérêts de 
retard calculés au taux légal et dus depuis le jour où la réduction a été opérée. 
 
L''alinéa 4 ne s''applique pas dans le cadre d''une procédure disciplinaire 
engagée ou poursuivie après une condamnation pénale définitive. 
 
CHAPITRE XI. - De la cessation des fonctions', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '136', NULL, 'Article 136 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['discipline','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 201, 'Art. 137 § 1', 'Article 137. - § 1er. Les membres du personnel du Service général de 
l''Inspection nommés à titre définitif ou stagiaires ou désignés à titre provisoire 
sont démis de leurs fonctions, d''office et sans préavis: 
1° s''ils n''ont pas été nommés à titre définitif ou admis au stage ou 
désignés à titre provisoire de façon régulière; 
2° s''ils cessent de répondre aux conditions suivantes: 
 [a) être belge ou ressortissant d''un Etat faisant partie de l''Espace 
économique européen ou de la Suisse ou disposer d''un titre de séjour et d''un 
permis de travail valides ;]296 
 b) jouir des droits civils et politiques; 
 c) avoir satisfait aux lois sur la milice; 
 d) être de conduite irréprochable; 
3° si après une absence autorisée, ils négligent, sans motif valable, de 
reprendre leur service et restent absents pour une période ininterrompue de 
plus de dix jours; 
4° s''ils abandonnent, sans motif valable, leur emploi et restent absents 
pendant une période ininterrompue de plus de dix jours; 
 
296Remplacé par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
5° s''ils se trouvent dans les cas où l''application des lois civiles et pénales 
entraine la cessation des fonctions; 
6° s''ils sont atteints d''une invalidité prématurée dûment constatée dans 
les conditions fixées par la loi et les mettant hors d''état de remplir leurs 
fonctions d''une manière complète, régulière et continue; 
7° si une incompatibilité est constatée et qu''aucun recours visé à l''article 
48 n''a été introduit ou que le membre du personnel refuse de mettre fin à une 
occupation incompatible, le cas échéant après épuisement de la procédure; 
8° s''ils sont mis à la retraite pour limite d''âge.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '137', '1', 'Article 137 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','inscription','exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 202, 'Art. 138', 'Article 138. - Pour les membres du personnel du Service général de 
l''Inspection nommés à titre définitif ou stagiaires, entraînent également la 
cessation définitive des fonctions: 
1° la démission volontaire: le membre du personnel ne peut abandonner 
son service qu''à condition d''y avoir été dûment autorisé conformément à 
l''article 55; 
2° la sanction disciplinaire de la démission disciplinaire ou de la 
révocation visées à l''article 105.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '138', NULL, 'Article 138 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','discipline','évaluation','personnel','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 203, 'Art. 139', 'Article 139. - Sans préjudice de l''application de l''article 137 du présent 
décret, moyennant un préavis de quinze jours, le Gouvernement peut mettre 
fin au stage d''un membre du personnel désigné en tant que stagiaire dans une 
fonction de promotion d''inspecteur. 
 
Préalablement à toute décision du Gouvernement, le membre du 
personnel doit avoir été invité à se faire entendre par le fonctionnaire général 
désigné par le Gouvernement ou l''Inspecteur général coordonnateur qu''il 
délègue à cet effet. 
 
La convocation à l''audition ainsi que les motifs en raison desquels le 
Gouvernement envisage de mettre fin au stage sont notifiés au membre du 
personnel cinq jours ouvrables au moins avant son audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. 
 
Au cours de l''audition, le membre du personnel peut se faire assister ou 
représenter par un représentant d''une organisation syndicale agréée, par un 
avocat ou par un défenseur choisi parmi les membres du personnel du Service 
général de l''Inspection, en activité de service ou retraités. 
 
L''audition fait l''objet d''un procès-verbal. 
 
La procédure se poursuit valablement lorsque le membre du personnel, 
dûment convoqué, ne se présente pas à l''audition ou n''y est pas représenté. 
 
Le Gouvernement prend sa décision dans les dix jours de la transmission 
du procès-verbal. 
 
 
Docu 46239 
 
D. 10-01-2019  
TITRE IV. - DISPOSITIONS TRANSITOIRES ET MODIFICATIVE, 
DISPOSITION ABROGATOIRE ET DISPOSITION FINALE 
 
CHAPITRE Ier. - Dispositions transitoires

Article 140. – […]297', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '139', NULL, 'Article 139 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 204, 'Art. 141', 'Article 141. - Sous réserve de l''alinéa 2, les membres du personnel qui, 
à la veille de l''entrée en vigueur du présent décret, sont nommés à titre 
définitif à la fonction d''inspecteur en vertu du décret du 8 mars 2007 relatif au 
service général de l''inspection, au service de conseil et de soutien pédagogiques 
de l''enseignement organisé par la Communauté française, aux cellules de 
conseil et de soutien pédagogiques de l''enseignement subventionné par la 
Communauté française et au statut des membres du personnel du service 
général de l''inspection et des conseillers pédagogiques, sont réputés nommés 
à titre définitif au sein du Service général de l''Inspection dans la même 
fonction, à la date d''entrée en vigueur du présent décret. 
 
Les membres du personnel qui, à la veille de l''entrée en vigueur du 
présent décret, sont nommés à titre définitif à la fonction d''inspecteur d''un 
cours de religion en vertu de l''article 9, alinéa 1er, de la loi du 29 mai 1959 
modifiant certaines dispositions de la législation de l''enseignement, sont 
réputés nommés à titre définitif au sein du Service général de l''Inspection à la 
date d''entrée en vigueur du présent décret, à la fonction d''inspecteur 
correspondante (tableau de l''annexe Ire). 
 
Les membres du personnel qui, à la veille de l''entrée en vigueur du 
présent décret, sont désignés et nommés par leur chef de culte pour l''inspection 
d''un cours de religion en vertu de l''article 9, alinéas 2 et 3, de la loi du 29 mai 
1959 modifiant certaines dispositions de la législation de l''enseignement, sont 
réputés nommés à titre définitif au sein du Service général de l''Inspection à la 
date d''entrée en vigueur du présent décret, à la fonction d''inspecteur 
correspondante (tableau de l''annexe Ire).', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '141', NULL, 'Article 141 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['exclusion','personnel','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 205, 'Art. 142', 'Article 142. - L''Inspecteur général coordonnateur, les Inspecteurs 
généraux et les Inspecteurs chargés de la coordination de l''Inspection désignés 
en cette qualité à la veille de l''entrée en vigueur du présent décret sont réputés 
désignés respectivement comme Inspecteur général coordonnateur, comme 
Inspecteurs généraux et comme Inspecteurs coordonnateurs, au sein du même 
service, ceci jusqu''au terme de leur mandat en cours à la date de l''entrée en 
vigueur du présent décret.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '142', NULL, 'Article 142 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 206, 'Art. 143', 'Article 143. - Par dérogation à l''article 57, les membres du personnel 
désignés à titre provisoire en qualité d''inspecteur à la veille de l''entrée en 
vigueur du présent décret continuent à bénéficier de leur désignation à titre 
provisoire. 
 
 
297Abrogé par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019  
Parmi les membres du personnel désignés à titre provisoire visés à 
l''alinéa 1er, ceux qui occupent un emploi qui n''est plus repris dans le cadre visé 
à l''article 9, alinéa 2, continuent à bénéficier de leur désignation à titre 
provisoire jusqu''au 31 août 2023. 
 
Parmi les membres du personnel désignés à titre provisoire visés à 
l''alinéa 1er, ceux qui occupent un emploi qui est repris dans le cadre visé à 
l''article 9, alinéa 2, continuent à bénéficier de leur désignation à titre 
provisoire jusqu''à l''entrée en stage des inspecteurs-stagiaires désignés en 
vertu du présent décret. 
 
Si le nombre d''entrées en stage par fonction conformément au cadre 
arrêté pour la première fois après l''entrée en vigueur du présent décret en 
vertu de l''article 9, alinéa 2, est inférieur au nombre de membres du personnel 
désignés à titre provisoire dans la fonction correspondante, il est mis fin par 
priorité aux désignations à titre provisoire les plus récentes.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '143', NULL, 'Article 143 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 207, 'Art. 144 § 1', 'Article 144. - § 1er. Par dérogation à l''article 21, les membres du 
personnel désignés à titre provisoire en qualité d''inspecteur à la veille de 
l''entrée en vigueur du présent décret sont dispensés de l''épreuve visée à 
l''article 17 pour autant qu''ils aient obtenu la mention «favorable» à 
l''évaluation prévue à l''article 89 du présent décret. 
 
Dans l''hypothèse où l''inspecteur désigné à titre provisoire se prévalant 
du bénéfice de l''alinéa 1er n''a pas fait l''objet de l''évaluation visée à l''article 
89, § 2, avant le 1er janvier 2020, celle-ci est réputée favorable. 
 
§ 2. […]298 
 
CHAPITRE II. - Dispositions modificatives', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '144', '1', 'Article 144 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 208, 'Art. 145', 'Article 145. - A l''article 9, l''alinéa 1er de la loi du 29 mai 1959 modifiant 
certaines dispositions de la législation de l''enseignement est remplacée par ce 
qui suit: 
«L''inspection des cours de religion dans les établissements d''enseignement 
organisé et subventionné par la Communauté française est assurée par les 
inspecteurs des cours de religion nommés conformément au décret du 10 
janvier 2019 relatif au Service général de l''Inspection.».

Article 146. - A l''article 9 de la même loi, les alinéas 2, 3 et 4 sont 
abrogés.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '145', NULL, 'Article 145 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 209, 'Art. 147', 'Article 147. - L''intitulé de l''arrêté royal du 25 octobre 1971 fixant le 
statut des maîtres de religion, des professeurs de religion et des inspecteurs de 
religion des religions catholique, protestante, israélite, orthodoxe et islamique 
des établissements d''enseignement de la Communauté française est remplacé 
par un intitulé rédigé comme suit: 
«Arrêté royal fixant le statut des maîtres et des professeurs de religion 
des religions catholique, protestante, israélite, orthodoxe et islamique des 
établissements d''enseignement de la Communauté française». 
 
 
298Abrogé par le D. 18-04-2024 
 
 
Docu 46239 
 
D. 10-01-2019', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '147', NULL, 'Article 147 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 210, 'Art. 148', 'Article 148. - A l''article 1er, l''alinéa 1er du même arrêté royal est 
remplacé par un nouvel alinéa rédigé comme suit: 
«Le présent arrêté s''applique aux maîtres de religion et aux professeurs 
de religion des religions catholique, protestante, israélite, orthodoxe et 
islamique des établissements d''enseignement de la Communauté française.».

Article 149. - L''article 31 et l''article 32, alinéa 2, du même arrêté royal 
sont abrogés.', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '148', NULL, 'Article 148 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 211, 'Art. 150', 'Article 150. - L''article 3, paragraphe 1er, 2°, de l''arrêté royal du 28 
septembre 1984 portant exécution de la loi du 19 décembre 1974 organisant 
les relations entre les autorités publiques et les syndicats des agents relevant 
de ces autorités est complété par les termes suivants: 
«e) du Service général de l''Inspection relevant du Gouvernement de la 
Communauté française».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '150', NULL, 'Article 150 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 212, 'Art. 151', 'Article 151. - L''article 61 du décret du 24 juillet 1997 définissant les 
missions prioritaires de l''enseignement fondamental et de l''enseignement 
secondaire et organisant les structures propres à les atteindre, abrogé par le 
décret du 27 mars 2002, est rétabli dans la rédaction suivante: 
 
«Article 61. - § 1er. Il est créé au sein du Ministère une Cellule 
intermédiaire de coordination dont les membres sont: 
1° le fonctionnaire général en charge de la Direction générale du Pilotage 
du Système éducatif ou son délégué; 
2° l''Inspecteur général coordonnateur du Service général de l''Inspection 
ou son délégué; 
3° le Délégué coordonnateur Service général de Pilotage des Ecoles et des 
Centres psycho-médico-sociaux ou son délégué. 
 
La Cellule intermédiaire de coordination: 
1° assure la coordination entre le Service général de l''Inspection et le 
Service général du Pilotage des Ecoles et des Centres psycho-médico-sociaux, 
ainsi que son rôle de coordination entre les deux Services généraux précités et 
les services et directions qui sont placés au sein de la Direction générale du 
Pilotage du Système Educatif; 
2° exerce les missions qui lui sont confiées par le décret du 10 janvier 
2019 relatif au Service général de l''Inspection; 
3° exerce les missions qui lui sont confiées par le décret du 13 septembre 
2018 portant création du Service général de pilotage des écoles et Centres 
psycho-médico-sociaux et fixant le statut des directeurs de zone et délégués au 
contrat d''objectifs; 
4° exerce toute autre mission qui lui est confiée par le Gouvernement. 
 
§ 2. La Cellule intermédiaire de coordination fixe son règlement d''ordre 
intérieur. Il est approuvé par le Gouvernement. Il prévoit au moins que: 
1° le fonctionnaire en charge de la Direction générale du Pilotage du 
Système Educatif ou son délégué la préside et en fixe l''ordre du jour; 
2° la Cellule intermédiaire de coordination se réunit au moins une fois 
par mois sauf pendant les mois de juillet et août et prévoit les modalités de 
concertation en urgence, notamment dans le cas des missions d''investigation 
et de contrôle spécifique; 
3° les décisions sont prises dans le respect de la règle du consensus; 
 
 
Docu 46239 
 
D. 10-01-2019  
4° lorsque la Cellule intermédiaire de coordination exerce une mission 
visée au paragraphe 1er, alinéa 2, 2°, le Délégué coordonnateur du Service 
général de Pilotage des Ecoles et des Centres psycho-médico-sociaux ou son 
délégué siège en tant qu''observateur; 
5° lorsque la Cellule intermédiaire de coordination exerce une mission 
visée au paragraphe 1er, alinéa 2, 3°, l''Inspecteur général coordonnateur du 
Service général de l''Inspection ou son délégué siège en qualité d''observateur; 
6° si la Cellule intermédiaire de coordination exerce une mission liée aux 
articles 4, §§ 2 et 5, 5, §§ 2, 3, et 8, 6, §§ 1er et 4, et 7, §§ 2 et 5, du décret du 10 
janvier 2019 relatif au Service général de l''Inspection, elle invite le Directeur 
de la Direction des standards éducatifs et des évaluations ainsi que le 
fonctionnaire général en charge du Service général de l''analyse et de la 
prospective qui siègent en tant qu''observateurs; 
7° si la Cellule intermédiaire de coordination exerce une mission liée aux 
articles 5, § 1er, 5°, et 7, § 1er, 4, du décret du 13 septembre 2018 portant 
création du Service général de pilotage des écoles et Centres psycho-médico-
sociaux et fixant le statut des directeurs de zone et délégués au contrat 
d''objectifs, elle invite le Directeur de la Direction des standards éducatifs et 
des évaluations ainsi que le fonctionnaire général en charge du Service général 
de l''analyse et de la prospective qui siègent en tant qu''observateurs.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '151', NULL, 'Article 151 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['évaluation','inspection','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 213, 'Art. 152 § 2', 'Article 152. - L''article 1er, § 2, du décret du 13 septembre 2018 portant 
création du Service général de Pilotage des Ecoles et des Centres psycho-
médico-sociaux et fixant le statut des directeurs de zone et délégués au contrat 
d''objectifs est complété par un 13° rédigé comme suit: 
«13° «La Cellule intermédiaire de coordination»: la cellule crée par 
l''article 61 du Décret missions.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '152', '2', 'Article 152 § 2 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 214, 'Art. 153 § 1', 'Article 153. - L''article 3, § 1er, alinéa 2, du même décret est remplacé par 
la disposition suivante: 
«La Cellule intermédiaire de coordination exerce la coordination entre le 
Service général de l''Inspection et le Service général du Pilotage des Ecoles et 
des Centres psycho-médico-sociaux, ainsi que la coordination entre les deux 
Services généraux précités et les services et directions placés au sein de la 
Direction générale du Pilotage du Système Educatif.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '153', '1', 'Article 153 § 1 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 215, 'Art. 154', 'Article 154. - L''article 37 du même décret est remplacé par ce qui suit: 
«Article 37. Est incompatible avec la qualité de membre du personnel, 
l''exercice de tout mandat, en ce compris syndical, auprès d''un pouvoir 
organisateur ou d''une fédération de pouvoirs organisateurs dont un ou 
plusieurs établissement(s) d''enseignement est (sont) compris(s) dans le 
territoire sur lequel le membre du personnel exerce la fonction de directeur de 
zone ou de délégué au contrat d''objectifs.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '154', NULL, 'Article 154 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 216, 'Art. 155', 'Article 155. - Dans les articles 67 et 82 du même décret, le paragraphe 
4 est chaque fois complété les alinéas rédigés comme suit: 
«Le membre du personnel visé à l''alinéa 1er, peut introduire, par envoi 
recommandé, un recours écrit contre la décision de non-réussite du stage, par 
la voie hiérarchique, dans les dix jours de sa notification auprès de la Chambre 
de recours visée à l''article 121. Ce recours est suspensif. 
 
La Chambre de recours remet son avis au Gouvernement dans un délai 
maximum d''un mois à partir de la date de réception du recours. Le 
Gouvernement prend sa décision et attribue la mention d''évaluation au 
 
 
Docu 46239 
 
D. 10-01-2019  
membre du personnel stagiaire dans un délai maximum d''un mois à dater de 
la réception de l''avis.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '155', NULL, 'Article 155 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 217, 'Art. 156', 'Article 156. - L''article 123 du même décret est remplacé par ce qui suit: 
 
«Article 123. - La Chambre de recours est composée: 
1° d''un président et d''un président suppléant désignés par le 
Gouvernement parmi les fonctionnaires généraux de rang 16 au moins; 
2° de trois membres désignés par le Gouvernement parmi les 
fonctionnaires généraux de l''Administration générale de l''Enseignement de 
rang 15 au moins; 
3° de trois membres désignés par les organisations syndicales 
représentatives parmi les directeurs de zone, chaque organisation syndicale 
disposant au moins d''un représentant; 
4° d''un secrétaire désigné par le Gouvernement parmi les agents de 
niveau 2+ au moins des Services du Gouvernement.».', 'Décret du 10 janvier 2019 — Service général de l''inspection', 'Décret inspection', '156', NULL, 'Article 156 du Décret du 10 janvier 2019 — Service général de l''inspection (CDA 46239)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 218, 'Art. 157', 'Article 157. - L''article 146 du même décret est remplacé par ce qui suit: 
«Article 146. - Le mandat de Délégué coordonnateur est pourvu pour la 
première fois lorsque le Service général est pourvu conformément à l''article 
