INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46239', 219, 'Art. 158', 'Article 158. - Est abrogé, à la date d''entrée en vigueur du présent décret, 
