-- CDA 5556: Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (59 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 0, 'Art. 1er', 'Article 1er. - Les traitements des membres du personnel soumis aux 
dispositions du présent arrêté sont fixés par des échelles comprenant : 
- un traitement minimum; 
- des traitements dénommés "échelons", résultant des augmentations biennales; 
- un traitement maximum. 
 
[Le caractère adéquat du traitement minimum visé à l''alinéa 1er, premier tiret, est 
réévalué tous les quatre ans à partir du 15 novembre 2024, en tenant compte des 
critères suivants tels qu''énoncés à l''article 5.2 de la directive 2022/2041 (UE) du 
Parlement européen et du Conseil du 19 octobre 2022 relative à des salaires minimaux 
adéquats dans l''Union européenne : 
 
- du pouvoir d''achat des membres du personnel qui perçoivent un traitement en 
application de l''alinéa 1er, compte tenu du coût de la vie ; 
 
- du niveau général et de la répartition des traitements et salaires ; 
 
- du taux de croissance des traitements et salaires ; 
 
- des niveaux et évolutions de la productivité nationale à long terme.]1 
 
[Il est également tenu compte de la valeur de référence indicative de 50 % des 
traitements et salaire moyens bruts.]2 
 
[A l''occasion de cette réévaluation, le Gouvernement prend en compte l''avis 
éventuellement donné par le Comité commun à l''ensemble des services publics, visé à 
l''article 3, §1er, alinéa 1er, 3°, de la loi du 19 décembre 1974 organisant les relations 
entre les autorités publiques et les syndicats des agents relevant de ces autorités, 
conformément à la législation fédérale.]3 
 
Modifié par A.R. 24-03-1967 
 
1Inséré par le D. 20-11-2025 
2Inséré par le D. 20-11-2025 
3Inséré par le D. 20-11-2025 
Lois 05556 
 
A.R. 15-04-1958', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '1er', NULL, 'Article 1er du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 1, 'Art. 2', 'Article 2. - Les traitements et les augmentations biennales sont exprimés en un 
nombre d''unités monétaires correspondant à leur montant annuel.  
 
Le traitement n''est jamais inférieur au minimum vital. 
 
Modifié par A.R. 24-03-1967 ; A.R. 29-10-1971', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '2', NULL, 'Article 2 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 2, 'Art. 3', 'Article 3. - Pour l''application du présent arrêté : 
 
L''expression « Service de l''Etat » désigne tout service relevant du pouvoir législatif, 
du pouvoir exécutif ou du pouvoir judiciaire et non constitué en personne juridique. 
 
L''expression « Service d''Afrique » désigne tout service relevant du gouvernement du 
Congo belge et du Ruanda-Urundi et non constitué en personne juridique. 
 
L''expression "services publics autres que les services de l''Etat et les services 
d''Afrique" désigne : 
1° tout service relevant du pouvoir exécutif et constitué en personne juridique; 
2° tout service qui relevait du gouvernement du Congo belge ou du gouvernement 
du Ruanda-Urundi et qui était constitué en personne juridique; 
3° tout service provincial ou communal; 
4° toute autre institution de droit belge qui répond à des besoins collectifs, d''intérêt 
général ou local et dans la création ou la direction particulière de laquelle se constate 
une prépondérance de l''autorité publique, ainsi que toute autre institution de droit 
colonial qui répondait aux mêmes conditions.  
 
Modifié par D. 14-03-2019 ; D. 14-03-2019', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '3', NULL, 'Article 3 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 3, 'Art. 4 § 1', 'Article 4. - § 1er. Pour l''application du présent arrêté, l''expression « fonction à 
prestations complètes » désigne la fonction comportant des prestations dont l''horaire 
est tel qu''elles absorbent totalement une activité professionnelle normale. 
 
Sont notamment complètes les prestations de l''agent qui, comme membre du 
personnel de l''Etat, effectue au moins, dans une ou plusieurs écoles régies par le 
présent statut, le nombre minimum d''heures de cours fixé pour sa fonction par l''arrêté 
royal prévu à l''article 7 ainsi qu''à l''article 5 du décret du 14 mars 2019 portant 
diverses dispositions relatives à l''organisation du travail des membres du personnel de 
l''enseignement et octroyant plus de souplesse organisationnelle aux Pouvoirs 
organisateurs. 
 
§ 2. Pour l''application des articles 5 et 16, sont également complètes les prestations 
de l''agent qui, comme membre du personnel de l''Etat, effectue au moins, dans une ou 
plusieurs écoles régies par le présent statut, un total d''heures de cours tel que la 
somme des valeurs relatives de ces heures atteigne l''unité. 
 
Dans une fonction, la valeur relative d''une heure de cours s''exprime par une 
fraction dont le numérateur est l''unité et le dénominateur le nombre minimum 
d''heures de cours fixé pour cette fonction par l''arrêté royal prévu à l''article 7 ainsi qu''à 
l''article 5 du décret du 14 mars 2019 portant diverses dispositions relatives à 
l''organisation du travail des membres du personnel de l''enseignement et octroyant 
plus de souplesse organisationnelle aux Pouvoirs organisateurs. 
 
Modifié par A.R. 10-03-1965 ; L. 08-02-1974 ; A.R. 15-12-1978 ;A.R. 06-02-1980 ; A.R. 
n°63 du 20-07-1982 ; A.R. n°161 du 30-12-1982 ;L. 01-08-1985 ; L. 27-02-1986 ; A.Gt 02-06-
1995 ; A.Gt 24-10-1996 ; D. 20-12-2001 (mod. 02-06-2006) ; D. 03-03-2004; D. 27-01-2006', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '4', '1', 'Article 4 § 1 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 4, 'Art. 5', 'Article 5. - Pour l''application du présent arrêté : 
L''expression « fonction accessoire » désigne la fonction, qu''elle soit ou non à 
prestations complètes, qu''exerce dans une ou plusieurs écoles ou institutions régies 
par le présent statut, l''agent: 
Lois 05556 
 
A.R. 15-04-1958  
a) qui exerce déjà une fonction à prestations complètes dans une ou plusieurs autres 
écoles ou institutions régies par le présent statut; 
b) (…) 
c) (…) 
d) qui exerce également une fonction à prestations complètes dans l''enseignement 
de promotion sociale ou à horaire réduit;  
e) (…) 
f) qui exerce une fonction non exclusive dans l''enseignement de plein exercice, pour 
laquelle il bénéficie d''un traitement complet, dont le montant brut est égal ou 
supérieur au minimum de son échelle de traitement. 
 
Pour l''application du présent arrêté, l''expression «fonction principale» désigne la 
fonction, qu''elle soit ou non à prestations complètes, qui n''est pas considérée comme 
accessoire conformément aux dispositions précédentes. 
 
L''expression "fonction non exclusive" désigne la fonction qu''exerce dans une ou 
plusieurs écoles ou institutions d''enseignement artistique de l''Etat, le professeur 
enseignant les cours artistiques et l''accompagnateur nommés à titre définitif avant le 
1er septembre 2002 et qui ont optés pour le maintien des cumuls antérieurs. 
 
Par mesure transitoire, est également réputée non exclusive la fonction qu''exerce 
dans l''enseignement artistique, l''inspecteur de cours artistiques.  
 
Inséré par L. 08-02-1974 ; modifié par L. 27-02-1986; remplacé par D. 27-01-2006', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '5', NULL, 'Article 5 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['exclusion','redoublement','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 5, 'Art. 5bis', 'Article 5bis. - La Commission créée par la loi du 8 février 1974 modifiant 
l''arrêté royal du 15 avril 1958, modifié par l''arrêté royal du 10 mars 1965, portant 
statut pécuniaire du personnel enseignant, scientifique et assimilé du Ministère de 
l''Instruction publique, conserve sa compétence d''avis, conformément aux dispositions 
applicables à la veille de l''entrée en vigueur de la présente disposition, pour les 
prestations effectuées avant le 1er janvier 2006 par l''agent qui exerce une fonction 
dans une ou plusieurs écoles ou institutions régies par le présent arrêté. 
 
Inséré par D. 27-01-2006 ; modifié par D. 19-07-2021', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '5bis', NULL, 'Article 5bis du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 6, 'Art. 5ter § 1', 'Article 5ter. - § 1er. Lors de son entrée en fonction dans une école ou institution 
régie par le présent arrêté, l''agent introduit une déclaration de cumul auprès de son 
pouvoir organisateur, suivant le modèle fixé par le Gouvernement. 
 
§ 2. L''agent qui exerce une fonction dans une ou plusieurs écoles ou institutions 
régies par le présent arrêté introduit la déclaration de cumul visée au § 1er lorsqu''il 
débute une activité indépendante ou salariée, et lors de toute modification de ladite 
activité. Dès qu''il cesse ladite activité, l''agent le déclare auprès de son pouvoir 
organisateur. 
 
TITRE II. - DES FONCTIONS PRINCIPALES A PRESTATIONS 
COMPLETES. 
 
CHAPITRE Ier. - Régime organique. 
 
Section Ière. - De la fixation des échelles.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '5ter', '1', 'Article 5ter § 1 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 7, 'Art. 6', 'Article 6. - L''échelle de chaque grade est fixée par le Roi, eu égard à 
l''importance de la fonction qui correspond normalement au niveau de chacun des 
diplômes ou titres admis pour l''accès à ce grade. 
 
Pour certains grades, l''échelle peut être remplacée par un traitement unique.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '6', NULL, 'Article 6 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['inscription','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 8, 'Art. 7', 'Article 7. - Les échelles des grades du personnel enseignant, scientifique et 
Lois 05556 
 
A.R. 15-04-1958  
assimilé du Ministère de l''Instruction publique sont fixées par arrêté royal pris sur la 
proposition du Ministre de l''Instruction publique avec l''accord du Premier Ministre. 
 
Modifié par A.R. 15-04-1961 ; A.R. 24-03-1967

Article 8. – […] abrogé par A.R. 18-02-1974. 
 
Modifié par A.R. 18-02-1974', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '7', NULL, 'Article 7 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 9, 'Art. 9', 'Article 9. - Toute échelle est rangée, soit dans la classe dite "20 ans", soit dans 
la classe dite "21 ans", soit dans la classe dite "22 ans", soit dans la classe dite "23 
ans", soit dans la classe dite "24 ans". 
 
Modifié par A.R. 24-03-1967 ; A.R. 18-02-1974', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '9', NULL, 'Article 9 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 10, 'Art. 10', 'Article 10. - L''échelle est désignée par un indice qui en mentionne le 
traitement minimum, le traitement maximum, la classe, ainsi que le nombre et le 
montant des augmentations périodiques. 
 
Section II. - De la fixation du traitement. 
 
A. Dispositions générales.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '10', NULL, 'Article 10 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 11, 'Art. 11', 'Article 11. - A chaque modification du statut pécuniaire d''un grade, tout 
traitement établi compte tenu de ce grade est refixé comme si le nouveau statut 
pécuniaire avait existé de tout temps. 
 
Si le traitement ainsi refixé est inférieur à celui dont l''agent bénéficiait dans son 
grade à l''entrée en vigueur de l''arrêté modificatif, le traitement le plus élevé lui est 
maintenu dans ce grade jusqu''à ce qu''il obtienne un traitement au moins égal.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '11', NULL, 'Article 11 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 12, 'Art. 12', 'Article 12. - Sont seules valables les modalités de fixation du traitement qui 
sont établies par le présent arrêté, ainsi que par l''arrêté royal prévu à l''article 7.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '12', NULL, 'Article 12 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 13, 'Art. 13', 'Article 13. - Pour la détermination de l''âge de l''agent en vue de la fixation de 
son traitement, l''anniversaire de la naissance qui tombe à une date autre que le 
premier du mois est toujours reporté au premier du mois suivant. 
 
B. De la détermination de l''échelle.', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '13', NULL, 'Article 13 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 14, 'Art. 14', 'Article 14. - Le traitement de tout agent est fixé dans l''échelle de son grade, 
compte tenu du diplôme ou titre dont il est titulaire. 
 
Modifié par A.R. 24-03-1967 ; A.R. 07-09-1969 ; A.R. 18-02-1974', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '14', NULL, 'Article 14 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 15, 'Art. 15', 'Article 15. - Le traitement minimum est destiné à l''agent ayant atteint l''âge de 
18 ans, quelle que soit la classe de son échelle. 
 
Pour l''agent âgé de moins de 18 ans, le traitement minimum est amputé d''une 
somme forfaitaire de 297,47 EUR (12.000 BEF). 
 
C. Des services admissibles.  
 
a) De l''admissibilité. 
 
