INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 16, 'Art. 16 § 1', '§ 1er. Sont admissibles, à partir de l''âge de 20, de 21, de 22, de 23 
ou 24 ans, selon la classe de son échelle : 
 
A. Sans limitation : 
 
a) les services effectifs que l''agent a prestés comme titulaire d''une fonction 
rémunérée et comportant des prestations complètes : 
• 
dans une école de l''Etat, de la Colonie, d''une province, d''une commune ou d''une 
administration subordonnée à une province ou à une commune; 
• 
dans une école subventionnée ou inspectée par l''Etat ou par la Colonie;  
• 
dans une école belge à l''étranger ou dans une école alliée, pendant la période du 
1er août 1914 au 31 janvier 1919 ou du 10 mai 1940 au 30 septembre 1945; 
• 
soit dans une université belge ou dans un établissement y assimilé en vertu de 
la loi sur la collation des grades académiques, soit dans un des établissements 
scientifiques dont la liste est établie par le Ministre de l''Instruction publique, à la 
condition d''y avoir fait partie du personnel enseignant ou scientifique; 
• 
dans une Université d''Etat d''un pays ressortissant de l''Union européenne à la 
condition d''y avoir fait partie du personnel enseignant ou scientifique ; 
• 
dans un établissement d''enseignement supérieur artistique de l''Union 
européenne, que cet établissement soit ou non intégré à la structure universitaire à 
condition d''y avoir fait partie du personnel enseignant. [inséré par D. 07-02-2019] 
 
b) les services effectifs que l''agent a prestés, avant le 1er janvier 1951, comme 
titulaire d''une fonction rémunérée et comportant des prestations complètes, dans un 
établissement d''instruction moyenne, organisé par une personne privée, qui a délivré, 
à la fin de l''année scolaire durant laquelle les services ont été rendus, des certificats de 
fin d''études moyennes complètes dûment homologués ou agréés ou des certificats 
complémentaires relatifs aux trois années d''études moyennes du degré inférieur, 
présentant les garanties nécessaires en vue de l''homologation ou de l''agréation future 
des certificats de fin d''études moyennes complètes; 
 
c) les services effectifs que l''agent a prestés : 
• 
comme intérimaire occasionnel ou comme temporaire dans une école de l''Etat, 
d''une province, d''une commune, d''une administration subordonnée à une province ou à 
une commune ou dans une école subventionnée par l''Etat; 
• 
comme intérimaire dans une école primaire ou gardienne, soit provinciale ou 
communale, soit adoptée ou adoptable; 
 
d) le temps que l''agent a passé à l''étranger comme bénéficiaire d''une bourse de 
voyage ou d''une rétribution accordée par le gouvernement, la Fondation universitaire 
ou un organisme culturel international reconnu par la Belgique; 
 
e) le temps que l''agent a passé en disponibilité, même sans traitement, pour remplir 
une mission dans l''intérêt de l''enseignement ou de la science;  
 
f) le temps que l''agent a passé comme titulaire d''une fonction à prestations 
complètes d''aspirant, de chargé de recherches, de chercheur qualifié, de collaborateur, 
d''assistant ou de chargé de mission : 
• 
au Fonds national de la Recherche scientifique; 
• 
dans un des organismes de recherche scientifique dont la liste est établie par le 
Ministre de l''Instruction publique; 
• 
dans un musée de l''Etat. 
 
g)  Les services effectifs que l''agent a prestés, avant  le 1er janvier 1961, comme 
titulaire d''une fonction rémunérée et comportant des prestations complètes, soit dans 
une école primaire ou gardienne, non visée ci-avant, établie en Belgique et organisée 
Lois 05556 
 
A.R. 15-04-1958  
par une personne privée, soit dans une institution pour enfants débiles ou 
prétuberculeux établie en Belgique ou à l''étranger, pour autant que cette école ou 
institution ait offert au moment où les services ont été prestés, des garanties 
suffisantes au point de vue de leur organisation et de leur enseignement et tout en 
étant porteur du diplôme requis pour la fonction correspondante exercée dans une 
école soumise au régime de la loi organique de l''enseignement primai', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '16', '1', 'Article 16 § 1 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['inscription','exclusion','évaluation','personnel','ROI'], 'commun');
