INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 21, 'Art. 16 § 1', '§ 1er du présent article sont valorisables dans 
