INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 24, 'Art. 17 § 1', '§ 1er. Pour le directeur, directeur adjoint, chef de bureau d''études, 
