INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('5556', 27, 'Art. 17 § 1', '§ 1 à 4 
s''étend à tous les membres du personnel visés à l''article 1er, alinéa 3 du décret du 11 
avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française. 
 
La date fixée par le Gouvernement est identique à celle à laquelle il fixera l''échelle 
barémique de référence pour les porteurs d''un titre de capacité requis qui possèdent 
une composante disciplinaire acquise dans le cadre d''un «master en Enseignement 
section 1, 2 ou 3» délivré dans le cadre du décret définissant la formation initiale des 
enseignants adopté en séance plénière le 6 février 2019. 
 
[En Haute Ecole, pour le maître-assistant autre que cité à l''alinéa premier, le 
chargé de cours, le chef de travaux, le professeur et le chef de bureau d''études forme 
également des services admissibles le temps qu''il a passé dans une entreprise à partir 
de l''âge de 21, 22, 23 ou 24 ans. Par dérogation, ce temps ne peut jamais excéder 5 
années]7. 
 
Inséré par A.R. 21-06-1962', 'Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant', 'AR statut pécuniaire', '17', '1', 'Article 17 § 1 du Arrêté royal du 15 avril 1958 — Statut pécuniaire du personnel enseignant (CDA 5556)', ARRAY['inscription','discipline'], 'commun');
