INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 29, 'Art. 10 § 4', '§ 4. Lorsque l''apprentissage par immersion est organisé et suivi dans 
