INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 30, 'Art. 10', 'Article 10/1. - Les périodes du cours d''éducation physique de la 
formation commune ne peuvent pas être remplacées par des périodes 
d''entraînement sportif prévues à l''article 1er, alinéa 2, de l''arrêté royal du 29 
juin 1984 précité, sauf dérogation accordée par le ministre qui a 
l''enseignement secondaire dans ses attributions ou son délégué sur base d''un 
rapport établi par le chef d''établissement.  
 
Modifié par D. 07-12-2007', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '10', NULL, 'Article 10 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 31, 'Art. 11', 'Article 11. - Le Service de l''Inspection de l''Enseignement est chargé du 
contrôle du respect des dispositions visées aux articles 6 à 10 et 13 à 31 du 
présent décret. 
 
Modifié par D. 07-12-2007', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '11', NULL, 'Article 11 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 32, 'Art. 12', 'Article 12. - L''organisation des activités complémentaires et leur 
volume ainsi que l’organisation du premier degré différencié fait l''objet d''un 
avis préalable et concerté avec les organisations syndicales représentatives. 
 
La concertation avec les organisations syndicales représentatives se 
fait : 
1° Dans l''enseignement de la Communauté française, conformément 
aux dispositions de la loi du 19 décembre 1974 organisant les relations entre 
les autorités publiques et les syndicats des agents relevant de ces autorités; 
2° Dans l''enseignement officiel subventionné, conformément aux 
dispositions des articles 85 à 96 du décret du 6 juin 1994 fixant le statut des 
membres du personnel subsidié de l''enseignement officiel subventionné; 
3° Dans l''enseignement libre subventionné, conformément aux 
dispositions relatives aux conseils d''entreprise, ou, à défaut, au Comité pour 
la protection du travail, ou, à défaut dans les instances de concertation 
locales, ou, à défaut avec les délégations syndicales. 
 
Inséré par D. 17-10-2013 
CHAPITRE 4. - De l''apprentissage par immersion en langue des 
signes et en français écrit en classes bilingues français-langue des 
signes 
 
Inséré par D. 17-10-2013 ; modifié par D. 13-07-2016', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '12', NULL, 'Article 12 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 33, 'Art. 12bis § 1', 'Article 
12bis. - § 1er. 
Dans 
l''enseignement 
organisé 
par 
la 
Communauté française, sur demande du chef d''établissement, après avoir 
pris l''avis du conseil de participation et après consultation préalable du 
comité de concertation de base, le Gouvernement peut autoriser un 
établissement à organiser l''ensemble des cours et activités pédagogiques de 
la grille-horaire dans le cadre de classes bilingues français-langue des signes. 
 
Dans l''enseignement subventionné, le Gouvernement peut autoriser un 
pouvoir organisateur à assurer dans un des établissements qu''il organise 
l''ensemble des cours et activités pédagogiques de la grille-horaire dans le 
cadre de classes bilingues français-langue des signes. La demande est 
accompagnée de l''avis du conseil de participation et du résultat de la 
consultation préalable de la Commission paritaire locale pour les 
établissements d''enseignement officiel subventionné par la Communauté 
française, du conseil d''entreprise, ou à défaut, de l''instance de concertation 
locale, ou à défaut des délégations syndicales pour les établissements 
d''enseignement libre subventionné par la Communauté française. 
 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
Par école concernée, un minimum de 4 périodes hebdomadaires 
identifiées parmi les cours de langue française, de langue des signes et/ou de 
langue moderne 1 doit être assuré par des enseignants de culture sourde, à 
défaut de pouvoir attribuer ces périodes à des enseignants de culture sourde, 
ces cours peuvent être dispensés par des enseignants disposant des titres tels 
que précisés à l''arrêté du Gouvernement de la Communauté française du 5 
juin 2014 relatif aux fonctions, titres de capacité et barèmes portant 
exécution des articles 7, 16, 50 et 263 du décret du 11 avril 2014 
réglementant les titres et fonctions dans l''enseignement fondamental et 
secondaire organisé et subventionné par la Communauté française. 
 
Lorsqu''une école ou une implantation organise des classes bilingues 
français-langue des signes, cette organisation est intégrée dans le projet 
d''établissement. 
 
Modifié par D. 13-07-2016 
§ 2. L''élève aborde l''apprentissage par immersion en langue des signes 
en classe bilingue français-langue des signes au niveau de la première année 
de l''enseignement secondaire. Cet apprentissage par immersion en langue 
des signes en classe bilingue français-langue des signes s''inscrit dans le 
continuum pédagogique relatif à l''apprentissage par immersion en langue 
des signes en classe bilingue français-langue des signes développé dans 
l''enseignement fondamental, quel que soit l''établissement. 
 
Par dérogation à l''alinéa précédent, le conseil de classe peut autoriser 
un élève à aborder cet apprentissage au cours du 1er degré pour autant qu''il 
apporte la preuve d''une maîtrise des compétences nécessaires. 
 
Une école secondaire qui commence à organiser l''apprentissage par 
immersion en langue des signes en classe bilingue français-langue des signes 
le fait de manière progressive du début du premier degré à la fin du premier 
degré et garantit qu''un élève ayant entamé l''apprentissage par immersion 
puisse poursuivre cet apprentissage durant la suite de sa scolarité au sein du 
premier degré dans le même établissement. 
 
Inséré par D. 17-10-2013', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '12bis', '1', 'Article 12bis § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation','personnel'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 34, 'Art. 12ter', 'Article 12ter. - Dans l''enseignement secondaire, l''apprentissage par 
immersion en langue des signes en classe bilingue français-langue des signes 
est assuré par des professeurs de cours généraux chargés des cours 
d''apprentissage par immersion en langue des signes. 
 
Les moyens de fonctionnement peuvent permettre l''engagement 
d''interprètes sous contrat de travail à durée déterminée, sous contrat de 
prestation de services ou sous contrat de collaboration. 
 
Inséré par D. 07-12-2007 ; intitulé modifié par D. 11-04-2014 
TITRE III. - De l''organisation d''une année supplémentaire au terme 
du premier degré de l''enseignement secondaire 
 
Remplacé par D. 11-04-2014 ; complété par D. 04-02-2016', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '12ter', NULL, 'Article 12ter du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 35, 'Art. 13 § 1', 'Article 13. - § 1er. Une année supplémentaire, appelée 2 S, est 
organisée : 
1° au bénéfice des élèves qui, au terme de la deuxième année commune, 
éprouvent des difficultés telles qu''une année supplémentaire au premier 
degré s''avère indispensable pour leur permettre d''atteindre la maîtrise des 
socles de compétences visées à la fin de la troisième étape du continuum 
pédagogique, conformément à l''article 16, § 1er, du «décret Missions»; 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
2° au bénéfice des élèves, titulaires ou non du Certificat d''Etudes de 
Base qui, au terme de la deuxième année différenciée, éprouvent des 
difficultés telles qu''une année supplémentaire s''avère indispensable pour 
leur permettre d''atteindre la maîtrise des socles de compétences visées à la 
fin de la deuxième et/ou de la troisième étape du continuum pédagogique, 
conformément à l''article 16, § 1er, du «décret Missions». 
3° au bénéfice des élèves ayant suivi deux années au sein du 1er degré 
dans un établissement organisé, subventionné ou reconnu par la 
Communauté flamande ou par la Communauté germanophone. [inséré par D. 
04-02-2016] 
 
§ 2. L''établissement scolaire qui oriente un élève vers l''année 
supplémentaire visée au paragraphe 1er est tenu d''organiser cette dernière en 
son sein. 
 
§ 3. Cette année supplémentaire ne peut en aucun cas constituer un 
redoublement de l''année antérieure. 
 
Complété par D. 12-12-2008 ; modifié par D. 12-07-2012 ; modifié par D. 
12-07-2012 ; Remplacé par D. 11-04-2014 ; modifié par D. 14-07-2015 ; D. 19-
07-2017', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '13', '1', 'Article 13 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['redoublement','ROI','DASPA'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 36, 'Art. 14 § 1', 'Article 14. - § 1er. Tout élève orienté vers l''année supplémentaire visée 
à l''article 13 bénéficie d''un PIA élaboré conformément à l''article 7bis. 
 
§ 2. Le PIA est décidé, suivi et ajusté dans les conditions de l''article 
7bis. 
 
Il est présenté par le chef d''établissement ou son délégué, avant le 15 
octobre de l''année scolaire concernée, à l''élève ainsi qu''à ses parents ou à la 
personne investie de l''autorité parentale. Le chef d''établissement ou son 
délégué peuvent être accompagnés d''un autre membre de l''équipe 
pédagogique ou d''un membre du Centre psycho-médico-social concerné. 
 
§ 3. Le PIA visé au paragraphe 1er définit la grille horaire de l''élève; elle 
peut être individualisée en fonction de ses difficultés particulières 
d''apprentissage ou de ses besoins spécifiques. Elle doit permettre à l''élève de 
combler ses lacunes dans les compétences visées à la fin de la deuxième et/ou 
de la troisième étape du continuum pédagogique, conformément à l''article 
16, § 1er, du «décret Missions» et au décret du 19 juillet 2001. Elle doit aussi 
favoriser le développement par l''élève des compétences qui ne présentent pas 
de difficultés pour lui et la construction d''un projet d''orientation scolaire 
positive. 
 
Alinéa remplacé par D. 14-07-2015 ; Modifié par D. 19-07-2017 
La grille horaire de l''année supplémentaire visée à l''article 13 
comprend, outre les périodes de religion et de morale non confessionnelle ou 
de philosophie et de citoyenneté visées à l''article 8 de la loi du 29 mai 1959 
précitée, de vingt-huit à trente périodes dont au moins deux périodes 
consacrées à l''éducation physique. 
 
La grille horaire des élèves peut comprendre la participation à des cours 
organisés au bénéfice des élèves de deuxième année commune, de deuxième 
année différenciée ou de troisième année. 
 
Remplacé par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '14', '1', 'Article 14 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['orientation','parents','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 37, 'Art. 15', 'Article 15. - L''année supplémentaire organisée au terme du premier 
degré est accessible : 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
1° à tout élève régulier au sens de l''article 2, 9°, de l''arrêté royal du 29 
juin 1984 précité qui a suivi la deuxième année commune et à l''égard duquel 
est prise une des décisions visées à l''article 26, § 2, alinéa 1er; 
2° à tout élève régulier au sens de l''article 2, 9°, de l''arrêté royal du 29 
juin 1984 précité qui a suivi la deuxième année différenciée et à l''égard 
duquel est prise une des décisions visées à l''article 28, § 1er, alinéa 1er, 1°, b, 
2°, alinéa 1er, b, et § 2, alinéa 2, 1° 
 
Inséré par D. 07-12-2007 
TITRE IV. - De l''organisation d''un premier degré différencié de 
l''enseignement secondaire 
 
Modifié par D. 11-04-2014 ; complété par D. 18-12-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '15', NULL, 'Article 15 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 38, 'Art. 16 § 1', 'Article 16. - § 1er. Le premier degré différencié défini à l''article 5 est 
organisé sous la forme de deux années d''études dénommées «première année 
différenciée» et «deuxième année différenciée». Il n''est accessible qu''aux 
élèves qui ne sont pas titulaires du Certificat d''Etudes de base et qui, soit ont 
suivi la sixième année de l''enseignement primaire ou qui soit sont âgés de 
douze ans au moins avant le 31 décembre de l''année scolaire qui suit sans 
avoir fréquenté la sixième année de l''enseignement primaire. 
 
L''établissement qui accueille des élèves au premier degré différencié se 
fait produire par leur école primaire d''origine une copie : 
1° du bilan de compétences portant sur la maîtrise des socles de 
compétences à 12 ans visé par l''article 29, § 4, du décret du 2 juin 2006 
précité et par l''article 28 /1 du décret du 3 mars 2004 précité; 
2° du PIA, lorsque l''élève est issu de l''enseignement primaire spécialisé. 
 
§ 2. Tout établissement scolaire peut organiser le premier degré 
différencié aux deux conditions suivantes : 
1° Accueillir au moins un élève entrant dans l''enseignement secondaire 
sans avoir obtenu le Certificat d''Etudes de Base; 
2° Répondre aux conditions fixées par l''article 12, § 1er, alinéa 1er, 1°; 
alinéa 2, 1°; alinéa 3, 1° et alinéa 4, 1° de l''arrêté de l''Exécutif de la 
Communauté française du 31 août 1992 exécutant le décret du 29 juillet 1992 
portant organisation de l''enseignement secondaire de plein exercice; 
 
Inséré par D. 18-12-2014 
§ 2/1. La condition énoncée au § 2, 2°, du présent article ne s''applique 
pas aux établissements qui organisent l''année de leur création ou l''année 
suivante à celle-ci une première année commune ou un premier degré 
commun. 
 
§ 3. Les établissements qui n''organisent pas de 1er degré commun et qui 
organisent depuis le 1er septembre 2008 soit une première année différenciée 
ou une deuxième année différenciée soit les deux années du 1er degré 
différencié 
doivent 
établir 
une 
convention 
avec 
un 
ou 
plusieurs 
établissements d''enseignement secondaire organisé ou subventionné par la 
Communauté française garantissant à l''élève l''ensemble des possibilités de 
parcours du premier degré. L''établissement ou les établissements avec 
lesquels ladite convention est établie doivent être situés dans la même zone 
au sens de l''arrêté de l''Exécutif de la Communauté française du 15 mars 
1993 fixant les obligations de concertation entre les établissements de même 
caractère dans l''enseignement secondaire de plein exercice ou dans une zone 
contiguë. Dans ce dernier cas, la distance entre les établissements concernés 
est au maximum de dix kilomètres. Cette convention porte sur la continuité 
pédagogique dont bénéficiera l''élève qui après avoir fréquenté le premier 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
degré différencié et avoir obtenu son Certificat d''Etudes de Base intégrera le 
premier degré commun. 
 
§ 4. Les dispositions réglant la convention visée au paragraphe 3 y 
compris les modalités d''organisation du premier degré différencié de l''école 
concernée devront être explicitées dans le projet d''établissement de chaque 
école signataire de ladite convention. 
 
Modifié par D. 11-04-2014 ; D. 14-07-2015 ; D. 04-02-2016 ; D. 19-07-2017', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '16', '1', 'Article 16 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation','spécialisé'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 39, 'Art. 17', 'Article 17. - Outre les périodes de religion ou de morale non 
confessionnelle ou de philosophie et de citoyenneté visé à l''article 8 de la loi 
du 29 mai 1959 précité, l''horaire hebdomadaire de la première et de la 
deuxième années différenciées est de trente périodes portant sur : 
1° Le français ainsi que la formation historique et géographique 
comprenant la vie sociale et économique à raison de huit à quatorze périodes 
hebdomadaires, dont deux périodes consacrées à la formation historique et 
géographique comprenant la vie sociale et économique; 
2° La formation mathématique ainsi que l''initiation scientifique à raison 
de six à onze périodes hebdomadaires, dont deux périodes consacrées à 
l''initiation scientifique; 
3° L''apprentissage d''une langue moderne I à raison de deux à quatre 
périodes hebdomadaires; 
4° 
L''éducation 
physique 
à 
raison 
de 
trois 
à 
cinq 
périodes 
hebdomadaires; 
5° L''éducation plastique et/ou musicale à raison de une à cinq périodes 
hebdomadaires; [modifié par D. 04-02-2016] 
6° l''éducation par la technologie à raison de deux à neuf périodes 
hebdomadaires pour autant qu''un maximum de trois périodes hebdomadaires 
soit consacré à chacune des sphères d''activités suivantes : l''initiation à 
l''informatique, le dessin technique, l''agronomie, le travail du métal, le travail 
du bois, l''initiation à l''électricité, la construction ou les services. 
 
Inséré par D. 11-04-2014 
La grille-horaire des élèves de deuxième année différenciée ayant réussi 
certaines parties de l''épreuve externe commune visée à l''article 18 peut 
comporter des cours de 1C, 2C ou de 2S. 
 
Modifié par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '17', NULL, 'Article 17 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 40, 'Art. 18 § 1', 'Article 18. - § 1er. Tous les élèves inscrits en première et en deuxième 
années différenciées sont soumis à l''épreuve externe commune octroyant le 
Certificat d''Etudes de Base, telle que définie par le décret du 2 juin 2006 
relatif à l''évaluation externe des acquis des élèves de l''enseignement 
obligatoire et au certificat d''Etudes de Base au terme de l''enseignement 
primaire. 
 
Les élèves visés à l''article 6, § 2, sont également soumis à l''épreuve 
visée à l''alinéa 1er. 
 
Le Gouvernement définit les modalités d''inscription à cette épreuve. 
 
§ 2. Le Conseil de Classe délivre le Certificat d''Etudes de Base à tout 
élève visé au § 1er qui réussit l''épreuve externe commune. 
 
§ 3. Le Conseil de Classe peut délivrer le Certificat d''Etudes de Base à 
l''élève inscrit en première année commune et dans les années constitutives 
du premier degré différencié qui n''a pas satisfait ou qui n''a pas pu participer 
en tout ou en partie à l''épreuve externe commune. 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
 
Le Conseil de Classe fonde la décision visée à l''alinéa 1er sur un dossier 
comportant la copie des bulletins de l''année scolaire en cours tels qu''ils ont 
été communiqués aux parents de l''élève concerné ou à la personne investie de 
l''autorité parentale à son égard, le rapport circonstancié des enseignants 
ayant eu l''élève en charge ainsi que tout autre élément estimé utile par le 
Conseil de Classe. 
 
La direction de l''établissement scolaire tient à la disposition du service 
d''inspection tous les documents relatifs à la décision d''octroi du Certificat 
d''Etudes de Base. Les membres du service d''inspection peuvent les consulter 
sur place. 
 
Les parents de l''élève auquel l''octroi du Certificat d''Etudes de base a été 
refusé ou la personne investie de l''autorité parentale à son égard peuvent 
introduire un recours selon les modalités définies à l''article 32 du décret du 2 
juin 2006 précité. 
 
Inséré par D. 07-12-2007 
TITRE V. - De l''organisation d''une année spécifique de 
différenciation et d''orientation à l''issue du premier degré de 
l''enseignement secondaire 
 
Modifié par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '18', '1', 'Article 18 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['recours','inscription','orientation','évaluation','inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 41, 'Art. 19', 'Article 19. - Une année spécifique, dénommée troisième année de 
différenciation et d''orientation, peut être organisée au sein du deuxième 
degré au bénéfice des élèves qui, à l''issue du premier degré parcouru en trois 
ans et ce, sans préjudice de la disposition visée à l''article 26, § 2, alinéa 2, 3°, 
n''ont pas acquis la maîtrise des socles de compétences visés à la fin de la 
troisième étape du continuum pédagogique conformément à l''article 16, § 2, 
du décret du 24 juillet 1997 et au décret du 19 juillet 2001 précités. 
 
Au cours de la 3SDO, les difficultés particulières d’apprentissage ou les 
besoins spécifiques de l’élève sont pris en compte pour l''aider à poursuivre le 
développement des compétences entamé afin d''atteindre le niveau de 
maîtrise évoqué à l''alinéa premier. L''organisation de la troisième année de 
différenciation et d''orientation vise également à aider chaque élève à élaborer 
un projet personnel lui permettant de poursuivre sa scolarité. L''élaboration 
du projet personnel de l''élève est réalisée en collaboration avec le Centre 
psycho-médico-social concerné. 
 
Modifié par D. 12-07-2012 ; remplacé par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '19', NULL, 'Article 19 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['orientation','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 42, 'Art. 20', 'Article 20. - La 3S-DO est accessible à tout élève régulier au sens de 
l''article 2, 9° de l''arrêté royal du 29 juin 1984 précité qui a suivi : 
1° soit la deuxième année commune et à l''égard duquel est prise la 
décision visée à l''article 26, § 2, alinéa 2, 2° ; 
2° soit la deuxième année différenciée et à l''égard duquel est prise la 
décision visée à l''article 28, § 1er, alinéa 1er, 2°, d, ou § 2, alinéa 1er, 2° ; 
3° soit l''année supplémentaire organisée au terme du 1er degré à l''égard 
duquel est prise la décision visée à l''article 28bis, § 2, alinéa 1er, 2°. 
 
Remplacé par D. 11-04-2014 ; modifié par D. 04-02-2016 ; 19-07-2017', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '20', NULL, 'Article 20 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 43, 'Art. 21 § 1', 'Article 21. - § 1er. Pour tout élève régulier au sens de l''article 2, 9°, de 
l''arrêté royal du 29 juin 1984 précité, orienté vers la 3S-DO, le Conseil de 
Classe élabore le rapport visé à l''article 22. 
 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
§ 2. Sur base du rapport visé au § 1er et dans le respect de l''article 
7bis, § 4, le Conseil de Classe de 3S-DO propose, à chaque élève inscrit en 3S-
DO le PIA visé à l''article 7bis. 
 
§ 3. Le PIA est décidé, suivi et ajusté dans les conditions de l''article 
7bis. 
 
Il est présenté par le chef d''établissement ou son délégué, avant le 15 
octobre de l''année scolaire concernée, à l''élève ainsi qu''à ses parents ou à la 
personne investie de l''autorité parentale. Le chef d''établissement ou son 
délégué peuvent être accompagnés d''un autre membre de l''équipe 
pédagogique ou d''un membre du centre psycho-médico-social concerné. 
 
Modifié par D. 19-07-2017 
§ 4. Le PIA visé au paragraphe 1er définit la grille horaire de l''élève 
concerné; elle peut être individualisée en fonction de ses difficultés 
particulières d''apprentissage ou de ses besoins spécifiques. 
 
Par dérogation à l''article 7bis, § 5, alinéa 1er, outre les périodes de 
religion ou de morale non confessionnelle ou de philosophie et de citoyenneté 
visées à l''article 8 de la loi du 29 mai 1959 précitée, l''horaire hebdomadaire 
de la 3S-DO est de trente-deux périodes portant sur : 
1° le français ainsi que la formation historique et géographique à raison 
de neuf à quatorze périodes, dont deux ou trois consacrées à la formation 
historique et géographique; 
2° la formation mathématique ainsi que l''initiation scientifique à raison 
de six à onze périodes hebdomadaires, dont deux ou trois périodes consacrées 
à l''initiation scientifique; 
3° l''apprentissage d''une langue moderne I à raison de deux à quatre 
périodes hebdomadaires; 
4° l''éducation physique à raison de deux ou trois périodes 
hebdomadaires; 
5° l''éducation plastique et/ou musicale à raison de une à cinq périodes 
hebdomadaires; [modifié par D. 04-02-2016] 
6° un module de formation intégrée, à raison d''au moins six périodes 
hebdomadaires ayant pour but de faire appréhender concrètement par l''élève 
le monde professionnel, les métiers, les formations, les diplômes qui y mènent 
et d''élaborer avec lui un projet de vie en lien avec une orientation tant dans 
l''enseignement de transition que de qualification. 
 
Un maximum de deux tiers des périodes réservées à ce module peuvent 
être consacrées à la participation à des cours techniques ou de pratique 
professionnelle d''options groupées relevant d''un ou de plusieurs secteurs 
organisés en troisième année. Les établissements peuvent conclure des 
conventions avec un ou plusieurs autres établissements pour assurer ces 
activités dans les meilleures conditions. 
 
La grille horaire des élèves peut aussi comprendre pour partie la 
participation à des cours organisés au bénéfice des élèves de 2S. 
 
La 3S-DO ne peut en aucun cas constituer un redoublement de l''année 
antérieure. 
 
§ 5. La direction de l''établissement scolaire tient à la disposition du 
service d''inspection tous les documents relatifs à l''application des 
dispositions du présent article. Les membres du service d''inspection peuvent 
les consulter sur place. 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
 
Inséré par D. 07-12-2007 
TITRE VI. - Des décisions du Conseil de Classe, de la certification et 
de l''orientation au terme du premier degré de l''enseignement 
secondaire 
 
Modifié par D. 12-07-2012 ; D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '21', '1', 'Article 21 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['redoublement','orientation','évaluation','inspection','parents'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 44, 'Art. 22', 'Article 22. - Au terme de chaque année du premier degré de 
l''enseignement secondaire, le Conseil de Classe élabore pour chaque élève 
régulier au sens de l''article 2, 9° de l''arrêté royal du 29 juin 1984 précité, un 
rapport sur les compétences acquises au regard des socles de compétences 
visées à la fin de la troisième étape du continuum pédagogique conformément 
à l''article 16, § 1er, du décret du 24 juillet 1997 ainsi qu''au décret du 19 juillet 
2001 précités et, s''il échet, aux compétences visées à la fin de la deuxième 
étape du continuum pédagogique conformément à l''article 16, § 1er, du décret 
du 24 juillet 1997 ainsi qu''au décret du 19 juillet 2001 précités en ce qui 
concerne les élèves fréquentant le premier degré différencié. 
 
Le rapport visé à l''alinéa précédent tient lieu de motivation des 
décisions prises par le Conseil de Classe. 
 
Remplacé par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '22', NULL, 'Article 22 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 45, 'Art. 23', 'Article 23. - Au terme de la première année commune, sur la base du 
rapport visé à l''article 22, le Conseil de Classe oriente l''élève vers la 
deuxième année commune (2C), le cas échéant en indiquant que le Conseil de 
Classe de 2 C proposera un PIA, tel que visé à l''article 7bis. 
 
Remplacé par D. 11-04-2014', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '23', NULL, 'Article 23 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 46, 'Art. 24', 'Article 24. - Au terme de la première année différenciée, sur la base du 
rapport défini à l''article 22, le Conseil de Classe oriente l''élève : 
1° soit vers la première année commune (1C), s''il est titulaire du 
Certificat d''Etudes de Base; en ce cas, il indique que le Conseil de Classe de 
1C proposera un PIA, tel que visé à l''article 7bis; 
2° soit vers la deuxième année différenciée (2 D) organisée 
conformément au titre IV, s''il n''est pas titulaire du Certificat d''Etudes de 
Base (CEB); en ce cas, il indique que le Conseil de Classe de 2D proposera un 
PIA, tel que visé à l''article 7bis, en vue de permettre à l''élève de poursuivre 
sa préparation du CEB en développant les compétences non encore acquises 
parmi celles qui ont été définies par les socles de compétences visées à la fin 
de la deuxième étape et, le cas échéant, d''acquérir certaines des compétences 
visées au terme de la troisième étape du continuum pédagogique 
conformément à l''article 16, § 1er, du décret du 24 juillet 1997.

Article 25. – […] Abrogé par D. 11-04-2014. 
 
Modifié par D. 11-04-2014 ; D. 04-02-2016', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '24', NULL, 'Article 24 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 47, 'Art. 26 § 1', 'Article 26. - § 1er. Au terme de la deuxième année commune, sur la 
base du rapport visé à l''article 22, le Conseil de Classe :  
1° Soit certifie de la réussite par l''élève du premier degré de 
l''enseignement secondaire dans ce cas, le conseil de classe attribue le CEB à 
l''élève qui n''en est pas porteur; [modifié par D. 04-02-2016] 
2° Soit ne certifie pas de la réussite par l''élève du premier degré de 
l''enseignement secondaire et prend une des décisions visées au § 2. 
 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
Remplacé par D. 11-04-2014 
§ 2. En ce qui concerne l''élève visé au § 1er, 2°, qui n''a pas épuisé les 
trois années d''études du premier degré conformément à l''article 6 ter, le 
Conseil de Classe l''oriente vers l''année supplémentaire organisée au terme 
du premier degré (2S) conformément au titre III; en ce cas, il indique que le 
Conseil de Classe de 2S proposera un PIA, tel que visé à l''article 7bis. 
 
En ce qui concerne l''élève visé au § 1er, 2°, qui a épuisé les trois années 
d''études du premier degré conformément à l''article 6ter, le Conseil de Classe 
définit les formes et sections qu''il peut fréquenter en troisième année de 
l''enseignement secondaire de plein exercice ou en alternance, en informe les 
parents ou la personne investie de l''autorité parentale et l''oriente : 
1. soit vers une des troisièmes années de l''enseignement secondaire 
correspondant aux formes et sections définies par le Conseil de Classe; 
2. soit vers la troisième année de différenciation et d''orientation visée 
au titre V; en ce cas, il indique que le Conseil de Classe de 3S-DO proposera 
un PIA, tel que visé à l''article 7bis; 
3. soit, s''il répond aux conditions d''admission, vers l''enseignement en 
alternance visé à l''article 2bis, § 1er, 2°, du décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance. 
 
Toutefois, les parents ou la personne investie de l''autorité parentale 
gardent la faculté de choisir celle des deux orientations visées à l''alinéa 
précédent vers laquelle le Conseil de Classe n''a pas orienté l''élève. Lorsqu''ils 
retiennent le choix visé à l''alinéa 2, 1°, le Conseil de Classe remet à l''élève un 
document reprenant des conseils complémentaires pour son orientation. 
Lesdits conseils portent sur les orientations d''études conseillées et, s''il échet, 
déconseillées, en lien avec le rapport visé à l''article 22. 
 
§ 3. La décision de non réussite prise par le Conseil de Classe en vertu 
du § 1er, 2° peut faire l''objet d''un recours selon la procédure prévue aux 
articles 95 à 99 du décret Missions. 
 
La définition, par le Conseil de Classe en vertu du § 2, alinéa 2, des 
formes et sections que l''élève peut fréquenter en troisième année de 
l''enseignement secondaire peut faire l''objet d''un recours selon la procédure 
prévue aux articles 95 à 99 du décret Missions.

Article 27. – […] Abrogé par D. 11-04-2014 
 
Remplacé par D. 11-04-2014 ; D. 04-02-2016 ; modifié par D. 24-05-2017', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '26', '1', 'Article 26 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['recours','inscription','orientation','évaluation','parents'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 48, 'Art. 28 § 1', '§ 1er. Au terme de la deuxième année différenciée, sur la 
base du rapport visé à l''article 22, 
1° en ce qui concerne l''élève titulaire du Certificat d''Etudes de Base, qui 
n''atteint pas l''âge de 16 ans à la date du 31 décembre de l''année scolaire qui 
suit, le Conseil de Classe l''oriente : 
a) soit vers la deuxième année commune en ce cas, il indique que le 
Conseil de Classe de 2C proposera un PIA, tel que visé à l''article 7bis; 
[complété par D. 24-05-2017] 
b) soit vers l''année supplémentaire organisée au terme du premier degré 
(2S), conformément au titre III ; en ce cas, il indique que le Conseil de Classe 
de 2S proposera un PIA, tel que visé à l''article 7bis, 
c) soit, s''il répond aux conditions d''admission, vers l''enseignement en 
alternance visé à l''article 2bis,', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '28', '1', 'Article 28 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['inscription','évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 49, 'Art. 28 § 1', '§ 1er, 2°, du décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance, 
d) soit vers la 3ème année de l''enseignement technique de qualification 
ou vers la 3ème année de l''enseignement professionnel. 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
Toutefois, les parents ou la personne investie de l''autorité parentale 
gardent la faculté de choisir celle des orientations visées au point 1° vers 
laquelle le Conseil de Classe n''a pas orienté l''élève. [1° remplacé par D. 04-02-
2016] 
2° en ce qui concerne l''élève titulaire du Certificat d''Etudes de Base, qui 
atteint l''âge de 16 ans à la date du 31 décembre de l''année scolaire qui suit, 
le Conseil de Classe définit les formes et sections que l''élève peut fréquenter 
dans une troisième année de l''enseignement secondaire, de plein exercice ou 
en alternance, en informe les parents ou la personne investie de l''autorité 
parentale et l''oriente : 
 a) soit vers l''année supplémentaire organisée au terme du premier 
degré (2S), conformément au titre III; en ce cas, il indique que le Conseil de 
Classe de 2S proposera un PIA, tel que visé à l''article 7bis; 
 b) soit vers une des troisièmes années de l''enseignement secondaire 
correspondant aux formes et sections définies par le Conseil de Classe; 
 c) soit vers la troisième année de différenciation et d''orientation (3S-
DO); en ce cas, il indique que le Conseil de Classe de 3S-DO proposera un 
PIA, tel que visé à l''article 7bis; 
 d) soit, s''il répond aux conditions d''admission, vers l''enseignement en 
alternance visé à l''article 2bis,', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '28', '1', 'Article 28 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['inscription','orientation','évaluation','parents','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 50, 'Art. 28 § 1', '§ 1er, 2°, du décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance. 
 
Toutefois, les parents ou la personne investie de l''autorité parentale 
