INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 52, 'Art. 28 § 1', '§ 1er, 2°, du décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance. 
 
