INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 53, 'Art. 28bis § 1', 'Article 28bis. - § 1er. Au terme de l''année supplémentaire (2S) 
organisée au terme du premier degré conformément au titre III, sur la base 
du rapport visé à l''article 22, le Conseil de Classe : 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
1° soit certifie de la réussite par l''élève du premier degré de 
l''enseignement secondaire dans ce cas, le conseil de classe attribue le CEB à 
l''élève qui n''en est pas porteur; [complété par D. 04-02-2016] 
2° soit ne certifie pas de la réussite par l''élève du premier degré de 
l''enseignement secondaire. 
 
§ 2. Pour l''élève visé par le § 1er, 2°, le Conseil de Classe définit les 
formes et sections que l''élève peut fréquenter dans une troisième année de 
l''enseignement secondaire de plein exercice ou en alternance, en informe les 
parents ou la personne investie de l''autorité et l''oriente : 
1° soit vers une des troisièmes années de l''enseignement secondaire 
correspondant aux formes et sections définies par le Conseil de Classe; 
2° soit vers la troisième année de différenciation et d''orientation (3S-
DO); en ce cas, il indique que le Conseil de Classe de 3S-DO proposera un 
PIA, tel que visé à l''article 7bis; 
3° soit, s''il répond aux conditions d''admission, vers l''enseignement en 
alternance visé à l''article 2bis, § 1er, 2°, du décret du 3 juillet 1991 organisant 
l''enseignement secondaire en alternance. 
 
Toutefois, les parents ou la personne investie de l''autorité parentale 
gardent la faculté de choisir celle des deux orientations visées à l''alinéa 1er 
vers laquelle le Conseil de Classe n''a pas orienté l''élève. Lorsqu''ils retiennent 
le choix visé à l''alinéa 1er, 1°, le Conseil de Classe remet à l''élève un 
document reprenant des conseils complémentaires pour son orientation. 
Lesdits conseils portent sur les orientations d''études conseillées et, s''il échet, 
déconseillées, en lien avec le rapport visé à l''article 22. 
 
§ 3. La décision de non réussite prise par le Conseil de Classe en vertu 
du § 1er, 2°, peut faire l''objet d''un recours selon la procédure prévue aux 
articles 95 à 99 du décret «Missions». 
 
La définition, par le Conseil de Classe en vertu du § 2, des formes et 
sections que l''élève peut fréquenter en troisième année de l''enseignement 
secondaire de plein exercice ou en alternance, peut faire l''objet d''un recours 
selon la procédure prévue aux articles 95 à 99 du décret «Missions».', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '28bis', '1', 'Article 28bis § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['recours','inscription','orientation','évaluation','parents'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 54, 'Art. 29 § 2', 'Article 29. - Si le Conseil de Classe certifie de la réussite du premier 
degré de l''enseignement secondaire de l''élève ayant bénéficié de la mesure 
visée à l''article 6, § 2 qui n''a pas obtenu son Certificat d''Etudes de Base dans 
le cadre de la disposition visée à l''article 18, cet élève est réputé titulaire du 
Certificat d''Etudes de Base à l''issue du premier degré de l''enseignement 
secondaire 
 
Modifié par D. 11-04-2014 ; D. 04-02-2016', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '29', '2', 'Article 29 § 2 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 55, 'Art. 30 § 1', 'Article 30. - § 1er. Avant le 15 janvier de l''année scolaire en cours, sur 
la base d''un rapport sur les compétences acquises en regard des socles de 
compétences visées à la fin de la troisième étape du continuum pédagogique 
conformément à l''article 16, § 2 du décret du 24 juillet 1997 ainsi qu''au 
décret du 19 juillet 2001 précités, en ce qui concerne l''élève inscrit en 
troisième année de différenciation et d''orientation, le Conseil de Classe peut : 
1° Soit certifier de sa réussite du premier degré de l''enseignement 
secondaire dans ce cas, le conseil de classe attribue le CEB à l''élève qui n''en 
est pas porteur; 
2° Soit proposer son orientation vers la troisième année de 
l''enseignement secondaire dans une forme et une section qu''il définit. Le 
Conseil de Classe remet alors à l''élève un document reprenant des conseils 
complémentaires pour son orientation. Lesdits conseils portent sur les 
Secondaire 
 
IV.A.34 
Lois 30998 
 
D. 30-06-2006 
Mis à jour au 29-10-2024 
orientations d''études conseillées et, s''il échet, déconseillées, en lien avec le 
rapport visé à l''article 22. 
 
Le Conseil de Classe détermine les modalités d''aide et de soutien 
pédagogique qui seront apportés à l''élève concerné par les dispositions visées 
à l''alinéa précédent. 
 
§ 2. Au terme de la troisième année de différenciation et d''orientation, 
sur la base d''un rapport sur les compétences acquises en regard des socles de 
compétences visées à la fin de la troisième étape du continuum pédagogique 
conformément à l''article 16, § 1er du décret du 24 juillet 1997 ainsi qu''au 
décret du 19 juillet 2001 précités, le Conseil de Classe : 
1° Soit certifie de la réussite par l''élève du premier degré de 
l''enseignement secondaire dans ce cas, le conseil de classe attribue le CEB à 
l''élève qui n''en est pas porteur; 
2° Soit oriente vers la troisième année de l''enseignement secondaire 
dans une forme et une section qu''il définit. Le Conseil de Classe remet alors à 
l''élève un document reprenant des conseils complémentaires pour son 
orientation. Lesdits conseils portent sur les orientations d''études conseillées 
et, s''il échet, déconseillées, en lien avec le rapport visé à l''article 22.', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '30', '1', 'Article 30 § 1 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['orientation','évaluation','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('30998', 56, 'Art. 31', 'Article 31. - Le Gouvernement arrête le modèle du Certificat attestant 
de la réussite du premier degré de l''enseignement secondaire. 
 
Le Gouvernement arrête le modèle des documents relatifs aux décisions 
autres que celle de réussite prises en vertu des articles 23 à 30. 
 
Abrogé par D. 11-04-2014 ; rétabli par D. 04-02-2016 
TITRE VII. - Dispositions transitoires 
 
Abrogé par D. 11-04-2014 ; rétabli par D. 04-02-2016 
Articles 32. –. Sans préjudice des dispositions visées par l''arrêté royal 
du 20 juillet 1971 déterminant les conditions et la procédure d''octroi de 
l''équivalence des diplômes et certificats d''études étrangers, la deuxième 
année commune est accessible à tout élève régulier au sens de l''article 2, 9°, 
de l''arrêté royal du 29 juin 1984 précité : 
1° soit qui a suivi avant le 30 juin 2016 une année complémentaire 
organisée au terme de la première année commune à l''égard duquel le 
Conseil de classe a pris la décision de l''orienter vers la deuxième année 
commune ; 
2° soit qui, titulaire du Certificat d''Etudes de Base, n''atteint pas l''âge de 
16 ans à la date du 31 décembre de l''année scolaire qui suit et a suivi avant 
le 30 juin 2016 la deuxième année différenciée et à l''égard duquel le Conseil 
de Classe a pris la décision de l''orienter vers la deuxième année commune ; 
3° soit qui a suivi la première année commune dans un établissement 
organisé, subventionné ou reconnu par la Communauté flamande ou par la 
Communauté germanophone. 
  
Articles 33 à 34. – […] Abrogés par D. 11-04-2014. 
  
TITRE V. - Entrée en vigueur', 'Décret du 30 juin 2006 — Premier degré du secondaire', 'Décret 1er degré', '31', NULL, 'Article 31 du Décret du 30 juin 2006 — Premier degré du secondaire (CDA 30998)', ARRAY['redoublement','évaluation','ROI','DASPA'], 'secondaire');
