-- CDA 31723: Décret du 12 janvier 2007 — Citoyenneté à l'école (5 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('31723', 0, 'Art. 1er', 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental 
