-- CDA 32365: Décret du 11 mai 2007 — Immersion linguistique (43 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 0, 'Art. 1er', 'Article 1er. - Le présent décret s''applique à l''enseignement fondamental et 
secondaire organisé ou subventionné par la Communauté française.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '1er', NULL, 'Article 1er du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 1, 'Art. 2', 'Article 2. - Pour l''application du présent décret, 
1° on entend par : 
- «Apprentissage par immersion», une procédure pédagogique visant à assurer la 
maîtrise des compétences attendues en assurant une partie des cours et des activités 
pédagogiques de la grille horaire dans une langue moderne autre que le français en 
vue de l''acquisition progressive de cette autre langue; 
- «Grille horaire», la liste des différents cours assurés hebdomadairement avec 
mention du nombre de périodes affectées à chacun. 
- «Décret missions», le décret du 24 juillet 1997 définissant les missions 
prioritaires de l''enseignement fondamental et secondaire et organisant les structures 
propres à les atteindre; 
- 
«Continuum 
pédagogique», 
le 
continuum 
pédagogique 
constitué 
de 
l''enseignement maternel et des huit premières années de la scolarité obligatoire tel 
que défini à l''article 13, § 1er, du décret missions; 
- «Loi linguistique», la loi du 30 juillet 1963 concernant le régime linguistique 
dans l''enseignement. 
2° Les périodes ont une durée de 50 minutes.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '2', NULL, 'Article 2 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 2, 'Art. 3', 'Article 3. - L''emploi, dans le présent décret, des noms masculins pour les 
différentes fonctions est épicène en vue d''assurer la lisibilité du texte nonobstant les 
dispositions du décret du 21 juin 1993 relatif à la féminisation des noms de métier. 
 
CHAPITRE II. - Des objectifs et des principes généraux de l''organisation de 
l''apprentissage par immersion 
 
Articles 4 à 8. - […] Abrogés par D. 03-05-2019 (code)  
 
Complété par D. 01-12-2022', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '3', NULL, 'Article 3 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 3, 'Art. 9 § 1', '§ 1er. Au cours du deuxième cycle de la première étape du continuum 
pédagogique, lorsqu''une partie de la grille horaire hebdomadaire est consacrée à 
l''apprentissage par immersion, cette partie couvre au moins 8 périodes et au plus 21 
périodes. 
 
Secondaire 
 
IV.A.37 
Lois 32365 
 
D. 11-05-2007 
mis à jour au 27-01-2023', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '9', '1', 'Article 9 § 1 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 4, 'Art. 9 § 2', '§ 2. Au cours du premier cycle de la deuxième étape du continuum pédagogique, 
lorsqu''une partie de la grille horaire hebdomadaire est consacrée à l''apprentissage par 
immersion, cette partie couvre au moins 8 périodes et au plus 18 périodes pour les 
élèves ayant entamé l''immersion en 3ème maternelle ou en 1ère primaire. 
 
Au cours du premier cycle de la deuxième étape du continuum pédagogique, 
lorsqu''une partie de la grille horaire hebdomadaire est consacrée à l''apprentissage par 
immersion, cette partie couvre au moins 12 périodes et au plus 18 périodes pour les 
élèves ayant entamé l''immersion en 3e primaire. 
 
Au cours du deuxième cycle de la deuxième étape du continuum pédagogique, 
lorsqu''une partie de la grille horaire hebdomadaire est consacrée à l''apprentissage par 
immersion, cette partie couvre au moins 8 périodes et au plus 18 périodes pour les 
élèves ayant entamé l''immersion en 3ème maternelle ou en 1ère primaire. 
 
Au cours du deuxième cycle de la deuxième étape du continuum pédagogique, 
lorsqu''une partie de la grille horaire hebdomadaire est consacrée à l''apprentissage par 
immersion, cette partie couvre au moins 12 périodes et au plus 18 périodes pour les 
élèves ayant entamé l''immersion en 3ème primaire.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '9', '2', 'Article 9 § 2 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 5, 'Art. 9 § 3', '§ 3. Lorsqu''un apprentissage par immersion est instauré dans une école ou une 
implantation, le cours de seconde langue, tel que défini à l''article 10, premier alinéa de 
la Loi linguistique et à l''article 7 du décret du 13 juillet 1998 portant organisation de 
l''enseignement maternel et primaire ordinaire et modifiant la réglementation de 
l''enseignement, est comptabilisé dans la partie de la grille horaire consacrée à 
l''apprentissage par immersion telle que définie au', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '9', '3', 'Article 9 § 3 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 6, 'Art. 9 § 2', '§ 2 du présent article. Dans ce cas, 
les apprentissages visés durant ce cours de seconde langue portent spécifiquement sur 
les compétences liées à la maîtrise de la langue concernée et sur le vocabulaire 
spécifique aux disciplines enseignées dans le cadre de l''apprentissage par immersion.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '9', '2', 'Article 9 § 2 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['discipline'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 7, 'Art. 9 § 4', '§ 4. Au cours de la troisième étape du continuum pédagogique, lorsqu''une partie 
de la grille horaire hebdomadaire est consacrée à l''apprentissage par immersion, cette 
partie couvre au moins 8 périodes et au plus 13 périodes. Les périodes visées à l''article 
8, 1° et 2° du décret du 30 juin 2006 relatif à l''organisation pédagogique du premier 
degré de l''enseignement secondaire ne peuvent pas être organisées dans le cadre de 
l''apprentissage par immersion. 
 
Alinéa inséré par D. 01-12-2022 
Par dérogation à l''alinéa 1er, lorsque l''apprentissage par immersion est organisé 
et suivi dans deux langues, la partie consacrée à l''apprentissage en immersion couvre 
au moins 8 périodes et au plus 12 périodes par langue concernée, sans pouvoir 
dépasser au total les deux tiers des périodes d''enseignement inscrites à la grille-
horaire des élèves. 
 
Sans préjudice de la disposition visée à l''article 7, alinéa 2 du présent décret, 
lorsqu’un apprentissage par immersion est instauré dans une école ou une 
implantation, les périodes de langue moderne, telles que définies à l''article 8, 3° du 
décret du 30 juin 2006 précité sont comptabilisées dans la partie de la grille horaire 
consacrée à l''apprentissage par immersion telle que définie à l''alinéa précédent. Dans 
ce cas, les apprentissages visés durant ce cours de langue moderne portent 
spécifiquement sur les compétences liées à la maîtrise de la langue concernée et sur le 
vocabulaire spécifique aux disciplines enseignées dans le cadre de l''apprentissage par 
immersion. 
 
Secondaire 
 
IV.A.37 
Lois 32365 
 
D. 11-05-2007 
mis à jour au 27-01-2023 
Deux, trois ou quatre des périodes d''activités complémentaires définies à l''article 
10 du décret du 30 juin 2006 relatif à l''organisation pédagogique du 1er degré de 
l''enseignement secondaire peuvent être consacrées à l''apprentissage de la langue dans 
laquelle est organisé l''apprentissage par immersion. Ces deux, trois ou quatre périodes 
ne sont pas comptabilisées dans les périodes visées à l''alinéa premier du présent 
paragraphe.

§ 5. Les cours de morale et de religion ne font pas partie de la partie de la grille 
horaire pouvant faire l''objet d''un apprentissage par immersion.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '9', '4', 'Article 9 § 4 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['discipline','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 8, 'Art. 10', 'Article 10. - […] Abrogé par D. 03-05-2019 (code)  
 
CHAPITRE IV. - De l''organisation de l''apprentissage par immersion durant 
les deuxième et troisième degrés de l''enseignement secondaire 
 
Complété par D. 12-12-2008 ; modifié par D. 13-01-2011 ; complété par D. 03-05-
2018', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '10', NULL, 'Article 10 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 9, 'Art. 11 § 1', 'Article 11. - § 1er. L''élève peut poursuivre, au cours des Humanités générales et 
technologiques visées aux articles 24 et suivants du décret missions et des Humanités 
professionnelles et techniques visées aux articles 39 et suivants du même décret, 
l''apprentissage par immersion suivi au cours de la troisième étape du continuum 
pédagogique. 
 
§ 2. L''élève peut également entamer l''apprentissage par immersion en première 
année des Humanités générales et technologiques ou des Humanités professionnelles 
et techniques dans la langue choisie s''il échet pour le cours de langue moderne I ou II 
tel que défini aux articles 4bis, § 3 et 4, 4ter § 2 et 3 et 4 quater § 1er de la Loi du 19 
juillet 1971 relative à la structure générale et à l''organisation de l''enseignement 
secondaire. 
 
Par dérogation à ce qui précède, le chef d''établissement dans l''enseignement 
organisé par la Communauté française ou le pouvoir organisateur dans l''enseignement 
subventionné peut accepter d''inscrire à un autre moment que celui défini à l''alinéa 
1er : 
1° un élève dont au moins l''un des parents a pour langue maternelle la langue 
d''immersion; 
2° un élève issu d''une école internationale dont la langue de l''enseignement est la 
même que la langue de l''immersion; 
3° un élève issu d''une école européenne dont la langue de l''enseignement est la 
même que la langue de l''immersion; 
4° un élève issu d''une école de la Communauté flamande ou germanophone dont 
la langue de l''enseignement est la même que la lange de l''immersion; [inséré par D. 03-05-
2018]  
5° un élève issu d''un pays étranger dont la langue d''enseignement est la même 
que la langue de l''immersion. [inséré par D. 03-05-2018] 
 
§ 3. Une école secondaire qui organise de l''apprentissage par immersion au 
niveau de la première année des Humanités générales et technologiques ou des 
Humanités professionnelles et techniques offre la possibilité de poursuivre cet 
apprentissage au cours de la suite de l''enseignement secondaire. 
 
Par dérogation aux dispositions visées à l''alinéa précédent, une école secondaire 
peut mettre en place progressivement l''apprentissage par immersion pour autant 
qu''un élève ayant suivi la première année des Humanités générales et technologiques 
ou des Humanités professionnelles et techniques dans le cadre de cet apprentissage 
puisse poursuivre la suite de la scolarité secondaire en apprentissage par immersion 
au sein du même établissement. 
Secondaire 
 
IV.A.37 
Lois 32365 
 
D. 11-05-2007 
mis à jour au 27-01-2023 
 
Complété par D. 01-12-2022', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '11', '1', 'Article 11 § 1 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['parents','ROI','DASPA'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 10, 'Art. 12 § 1', 'Article 12. - § 1er. Au cours de chacune des quatre années couvrant soit les 
Humanités générales et technologiques, soit les Humanités professionnelles et 
techniques, lorsqu''une partie de la grille horaire est consacrée à l''apprentissage par 
immersion, cette partie couvre au moins 8 périodes et au plus 13 périodes. 
 
Par dérogation à l''alinéa 1er, lorsque l''apprentissage par immersion est organisé 
et suivi dans deux langues, la partie consacrée à l''apprentissage en immersion couvre 
au moins 8 périodes et au plus 12 périodes par langue concernée, sans pouvoir 
dépasser au total les deux tiers des périodes d''enseignement inscrites à la grille-
horaire des élèves. 
 
Les périodes consacrées s''il échet spécifiquement au cours de langue moderne 
dans laquelle est pratiquée l''immersion sont comptabilisées dans la partie de la grille 
horaire consacrée à l''apprentissage par immersion. Dans ce cas, les apprentissages 
visés durant ce cours de langue moderne portent spécifiquement sur les compétences 
liées à la maîtrise de la langue concernée et sur le vocabulaire spécifique aux 
disciplines enseignées dans le cadre de l''apprentissage par immersion. 
 
§ 2. Les cours de morale et de religion ne font pas partie de la partie de la grille 
horaire pouvant faire l''objet d''un apprentissage par immersion. 
 
CHAPITRE V. - Des modalités à remplir pour organiser de l''apprentissage 
par immersion 
 
Modifié par D. 13-09-2018 
Articles 13 à 15. - […] Abrogés par D. 03-05-2019 (code)  
 
CHAPITRE VI. - De l''accompagnement et du contrôle de l''apprentissage par 
immersion 
 
Modifié par D. 28-03-2019', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '12', '1', 'Article 12 § 1 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['discipline','inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 11, 'Art. 16 § 1', 'Article 16. - § 1er. 
Un 
organe 
d''observation 
et 
d''accompagnement 
de 
l''apprentissage par immersion, ci-après dénommé «l''organe», est créé au sein de 
l''Administration générale de l''Enseignement et de la Recherche scientifique. Cet 
organe a une compétence consultative. 
 
§ 2. L''organe visé au paragraphe précédent a pour mission, dans le respect de la 
liberté en matière de méthodes pédagogiques : 
1° De formuler à l''intention du Gouvernement, de la Commission de Pilotage, des 
pouvoirs organisateurs et des écoles des propositions visant à améliorer le dispositif 
d''apprentissage par immersion notamment sur la base du rapport général rédigé tous 
les trois ans par le Service général d''inspection; 
2° De remettre, dans le cadre des dispositions visées aux articles 6, 5e alinéa, et 
15, 5e alinéa, du décret du 19 mai 2006 relatif à l''agrément et à la diffusion de 
manuels scolaires, de logiciels scolaires et d''autres outils pédagogiques au sein des 
établissements d''enseignement obligatoire, un avis à la Commission de Pilotage, à la 
demande de celle-ci, à propos des manuels et des outils pédagogiques destinés à 
l''apprentissage par immersion; 
3° De formuler à l''intention du Gouvernement et de la Commission de Pilotage 
des propositions en matière de formation en cours de carrière des enseignants 
exerçant leur fonction dans le cadre de l''apprentissage par immersion. 
 
Secondaire 
 
IV.A.37 
Lois 32365 
 
D. 11-05-2007 
mis à jour au 27-01-2023 
Inséré par D. 28-03-2019 
§ 2bis. - L''organe se réunit au minimum deux fois par an.» ; 
2° au § 3, alinéa premier, les mots «Administrateur général de l''Enseignement et 
de la Recherche scientifique» sont remplacés par les mots «Administrateur général de 
l''Enseignement. 
 
§ 3. L''organe est présidé par l''Administrateur général de l''Enseignement ou par 
son délégué. 
 
Il est composé : 
- De l''Administrateur général de l''Enseignement ou de son délégué; 
- De quatre inspecteurs désignés par le Gouvernement sur proposition de 
l''Administrateur général de l''Enseignement; au moins deux de ces inspecteurs ont en 
charge l''inspection d''une ou de plusieurs disciplines dont l''apprentissage peut être 
poursuivi dans le cadre de l''apprentissage par immersion; 
- De quatre experts en pédagogie ou en didactique des langues désignés par le 
Gouvernement sur proposition de la Commission de Pilotage. 
 
Le secrétariat du groupe de travail est assuré par un agent de l''Administration 
générale de l''Enseignement. 
 
Lorsqu''ils participent aux réunions du groupe de travail, les membres bénéficient 
du remboursement de leurs frais de déplacement et de séjour dans les mêmes 
conditions que les agents de rang 12 des services du Gouvernement de la Communauté 
française. 
 
CHAPITRE VII. - Des conditions à remplir pour enseigner dans le cadre de 
l''apprentissage par immersion', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '16', '1', 'Article 16 § 1 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['discipline','inspection','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 12, 'Art. 17', 'Article 17. - A l''article 6 de l''arrêté de l''Exécutif de la Communauté française du 
2 octobre 1968 déterminant et classant les fonctions des membres du personnel 
directeur et enseignant, du personnel auxiliaire d''éducation, du personnel 
