«Sous-section 2. - Fonctions de recrutement de membre du personnel 
enseignant chargé des cours en immersion linguistique.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '22', NULL, 'Article 22 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 19, 'Art. 11bis', 'Art. 11bis. - Les titres jugés suffisants pour les fonctions de chargé des cours en 
immersion linguistique sont fixés comme suit : 
1° Le titre jugé suffisant pour exercer la fonction correspondante de la sous-
section 1ère délivré dans la langue de l''immersion; 
2° Le titre étranger équivalent au titre jugé suffisant pour exercer la fonction 
correspondante de la sous-section 1ère délivré dans la langue de l''immersion; 
Secondaire 
 
IV.A.37 
Lois 32365 
 
D. 11-05-2007 
mis à jour au 27-01-2023 
3° Le titre jugé suffisant pour exercer la fonction correspondante de la sous-
section 1ère, complété par un certificat d''enseignement secondaire supérieur délivré 
dans la langue de l''immersion ou par un titre étranger équivalent au moins à ce 
certificat délivré dans la langue de l''immersion; 
4° Le titre jugé suffisant pour exercer la fonction correspondante de la sous-
section 1ère, complété par le CCALI; 
5° Pour les cours d''immersion en langue néerlandaise, le titre jugé suffisant pour 
exercer la fonction correspondante de la sous-section 1ère, complété par le CCALN; 
6° Pour les cours d''immersion en langue allemande, le titre jugé suffisant pour 
exercer la fonction correspondante de la sous-section 1re, complété par le CCALA.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '11bis', NULL, 'Article 11bis du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 20, 'Art. 11ter', 'Art. 11ter. - L''échelle d''une fonction de membre du personnel enseignant chargé 
des cours en immersion linguistique est identique à celle fixée pour la fonction 
correspondante de la sous-section 1ère aux mêmes conditions de titres.»', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '11ter', NULL, 'Article 11ter du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 21, 'Art. 23', 'Article 23. - Au chapitre II de l''arrêté royal du 30 juillet 1975 relatif aux titres 
