INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 25, 'Art. 25', 'Article 25. - Au chapitre II de l''arrêté royal du 30 juillet 1975 relatif aux titres 
