INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 27, 'Art. 26 § 3', 'Article 26. - A l''article 1er, § 3, du décret du 17 juillet 2003 portant des 
dispositions générales relatives à l''enseignement en langue d''immersion et diverses 
mesures en matière d''enseignement, les termes «8 membres effectifs et 8 membres 
suppléants, porteurs d''un titre requis ou d''un titre jugé suffisant A pour exercer la 
fonction d''instituteur maternel chargé des cours en immersion, la fonction 
d''instituteur primaire chargé des cours en immersion, la fonction de professeur de 
cours généraux chargé des cours en immersion au degré inférieur ou la fonction de 
professeur de cours généraux chargé des cours en immersion au degré supérieur, avec 
une représentation de deux membres pour chaque fonction.» sont remplacés comme 
suit : «4 membres effectifs et 4 membres suppléants, porteurs d''un titre requis ou d''un 
titre jugé suffisant du groupe A pour exercer une fonction de membre du personnel 
enseignant chargé des cours en immersion linguistique.»', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '26', '3', 'Article 26 § 3 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 28, 'Art. 27 § 1', 'Article 27. - A l''article 2 du même décret, les modifications suivantes sont 
apportées : 
1° Au § 1er, les termes «Pour l''application des articles 6bis, 7, 1erbis, 8, 2, et 9, 
1erbis, de l''arrêté de l''Exécutif de la Communauté française du 22 avril 1969 fixant les 
titres requis des membres du personnel directeur et enseignant, du personnel 
auxiliaire d''éducation, du personnel paramédical, du personnel psychologique et du 
personnel social des établissements d''enseignement préscolaire, primaire, spécial, 
moyen, technique, artistique, de promotion sociale et supérieur non universitaire de la 
Communauté française et des internats dépendant de ces établissements, sont 
considérés comme titres pédagogiques étrangers équivalents à ceux qu''ils énumèrent» 
sont remplacés par les termes «Pour l''application de l''article 13.1 de l''arrêté de 
l''Exécutif de la Communauté française du 22 avril 1969 fixant les titres requis des 
membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du 
personnel paramédical, du personnel psychologique et du personnel social des 
établissements d''enseignement préscolaire, primaire, spécial, moyen, technique, 
artistique, de promotion sociale et supérieur non universitaire de la Communauté 
française et des internats dépendant de ces établissements, de l''article 11bis de 
l''arrêté royal du 20 juin 1975 relatif aux titres jugés suffisants dans l''enseignement 
gardien et primaire, de l''article 11bis de l''arrêté royal du 30 juillet 1975 relatif aux 
titres 
jugés 
suffisants 
dans 
l''enseignement 
secondaire 
dispensé 
dans 
les 
établissements 
d''enseignement 
moyen 
ou 
d''enseignement 
normal 
officiels 
subventionnés, de l''article 11bis de l''arrêté royal du 30 juillet 1975 relatif aux titres 
jugés suffisants dans l''enseignement secondaire dispensé dans les établissements 
libres d''enseignement moyen ou d''enseignement normal subventionnés, y compris 
l''année postsecondaire psychopédagogique, et de l''article 11bis de l''arrêté royal du 30 
juillet 1975 relatif aux titres jugés suffisants dans les établissements subventionnés 
d''enseignement technique et d''enseignement professionnel secondaire de plein 
exercice et de promotion sociale, sont considérés comme titres étrangers équivalents à 
ceux qu''ils énumèrent». 
2° Au § 1er, c), les termes «les fonctions d''instituteur ou de professeur de cours 
généraux chargés des cours en immersion.» sont remplacés par les termes : «une 
fonction de membre du personnel enseignant chargé des cours en immersion 
linguistique.». 
3° Le § 2 est remplacé comme suit : «L''arrêté du Gouvernement visé au § 1er, c), 
précise le diplôme auquel le titre pédagogique étranger correspond, en spécifiant le cas 
échéant la section ou le groupe dont il relève.» 
4° Le § 3 est supprimé.', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '27', '1', 'Article 27 § 1 du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 29, 'Art. 28 § 3', 'Article 28. - A l''article 3, § 3, du même décret, le 1er alinéa est remplacé comme 
