INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 30, 'Art. 29', 'Article 29. - A l''article 4 §, 1er, du même décret, les termes «des fonctions 
