INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 32, 'Art. 30bis', 'Article 30bis. - Les membres du personnel enseignant chargés des cours en 
immersion bénéficient de l''échelle de traitement à laquelle leur titre de capacité de 
base, hors compétence linguistique particulière requise en la matière, leur donnerait 
droit s''ils exerçaient la fonction correspondante dans l''enseignement organisé en 
langue française. 
 
CHAPITRE VIII. - Des dispositions modificatives, transitoires et finales', 'Décret du 11 mai 2007 — Immersion linguistique', 'Décret immersion', '30bis', NULL, 'Article 30bis du Décret du 11 mai 2007 — Immersion linguistique (CDA 32365)', ARRAY['ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 33, 'Art. 31', 'Article 31. - Dans la loi du 19 juillet 1971 relative à la structure générale et à 
