INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('32365', 34, 'Art. 32', 'Article 32. - Les points 20° et 22° de l''article 2 du décret du 13 juillet 1998 
