-- CDA 34295: Décret du 30 avril 2009 — Encadrement différencié (79 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 0, 'Art. 1er', 'Article 1er. - Le présent décret s''applique à l''enseignement ordinaire maternel, 
primaire et secondaire de plein exercice ainsi qu''aux centres psycho-médico-sociaux.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '1er', NULL, 'Article 1er du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 1, 'Art. 2', 'Article 2. - Le présent décret a pour objet d''organiser un encadrement différencié 
au sein des établissements scolaires organisés ou subventionnés par la Communauté 
française relevant des niveaux d''enseignement visés à l''article 1er, afin d''assurer à 
chaque élève des chances égales d''émancipation sociale dans un environnement 
pédagogique de qualité. 
 
Dans ce cadre, le présent décret vise à différencier l''encadrement et le 
financement dans certaines implantations d''enseignement ordinaire maternel, 
primaire, fondamental et secondaire de plein exercice, organisées ou subventionnées 
par la Communauté française, ci-après dénommées « les implantations bénéficiaires 
de l''encadrement différencié ». 
 
La différenciation visée à l''alinéa précédent consiste en une attribution objective 
et proportionnée de moyens humains et de moyens financiers complémentaires et 
significatifs sur la base de critères socio-économiques objectifs et uniformes dans le but 
d''y promouvoir des actions pédagogiques complémentaires destinées à atteindre plus 
efficacement et plus équitablement les objectifs visés aux articles 6, en particulier le 
4°, 10, 11, 12, 24 et 34 du décret du 24 juillet 1997 définissant les missions prioritaires 
de l''enseignement fondamental et de l''enseignement secondaire et organisant les 
structures propres à les atteindre, ci-après dénommé « le décret missions ». 
 
Les synergies avec les associations locales et régionales agissant dans les 
quartiers ainsi que les partenariats entre plusieurs implantations bénéficiaires de 
Lois 34295 
 
D. 30-04-2009 
l''encadrement différencié sont encouragées. Dans ce cadre, les moyens humains et les 
moyens financiers complémentaires peuvent être réunis et utilisés en commun par 
plusieurs implantations bénéficiaires. 
 
Par actions pédagogiques complémentaires telles que visées par le présent décret, 
il y a lieu d''entendre notamment les initiatives visant : 
 
1° A renforcer la maîtrise des apprentissages de base, et de la langue française en 
particulier, par tous les élèves. 
2° A lutter contre l''échec, le redoublement et le retard scolaires. 
3° A favoriser la détection rapide des difficultés scolaires, l''organisation de la 
remédiation immédiate et la mise en oeuvre de pédagogies différenciées. 
4° A prévenir le décrochage scolaire et, ce faisant, les éventuels phénomènes 
d''incivilités et de violence. 
 
Parmi 
les 
actions 
pédagogiques 
complémentaires, 
une attention 
toute 
particulière est portée à l''adaptation à la langue française pour les élèves qui ne 
maîtrisent pas suffisamment celle-ci afin de leur permettre de s''adapter avec succès 
aux activités de la classe dans laquelle ils sont inscrits. 
 
[A partir de l''année scolaire 2026-2027, outre les objectifs précités, les 
implantations 
bénéficiaires 
de 
l''encadrement 
différencié 
ont 
pour 
objectif 
l''organisation de repas sains et durables au sein des cantines scolaires.]1 
 
CHAPITRE II. - De la détermination des implantations d''enseignement 
fondamental et d''enseignement secondaire bénéficiaires de l''encadrement 
différencié 
 
Modifié par D. 08-07-2010 ; remplacé par D. 06-07-2017 ; complété par D. 14-06-
2018', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '2', NULL, 'Article 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['redoublement'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 2, 'Art. 3', 'Article 3. - Le Gouvernement de la Communauté française établit l''indice socio-
économique moyen, sur la base des éléments pertinents qui lui sont communiqués par 
les organismes compétents, tels que la Banque carrefour de la sécurité sociale (BCSS), 
selon le processus décrit au présent décret. 
 
Tous les ans, avant le 31 octobre, les Services du Gouvernement transmettent 
aux organismes compétents la liste par implantation des élèves inscrits au 15 janvier 
précédent. Avant le 30 novembre, les organismes compétents établissent, après 
vérification par les Services du gouvernement, la moyenne des différentes variables 
nécessaires à la détermination de l''indice socio-économique de chaque secteur 
statistique, de chaque implantation et de chaque établissement qui comptaient des 
élèves inscrits au 15 janvier précédent, au moyen d''une formule de calcul prenant en 
compte les dernières données statistiques disponibles pour les critères suivants : 
1° revenu par habitant ; 
2° niveau des diplômes ; 
3° taux de chômage, taux d''activité et taux de bénéficiaires d''une aide sociale; 
4° activités professionnelles. 
 
Chacun des critères est déterminé en fonction d''une ou de plusieurs variables. 
 
Les indices socio-économiques de chaque secteur statistique, de chaque 
implantation et de chaque établissement sont exprimés à l''aide d''un indice composite 
dont une valeur faible indique un niveau socio-économique moins favorisé. La formule 
de calcul de ces indices est établie par le Gouvernement et fait apparaître les variables 
déterminant chacun des critères et la méthode de détermination de la part de chacune 
d''elles dans le cadre de la formule de calcul. 
 
1Inséré par le D. 17-12-2025 
Lois 34295 
 
D. 30-04-2009 
Pour l''année scolaire 2017-2018, les Services du gouvernement transmettent aux 
organismes compétents la liste par implantation des élèves inscrits au 15 janvier 2015. 
Les organismes compétents établissent la moyenne des différentes variables 
nécessaires à la détermination de l''indice socio-économique de chaque secteur 
statistique, de chaque implantation et de chaque établissement au moyen d''une 
formule de calcul prenant en compte les dernières données statistiques disponibles 
pour les critères mentionnés dans le présent article. 
 
Inséré par D. 14-06-2018 
Pour l''année scolaire 2018-2019, les Services du gouvernement transmettent aux 
organismes compétents la liste par implantation des élèves inscrits au 15 janvier 2016. 
Les organismes compétents établissent la moyenne des différentes variables 
nécessaires à la détermination de l''indice socioéconomique de chaque secteur 
statistique, de chaque implantation et de chaque établissement au moyen d''une 
formule de calcul prenant en compte les dernières données statistiques disponibles 
pour les critères mentionnés dans le présent article. 
 
Modifié par D. 08-07-2010 ; D.10-02-2011 ; modifié par D. 21-11-2013 ; remplacé 
par D. 06-07-2017 ; modifié par D. 24-02-2022', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '3', NULL, 'Article 3 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 3, 'Art. 4', 'Article 4. - Pour les élèves mineurs séjournant illégalement sur le territoire tels que visés à l''article 79bis du décret "Missions" du 24 juillet 1997 définissant les missions prioritaires de l''enseignement fondamental et de l''enseignement secondaire et organisant les structures propres à les atteindre, et pour les élèves considérés comme primo-arrivants en vertu de l''article 2, 1°, du décret du 7 février 2019 visant à l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent pas la langue de l''enseignement dans l''enseignement organisé ou subventionné par la Communauté française, il est attribué pour chaque variable intervenant dans la construction de l''indice socio-économique la moyenne arithmétique des 2000 valeurs les plus faibles durant 6 ans. En fonction des indices socio-économiques calculés en vertu de l''article 3, les Services du Gouvernement fixent, d''une part, le classement des implantations de l''enseignement fondamental et, d''autre part, celui des implantations de l''enseignement secondaire. Dans les deux cas, les implantations sont classées de manière croissante, en débutant par l''implantation qui obtient l''indice socio-économique le plus faible et en terminant par celle qui présente l''indice socio-économique le plus élevé. Les implantations telles qu''ordonnées conformément à l''alinéa précédent sont réparties, en fonction de leur population scolaire cumulée, en vingt classes comportant chacune 5,00 % (cinq pour cent) de la population de l''enseignement fondamental d''une part, secondaire de plein exercice d''autre part. Ces classes sont numérotées de 1 à 20, de celle comportant l''indice socio-économique le plus faible à celle qui comporte l''indice socio-économique le plus élevé. Par dérogation à l''alinéa 4, la classe 3 est scindée en une classe 3a et une classe 3b comportant chacune 2,5 % (deux pour cent et demi) de la population pour l''enseignement fondamental et respectivement 3,5 % (trois pour cent et demi) et 1,5 % (un pour cent et demi) pour l''enseignement secondaire de plein exercice. Si, du fait de la comptabilisation de la population scolaire cumulée par tranche, la délimitation supérieure d''une classe telle que visée aux deux alinéas précédents ne correspond qu''à une partie de la population scolaire d''une même implantation, la population scolaire de cette dernière implantation est considérée comme répartie entre les deux classes en commençant par compléter la classe dont le coefficient est le plus favorable à l''exception des implantations relevant des classes 13 à 20 qui seraient Lois 34295 D. 30-04-2009 dans ce cas et pour lesquelles l''ensemble de la population scolaire est réputée appartenir à la classe la plus favorable. Le cas échéant, pour l''application des chapitres IV et VI du présent décret, les implantations visées par le présent alinéa sont réputées appartenir à la classe la plus favorable. Sur cette base, les implantations bénéficiaires de l''encadrement différencié sont celles qui à trois reprises au moins sur les six derniers classements, relèvent totalement ou partiellement des classes numérotées de 1 à 5, c''est-à-dire qui, dans l''ordre du classement visé au présent article, ou de celui des cinq années précédentes, sont les moins favorisées et dont la somme des nombres des élèves y inscrits est égale à 25,00 % (vingt-cinq pour cent), respectivement pour l''enseignement fondamental et pour l''enseignement secondaire, du nombre total des élèves inscrits respectivement dans les implantations d''enseignement fondamental ordinaire et dans les implantations d''enseignement secondaire ordinaire de plein exercice en Communauté française. Sont également bénéficiaires de l''encadrement différencié, les implantations qui, dans tous les classements où elles ont été classées à partir de 2017-2018, ont toujours relevé totalement ou partiellement des classes numérotées de 1 à 5. A contrario, les autres implantations sont réputées non bénéficiaires de l''encadrement différencié. Les listes des impla', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '4', NULL, 'Article 4 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['ROI','DASPA'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 4, 'Art. 4', 'de l''enseignement fondamental et de l''enseignement secondaire bénéficiaires et non-bénéficiaires de l''encadrement différencié ainsi que la classe à laquelle elles appartiennent sont transmises par les Services du Gouvernement au Gouvernement avant le 30 janvier et sont approuvées tous les ans par le Gouvernement, avant le 28 février. Pour l''année scolaire 2017-2018, les listes des implantations de l''enseignement fondamental et de l''enseignement secondaire bénéficiaires et non-bénéficiaires de l''encadrement différencié ainsi que la classe à laquelle elles appartiennent sont transmises par les Services du Gouvernement au Gouvernement et approuvées par le Gouvernement au plus tard pour le 30 juin 2017.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '4', NULL, 'Article 4 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 5, 'Art. 5', 'Article 5. – […] Abrogé par D. 06-07-2017 
 
