INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 6, 'Art. 6 § 1', '§ 1er. Dans l''enseignement fondamental des périodes et des crédits 
