INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 14, 'Art. 6 § 3', '§ 3ter. Un coefficient d''ajustement est calculé en divisant 8.603.000 euros 
