INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 31, 'Art. 9 § 2', '§ 2, doivent être mobilisés pour 
l''encadrement en classe ou hors classe, la remédiation, l''étude dirigée, l''apprentissage 
du français, le soutien dans l''apprentissage, le conseil pédagogique, la formation, le 
travail en équipe ou le tutorat dans le cadre de la lutte contre l''échec et le décrochage 
scolaires et peuvent permettre : 
1° L''engagement ou la désignation d''instituteurs primaires à raison d''au moins 6 
périodes sous forme de capital-périodes supplémentaires. 
2° L''engagement ou la désignation d''instituteurs maternels à raison d''au moins 1 
emploi quart-temps, cet emploi étant converti en capital-périodes à raison de 24 
périodes par charge complète. 
3° L''engagement ou la désignation de maîtres d''éducation physique à raison d''au 
moins 6 périodes sous forme de capital-périodes supplémentaires. 
4° L''engagement ou la désignation de maîtres de psychomotricité à raison d''au 
moins 6 périodes sous forme de capital-périodes supplémentaires. 
5° L''engagement ou la désignation, à titre temporaire et pour une durée 
déterminée, dans le centre psycho-médico-social compétent pour une ou plusieurs 
implantations bénéficiaires de l''encadrement différencié et avec mise à disposition 
spécifique pour cette ou ces implantations, d''un auxiliaire social, d''un auxiliaire 
paramédical, d''un auxiliaire psycho-pédagogique ou d''un conseiller psychopédagogique 
supplémentaire d''au moins un quart-temps, cet emploi étant converti en capital-
périodes, à raison de 24 périodes par charge complète. 
6° L''engagement ou la désignation d''éducateurs à raison d''au moins 1 emploi 
quart-temps, cet emploi étant converti en capital-périodes à raison de 24 périodes par 
charge complète. 
7° L''engagement ou la désignation de puéricultrices et puériculteurs à raison 
d''au moins 1 emploi quart-temps, cet emploi étant converti en capital-périodes, à 
raison de 24 périodes par charge complète. 
8° L''engagement ou la désignation, à titre temporaire et pour une durée 
déterminée, dans l''enseignement secondaire artistique à horaire réduit, pour une ou 
plusieurs implantations bénéficiaires de l''encadrement différencié et avec mise à 
disposition spécifique pour cette ou ces implantations d''un ou de plusieurs membres 
du personnel enseignant d''un établissement d''enseignement artistique à horaire 
réduit, cet emploi étant converti en dotation de périodes, à raison de 24 périodes par 
charge complète. [inséré par D. 13-07-2016] 
9° L''engagement ou la désignation d''un maître de philosophie et de citoyenneté 
sous forme de capital-périodes supplémentaires pour l''encadrement du cours de 
philosophie et de citoyenneté dispensé à tous les élèves conformément à l''article 8, 
alinéa 3, de la loi du 29 mai 1959 modifiant certaines dispositions de la législation de 
l''enseignement [inséré par D. 13-07-2016(1)- Erratum M.B. 27-10-2016] 
 
Dans les cas visés au 1° à 8° à l''alinéa précédent : 
1° Les moyens humains sous forme de capital-périodes sont attribués après 
concertation avec les organisations syndicales représentatives conformément à l''article 
8. 
2° Les services prestés dans ce cadre sont en tout point assimilés aux services 
prestés dans le cadre organique. 
3° L''accès à ces emplois est soumis aux mêmes dispositions statutaires que ceux 
du cadre organique. 
4° Les emplois ainsi créés peuvent donner lieu à nomination ou engagement à 
titre définitif hormis ceux visés au 5°, 7° et 8 du précédent alinéa. 
 
Il ne peut être dérogé aux minimas mentionnés aux 1° à 7° de l''alinéa 1er que 
lorsque le nombre de périodes obtenu en application de l''article 6,', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '9', '2', 'Article 9 § 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['exclusion','personnel'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 32, 'Art. 9 § 2', '§ 2 est inférieur à 6. 
Lois 34295 
 
D. 30-04-2009 
Complémentairement aux dispositifs établis par le décret du 7 février 2019 
visant à l''accueil, la scolarisation et l''accompagnement des élèves qui ne maîtrisent 
pas la langue de l''enseignement dans l''enseignement organisé ou subventionné par la 
Communauté française, de manière à renforcer la maîtrise des apprentissages de base, 
et de la langue française en particulier, par tous les élèves, les moyens humains visés 
au présent article peuvent notamment être utilisés sous la forme de périodes et/ou de 
classes plus spécifiquement dédicacées à l''adaptation à la langue française pour les 
élèves qui ne maîtrisent pas suffisamment celle-ci afin de leur permettre de s''adapter 
avec succès aux activités de la classe dans laquelle ils sont inscrits. Le cas échéant, 
une telle activité pédagogique peut être organisée au-delà de l''horaire hebdomadaire 
de l''élève. 
 
Complété par D. 17-12-2014 ; modifié par D. 17-06-2021

§ 2. Les moyens de fonctionnement visés à l''article 6,', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '9', '2', 'Article 9 § 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 33, 'Art. 9 § 3', '§ 3, peuvent permettre : 
1° L''engagement de personnel non enseignant, notamment sous contrat de travail à 
durée déterminée, sous contrat de prestation de services ou sous contrat de 
collaboration, notamment : 
a) Des logopèdes; 
b) Du personnel chargé de l''encadrement des élèves en dehors des heures de 
cours, en ce compris de l''étude dirigée; 
c) Des associations ou des organismes pédagogiques, éducatifs, culturels et 
sportifs; 
d) Des médiateurs; 
e) Des bibliothécaires et responsables multimédias. 
2° L''engagement d''agents contractuels subventionnés, en collaboration avec les 
régions, notamment : 
a) Des enseignants; 
b) Des éducateurs; 
c) Des assistants sociaux; 
d) Des puéricultrices et des puériculteurs; 
e) Des logopèdes; 
f) Des médiateurs; 
g) Des bibliothécaires et responsables multimédias. 
3° L''engagement de personnel non enseignant sous contrat de travail dans le cadre 
d''un programme de transition professionnelle, en collaboration avec les régions, 
notamment : 
a) Du personnel chargé de travaux d''embellissement, d''aménagement et de 
réhabilitation légère de locaux ou des abords, tels que des travaux de peinture et de 
menuiserie; 
b) Du personnel chargé d''apporter un soutien à l''équipe éducative. 
4° Le remplacement des enseignants, dans le cadre de la formation continuée, 
notamment par l''organisation d''activités pédagogiques d''animation. [Modifié par D. 17-06-
2021] 
5° L''organisation et la participation de membres de l''équipe éducative, ainsi que 
leur remplacement éventuel s''il s''agit d''enseignants, dans ou en dehors de 
l''implantation, à des formations et séminaires spécifiques dans les domaines suivants : 
remédiation immédiate et mise en oeuvre de pédagogies différenciées en cas de 
difficultés scolaires, adaptation à la langue française par les élèves qui ne maîtrisent 
pas suffisamment celle-ci, hétérogénéité des publics scolaires, interculturalité, 
renforcement des relations « familles-école », gestion et prévention du décrochage 
scolaire, gestion et prévention des conflits et des phénomènes de violence. 
6° Des actions en commun, notamment dans le cadre de la mise en oeuvre des 
articles 6 et 8, 9° et 10° du décret missions, avec les services du secteur de l''Aide à la 
jeunesse fixés à l''article 1er du décret du 4 mars 1991 relatif à l''Aide à la jeunesse, et 
plus spécifiquement les services d''aide en milieu ouvert agréés en application de 
l''Arrêté du 15 mars 1999 relatif aux conditions particulières d''agrément et d''octroi des 
subventions pour les services d''aide en milieu ouvert. 
Lois 34295 
 
D. 30-04-2009 
7° Au bénéfice des élèves de l''implantation, la création d''espaces de rencontres, 
l''installation et le fonctionnement de bibliothèques, de centres de documentation et de 
ressources multimédias, l''achat de livres, de manuels scolaires, de journaux, de revues 
et périodiques, de logiciels scolaires et d''autres supports d''information. 
8° La prise en charge, tant pour les élèves de l''implantation que pour les membres 
du personnel accompagnant, des frais de participation aux activités pédagogiques, 
éducatives, culturelles et sportives comme notamment les droits d''entrée et de 
participation, que celles-ci soient organisées dans ou en dehors de l''implantation, le 
cas échéant en ce compris la prise en charge de frais de déplacements en résultant. 
9° L''aménagement et l''embellissement des locaux ou des abords de l''implantation. 
10° L''achat de matériel destiné spécifiquement à l''implantation. 
11° L''engagement de personnel enseignant supplémentaire ou des périodes 
complémentaires pour l''encadrement en classe ou hors classe, la remédiation, l''étude 
dirigée, le soutien dans l''apprentissage, le conseil pédagogique, la formation, le travail 
en équipe, le tutorat dans le cadre de la lutte contre l''échec et le décrochage scolaires. 
[inséré par D. 17-12-2014] 
[12° Le financement de l''organisation de repas sains et durables au sein des 
cantines scolaires.]4 
 
[Dans cette hypothèse : 
 
a.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '9', '3', 'Article 9 § 3 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['parents','ROI'], 'secondaire');
