INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 39, 'Art. 10 § 3', '§ 3, peuvent permettre : 
 
1° L''engagement de personnel non enseignant, notamment sous contrat de travail à 
durée déterminée, sous contrat de prestation de services ou sous contrat de 
collaboration, notamment : 
a) Des logopèdes; 
b) Du personnel chargé de l''encadrement des élèves en dehors des heures de 
cours, en ce compris de l''étude dirigée; 
c) Des associations ou des organismes pédagogiques, éducatifs, culturels et 
sportifs; 
d) Des médiateurs; 
e) Des bibliothécaires et responsables multimédias. 
2° L''engagement d''agents contractuels subventionnés, en collaboration avec les 
régions, notamment : 
a) Des enseignants; 
b) Des éducateurs; 
c) Des assistants sociaux; 
d) Des bibliothécaires, des spécialistes des médias, de l''audiovisuel et de 
l''animation socio-culturelle; 
e) Des logopèdes; 
f) Des médiateurs; 
g) Des bibliothécaires et responsables multimédias. 
3° L''engagement de personnel non enseignant sous contrat de travail dans le cadre 
d''un programme de transition professionnelle, en collaboration avec les régions, 
notamment : 
a) Du personnel chargé de travaux d''embellissement, d''aménagement et de 
réhabilitation légère de locaux ou des abords, tels que des travaux de peinture et de 
menuiserie 
b) Du personnel chargé d''apporter un soutien à l''équipe éducative. 
4° Le remplacement des enseignants des deux premières années de l''enseignement 
secondaire dans le cadre de la formation continuée, notamment par l''organisation 
d''activités à caractère socio-culturel. [Modifié par D. 17-06-2021] 
5° L''organisation et la participation de membres de l''équipe éducative, ainsi que 
leur remplacement éventuel s''il s''agit d''enseignants, dans ou en dehors de 
l''implantation, à des formations et séminaires spécifiques dans les domaines suivants : 
remédiation immédiate et mise en oeuvre de pédagogies différenciées en cas de 
difficultés scolaires, adaptation à la langue française par les élèves qui ne maîtrisent 
pas suffisamment celle-ci, hétérogénéité des publics scolaire, interculturalité, 
renforcement des relations « familles-école », gestion et prévention du décrochage 
scolaire, gestion et prévention des conflits et des phénomènes de violence. 
6° Des actions en commun, notamment dans le cadre de la mise en oeuvre des 
articles 6 et 8, 9° et 10°, du décret missions, avec les services du secteur de l''Aide à la 
jeunesse fixés à l''article 1er du décret du 4 mars 1991 relatif à l''Aide à la jeunesse, et 
plus spécifiquement les services d''aide en milieu ouvert agréés en application de 
l''Arrêté du 15 mars 1999 relatif aux conditions particulières d''agrément et d''octroi des 
subventions pour les services d''aide en milieu ouvert. 
Lois 34295 
 
D. 30-04-2009 
7° Au bénéfice des élèves de l''implantation, la création d''espaces de rencontres, 
l''installation et le fonctionnement de bibliothèques, de centres de documentation et de 
ressources multimédias, l''achat de livres, de manuels scolaires, de journaux, de revues 
et périodiques, de logiciels scolaires et d''autres supports d''information. 
8° La prise en charge, tant pour les élèves de l''implantation que pour les membres 
du personnel accompagnant, des frais de participation aux activités pédagogiques, 
éducatives, culturelles et sportives comme notamment les droits d''entrée et de 
participation, que celles-ci soient organisées dans ou en dehors de l''implantation, le 
cas échéant en ce compris la prise en charge de frais de déplacements en résultant. 
9° L''aménagement et l''embellissement des locaux ou des abords de l''implantation. 
10° L''achat de matériel destiné spécifiquement à l''implantation. 
11° L''engagement de personnel enseignant supplémentaire ou des périodes 
complémentaires pour l''encadrement en classe ou hors classe, la remédiation, l''étude 
dirigée, le soutien dans l''apprentissage, le conseil pédagogique, la formation, le travail 
en équipe, le tutorat dans le cadre de la lutte contre l''échec et le décrochage scolaires. 
[11° inséré par D. 17-12-2014] 
Inséré p', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '10', '3', 'Article 10 § 3 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['parents','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 40, 'Art. 10 § 2', '§ 2 alinéa 3(a), doivent être utilisés dans le cadre de la 
lutte contre l''échec et le décrochage scolaires sur base de la stratégie établie dans le 
PGAED à hauteur de pourcentages minima que le Gouvernement fixera, sur base 
d''une évaluation. 
 
Remplacé par D. 06-07-2017 ; D. 31-03-2022', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '10', '2', 'Article 10 § 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 41, 'Art. 11 § 3', 'Article 11. - Les crédits supplémentaires visés aux articles 6, § 3, et 7, § 3, sont 
engagés et liquidés entièrement par les Services du Gouvernement sur le budget de la 
deuxième année civile où l''année scolaire prend fin. 
 
Les crédits supplémentaires visés aux articles 6, § 3, et 7, § 3, sont dépensés 
entièrement par les implantations bénéficiaires au plus tard le dernier jour de l''année 
scolaire qui suit l''année scolaire pour laquelle ces crédits ont été octroyés. 
 
CHAPITRE IV. - Des mesures et règles diverses applicables à certaines 
implantations bénéficiaires de l''encadrement différencié', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '11', '3', 'Article 11 § 3 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 42, 'Art. 12 § 1', 'Article 12. - § 1er. Les emplois visés à l''article 3 de l''arrêté royal du 15 avril 1977 
fixant les règles et les conditions de calcul du nombre d''emplois dans certaines 
fonctions du personnel auxiliaire d''éducation et du personnel administratif des 
établissements d''enseignement secondaire peuvent être créés ou subventionnés, selon 
l''ordre de dévolution qui y est fixé, à concurrence d''un emploi par tranche complète : 
1° De 70 élèves dans les implantations d''enseignement secondaire bénéficiaires 
de l''encadrement différencié appartenant à la classe 1; 
2° De 80 élèves dans les implantations d''enseignement secondaire bénéficiaires 
de l''encadrement différencié appartenant à la classe 2 ou 3. 
 
§ 2. Dans l''arrêté royal visé au § 1er, il est apporté la modification suivante : 
l''article 4 est remplacé par les termes :  
«Article 4. Dans les implantations d''enseignement secondaire bénéficiaires de 
l''encadrement différencié en vertu du décret du 30 avril 2009 organisant un 
encadrement différencié au sein des établissements scolaires de la Communauté 
française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans 
un environnement pédagogique de qualité, les emplois visés à l''article 3 peuvent être 
créés ou subventionnés, selon l''ordre de dévolution qui y est fixé, à concurrence d''un 
emploi par tranche complète : 
Lois 34295 
 
D. 30-04-2009 
1° De 70 élèves dans les implantations d''enseignement secondaire bénéficiaires 
de l''encadrement différencié appartenant à la classe 1; 
2° De 80 élèves dans les implantations d''enseignement secondaire bénéficiaires 
de l''encadrement différencié appartenant à la classe 2 ou 3. 
 
Les emplois ainsi créés peuvent donner lieu à nomination ou engagement à titre 
définitif. ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '12', '1', 'Article 12 § 1 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['exclusion','personnel'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 43, 'Art. 13', 'Article 13. - Dans les implantations d''enseignement secondaire bénéficiaires de 
l''encadrement différencié appartenant à la classe 1 : 
1° L''utilisation des périodes-professeurs visées à l''article 10 permet de contribuer 
à l''amélioration des conditions de travail par la guidance des élèves et la concertation 
au sein des équipes éducatives. 
2° Par dérogation à l''arrêté royal du 30 décembre 1959 relatif aux congés de 
maladie et de maternité des membres du personnel de l''enseignement de l''Etat, le 
remplacement des membres du personnel en congé de maladie est autorisé dès que 
cette absence compte au moins cinq jours. 
3° Chaque année, à partir du 1er octobre, il ne sera procédé à aucune réaffectation 
ou complément de charge d''un membre du personnel qui conduirait à licencier ou à 
réduire la charge d''un membre du personnel temporaire. 
 
Complété par D. 11-04-2014 ; modifié par A.Gt 25-10-2017 ; complété par D. 11-07-
2018', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '13', NULL, 'Article 13 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['exclusion','personnel','obligation scolaire'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 44, 'Art. 14', 'Article 14. - Dans l''enseignement organisé par la Communauté française, la priorité dans les changements d''affectation des membres du personnel directeur, enseignant ou auxiliaire d''éducation, est accordée à ceux qui ont été en service, pendant 10 années au moins, dans une implantation bénéficiaire de l''encadrement différencié de classe 1, 2 ou 3 et/ou dans une implantation bénéficiaire de l''encadrement différencié visée à l''article 39 et/ou dans une implantation bénéficiaire des discriminations positives telles qu''elles étaient déterminées par l''article 4 ainsi que par l''article 64 du décret du 30 juin 1998 visant à assurer à tous les élèves des chances égales d''émancipation sociale, notamment par la mise en oeuvre de discriminations positives. Dans l''enseignement officiel subventionné par la Communauté française, la priorité dans les changements d''affectation des membres du personnel directeur, enseignant ou auxiliaire d''éducation, est accordée à ceux qui ont été en service, pendant 10 années au moins, dans une implantation bénéficiaire de l''encadrement différencié de classe 1, 2 ou 3 et/ou dans une implantation bénéficiaire de l''encadrement différencié visée à l''article 39 et/ou dans une implantation bénéficiaire des discriminations positives telles qu''elles étaient déterminées par l''article 4 ainsi que par l''article 64 du décret du 30 juin 1998 précité. Dans l''enseignement libre subventionné par la Communauté française, la priorité visée à l''article 29quater, 2° du décret du 1er février 1993 fixant le statut des membres du personnel subsidiés de l''enseignement libre subventionné est accordée aux membres du personnel engagés dans une fonction de recrutement qui ont été en service, pendant dix années au moins, dans une implantation bénéficiaire de l''encadrement différencié de classe 1, 2 ou 3 et/ou dans une implantation bénéficiaire de l''encadrement différencié visée à l''article 39 et/ou dans une implantation bénéficiaire des discriminations positives telles qu''elles étaient déterminées par l''article 4 ainsi que par l''article 64 du décret du 30 juin 1998 précité. Le membre du personnel qui refuse la proposition de changement d''affectation alors que la proposition qui lui a été faite l''a été sur base de la liste des établissements qu''il a choisis perd sa priorité. [Complété par D. 11-04-2014] Lois 34295 D. 30-04-2009 Inséré par D. 11-07-2018(1) Les membres du personnel qui sollicitent pour la première fois le bénéfice des dispositions visées aux alinéas précédents doivent être en fonction dans une implantation bénéficiaire de l''encadrement différencié de classe 1, 2 ou 3 au moment de la demande. Inséré par D. 11-07-2018(1) Lorsqu''une implantation voit son classement modifié et ne bénéficie plus de l''encadrement différencié de classe 1, 2 ou 3, le membre du personnel qui a bénéficié l''année scolaire qui précède des dispositions des alinéas 1, 2 ou 3 est réputé répondre à la condition posée par l''alinéa précédent pendant les trois années scolaires suivant la modification de classement et jusqu''à ce qu''il soit dans les conditions pour être nommé, engagé à titre définitif ou, dans les réseaux subventionnés, temporaire prioritaire. Inséré par D. 11-07-2018(1) Lorsqu''une implantation bénéficiaire de l''encadrement différencié de classe 1, 2 ou 3 est fermée, restructurée ou fusionnée avec une autre implantation et que l''implantation fusionnée ou restructurée ne bénéficie pas de l''encadrement différencié de classe 1, 2 ou 3, le membre du personnel de l''implantation fermée, restructurée ou fusionnée qui a bénéficié l''année scolaire qui précède des dispositions des alinéas 1, 2 ou 3, est réputé satisfaire à la condition posée à l''alinéa 4 pendant les trois années suivant la fermeture, la restructuration ou la fusion. Le membre du personnel qui accepte l''emploi qui lui est proposé par la Commission zonale d''affectation le notifie par envoi recommandé au Pouvoir organisateur où il est affecté, avec copie pour le Président de la Commission', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '14', NULL, 'Article 14 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['exclusion','personnel','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 45, 'Art. 14', 'zonale d''affectation, et ce dans les 5 jours ouvrables de la réception de la proposition d''emploi faite par la Commission zonale d''affectation. A défaut de réponse dans ce délai, le membre du personnel est présumé refuser l''emploi qui lui est proposé. Le délai de 10 années au moins visé au présent article est suspendu lorsqu''un membre du personnel visé aux alinéas précédents bénéficie d''un congé pour exercer provisoirement une autre fonction en vertu de l''article 14 de l''arrêté royal du 15 janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel directeur et enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des établissements d''enseignement, gardien, primaire, spécial, moyen, technique, de promotion sociale et artistique de l''Etat, des internats dépendant de ces établissements et des membres du personnel du service d''inspection chargé de la surveillance de ces établissements, auprès d''un centre-relais, conformément au Chapitre V du décret du 12 mai 2004 portant diverses mesures de lutte contre le décrochage scolaire, l''exclusion et la violence à l''école et, notamment, la création du Centre de rescolarisation et de resocialisation de la Communauté française, durant le temps de ce congé. Le présent article s''applique aux changements d''affectations prévus par le décret du 2 juin 2006 relatif au cadre organique et au statut des puériculteurs des établissements d''enseignement maternel ordinaire organisés et subventionnés par la Communauté française.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '14', NULL, 'Article 14 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['exclusion','inspection','surveillance'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 46, 'Art. 15', 'Article 15. - Dans la limite des possibilités budgétaires, le Gouvernement peut 
intervenir dans la part des Pouvoirs publics afin de faciliter l''engagement de personnel 
non enseignant sous contrat de travail dans le cadre d''un programme de transition 
professionnelle au sein des implantations bénéficiaires de l''encadrement différencié : 
1° Pour des travaux d''embellissement, d''aménagement et de réhabilitation légère 
de locaux ou des abords, tels des travaux de peinture, de menuiserie. 
2° Pour un soutien à l''équipe éducative. 
 
Lois 34295 
 
D. 30-04-2009', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '15', NULL, 'Article 15 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 47, 'Art. 16', 'Article 16. - Dans des circonstances d''une gravité exceptionnelle dont il est juge, 
le Gouvernement peut déroger aux obligations de délai, de consultation et de 
concertation prévues aux articles 7 à 11 et permettre l''engagement, dans l''urgence, des 
moyens humains et des moyens de fonctionnement complémentaires nécessaires au 
bon fonctionnement d''une implantation bénéficiaire de l''encadrement différencié. 
 
Inséré par D. 21-11-2013', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '16', NULL, 'Article 16 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 48, 'Art. 16', 'Article 16/1. - Les travaux nécessaires à l''installation dans les établissements ou 
implantations bénéficiaires d''un encadrement différencié de classes 1 à 3, telles que 
visées à l''article 4, alinéas 5 et 6 des infrastructures propres à prévenir les intrusions, 
dans les cas où celles-ci revêtent un caractère de gravité ou de répétition tel que les 
conditions de travail et d''études sont lourdement perturbées, bénéficient de la priorité 
dans les affectations des fonds visés aux articles 5, 7 et 9 du décret du 5 février 1990 
relatif aux bâtiments scolaires de l''enseignement non universitaire organisé ou 
subventionné par la Communauté française. 
 
CHAPITRE V. - De l''évaluation continue du dispositif d''encadrement 
différencié et du contrôle 
 
Modifié par D.10-02-2011', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '16', NULL, 'Article 16 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['évaluation','inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 49, 'Art. 17', 'Article 17. - La Commission de pilotage créée par le décret du 27 mars 2002 
relatif au pilotage du système éducatif de la Communauté française est chargée 
d''observer, de suivre et d''évaluer de manière continue le dispositif d''encadrement 
différencié tel qu''établi par le présent décret. 
 
Dans l''exercice de cette mission, la Commission de pilotage mobilise les moyens 
logistiques dont elle dispose et procède à toutes les expertises et auditions utiles, dont 
celles de chefs d''établissement et de membres d''équipes éducatives de l''enseignement 
fondamental et de l''enseignement secondaire bénéficiaires de l''encadrement 
différencié, de pouvoirs organisateurs de l''enseignement fondamental et de 
l''enseignement secondaire, de membres du Service général de l''Inspection, d''experts 
universitaires. Elle s''appuie également sur les résultats et constats issus des 
évaluations externes internationales, des évaluations externes menées dans le cadre 
du décret du 2 juin 2006 relatif à l''évaluation externe des acquis des élèves de 
l''enseignement obligatoire et au certificat d''études de base au terme de l''enseignement 
primaire et des indicateurs objectifs, notamment les taux de réussite et d''échecs 
scolaires, de redoublement et de retard scolaire, de changements d''établissement, 
d''orientation des élèves à l''issue du continuum pédagogique visés à l''article 13 du 
décret missions, d''orientation des élèves dans l''enseignement spécialisé. 
 
Sur la base de ses observations, la Commission de pilotage rédige tous les trois 
ans un rapport à l''adresse du Gouvernement, dont le premier est toutefois établi pour 
la première fois au plus tard le 30 juin 2013. Ce rapport évalue notamment si les 
objectifs d''assurer à chaque élève des chances égales d''émancipation sociale dans un 
environnement pédagogique de qualité et de promouvoir, dans les implantations 
bénéficiaires de l''encadrement différencié, des actions pédagogiques destinées à 
atteindre les objectifs visé aux articles 6, en particulier le 4°, 10, 11, 12, 24 et 34 du 
décret missions sont atteints et dans quelle mesure. Le rapport contient les 
propositions qui, le cas échéant, permettraient de mieux atteindre ou de parfaire ceux-
ci.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '17', NULL, 'Article 17 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['redoublement','orientation','évaluation','inspection','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 50, 'Art. 18', 'Article 18. - Les pouvoirs organisateurs dont une ou plusieurs implantations 
bénéficient de l''encadrement différencié octroyé par la Communauté française dans le 
cadre du présent décret doivent, durant toute la période au cours de laquelle ils 
bénéficient de celui-ci, ne pas réduire les moyens qu''ils accordent sur fonds propres à 
ces mêmes implantations. 
 
Lois 34295 
 
D. 30-04-2009 
Les Services du Gouvernement assurent l''application et le contrôle du respect du 
présent décret par les établissements scolaires, les différentes implantations 
bénéficiaires de l''encadrement différencié et leurs pouvoirs organisateurs respectifs.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '18', NULL, 'Article 18 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 51, 'Art. 19', 'Article 19. - Lorsque les Services du Gouvernement disposent d''éléments 
indiquant qu''un pouvoir organisateur dans l''enseignement subventionné par la 
Communauté française affecte tout ou partie des moyens complémentaires tant 
humains que de fonctionnement, attribués dans le cadre du présent décret, à d''autres 
fins ou à d''autres implantations que celles légalement prévues, ou encore qu''il ne se 
conforme pas à l''article 18, ils entendent le représentant du pouvoir organisateur et 
transmettent le dossier ainsi constitué au Ministre compétent. 
 
Sur cette base, en cas de faits établis, le Ministre compétent peut mettre en 
demeure le pouvoir organisateur dans l''enseignement subventionné par la 
Communauté française de faire cesser sans délai tout agissement non conforme et de 
rembourser à la Communauté française le montant des moyens complémentaires, tant 
humains que de fonctionnement, ainsi affectés non conformément. Dans le même 
temps, le Gouvernement peut faire diminuer, à hauteur de 50,00 % (cinquante pour 
cent) et pour chacune des implantations concernées, l''attribution de moyens humains 
et de moyens de fonctionnement complémentaires dans le cadre de l''encadrement 
différencié pour l''année scolaire qui suit. 
 
Le cas échéant, en cas de récidive établie ou de refus d''obtempérer, le 
Gouvernement fait diminuer, à hauteur de 100,00 % (cent pour cent) et pour chacune 
des implantations concernées, l''attribution de moyens humains et de moyens de 
fonctionnement complémentaires dans le cadre de l''encadrement différencié pour deux 
années scolaires au moins. 
 
CHAPITRE VI. - Dispositions modificatives et abrogatoires', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '19', NULL, 'Article 19 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['évaluation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 52, 'Art. 20 § 3', 'Article 20. - Dans la loi du 29 mai 1959 modifiant certaines dispositions de la 
législation de l''enseignement, les modifications suivantes sont apportées : 
1° A l''article 3, § 3, alinéa 7, 8°, il est ajouté un dernier alinéa libellé comme tel : « 
Par implantations en discriminations positives, sont visées également les 
implantations classées conformément à l''article 4, alinéa 4 du décret du 30 avril 2009 
organisant un encadrement différencié au sein des établissements scolaires de la 
Communauté française afin d''assurer à chaque élève des chances égales 
d''émancipation sociale dans un environnement pédagogique de qualité qui, dans 
l''ordre de ces classements, scolarisent en leur sein 12,5 % des élèves pour 
l''enseignement fondamental et 13,5 % des élèves pour l''enseignement secondaire ». 
2° A l''article 24, § 2, alinéa 2, 2°quater, il est ajouté les termes « et respecter les 
dispositions fixées par le décret du 30 avril 2009 précité » après les termes « 
discriminations positives ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '20', '3', 'Article 20 § 3 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 53, 'Art. 21 § 1', 'Article 21. - Dans le décret du 4 mars 1991 relatif à l''Aide à la jeunesse, la 
modification suivante est apportée : à l''article 28, § 1er, les termes « le président de la 
Commission des discriminations positives créée par le décret du 30 juin 1998 visant à 
assurer à tous les élèves des chances égales d''émancipation sociale, notamment par la 
mise en oeuvre de discriminations positives, ou son délégué » sont remplacés par les 
termes « le Fonctionnaire dirigeant de la Direction générale de l''enseignement 
obligatoire, ou son délégué ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '21', '1', 'Article 21 § 1 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 54, 'Art. 22', 'Article 22. - Dans le décret du 29 juillet 1992 portant organisation de 
l''enseignement secondaire de plein exercice, les modifications suivantes sont 
apportées : 
1° A l''article 4, 8°, les termes « 250, pour un établissement mentionné dans la 
liste des établissements à aider de manière très prioritaire, fixée par le Gouvernement 
conformément à l''article 10 du décret du 27 octobre 1994 organisant la concertation 
Lois 34295 
 
D. 30-04-2009 
dans l''enseignement secondaire » sont remplacés par les termes « 250, pour un 
établissement dont la ou les implantations d''enseignement secondaire sont 
bénéficiaires de l''encadrement différencié et appartiennent à la classe 1 tel que 
déterminée par le décret du 30 avril 2009 organisant un encadrement différencié au 
sein des établissements scolaires de la Communauté française afin d''assurer à chaque 
élève des chances égales d''émancipation sociale dans un environnement pédagogique 
de qualité ». 
2° A l''article 20, § 4, les termes « octroyées sur base de l''article 11 du décret du 30 
juin 1998 visant à assurer à tous les élèves des chances égales d''émancipation sociale, 
notamment par la mise en oeuvre de discriminations positives » sont remplacés par les 
termes « octroyées sur la base de l''article 10 du décret du 30 avril 2009 précité ». 
3° A l''article 21, § 1er, les termes « à l''exception des établissements ou 
implantations bénéficiaires de discriminations positives reconnues comme prioritaires 
et du complément de périodes-professeurs accordé en vertu de l''article 11 du décret du 
30 juin 1998 visant à assurer à tous les élèves des chances égales d''émancipation 
sociale, notamment par la mise en oeuvre de discriminations positives » sont 
remplacés par les termes « à l''exception des implantations bénéficiaires de 
l''encadrement différencié de classe 1 et du complément de périodes-professeurs 
accordé aux implantations bénéficiaires de l''encadrement différencié de classe 2, 3, 4 
et 5 en vertu du décret du 30 avril 2009 précité ». 
4° A l''article 21quater, le troisième alinéa est supprimé.', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '22', NULL, 'Article 22 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 55, 'Art. 23', 'Article 23. - Dans le décret du 1er février 1993 fixant le statut des membres du 
personnel subsidiés de l''enseignement libre subventionné, les modifications suivantes 
sont apportées : 
1° A l''article 3, § 1erbis, les termes « sauf la dérogation prévue par l''article 14 du 
décret du 30 juin 1998 visant à assurer à tous les élèves des chances égales 
d''émancipation sociale, notamment par la mise en oeuvre de discriminations positives 
» sont remplacés par les termes « sauf la dérogation prévue à l''article 13, 2° du décret 
du 30 avril 2009 organisant un encadrement différencié au sein des établissements 
scolaires de la Communauté française afin d''assurer à chaque élève des chances égales 
d''émancipation sociale dans un environnement pédagogique de qualité ». 
2° A l''article 29quater, 2°, les termes « dans le respect de l''article 18 du décret du 
30 juin 1998 visant à assurer à tous les élèves des chances égales d''émancipation 
sociale, notamment par la mise en oeuvre de discriminations positives » sont 
remplacés par les termes « dans le respect de l''article 14 du décret du 30 avril 2009 
précité ». 
3° A l''article 34quater, § 3, les termes « le respect par les pouvoirs organisateurs 
de l''article 18 du décret du 30 juin 1998 visant à assurer à tous les élèves des chances 
égales d''émancipation sociale, notamment par la mise en oeuvre de discriminations 
positives lorsqu''ils affectent les candidats » sont remplacés par les termes « le respect 
par les pouvoirs organisateurs de l''article 14 du décret du 30 avril 2009 précité 
lorsqu''ils affectent les candidats ». 
4° A l''article 34quater, § 5, alinéas 4, 5 et 6, les termes « contrôle le respect de 
l''article 18 du décret du 30 juin 1998 précité » sont remplacés par les termes « contrôle 
le respect de l''article 14 du décret du 30 avril 2009 précité ». 
5° A l''article 71quater, 2° b), les termes « de l''article 18 du décret du 30 juin 1998 
visant à assurer à tous les élèves des chances égales d''émancipation sociale, 
notamment par la mise en oeuvre de discriminations positives » sont remplacés par les 
termes « de l''article 14 du décret du 30 avril 2009 précité ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '23', NULL, 'Article 23 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['inspection'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 56, 'Art. 24', 'Article 24. - Dans le décret du 24 juillet 1997 définissant les missions 
