INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 61, 'Art. 29', 'Article 29. - Dans le décret du 14 juin 2001 visant à l''insertion des élèves primo-
