INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 62, 'Art. 30 § 2', 'Article 30. - Dans le décret du 20 décembre 2001 relatif à la promotion de la 
santé à l''école, la modification suivante est apportée : à l''article 21, § 2, alinéa 2, les 
termes « visée à l''article 4 du décret du 30 juin 1998 visant à assurer à tous les élèves 
des chances égales d''émancipation sociale notamment par la mise en oeuvre de 
discriminations positives » sont remplacés par les termes « visée à l''article 3 du décret 
du 30 avril 2009 organisant un encadrement différencié au sein des établissements 
scolaires de la Communauté française afin d''assurer à chaque élève des chances égales 
d''émancipation sociale dans un environnement pédagogique de qualité ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '30', '2', 'Article 30 § 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 63, 'Art. 31', 'Article 31. - Dans le décret du 27 mars 2002 relatif au pilotage du système 
éducatif, la modification suivante est apportée : à l''article 3, il est ajouté un dernier 
alinéa rédigé comme suit : « 14. D''observer, de suivre et d''évaluer le dispositif 
d''encadrement différencié tel qu''établi par le décret du 30 avril 2009 organisant un 
encadrement différencié au sein des établissements scolaires de la Communauté 
française afin d''assurer à chaque élève des chances égales d''émancipation sociale dans 
un environnement pédagogique de qualité. Dans l''exercice de cette mission, la 
Commission de pilotage mobilise les moyens logistiques dont elle dispose et procède à 
toutes les expertises et auditions utiles, dont celles de chefs d''établissement et de 
membres d''équipes éducatives de l''enseignement fondamental et de l''enseignement 
secondaire bénéficiaires de l''encadrement différencié, de pouvoirs organisateurs de 
l''enseignement fondamental et de l''enseignement secondaire, de membres du Service 
général de l''Inspection, d''experts universitaires. Sur la base de ses observations, la 
Commission de pilotage rédige tous les trois ans un rapport à l''adresse du 
Gouvernement, dont le premier est toutefois établi au plus tard le 1er juin 2011. Ce 
rapport évalue notamment si les objectifs d''assurer à chaque élève des chances égales 
d''émancipation sociale dans un environnement pédagogique de qualité et de 
promouvoir, dans les implantations bénéficiaires de l''encadrement différencié, des 
actions pédagogiques destinées à atteindre les objectifs visés aux articles 6, en 
particulier le 4°, 10, 11, 12, 24 et 34 du décret missions sont atteints et dans quelle 
mesure. Le rapport contient les propositions qui, le cas échéant, permettraient de 
mieux atteindre ou de parfaire ceux-ci. ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '31', NULL, 'Article 31 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['inspection','ROI'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 64, 'Art. 32', 'Article 32. - Dans le décret du 28 avril 2004 relatif à la différenciation du 
financement des établissements d''enseignement fondamental et secondaire, les 
