articles 3 et 4 du décret du 30 avril 2009 précité ».', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '32', NULL, 'Article 32 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 65, 'Art. 33', 'Article 33. - Dans le décret du 24 mars 2006 relatif à la mise en oeuvre, la 
