INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 66, 'Art. 34', 'Article 34. - Dans le décret du 20 juillet 2006 relatif à la concertation des 
