INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 67, 'Art. 35', 'Article 35. - Dans le décret du 2 février 2007 fixant le statut des directeurs, les 
