INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 68, 'Art. 36', 'Article 36. - Dans le décret du 8 mars 2007 relatif au service général de 
l''inspection, au service de conseil et de soutien pédagogiques de l''enseignement 
organisé par la Communauté française, aux cellules de conseil et de soutien 
