INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 76, 'Art. 44', 'Article 44. - Dans 
l''enseignement 
fondamental 
et 
dans 
l''enseignement 
secondaire, s''il s''avère que des implantations visées dans les arrêtés du Gouvernement 
de la Communauté française du 30 septembre 2005 précités ne sont pas visées, lors de 
leur adoption, par les arrêtés visés à l''article 4 du présent décret, celles-ci sont 
réputées sortantes et, pour l''année scolaire 2010-2011, bénéficient de 50,00 % 
(cinquante pour cent) des périodes et des moyens de fonctionnement qui leur ont été 
accordés l''année scolaire précédente et, pour l''année scolaire 2011-2012, de 25,00 % 
(vingt-cinq pour cent) des périodes et des moyens de fonctionnement qui leur ont été 
accordés deux ans auparavant. La part de chaque implantation sortante est arrondie à 
l''unité inférieure et ne peut être inférieure à moins de 6 périodes. 
 
Dans l''enseignement fondamental et dans l''enseignement secondaire, s''il s''avère 
que des implantations visées dans les arrêtés du Gouvernement de la Communauté 
française du 30 septembre 2005 précités sont également visées, lors de leur adoption, 
par les arrêtés visés à l''article 4 du présent décret et appartiennent aux classes 1 à 3, 
mais ne bénéficieraient pas, par ce biais, d''au moins autant de périodes et de moyens 
de fonctionnement complémentaires que ceux accordés pour l''année scolaire 2008-2009 
par le biais des discriminations positives, ces implantations voient, pour les années 
scolaires 2010-2011 et 2011-2012, leurs périodes et moyens de fonctionnement 
complémentaires être portés au même niveau que ceux octroyés pour l''année scolaire 
2008-2009. 
 
 
Le deuxième alinéa du présent article ne s''applique pas ou plus aux 
implantations y visées qui, entre le 15 janvier 2009 et le 15 janvier 2010 ou entre le 15 
janvier 2009 et le 15 janvier 2011, connaissent une variation à la baisse de leur 
population scolaire de l''ordre de plus de 10 %. 
 
Inséré par D. 14-07-2015 ; remplacé par D. 13-07-2016', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '44', NULL, 'Article 44 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', ARRAY['orientation'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 77, 'Art. 44bis § 2', 'Article 44bis. - Par dérogation à l''article 3, alinéa 1er, à l''article 4, alinéas 1er, 8 
et 9, à l''article 5, à l''article 6, § 2, alinéa 3, et § 4, à l''article 7, § 2, alinéa 3, et § 4, à 
l''article 8, § 1er, alinéas 1er et 5, et § 2, alinéa 1er, la période quinquennale ayant pris 
cours le 1er septembre 2010 est prolongée jusqu''au 31 août 2017. 
 
CHAPITRE VIII. - Entrée en vigueur', 'Décret du 30 avril 2009 — Encadrement différencié', 'Décret encadrement différencié', '44bis', '2', 'Article 44bis § 2 du Décret du 30 avril 2009 — Encadrement différencié (CDA 34295)', NULL, 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('34295', 78, 'Art. 45', 'Article 45. - Le présent décret entre en vigueur le 1er juin 2009. 
 
