INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 17, 'Art. 15', 'Article 15. - Le Gouvernement détermine les règles de fonctionnement 
du collège de prévention et la procédure de nomination de ses membres. 
 
[2.5. - Titre 5. - Les missions spécifiques en matière de prévention]36 
 
[Article 15/1. - Dans le cadre la mise en œuvre du Livre II, le 
Gouvernement, en collaboration avec l''administration compétente, est chargé : 
 
1° d''établir un rapport triennal, comportant un bilan de l''exécution de la 
prévention et les recommandations qui en découlent ; 
 
2° d''apporter une expertise au sujet des actions en matière de prévention ; 
 
3° de centraliser les diagnostics sociaux des conseils de prévention et les 
évaluations triennales visés à l''article 7, 6°, et de les communiquer, avec avis 
de l''administration compétente au collège de prévention].37 
 
3. - Livre II. - Les autorités administratives sociales 
 
3.1. - Titre 1er. - Le conseiller de l''aide à la jeunesse', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '15', NULL, 'Article 15 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 18, 'Art. 16', 'Article 16. - Un conseiller de l''aide à la jeunesse est désigné dans chaque 
division ou dans chaque arrondissement qui n''est pas composé de divisions. 
 
Un ou plusieurs conseillers adjoints de l''aide à la jeunesse peuvent être 
désignés pour assister le conseiller. 
 
Sauf disposition contraire, le conseiller adjoint de l''aide à la jeunesse a 
les mêmes compétences et obligations que le conseiller, à l''exception de la 
direction du service de l''aide à la jeunesse.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '16', NULL, 'Article 16 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 19, 'Art. 17', 'Article 17. - Le conseiller est placé sous l''autorité hiérarchique du 
fonctionnaire dirigeant. 
 
Le conseiller et ses adjoints exercent leurs compétences en matière d''aide 
individuelle en toute indépendance. 
 
Le conseiller dirige le service de l''aide à la jeunesse qui est mis à sa 
disposition pour l''assister dans l''exercice de ses compétences. 
 
Le service de l''aide à la jeunesse mis à la disposition du conseiller 
comporte : 
1° une section sociale [qui organise une permanence spécialisée]38; 
2° une section administrative. 
 
36 Inséré par D. 20-07-2023. 
37 Inséré par D. 20-07-2023. 
38 Ajouté par D. 20-07-2023. 
 
 
Docu 45031 
 
D. 18-01-2018  
La section sociale du service de l''aide la jeunesse comprend au moins un 
agent chargé des missions transversales et intersectorielles. 
 
3.2. - Titre 2. - Le directeur de la protection de la jeunesse', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '17', NULL, 'Article 17 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 20, 'Art. 18', 'Article 18. - Un directeur de la protection de la jeunesse est désigné dans 
chaque division ou dans chaque arrondissement qui n''est pas composé de 
divisions. 
 
Un ou plusieurs directeurs adjoints de la protection de la jeunesse 
peuvent être désignés pour assister le directeur. 
 
Sauf disposition contraire, le directeur adjoint de la protection de la 
jeunesse a les mêmes compétences et obligations que le directeur, à l''exception 
de la direction du service de la protection de la jeunesse.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '18', NULL, 'Article 18 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 21, 'Art. 19', 'Article 19. - Le directeur est placé sous l''autorité hiérarchique du 
fonctionnaire dirigeant. 
 
Le directeur et ses adjoints exercent leurs compétences en matière de 
protection individuelle en toute indépendance. 
 
Le directeur dirige le service de la protection de la jeunesse qui est mis à 
sa disposition pour l''assister dans l''exercice de ses compétences. 
 
Le service de la protection de la jeunesse mis à la disposition du directeur 
comporte : 
1° une section sociale; 
2° une section administrative. 
 
