INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 22, 'Art. 19', 'Article 19/1. - Un 
coordinateur 
de 
zone, 
placé 
sous 
