INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 195, 'Art. 151', 'Article 151/11. - Dans le cadre des missions visées au Livre V, les services 
