INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 210, 'Art. 151', 'Article 151/18. - Dans le cadre des missions visées au Livre VIII, les services 
habilités à assurer les compétences relatives à la prise en charge financière 
des décisions prises en vertu présent décret qui entraînent des dépenses à 
charge du budget de la Communauté française réalisent le traitement de 
données personnelles visé à l''article 151/2, 6°, aux fins de : 
 
1° identifier et authentifier les personnes concernées ; 
 
2° gérer les allocations familiales ; 
 
3° gérer les paiements aux prestataires et accueillants familiaux ; 
 
4° gérer les recettes, les indus, et les parts contributives ; 
 
5° assurer la gestion administrative, sous format papier et électronique, des 
dossiers et des données personnelles des acteurs impliqués dans le traitement.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '151', NULL, 'Article 151 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 211, 'Art. 151 § 1', 'Article 151/19. - §1er. Dans le cadre du traitement visé à l''article 151/2, 6°, 
les catégories de données personnelles susceptibles d''être traitées par 
catégorie de personnes concernées sont les suivantes : 
 
1° le jeune :  
 
a) les données d''identification et de contact ; 
 
b) les données financières ; 
 
c) les données relatives à la composition du ménage ; 
 
d) les données relatives aux études et à la formation ; 
 
e) les données relatives au parcours scolaire ; 
 
f) les données de santé ; 
 
g) les données relatives à la vie ou à l''orientation sexuelle ; 
 
133Titre remplacé par le décret du 04 avril 2024 
 
 
Docu 45031 
 
D. 18-01-2018  
h) les données relatives aux poursuites, condamnations et infractions pénales 
; 
 
i) les données concernant le préjudice subi (préjudice moral, physique ou 
financier) et concernant le dépôt de sa plainte ; 
 
2° les personnes qui exercent l''autorité parentale du jeune : 
 
a) les données d''identification et de contact ; 
 
b) les données financières ; 
 
c) les données relatives à la composition du ménage ; 
 
d) Les données relatives aux études et à la formation ; 
 
e) les données relatives aux poursuites, condamnations et infractions pénales 
; 
 
3° les membres des services agréés : 
 
a) les données d''identification et de contact ; 
 
b) les données financières ; 
 
c) les données relatives aux études et à la formation ; 
 
d) les données relatives à la profession et à l''emploi ; 
 
e) les données relatives aux poursuites, condamnations et infractions pénales 
; 
 
4° les prestataires : 
 
a) les données d''identification et de contact ; 
 
b) les données financières ; 
 
c) les données relatives aux études et à la formation ; 
 
d) les données relatives à la profession et à l''emploi ; 
 
e) les données relatives aux poursuites, condamnations et infractions pénales 
; 
 
 
 
Docu 45031 
 
D. 18-01-2018  
5° les accueillants familiaux : 
 
a) les données d''identification et de contact ; 
 
b) les données financières ; 
 
c) les données relatives à la composition du ménage ; 
 
d) les données relatives à la profession et à l''emploi 
 
e) les données relatives aux poursuites, condamnations et infractions pénales 
; 
 
6° les collaborateurs du Ministère de la Communauté française : 
 
a) les données d''identification et de contact ; 
 
b) les données permettant le traçage des activités online ; 
 
c) les données relatives à l''entité à laquelle l''agent appartient ; 
 
d) les données relatives à la profession et à l''emploi. 
 
§2. Parmi la catégorie de données relative aux données d''identification et de 
contact, le numéro de registre national et les données associées sont collectées 
directement ou indirectement auprès des personnes concernées. 
 
§3. Le traitement des données personnelles liées aux données de santé, à 
l''origine raciale ou ethnique, aux opinions politiques, aux convictions 
religieuses ou philosophiques, à la vie ou à l''orientation sexuelle, n''est 
envisageable que pour autant qu''il soit nécessaire pour des motifs d''intérêt 
public important au sens de l''article 9.2., g), du RGPD. 
 
§4. La catégorie des prestataires visée au §1er, 4°, fait référence aux personnes 
morales ou personnes physiques qui mettent en œuvre une mesure d''aide à 
l''enfant ou aux jeunes en application de la décision d''une autorité mandante 
et qui à ce titre perçoivent des subsides et sont susceptibles d''être contrôlées 
quant à la qualité de la prestation fournie. 
 
Sont également visées les personnes qui apportent leur concours à la prise en 
charge d''un jeune en application de l''arrêté du 23 janvier 2019 relatif aux 
subventions et interventions pour frais individuels liés à la prise en charge 
d''enfants et de jeunes. 
 
 
 
Docu 45031 
 
D. 18-01-2018  
9. - Livre VIII. - Les dispositions financières, générales, pénales et 
finales 
 
9.1. - Titre 1er. - Les dispositions financières', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '151', '1', 'Article 151 § 1 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['orientation','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 212, 'Art. 152', 'Article 152. - L''administration compétente reçoit notification de toute 
décision prise en vertu du présent code lorsqu''elle entraîne des dépenses à 
charge du budget de la Communauté française.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '152', NULL, 'Article 152 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 213, 'Art. 153 § 4', 'Article 153. - La participation des personnes qui doivent des aliments à 
l''enfant aux frais résultant des mesures prises en application des articles 
35, § 4, 37, 51, 52, 101 et 108 est fixée [par le Conseiller, par le Directeur ou 
par le Tribunal de la jeunesse]134 suivant les critères et modalités arrêtés par 
le Gouvernement. 
 
La fixation d''une participation aux frais dans le chef d''un débiteur 
d''aliments autre qu''un ascendant au premier degré n''exclut pas l''octroi de 
subventions à ce débiteur d''aliments lorsque l''aide ou la protection est 
dispensée par son intermédiaire. 
 
Le tribunal de la jeunesse statue sur les recours introduits contre ces 
fixations. 
 
Le recouvrement des frais mis à charge des intéressés est poursuivi par 
le Gouvernement. 
 
En cas d''exécution forcée, le recouvrement de ces frais est confié à 
l''administration de l''enregistrement et des domaines, conformément aux 
dispositions de l''article 3 de la loi domaniale du 22 décembre 1949. 
 
9.2. - Titre 2. - Les dispositions générales', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '153', '4', 'Article 153 § 4 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 214, 'Art. 154', 'Article 154. - Le Gouvernement fait inspecter par les fonctionnaires qu''il 
délègue à cet effet : 
1° les services agréés; 
2° les services de l''aide à la jeunesse ainsi que les services de la protection 
de la jeunesse; 
3° les institutions publiques, à régime ouvert et à régime fermé; 
4° les personnes morales non agréées et les personnes qui apportent 
occasionnellement leur concours à l''application du présent code.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '154', NULL, 'Article 154 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 215, 'Art. 155', 'Article 155. - Sauf en cas de contre-indication médicale, les enfants et 
les jeunes confiés à un service agréé résidentiel ou à une institution publique 
en vertu d''une mesure d''aide ou de protection peuvent être soumis à des 
vaccinations et inoculations préventives, selon les règles fixées par le 
Gouvernement.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '155', NULL, 'Article 155 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 216, 'Art. 156', 'Article 156. - Les protocoles de collaboration sont conclus entre le 
secteur de la prévention, de l''aide à la jeunesse et de la protection de la 
jeunesse et d''autres secteurs dans le but d''améliorer la prévention et la prise 
en charge des enfants, des jeunes et des familles visés par le présent code. 
 
 
134Remplacé par le décret du 04 avril 2024 
 
 
Docu 45031 
 
D. 18-01-2018  
