INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 217, 'Art. 157', 'Article 157. - Toute personne qui apporte son concours à l''application du 
présent code est, de ce fait, dépositaire des secrets qui lui sont confiés dans 
l''exercice de sa mission et qui se rapportent à celle-ci et se voit appliquer les 
dispositions du Code pénal relatives au secret professionnel.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '157', NULL, 'Article 157 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 218, 'Art. 158', 'Article 158. - Celui qui héberge habituellement des enfants ou des 
jeunes sous le couvert de l''application du présent code sans avoir obtenu 
l''agrément ou en contravention avec une décision de refus ou de retrait 
d''agrément est puni d''un emprisonnement de huit jours à six mois et d''une 
amende de vingt-six euros à cinq mille euros ou d''une de ces peines seulement.', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '158', NULL, 'Article 158 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
