INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 221, 'Art. 161', 'Article 161. - A l''article 2 du décret du 31 mars 2004 relatif à l''adoption, 
