INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 223, 'Art. 163', 'Article 163. - A l''article 15, alinéa 3, 2°, du même décret, les mots «la 
