INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 224, 'Art. 164', 'Article 164. - Dans l''article 1er du décret du 12 mai 2004 relatif à l''aide 
