INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 225, 'Art. 165', 'Article 165. - L''article 4 du même décret est remplacé par ce qui suit : 
«Article 4. Il est institué une commission de coordination de l''aide aux 
enfants victimes de maltraitance dans chaque division ou dans chaque 
arrondissement qui n''est pas composé de divisions. 
 
Toutefois, une commission de coordination peut être instituée pour 
plusieurs divisions.».', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '165', NULL, 'Article 165 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 226, 'Art. 166', 'Article 166. - A l''article 6, alinéa 1er, du même décret, les modifications 
