INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 227, 'Art. 167', 'Article 167. - A l''article 6, alinéa 3, du même décret, les mots «par 
