INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 228, 'Art. 168 § 3', 'Article 168. - A l''article 9, 1°, du même décret, les mots «par le conseiller 
