INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 231, 'Art. 172', 'Article 172. - Dans l''article 1er du décret du 21 novembre 2013 
organisant les politiques conjointes de l''enseignement obligatoire et de l''aide à 
