INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 244, 'Art. 184', 'Article 184/1. - Dans l''article 60 de la loi du 8 avril 1965, les 
modifications suivantes sont apportées: 
 
