INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 245, 'Art. 185', 'Article 185. - Le décret du 4 mars 1991 relatif à l''aide à la jeunesse, 
modifié par les décrets des 16 mars 1998, 6 avril 1998, 30 juin 1998, 5 mai 
1999, 29 mars 2001, 31 mars 2004, 12 mai 2004, 19 mai 2004, 1er juillet 2005, 
16 juin 2006, 19 octobre 2007, 7 décembre 2007, 19 février 2009, 30 avril 2009, 
29 novembre 2012 et 21 novembre 2013, est abrogé. 
 
Les dispositions suivantes sont abrogées : 
1° les articles 3 et 4 de l''arrêté du Gouvernement de la Communauté 
française du 27 juillet 1998 fixant les modalités de la consultation des pièces 
du dossier du conseiller ou du directeur de l''aide à la jeunesse; 
2° l''article 1er, 11°, de l''arrêté du Gouvernement de la Communauté 
française du 15 mars 1999 relatif aux conditions générales d''agrément et 
d''octroi des subventions pour les services visés à l''article 43 du décret du 4 
mars 1991 relatif à l''aide à la jeunesse; 
3° les articles 25 et 26 de l''arrêté du Gouvernement de la Communauté 
française du 11 juin 2004 fixant les conditions d''agrément et d''octroi des 
subventions pour les services privés de formation et de perfectionnement visés 
à l''article 54 du décret du 4 mars 1991 relatif à l''aide à la jeunesse; 
4° les articles 10, 40, alinéas 1er et 2, 41, alinéas 1er et 2, 42, 43, 52, 53, 
54, 55, 57, 58, 61, 62, 63 et 80 de l''arrêté du Gouvernement de la Communauté 
française du 13 mars 2014 relatif au code des institutions publiques de 
protection de la jeunesse visé à l''article 19bis du décret du 4 mars 1991 relatif 
à l''aide à la jeunesse. 
 
Modifié par D. 29-11-2018', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '185', NULL, 'Article 185 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45031', 246, 'Art. 186', 'Article 186. - Le présent code entre en vigueur le 1er janvier 2019, à 
l’exception des dispositions suivantes qui entrent en vigueur le 1er mai 2019 :  
1° les dispositions du Livre V; 
2° l''article 184; 
3° l''article 185, alinéa 1er, en ce qu''il porte sur les dispositions du décret 
du 4 mars 1991 relatif à l''aide à la jeunesse applicables aux jeunes poursuivis 
du chef d''un fait qualifié infraction commis avant l''âge de dix-huit ans; 
 
 
Docu 45031 
 
D. 18-01-2018  
4° l''article 185, alinéa 2, 4°. 
 
Le Gouvernement peut fixer une date d''entrée en vigueur antérieure à 
celle mentionnée à l''alinéa 1er pour chacune de ses dispositions. 
 
Si, en vertu de l''alinéa 2, le Gouvernement fixe plusieurs dates d''entrée 
en vigueur différentes, il précise les dispositions du décret du 4 mars 1991 
relatif à l''aide à la jeunesse qui sont abrogées suite à l''entrée en vigueur des 
dispositions correspondantes du présent code. 
 
Promulguons le présent décret, ordonnons qu''il soit publié au Moniteur 
belge. 
 
Bruxelles, le 18 janvier 2018. 
 
Le Ministre-Président, 
R. DEMOTTE 
La Vice-Présidente et Ministre de la Culture et de l''Enfance, 
A. GREOLI 
Le Vice-Président et Ministre de l''Enseignement supérieur, de la Recherche 
et des Médias, 
J.-Cl. MARCOURT 
Le Ministre de l''Aide à la jeunesse, des Maisons de justice, des Sports et de la 
Promotion de Bruxelles, chargé de la tutelle sur la Commission 
communautaire française de la Région de Bruxelles-Capitale, 
R. MADRANE 
La Ministre de l''Education, 
M.-M. SCHYNS 
Le Ministre du Budget, de la Fonction publique et de la Simplification 
administrative, 
A. FLAHAUT 
La Ministre de l''Enseignement de promotion sociale, de la Jeunesse, des 
Droits des femmes et de l''Egalité des chances, 
I. SIMONIS', 'Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse', 'Code prévention jeunesse', '186', NULL, 'Article 186 du Décret du 18 janvier 2018 — Code de prévention et aide à la jeunesse (CDA 45031)', ARRAY['ROI','DASPA'], 'commun');

-- CDA 45593: Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (158 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 0, 'Art. 1er § 1', 'Article 1er. - § 1er. Le présent décret s''applique à l''enseignement 
fondamental, maternel, primaire, secondaire, ordinaire et spécialisé, de plein 
exercice ou en alternance, organisé ou subventionné par la Communauté 
française. 
 
Il s''applique également aux centres psycho-médico-sociaux organisés ou 
subventionnés par la Communauté française.  
 
§ 2. Pour l''application du présent décret, il y a lieu d''entendre par : 
1° «le Service général» : le Service général du Pilotage des Ecoles et 
Centres psycho-médico-sociaux créé à l''article 3; 
2° «le Délégué coordonnateur» : le délégué coordonnateur visé à l''article 
3; 
3° «le Directeur général» : le fonctionnaire général en charge de la 
Direction générale du Pilotage du Système Educatif; 
4° «le Code»: le Code de l''enseignement fondamental et de l''enseignement 
secondaire; [remplacé par D. 24-02-2022] 
5° «l''Institut interréseaux de la Formation professionnelle continue» : 
l''Institut interréseaux de la Formation professionnelle continue créé par 
l''article 25 du décret du 11 juillet 2002 relatif à l''Institut interréseaux de la 
Formation professionnelle continue (IFPC); [remplacé par D. 17-06-2021] 
 6° «zones» : les zones telles que définies à l''article 1er de l''arrêté de 
l''Exécutif de la Communauté française du 15 mars 1993 fixant les obligations 
 
 
Docu 45593 
 
D. 13-09-2018  
de concertation entre les établissements dans l''enseignement secondaire de 
plein exercice;  
7° «écoles» : les établissements d''enseignement [tels que visés à l''article 
1.3.1-1, 23°, du Code]1; 
8° «plan de pilotage» : le plan tel que défini à l''article 1.3.1-1, 45° /1 du 
Code; [modifié par D. 24-02-2022] 
9° «contrat d''objectifs» : le contrat tel que défini à l''article 1.3.1-1, 18° /1 
du Code; [modifié par D. 24-02-2022] 
10° «dispositif d''ajustement» : le dispositif visé à l''article tel que défini à 
l''article 1.3.1-1, 22° /1 du Code; [modifié par D. 24-02-2022] 
11° «protocole de collaboration» : le dispositif visé à l''article tel que défini 
à l''article 1.3.1-1, 49° /1 du Code; [modifié par D. 24-02-2022] 
12° «jour ouvrable» : le lundi, mardi, mercredi, jeudi ou vendredi non 
férié ; 
13° «[la]2 Cellule intermédiaire de coordination»: la cellule crée par 
l''article 1.6.1-2 du Code. [Inséré par D. 10-01-2019 ; modifié par D. 24-02-2022]', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '1er', '1', 'Article 1er § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['inspection','spécialisé','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 1, 'Art. 2', 'Article 2. - L''emploi dans le présent décret des noms masculins pour les 
différents titres et fonctions est épicène en vue d''assurer la lisibilité du texte 
nonobstant les dispositions du décret du 21 juin 1993 relatif à la féminisation 
des noms de métier. 
 
Modifié par D. 10-01-2019 ; D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '2', NULL, 'Article 2 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 2, 'Art. 3 § 1', 'Article 3. - § 1er. Il est créé, auprès du Gouvernement, un Service 
général de Pilotage des Ecoles et des Centres psycho-médico-sociaux, ci-après 
dénommé «le Service général», dirigé par un Délégué coordonnateur. 
 
La Cellule intermédiaire de coordination exerce la coordination entre le 
Service général de l''Inspection et le Service général du Pilotage des Ecoles et 
des Centres psycho-médico-sociaux, ainsi que la coordination entre les deux 
Services généraux précités et les services et directions placés au sein de la 
Direction générale du Pilotage du Système Educatif. 
 
§ 2. Le service général est, notamment, chargé de la contractualisation 
avec les écoles visée aux articles 1.5.2-1 à 1.5.2-22 […]3 du Code.  
 
Ce Service général comprend notamment : 
1° 9 directeurs de zone [maximum]4 ; 
2° 88 délégués au contrat d''objectifs [maximum]5. 
 
Sans préjudice de l''article 5, § 3, il est affecté un directeur de zone pour 
chaque zone. Le Gouvernement fixe la répartition des délégués au contrat 
d''objectifs entre les différentes zones en tenant compte, notamment, du 
nombre d''écoles organisées ou subventionnées par la Communauté française 
sur le territoire de chaque zone. 
 
Les modalités de fonctionnement au sein du Service général, notamment 
l''organisation de réunions régulières ou de groupes de travail, sont 
déterminées par le Délégué coordonnateur. 
 
1Inséré par le D. 18-04-2024 
2Remplacé par le D. 18-04-2024 
3Abrogé par le D. 18-04-2024 
4Inséré par le D. 18-04-2024 
5Inséré par le D. 18-04-2024 
 
 
Docu 45593 
 
D. 13-09-2018  
Les modalités de fixation de la résidence administrative des directeurs de 
zone et des délégués au contrat d''objectifs sont fixées par le Gouvernement. 
 
Le Gouvernement, [évalue le fonctionnement du Service tous les six ans. 
Après évaluation, il]6 peut réévaluer le nombre de délégués au contrat 
d''objectifs en tenant compte du nombre, exprimé en unité, des établissements 
d''enseignement fondamental et secondaire de plein exercice et en alternance, 
ordinaire et spécialisé, organisé ou subventionné par la Communauté 
française. Cette réévaluation ne peut porter d''effets qu''à compter du 1er janvier 
[2026]7 au plus tôt.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '3', '1', 'Article 3 § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','inspection','spécialisé','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 3, 'Art. 4', 'Article 4. - Pour le 1er juillet de chaque année, le Délégué coordonnateur 
transmet au Gouvernement, par la voie hiérarchique, un bilan relatif à 
chacune des missions du Service général. 
 
CHAPITRE II. - Des directeurs de zone 
 
Modifié par D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '4', NULL, 'Article 4 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 4, 'Art. 5 § 1', 'Article 5. - § 1er. Les directeurs de zone visés à l''article 3 sont chargés : 
1° de la coordination et de la supervision des délégués au contrat 
d''objectifs de leur zone, notamment en ce qui concerne : 
 a) la procédure de contractualisation des plans de pilotage, le suivi de 
leur degré de réalisation et l''évaluation des contrats d''objectifs; 
 b) la procédure de contractualisation des dispositifs d''ajustements, le 
suivi de leur degré de réalisation et l''évaluation des protocoles de collaboration; 
2° de la signature des contrats d''objectifs et des protocoles de 
collaboration; 
3° avec le Délégué coordonnateur, au sein de l''instance collégiale ainsi 
formée, de la gestion de la demande motivée d''un établissement en cas de 
désaccord persistant entre un établissement et le délégué aux contrats 
d''objectifs, soit sur l''appréciation de celui-ci de l''adéquation d''un plan de 
pilotage avec les objectifs d''amélioration et, le cas échéant, avec les objectifs 
particuliers ou sur sa conformité, soit sur l''évaluation de la mise en oeuvre du 
contrat d''objectif ; 
4° de l''analyse des demandes d''audit à réaliser par le Service général de 
l''Inspection introduites par un délégué au contrat d''objectifs ou un pouvoir 
organisateur et de la transmission de celles-ci pour décision au Délégué 
coordonnateur; 
5° de la coordination interréseaux par zone selon les modalités définies 
par ou en vertu des lois, décrets et règlements;  
6° de l''élaboration, tous les ans, du rapport d''activités de leur zone selon 
le modèle fixé par le Délégué coordonnateur; 
7° de la formulation d''avis et de propositions, d''initiative ou à la demande 
du Gouvernement, sur tout ce qui relève de leur compétence;  
8° de l''exercice de toutes autres tâches qui leur sont confiées par ou en 
vertu des lois, décrets et règlements ainsi que toutes autres missions qui leur 
sont attribuées dans l''intérêt du service par le Délégué coordonnateur. 
 
§ 2. Le Gouvernement fixe le profil de fonction du directeur de zone. 
 
 
6Remplacé par le D. 18-04-2024 
7Remplacé par le D. 18-04-2024 
 
 
Docu 45593 
 
D. 13-09-2018  
§ 3. Les directeurs de zone exercent leurs missions au sein de leur zone 
d''affectation.  
 
Toutefois, selon les besoins, ils peuvent être chargés de plusieurs zones 
et être autorisés par le Délégué coordonnateur à effectuer des missions au sein 
d''une autre zone.  
 
§ 4. Les modalités d''exercice des missions visées au présent article sont 
déterminées par le Délégué coordonnateur, dans le respect des dispositions 
arrêtées par le Gouvernement en exécution du Code. 
 
Modifié par D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '5', '1', 'Article 5 § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','inspection','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 5, 'Art. 6', 'Article 6. - Dans le cadre de sa mission de coordination et de supervision 
des délégués au contrat d''objectifs de sa zone, le directeur de zone est 
responsable des procédures qui le concernent aux articles 1.5.2-1, à 1.5.2-22, 
du Code. 
 
CHAPITRE III. - Des délégués au contrat d''objectifs 
 
Modifié par D. 17-06-2021 ; D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '6', NULL, 'Article 6 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 6, 'Art. 7 § 1', 'Article 7. - § 1er. Les délégués au contrat d''objectifs visés à l''article 3 
sont chargés :  
1° de la procédure de contractualisation des plans de pilotage, du suivi de 
leur degré de réalisation et de l''évaluation des contrats d''objectifs tels que 
définis aux articles 1.5.2-1 à 1.5.2-12 du Code et ses arrêtés d''exécution; 
2° de la procédure de contractualisation des dispositifs d''ajustement, du 
suivi et l''évaluation de leur degré de réalisation et de l''évaluation de la mise 
en oeuvre des protocoles de collaboration tels que définis aux articles 1.5.2-13 
à 1.5.2-22 du Code et ses arrêtés d''exécution; 
3° de la procédure de contractualisation des plans de pilotage, du suivi de 
leur degré de réalisation et de l''évaluation des contrats d''objectifs conclus entre 
un centre psycho-médico-social et le Gouvernement; 
3° /1 de réaliser à partir des plans de formation la collecte des besoins en 
matière de formations professionnelles continues conformément à l''article 9/1; 
[inséré par D. 17-06-2021] 
4°  en collaboration avec le Service général de l''Inspection, de 
l''organisation de la passation, de la correction et du jury externe de l''épreuve 
externe commune conduisant à la délivrance du Certificat d''Etudes de Base au 
terme de l''enseignement primaire ainsi que de l''organisation de la passation, 
de la correction ou du jury de toutes autres épreuves externes certificatives qui 
leur seraient confiées par le Gouvernement; 
5° de la formulation d''avis et de propositions, d''initiative ou à la demande 
du Gouvernement, sur tout ce qui relève de leur compétence; 
6° de la participation à des groupes de travail, commissions et conseils, 
en vertu des lois, décrets et règlements;  
7° de l''exercice de toutes autres tâches qui leur sont confiées par ou en 
vertu des lois, décrets et règlements ainsi que toutes autres missions qui leur 
sont attribuées dans l''intérêt du service par le Délégué coordonnateur ou le 
directeur de zone dont ils dépendent. 
 
§ 2. Le Gouvernement fixe le profil de fonction du délégué au contrat 
d''objectifs. 
 
§ 3. Les délégués au contrat d''objectifs exercent leurs missions au sein de 
leur zone d''affectation. Toutefois, selon les besoins, ils peuvent être 
 
 
Docu 45593 
 
D. 13-09-2018  
[mobilisés]8 par le Délégué coordonnateur et selon les modalités qu''il 
détermine avec le directeur de zone concerné, à effectuer des missions au sein 
d''une autre zone.  
 
§ 4. Les modalités d''exercice des missions visées au présent article sont 
déterminées par le Délégué coordonnateur, dans le respect des dispositions 
arrêtées par le Gouvernement en exécution du Code. 
 
Modifié par D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '7', '1', 'Article 7 § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','inspection','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 7, 'Art. 8', 'Article 8. - Le délégué au contrat d''objectifs exerce ses missions 
