INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 9, 'Art. 9', 'Article 9/1. - Tous les six ans, sur la base des plans de formation repris 
dans les contrats d''objectifs, les délégués au contrat d''objectifs collectent les 
besoins en matière de formations professionnelles continues répondant à des 
besoins collectifs. Ils en font l''analyse avec les services du gouvernement et 
transmettent celle-ci au Conseil de la formation professionnelle continue par 
la voie hiérarchique pour le 1er avril.  
 
Sur base des éléments relevés lors des évaluations intermédiaires, les 
délégués au contrat d''objectifs collectent les éventuels besoins nouveaux en 
matière de formations professionnelles continues répondant à des besoins 
collectifs. Ils en font l''analyse avec les services du gouvernement et 
transmettent celle-ci au Conseil de la formation professionnelle continue par 
la voie hiérarchique pour le 1er avril. 
 
[TITRE II. - De l''accès aux fonctions de directeur de zone et de 
délégué au contrat d''objectifs]9 
 
[CHAPITRE Ier. - Des conditions d''accès]10', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '9', NULL, 'Article 9 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','pilotage'], 'commun');
