INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 18, 'Art. 10 § 1', '§1er, alinéa 1er, 8°, sont seuls admissibles les services effectifs que 
