INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 26, 'Art. 27', 'Article 27. - Les membres du personnel doivent, en toutes occasions, 
avoir le souci constant des intérêts de la Communauté française, des élèves 
fréquentant les établissements d''enseignement organisés ou subventionnés 
par la Communauté française et des membres du personnel de ces 
établissements.  
 
Ils s''acquittent de leur mission avec une égale sollicitude vis-à-vis de tous 
les établissements scolaires et en toute indépendance à l''égard des pouvoirs 
organisateurs.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '27', NULL, 'Article 27 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 27, 'Art. 28', 'Article 28. - Ils doivent observer les principes de neutralité dans 
l''exercice de leurs fonctions. Ils ne peuvent utiliser les élèves à des fins de 
propagande politique, religieuse, philosophique ou de publicité commerciale.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '28', NULL, 'Article 28 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 28, 'Art. 29', 'Article 29. - Ils accomplissent personnellement et consciencieusement 
les obligations qui leur sont imposées par les lois, décrets, arrêtés et 
règlements. 
 
Ils doivent fournir, dans les limites fixées par la réglementation, les 
prestations nécessaires à la bonne marche du service. 
 
Ils exécutent ponctuellement les missions qui leur sont confiées et 
accomplissent leur tâche avec zèle et exactitude. 
 
Ils ne peuvent suspendre l''exercice de leurs fonctions sans autorisation 
préalable de leur supérieur hiérarchique.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '29', NULL, 'Article 29 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 29, 'Art. 30', 'Article 30. - Ils sont tenus à la correction la plus stricte tant dans leurs 
rapports de service que dans leurs rapports avec le public et doivent s''entraider 
dans la mesure où l''exige l''intérêt du service. 
 
Ils doivent, dans le service comme dans leur vie privée, éviter tout ce qui 
pourrait porter atteinte à la confiance du public ou compromettre l''honneur ou 
la dignité de leur fonction. Ils s''abstiennent de tout acte de harcèlement.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '30', NULL, 'Article 30 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 30, 'Art. 31', 'Article 31. - Ils ne peuvent se livrer à aucune activité qui est en 
opposition avec la Constitution et les lois du peuple belge, qui poursuit la 
destruction de l''indépendance du pays ou qui met en danger la défense 
nationale ou l''exécution des engagements de la Belgique en vue d''assurer sa 
sécurité. Ils ne peuvent adhérer ni prêter leur concours à un mouvement, 
groupement, organisation ou association ayant une activité de même nature.

Article 32. - Ils ne peuvent révéler les faits dont ils auraient eu 
connaissance en raison de leurs fonctions et qui auraient un caractère secret.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '31', NULL, 'Article 31 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 31, 'Art. 33', 'Article 33. - Ils ne peuvent solliciter, exiger ou recevoir, directement ou 
par personne interposée, même en dehors de leurs fonctions mais en raison de 
celles-ci, des dons, gratifications ou avantages quelconques. 
 
 
 
Docu 45593 
 
D. 13-09-2018

Article 34. - Le Gouvernement peut préciser les devoirs prévus par la 
présente section. 
 
Modifié par D. 24-02-2022', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '33', NULL, 'Article 33 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 32, 'Art. 35', 'Article 35. - Sans préjudice de l''application des lois pénales et, s''il y 
échet, de l''article 1.7.3-5 du Code, les infractions aux dispositions de la 
présente section sont punies, suivant le cas, de l''une des sanctions 
disciplinaires prévues à l''article 110.  
 
Section II. - Des incompatibilités', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '35', NULL, 'Article 35 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['discipline'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 33, 'Art. 36', 'Article 36. - Est incompatible avec la qualité de membre du personnel, 
l''exercice du mandat politique :  
1° de bourgmestre, d''échevin, de conseiller communal, de président du 
conseil de l''aide sociale ou de membre du conseil de l''aide sociale dans une 
commune comprise, en tout ou partie, dans le territoire sur lequel le membre 
du personnel exerce la fonction de directeur de zone ou de délégué au contrat 
d''objectifs; 
2° de député provincial ou de conseiller provincial dans une province qui 
comprend, en tout ou en partie, le territoire sur lequel le membre du personnel 
exerce la fonction de directeur de zone ou de délégué au contrat d''objectifs. 
 
Remplacé par D. 10-01-2019', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '36', NULL, 'Article 36 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 34, 'Art. 37', 'Article 37. - Est incompatible avec la qualité de membre du personnel, 
l''exercice de tout mandat, en ce compris syndical, auprès d''un pouvoir 
organisateur ou d''une fédération de pouvoirs organisateurs dont un ou 
plusieurs établissement(s) d''enseignement est (sont) compris(s) dans le 
territoire sur lequel le membre du personnel exerce la fonction de directeur de 
zone ou de délégué au contrat d''objectifs.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '37', NULL, 'Article 37 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 35, 'Art. 38', 'Article 38. - Est incompatible avec la qualité de membre du personnel, 
toute occupation qui serait de nature à nuire à l''accomplissement des devoirs 
de sa fonction ou contraire à la dignité de celle-ci.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '38', NULL, 'Article 38 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 36, 'Art. 39', 'Article 39. - Le Gouvernement constate les incompatibilités visées aux 
articles 36 à 38. Il en informe le membre du personnel concerné dans un délai 
de vingt jours à partir du jour où il constate l''incompatibilité par lettre 
recommandée à la poste sortant ses effets le troisième jour ouvrable suivant la 
date de son expédition.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '39', NULL, 'Article 39 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 37, 'Art. 40', 'Article 40. - En cas de contestation sur l''existence d''une incompatibilité 
mentionnée à l''article 39, le membre du personnel concerné peut introduire, 
par la voie hiérarchique, dans un délai de vingt jours ouvrables à compter de 
la date à laquelle la notification de l''incompatibilité a été faite, une réclamation 
devant la Chambre de recours visée à l''article 121. Celle-ci donne son avis au 
Gouvernement dans un délai de deux mois à partir de la date de réception de 
la réclamation. 
 
Le Gouvernement prend sa décision dans un délai d''un mois à partir de 
la réception de l''avis de la Chambre de recours. 
 
 
 
Docu 45593 
 
D. 13-09-2018  
CHAPITRE III. - Du mandat pour l''exercice de la fonction de 
promotion de délégué coordonnateur 
 
Section Ire. - Procédure et conditions d''obtention du mandat de 
Délégué coordonnateur', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '40', NULL, 'Article 40 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 38, 'Art. 41', 'Article 41. - L''emploi de Délégué coordonnateur est conféré par mandat. 
 
Un mandat ne peut être conféré qu''en cas de vacance d''emploi dans la 
fonction considérée. 
 
Le Gouvernement arrête le profil de fonction du Délégué coordonnateur.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '41', NULL, 'Article 41 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', NULL, 'commun');
