INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 65, 'Art. 63 § 2', '§ 2]60. Le stagiaire qui se voit attribuer une mention «défavorable» peut 
introduire par envoi recommandé une réclamation écrite contre cette mention, 
par la voie hiérarchique, dans les dix jours de sa notification, auprès de la 
chambre de recours visée à l''article 121. 
 
La Chambre de recours remet son avis au Gouvernement dans un délai 
maximum [de deux]61 mois à partir de la date de réception du recours. Le 
Gouvernement prend sa décision et attribue la mention d''évaluation au 
membre du personnel stagiaire dans un délai maximum d''un mois à dater de 
la réception de l''avis. 
 
[', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '63', '2', 'Article 63 § 2 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['recours','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 66, 'Art. 63 § 3', '§3. Dans le cas visé à l''article 12, une seule évaluation a lieu au plus tard 
six mois après l''entrée en fonction, selon les modalités fixées par le 
Gouvernement. L''évaluation aboutit à l''attribution de la mention « favorable » 
ou « réservée ». 
 
Une deuxième évaluation, en fin de stage, peut uniquement donner lieu 
à l''attribution de la mention « favorable » ou « défavorable ». 
 
Le stagiaire qui se voit attribuer une mention « défavorable » peut 
introduire par envoi recommandé une réclamation écrite contre cette mention, 
par la voie hiérarchique, dans les dix jours de sa réception, auprès de la 
chambre de recours visée à l''article 121. 
 
La Chambre de recours remet son avis au Gouvernement dans un délai 
maximum de deux mois à partir de la date de réception du recours. Le 
Gouvernement prend sa décision et attribue la mention d''évaluation au 
membre du personnel stagiaire dans un délai maximum d''un mois à dater de 
la réception de l''avis.]62 
 
[', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '63', '3', 'Article 63 § 3 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['recours','évaluation'], 'commun');
