INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 75, 'Art. 63 § 2', '§ 2. Le membre du personnel qui fait l''objet d''une évaluation favorable à 
l''issue du stage fait l''objet d''une proposition de nomination à titre définitif à la 
fonction de directeur de zone […]103.  
 
Cette proposition lui est notifiée par le [Directeur général]104, soit par 
lettre recommandée à la poste avec accusé de réception portant ses effets trois 
jours ouvrables après la date de son expédition, [soit par courriel à l’adresse 
renseignée ou]105 soit par la remise d''une lettre de la main à la main avec 
accusé de réception portant ses effets à la date figurant sur cet accusé de 
réception. 
 
Le membre du personnel dispose d''un délai de dix jours pour remettre la 
proposition complétée et signée au Délégué coordonnateur et y indiquer s''il 
accepte ou renonce à une nomination à titre définitif à la fonction de directeur 
de zone.  
 
[A défaut de réponse dans les 10 jours par courriel avec accusé de 
réception, et sauf cas de force majeure, la renonciation est présumée et le stage 
prend fin de plein droit.]106 
 
En cas de renonciation dans le délai de 10 jours à une nomination à titre 
définitif, le membre du personnel [nommé ou engagé à titre définitif]107 
réintègre sa fonction et son affectation d''origine. 
 
[Article 69. - Dans le cas visé à l''article 12, le stagiaire suit 
exclusivement le volet de la formation professionnelle visée à l''article 66,

§1er, 
5°. 
 
A l''issue du stage, le stagiaire est évalué par le jury visé à l''article 66,', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '63', '2', 'Article 63 § 2 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['exclusion','évaluation','personnel','ROI'], 'commun');
