INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 78, 'Art. 70', 'Article 70. - Nul ne peut être nommé à la fonction de promotion de 
directeur de zone visée à l''article 24, 2°, s''il ne remplit les conditions 
suivantes : 
1° satisfaire aux conditions visées à l''article [14]109, §§ 1er [ou]110 2; 
2° avoir marqué son accord sur la proposition de nomination à titre 
définitif selon les modalités visées à l''article [68]111, § 2; 
3° ne pas avoir été démis de ses fonctions en application de l''article 76 ou 
de l''article [95]112.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '70', NULL, 'Article 70 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 79, 'Art. 71', 'Article 71. - La nomination à une fonction de promotion de directeur de 
zone ne peut avoir lieu qu''en cas de vacance d''emploi de la fonction à conférer.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '71', NULL, 'Article 71 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 80, 'Art. 72', 'Article 72. - Les membres du personnel sont nommés à titre définitif à 
la fonction de promotion de directeur de zone par le Gouvernement.  
 
La nomination à une fonction de promotion de directeur de zone produit 
ses effets, pour l''intéressé, le jour de l''admission au stage. 
 
L''emploi dont était titulaire le membre du personnel stagiaire au sein de 
son pouvoir organisateur d''origine, du Service général du pilotage des écoles 
et centres psycho-médico-sociaux ou du Service général de l''Inspection ne peut 
être déclaré vacant qu''à la date de la décision de nomination au grade de 
directeur de zone. 
 
L''arrêté de nomination est publié par extrait au Moniteur belge. 
 
Section IV. - De la désignation à titre provisoire à la fonction de 
promotion de directeur de zone', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '72', NULL, 'Article 72 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['inscription','exclusion','personnel','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 81, 'Art. 73 § 1', 'Article 73. - § 1er. En cas d''absence temporaire d''un directeur de zone ou 
de vacance d''un emploi de directeur de zone pour lequel il n''est pas possible de 
désigner un stagiaire, le Gouvernement peut procéder à la désignation à titre 
provisoire dans un emploi d''une fonction de directeur de zone. 
 
