INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 95, 'Art. 83', 'Article 83. - Au cours du stage, moyennant un préavis de [six 
semaines]182, il peut être mis fin à celui-ci à la demande du membre du 
personnel. Dans ce cas, le membre du personnel [nommé ou engagé à titre 
définitif]183 réintègre […] sa fonction et son affectation d''origine et, sauf 
circonstances exceptionnelles dûment motivées, il ne pourra être admis au 
stage ou désigné à titre provisoire à une fonction de directeur de zone ou de 
délégué au contrat d''objectifs qu''après avoir répondu à un nouvel appel aux 
candidats. [Le préavis peut être réduit de commun accord.]184', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '83', NULL, 'Article 83 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['inscription','exclusion','personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 96, 'Art. 84 § 1', 'Article 84. - § 1er. A l''issue du stage, le membre du personnel qui a réussi 
la formation […]185 professionnelle visée à l''article 82 est évalué selon les 
mêmes modalités qu''à l''article 81. 
 
Le membre du personnel qui se voit attribuer une mention «défavorable» 
peut introduire par envoi recommandé une réclamation écrite contre cette 
mention selon les mêmes modalités qu''à l''article 81, § [2]186. [Ce recours est 
suspensif. Il est mis fin au stage lorsque le Gouvernement confirme l''échec. Le 
stage prend fin après l''écoulement d''un délai de 15 jours et le membre du 
personnel réintègre sa fonction et son affectation d''origine dans lesquelles il 
est nommé ou engagé à titre définitif. A défaut, ce délai est porté à six 
semaines.]187 
 
§ 2. Le membre du personnel qui fait l''objet d''une évaluation favorable à 
l''issue du stage fait l''objet d''une proposition de nomination à titre définitif à la 
fonction de délégué au contrat d''objectifs […]188.  
 
Cette proposition lui est notifiée par le Délégué coordonnateur, soit par 
lettre recommandée à la poste [soit par courriel à l’adresse renseignée ou]189 
avec accusé de réception portant ses effets trois jours ouvrables après la date 
de son expédition, soit par la remise d''une lettre de la main à la main avec 
accusé de réception portant ses effets à la date figurant sur cet accusé de 
réception. 
 
Le membre du personnel dispose d''un délai de dix jours pour remettre la 
proposition complétée et signée au Délégué coordonnateur et y indiquer s''il 
accepte ou renonce à une nomination à titre définitif à la fonction de délégué 
au contrat d''objectifs.  
 
[A défaut de réponse dans les 10 jours par courriel avec accusé de 
réception, et sauf cas de force majeure la renonciation est présumée et le stage 
prend fin de plein droit.]190 
 
 
