INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 97, 'Art. 85', 'Article 85. - Nul ne peut être nommé à une fonction de promotion de 
délégué au contrat d''objectifs visée à l''article 24, 3°, s''il ne remplit les 
conditions suivantes : 
1° satisfaire aux conditions visées à l''article [14]192, § 1er ou § 2; 
2° avoir marqué son accord sur la proposition de nomination à titre 
définitif selon les modalités visées à l''article 84, § 2 [ ;]193  
[3° ne pas avoir été démis de ses fonctions en application de l''article 76 
ou de l''article 95.]194', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '85', NULL, 'Article 85 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['exclusion','personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 98, 'Art. 86', 'Article 86. - La nomination à une fonction de promotion de délégué au 
contrat d''objectifs ne peut avoir lieu qu''en cas de vacance d''emploi de la 
fonction à conférer.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '86', NULL, 'Article 86 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 99, 'Art. 87', 'Article 87. - Les membres du personnel sont nommés à titre définitif à 
la fonction de promotion de délégué au contrat d''objectifs par le Gouvernement.  
 
La nomination à une fonction de promotion déléguée au contrat d''objectifs 
produit ses effets, pour l''intéressé, le jour de l''admission au stage. 
 
L''emploi dont était titulaire le membre du personnel stagiaire au sein de 
son pouvoir organisateur d''origine, du Service général du pilotage des écoles 
et centres psycho-médico-sociaux ou du Service général de l''Inspection ne peut 
être déclaré vacant qu''à la date de la décision de nomination au grade de 
délégué au contrat d''objectifs. 
 
L''arrêté de nomination est publié par extrait au Moniteur belge. 
 
Section IV. - De la désignation à titre provisoire à une fonction de 
promotion de délégué au contrat d''objectifs', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '87', NULL, 'Article 87 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['inscription','exclusion','personnel','inspection','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 100, 'Art. 88 § 1', 'Article 88. - § 1er. En cas d''absence temporaire d''un délégué au contrat 
d''objectifs ou de vacance d''un emploi de délégué au contrat d''objectifs pour 
lequel il n''est pas possible de désigner un stagiaire, le Gouvernement peut 
procéder à la désignation à titre provisoire dans un emploi d''une fonction de 
délégué au contrat d''objectifs. 
 
§ 2. Le Gouvernement peut procéder à la désignation à titre provisoire 
dans un emploi d''une fonction de promotion de délégué au contrat d''objectifs 
visée à l''article 24, 3° [,]195 d''un membre du personnel remplissant les 
conditions suivantes :  
1° satisfaire aux conditions visées à l''article [14]196, § 1er ou § 2; 
 
191Inséré par le D. 18-04-2024 
192Remplacé par le D. 18-04-2024 
193Remplacé par le D. 18-04-2024 
194Inséré par le D. 18-04-2024 
195Inséré par le D. 18-04-2024 
196Remplacé par le D. 18-04-2024 
 
 
Docu 45593 
 
D. 13-09-2018  
2° avoir introduit sa candidature dans les formes et délais conformément 
à l''article 89; 
3° faire preuve des expériences professionnelles suivantes : 
 a) minimum cinq ans de pratique professionnelle soit en tant que 
membre d''une équipe pédagogique, soit en tant qu''agent au sein d''un centre 
psycho-médico-social; 
 b) trois expériences professionnelles significatives - d''un an au moins - 
soit dans des niveaux d''enseignement différents, soit dans des fonctions 
différentes, qu''elles aient ou non été exercées dans la même école, soit auprès 
de partenaires scolaires; 
 c) une expérience de trois ans au moins dans le domaine de la gestion ou 
de la coordination d''équipe d''adultes dont au moins deux ans dans le domaine 
de l''enseignement constitue un atout; 
 d) une expérience professionnelle dans les matières visées par les 
missions de délégué au contrat d''objectif, soit en matière d''audit, d''analyse 
systémique, d''analyse de variables / indicateurs, constitue un atout. 
 
Par priorité est désigné un candidat détenteur de l''attestation de réussite 
de [de l''épreuve donnant accès à la nomination]197 en rapport avec la fonction 
de délégué au contrat d''objectifs à conférer, visée au Titre II. 
 
Dans l''hypothèse visée à l''alinéa précédent, le Gouvernement applique le 
classement de la réserve de recrutement visée à l''article [18, alinéa 4]198, selon 
les mêmes modalités que celles visées à l''article 79[…]199.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '88', '1', 'Article 88 § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['exclusion','personnel','inspection','obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 101, 'Art. 89', 'Article 89. - Le Gouvernement invite les membres du personnel à 
introduire leur candidature à une désignation à titre provisoire selon les 
modalités qu''il détermine. 
 
Le membre du personnel qui postule pour plusieurs zones indique les 
zones pour lesquelles il se porte candidat. 
 
Peuvent seuls être désignés à titre provisoire à une fonction de promotion 
de [délégué au contrat d''objectifs]200 les candidats qui ont respecté la forme et 
le délai dans lesquels les candidatures doivent être introduites. 
 
La période durant laquelle un membre du personnel est désigné à titre 
provisoire en application des dispositions de la présente section ne peut être 
assimilée au stage visé à l''article 80.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '89', NULL, 'Article 89 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 102, 'Art. 90 § 1', 'Article 90. - § 1er. Moyennant 
un préavis de 
quinze jours, le 
Gouvernement peut mettre fin, dans l''intérêt du service, à la désignation d''un 
membre du personnel désigné à titre provisoire dans une fonction de promotion 
de délégué au contrat d''objectifs. Dans ce cas, le membre du personnel 
réintègre à titre définitif sa fonction et son affectation d''origine et, sauf 
circonstances exceptionnelles dûment motivées, il ne pourra être admis au 
stage ou désigné à titre provisoire à une fonction de directeur de zone ou de 
délégué au contrat d''objectifs qu''après avoir répondu à un nouvel appel aux 
candidats. 
 
 
197Remplacé par le D. 18-04-2024 
198Remplacé par le D. 18-04-2024 
199Abrogé par le D. 18-04-2024 
200Remplacé par le D. 18-04-2024 
 
 
Docu 45593 
 
D. 13-09-2018  
§ 2. Moyennant un préavis de [six semaines]201, le membre du personnel 
peut renoncer à sa désignation à titre provisoire. Dans ce cas, le membre du 
personnel réintègre à titre définitif sa fonction et son affectation d''origine et, 
sauf circonstances exceptionnelles dûment motivées, il ne pourra être admis 
au stage ou désigné à titre provisoire à une fonction de directeur de zone ou de 
délégué au contrat d''objectifs qu''après avoir répondu à un nouvel appel aux 
candidats.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '90', '1', 'Article 90 § 1 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['inscription','exclusion','personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 103, 'Art. 91', 'Article 91. - Il est d''office mis fin à la désignation à titre provisoire du 
membre du personnel lorsque celui-ci fait l''objet de l''une des sanctions 
disciplinaires visées à l''article 110, 4° à 7°.  
 
Les sanctions disciplinaires visées à l''article 110, 6° et 7°, mettent fin, en 
outre, à tout lien statutaire, même dans sa fonction et son affectation d''origine. 
 
CHAPITRE VI. - De l''évaluation en cours de carrière des directeurs 
de zone et des délégués au contrat d''objectifs', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '91', NULL, 'Article 91 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['discipline','évaluation','personnel','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 104, 'Art. 92', 'Article 92. - Sans préjudice des articles [65]202, [68]203, 81 et 84, au moins 
tous les deux ans et au plus tard six mois après sa première entrée en fonction, 
chaque directeur de zone ou chaque délégué au contrat d''objectifs fait l''objet 
d''une évaluation. Celle-ci se base sur l''accomplissement des missions qui lui 
ont été attribuées conformément aux dispositions du Titre Ier.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '92', NULL, 'Article 92 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 105, 'Art. 93', 'Article 93. - Les directeurs de zone sont évalués par le Délégué 
coordonnateur. Les délégués au contrat d''objectifs sont évalués par le directeur 
de zone dont ils relèvent. 
 
L''évaluation fait l''objet de l''une des mentions suivantes : 
1° «Favorable»; 
2° «Réservée»; 
3° «Défavorable». 
 
Lorsque l''évaluation aboutit à l''attribution de la mention «réservée», la 
mention attribuée lors de l''évaluation suivante est soit «favorable» soit 
«défavorable». 
 
Dans le cadre d''une évaluation «réservée», le membre du personnel peut 
se voir formuler des recommandations complémentaires à la formation 
obligatoire individuelle visée à l''article 98, § 2.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '93', NULL, 'Article 93 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 106, 'Art. 94', 'Article 94. - En vue de l''attribution de l''évaluation, il est procédé à un 
entretien avec le membre du personnel et à la rédaction d''un rapport 
d''évaluation dont le modèle est fixé par le Gouvernement. 
 
Le Gouvernement fixe les modalités selon lesquelles l''entretien se 
déroule.', 'Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS', 'Décret pilotage', '94', NULL, 'Article 94 du Décret du 13 septembre 2018 — Service général de pilotage des écoles et CPMS (CDA 45593)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45593', 107, 'Art. 95', 'Article 95. - Le membre du personnel qui se voit attribuer une mention 
«réservée» ou «défavorable» peut introduire par envoi recommandé une 
 
