INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('45721', 58, 'Art. 16', '6 TQ Technicien/Technicienne en environnement 01/09/2003 7 PB Complément en techniques spécialisées de production des entreprises agroalimentaires S-O 6 TQ Technicien/Technicienne des industries agroalimentaires 01/09/2003 6 P Opérateur/Opératrice de production des entreprises agroalimentaires 01/09/2003 1 Pour les options organisées en 5e et 6e années ou en 4e, 5e et 6e années, la date de début se réfère à l''année scolaire au cours de laquelle l''option de base groupée est organisée pour la première fois en 5e année. 2 Pour les options organisées en 5e et 6e années ou en 4e, 5e et 6e années, la date de suppression se réfère à l''année scolaire au cours de laquelle l''option de base groupée n''est plus organisée pour la première fois en 5e année. Vu pour être annexé à l’arrêté du Gouvernement de la Communauté française du 6 novembre 2018 fixant les répertoires des options de base et des formations dans l''enseignement secondaire Bruxelles, le 6 novembre 2018. Le Ministre-Président, R. DEMOTTE La Ministre de l''Education, M.-M. SCHYNS Docu 45721 A.Gt 06-11-2018 Version coordonnée au 02-08-2023 [modifiée par A.Gt 02-03-2023] ANNEXE VIII à l’arrêté du Gouvernement de la Communauté française fixant les répertoires des options de base et des formations dans l''enseignement secondaire. Formations article 45 du décret « Missions » Secteur Code Formation PF de référence 1 Origine CPU Date de début 2 Date de suppression 2 Transforma tion vers 1 Agronomie 1017 Eleveur/Eleveuse id CCPQ 1 Agronomie 1019 Polyculteur/Polycultrice id CCPQ 1 Agronomie 1018 Groom-lad id CCPQ 1 Agronomie 1007 Ouvrier jardinier/ Ouvrière jardinière id CCPQ 01/09/2017 1023 1 Agronomie 1012 Ouvrier/Ouvrière en cultures florales et ornementales id CCPQ 1 Agronomie 1010 Ouvrier/Ouvrière en cul