CHAPITRE IV. - Disposition finale', 'Décret du 7 février 2019 — Accueil des élèves allophones (DASPA/FLA)', 'Décret DASPA/FLA', '40', NULL, 'Article 40 du Décret du 7 février 2019 — Accueil des élèves allophones (DASPA/FLA) (CDA 46275)', ARRAY['DASPA'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('46275', 43, 'Art. 41', 'Article 41. - Le présent décret entre en vigueur le 1er septembre 2019. 
