-- CDA 47114: AGCF du 3 juillet 2019 — Profil de la fonction d'éducateur (3 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47114', 0, 'Section 1', 'Docu 47114 A.Gt 03-07-2019 Imprimé le 05/09/2019 Arrêté du Gouvernement de la Communauté française fixant le profil de la fonction d''éducateur dans l''enseignement secondaire de plein exercice et en alternance A.Gt 03-07-2019 M.B. 05-09-2019 Le Gouvernement de la Communauté française, Vu le décret du 11 avril 2014 réglementant les titres et fonctions dans l''enseignement fondamental et secondaire organisé et subventionné par la Communauté française, l''article 3, § 8 ; Vu l''avis de l''Inspection des Finances, donné le 18 avril 2019 ; Vu l''accord du Ministre du Budget, donné le 28 mai 2019 ; Vu l''avis de la Commission paritaire centrale de l''enseignement libre confessionnel, donné le 30 avril 2019 ; Vu l''avis de la Commission paritaire centrale de l''enseignement officiel subventionné, donné le 3 mai 2019 ; Vu l''avis de la Commission paritaire centrale de l''enseignement libre non confessionnel, donné le 16 mai 2019 ; Vu le protocole de négociation du 14 juin 2019 du Comité de négociation - secteur IX Enseignement, du Comité des services publics locaux et provinciaux - section II, et du Comité de négociation pour les statuts des personnels de l''enseignement libre subventionné, réunis conjointement ; Vu le protocole de négociation du 14 juin 2019 du Comité de concertation entre le Gouvernement de la Communauté française et les organes de représentation et de coordination des pouvoirs organisateurs de l''enseignement et des centres psycho-médico-sociaux subventionnés reconnus par le Gouvernement ; Vu le « test genre » du 5 avril 2019 établi en application de l''article 4, alinéa 2, 1°, du décret du 7 janvier 2016 relatif à l''intégration de la dimension de genre dans l''ensemble des politiques de la Communauté française ; Vu l''avis n° 66.297/2 du Conseil d''Etat, donné le 24 juin 2019, en application de l''article 84, § 1er, alinéa 1er, 2°, des lois sur le Conseil d''Etat, coordonnées le 12 janvier 1973 ; Sur la proposition de la Ministre de l''Education ; Après délibération, Arrête : Article 1er. - Le profil de la fonction d''éducateur dans l''enseignement secondaire de plein exercice et en alternance est déterminé conformément à l''annexe au présent arrêté. Article 2. - Le présent arrêté entre en vigueur le 1er septembre 2019. Docu 47114 A.Gt 03-07-2019 Imprimé le 05/09/2019 Bruxelles, le 3 juillet 2019. Le Ministre-Président, en charge de l''Egalité des Chances et des Droits des Femmes, R. DEMOTTE La Ministre de l''Education, M.-M. SCHYNS Docu 47114 A.Gt 03-07-2019 Imprimé le 05/09/2019 Annexe de l''arrêté du Gouvernement de la Communauté française fixant le profil de fonction des éducateurs dans l''enseignement secondaire de plein exercice et en alternance L''usage du terme « éducateur » dans ce document vise uniquement les éducateurs dans l''enseignement secondaire de plein exercice et en alternance. Placé sous l''autorité du Directeur/Directrice, la tâche de l''éducateur consiste à accompagner et encadrer les élèves qui lui sont confiés. Cette tâche comprend des éléments socio-éducatifs et administratifs constituant un tout à répartir équitablement sur l''ensemble des éducateurs. Par accompagnement et encadrement, il faut entendre les relations de l''éducateur, d''une part avec les élèves individuellement, d''autre part avec le groupe dont il a la charge, en vue d''un suivi de l''élève confronté à des situations multiples et complexes. Une observation constante des élèves en partenariat avec l''équipe de direction, les enseignants, les collègues et les CPMS est indispensable pour pouvoir remplir cette mission. Par accompagnement et encadrement, il faut entendre également les tâches administratives du suivi des élèves qui sont en relation avec le travail socio-éducatif de l''éducateur. On peut ainsi différencier les tâches administratives liées aux missions éducatives, des tâches administratives relevant de la délégation et de l''autorité du chef d''établissement. Au niveau socio-éducatif, l''éducateur : - joue un rôle social basé sur le climat de confiance, m', 'AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur', 'AGCF éducateur', NULL, NULL, 'du AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur (CDA 47114)', ARRAY['évaluation','inspection','ROI','spécialisé'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47114', 1, 'Section 2', 'en place des médiations de première ligne, pratique l''écoute active, la bienveillance, l''empathie, l''assertivité et la communication non violente, prévient et gère les situations conflictuelles et favorise le dialogue dans une approche constructive ; - est référent d''un groupe classe, d''un niveau, d''un degré et ce en collaboration étroite avec les titulaires de classe. Il construit une relation de groupe et une relation personnelle afin d''être en mesure d''aboutir à un suivi de qualité et à l''épanouissement des jeunes placés sous sa responsabilité. Il est référent d''un groupe, mais est disponible et veille au bien-être, à la sécurité de tous les élèves. On entend par `référent'', l''intermédiaire privilégié d''un groupe d''élèves défini. Tous les élèves doivent avoir un référent, mais selon la gestion de l''établissement, tous les éducateurs ne doivent pas nécessairement être des référents. - gère les temps et espaces transitionnels en veillant à l''accueil, au bien- être, à la sécurité des élèves et au respect du ROI de l''établissement, notamment durant les intercours, récréations, les temps de midi, les entrées et les sorties ; - est en relation avec d''autres acteurs intérieurs et extérieurs à l''école (les agents des Centres P.M.S et P.S.E., les parents et un réseau d''intervenants périscolaires (SAJ, SPJ, AMO, CPAS...), mobilise des acteurs autour de projets fédérateurs avec les partenaires internes et externes à l''école, avec l''accord de la direction, installe et entretient un réseau avec des partenaires internes et externes ; Docu 47114 A.Gt 03-07-2019 Imprimé le 05/09/2019 - participe activement à la gestion de la fréquentation scolaire. A cet égard, il gère la partie administrative de ce suivi et prend tous les contacts nécessaires avec les partenaires internes et externes, est en contact régulier avec les responsables légaux des jeunes dont il est référent. Il participe donc activement au contrôle de l''assiduité et à la prévention du décrochage scolaire ; - participe à l''élaboration du ROI et veille au respect de celui-ci dans la perspective de la gestion du vivre ensemble, en collaboration avec les autres acteurs de l''école et propose des réponses éducatives et positives lorsqu''il est confronté à l''infraction à la règle ; - joue un rôle actif dans la prévention de la violence et du harcèlement sous toutes ses formes, via les moyens mis en place au sein de l''école pour l''y aider ; - accompagne, anime et organise, le cas échéant, des activités d''éducation à la santé et de prévention en matière d''assuétudes, et des séquences en lien avec le vivre ensemble et l''éducation à la citoyenneté ; - encadre des séquences d''études au cours desquelles les élèves utilisent les documents pédagogiques qui auront été fournis à l''éducateur par les enseignants. Il tient ces documents à disposition de la hiérarchie et des services de l''inspection, s''il échet ; - est membre de droit du conseil de classe des élèves dont il est référent avec voix consultative lors de la délibération de fin d''année et voix délibérative lors des procédures disciplinaires ; - participe activement aux réunions d''équipe d''éducateurs dont la fréquence est à déterminer en fonction des réalités de chaque école ; - participe chaque année à des formations continuées adaptées aux différentes problématiques rencontrées dans le milieu scolaire. Au niveau administratif, l''éducateur contribue à la gestion des dossiers administratifs des élèves, en veillant aux : - présences en classe ; - présences à l''étude ; - présences pendant le temps de midi ; - retards/autorisations ; - absences et justifications ; - suivi et accompagnement des élèves en cas de décrochage ; - contact et communication avec les familles ; Pour ce faire, l''éducateur utilisera l''outil informatique et le programme adéquat fournis. Docu 47114 A.Gt 03-07-2019 Imprimé le 05/09/2019 Vu pour être annexé à l''arrêté du Gouvernement de la Communauté française fixant le profil de la fonction d''éducateur dans l''enseignement', 'AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur', 'AGCF éducateur', NULL, NULL, 'du AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur (CDA 47114)', ARRAY['discipline','évaluation','inspection','obligation scolaire','parents'], 'secondaire');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47114', 2, 'Section 3', 'secondaire. Bruxelles, le 3 juillet 2019. Le Ministre-Président, en charge de l''Egalité des Chances et des Droits des Femmes, R. DEMOTTE La Ministre de l''Education, M.-M. SCHYNS', 'AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur', 'AGCF éducateur', NULL, NULL, 'du AGCF du 3 juillet 2019 — Profil de la fonction d''éducateur (CDA 47114)', ARRAY['ROI'], 'secondaire');

-- CDA 47237: Décret du 28 mars 2019 — Cellule de soutien et d'accompagnement (73 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 0, 'Art. 1er § 1', 'Article 1er. - § 1er. Le présent décret s''applique à l''enseignement 
fondamental, secondaire, ordinaire et spécialisé, de plein exercice ou en 
alternance, organisé ou subventionné par la Communauté française. 
 
Il s''applique également aux centres psycho-médico-sociaux organisés ou 
subventionnés par la Communauté française. 
 
§ 2. Au sens du présent décret, il y a lieu d''entendre par : 
1° Code : le Code de l''enseignement fondamental et de l''enseignement 
secondaire; [Remplacé par D. 25-03-2021] 
2° pouvoir organisateur : la personne morale de droit public ou la 
personne morale de droit privé qui assume la responsabilité de l''organisation 
d''une école; 
3° WBE : l''organisme public autonome créé par le décret spécial du 7 
février 2019 portant création de l''organisme public chargé de la fonction de 
pouvoir organisateur de l''enseignement organisé par la Communauté 
française; 
4° fédération de pouvoirs organisateurs : l''un des organes de 
représentation 
et 
de 
coordination 
des 
pouvoirs 
organisateurs 
de 
l''enseignement et des centres psycho-médico-sociaux reconnus par le 
Gouvernement, répondant aux critères de l''article 1.6.5-2 du Code; [modifié par 
D. 25-03-2021] 
5° Inspection : le Service général de l''Inspection visé par le décret du 10 
janvier 2019 relatif au Service général de l''Inspection; 
6° l''Institut interréseaux de la Formation professionnelle continue : 
l''Institut interréseaux de la Formation professionnelle continue créé par 
l''article 25 du décret du 11 juillet 2002 relatif à l''Institut interréseaux de la 
Formation professionnelle continue (IFPC); [remplacé par D. 17-06-2022] 
7° plan de pilotage : le plan visé à l''article 1.5.2-1 du Code; [modifié par D. 
25-03-2021] 
8° contrat d''objectifs : le contrat visé aux articles 1.5.2-5 et 1.5.2-6 du 
Code; [modifié par D. 25-03-2021] 
9° dispositif d''ajustement : le dispositif visé à l''article 1.5.2-16, § 1er, du 
Code ; [modifié par D. 25-03-2021] 
 
 
Docu 47237 
 
D. 28-03-2019  
10° protocole de collaboration : le dispositif visé à l''article 1.5.2-17 du 
Code ; [Modifié par D. 25-03-2021] 
11° 
PECA : 
le 
parcours 
d''éducation 
culturelle 
et 
artistique, 
interdisciplinaire, se fondant sur des connaissances culturelles, des pratiques 
individuelles et collectives ainsi que sur des rencontres avec des artistes et des 
oeuvres, se définissant de manière transversale à l''ensemble des savoirs et 
compétences composant le cursus scolaire et concernant donc tous les cours. 
[Inséré par D. 25-03-2021]', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '1er', '1', 'Article 1er § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['discipline','inspection','ROI','spécialisé','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 1, 'Art. 2', 'Article 2. - L''emploi dans le présent décret des noms masculins pour les 
différents titres et fonctions est épicène en vue d''assurer la lisibilité du texte 
nonobstant les dispositions du décret du 21 juin 1993 relatif à la féminisation 
des noms de métier. 
 
Modifié par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '2', NULL, 'Article 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 2, 'Art. 3', 'Article 3. - WBE et chaque fédération de pouvoirs organisateurs dispose 
d''une Cellule de soutien et d''accompagnement, placée sous son autorité. 
 
La Cellule de soutien et d''accompagnement de WBE est compétente pour 
les écoles qu''il organise et pour celles avec lesquelles WBE a conclu une 
convention en application de l''article 1.7.3-1, § 2, alinéa 2, 5°, du Code. 
 
La Cellule de soutien et d''accompagnement d''une fédération de pouvoirs 
organisateurs est compétente pour les écoles dont le pouvoir organisateur est 
affilié à la fédération de pouvoirs organisateurs concernée et pour les écoles 
avec lesquelles ladite fédération de pouvoirs organisateurs a conclu une 
convention en application de l''article 1.7.3-1, § 2, alinéa 2, 5°, du Code. 
 
CHAPITRE II. - Des Cellules de soutien et d''accompagnement 
 
Section Ire. - Les missions des Cellules de soutien et 
d''accompagnement 
 
Modifié par D. 25-03-2021 ; D. 17-06-2021 ; D. 17-06-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '3', NULL, 'Article 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 3, 'Art. 4 § 1', 'Article 4. - Chaque Cellule de soutien et d''accompagnement visée à 
l''article 3 exécute au minimum les missions suivantes en application de 
l''article 14, § 1er : 
1° offrir son appui aux écoles pour l''élaboration de leur plan de pilotage 
et la modification de leur contrat d''objectifs conformément aux articles 1.5.2-1 
à 1.5.2-12 du Code ainsi que pour l''élaboration de l''annexe relative au pôle 
territorial visée à l''article 6.2.4-1, du Code; [modifié par D. 25-03-2021 ; complété par 
D. 17-06-2021] 
2° accompagner et suivre la mise en oeuvre du contrat d''objectifs des 
écoles visé aux articles 1.5.2-1 à 1.5.2-12 du Code ainsi que pour accompagner 
et suivre la mise en oeuvre de l''annexe relative au pôle territorial visée à 
l''article 6.2.4-1, du Code; [modifié par D. 25-03-2021 ; ; complété par D. 17-06-2021] 
3° apporter son appui aux écoles dont les performances présentent un 
écart significatif en dessous de la moyenne des écoles comparées pour rédiger 
une proposition de dispositif d''ajustement et remettre son avis sur cette 
proposition conformément aux articles 1.5.2-13 à 1.5.2-22 du Code; [modifié par 
D. 25-03-2021] 
4° accompagner et suivre la mise en oeuvre du protocole de collaboration 
des écoles dans le cadre de la convention d''accompagnement et de suivi visée 
aux articles 1.5.2-13 à 1.5.2-22 du Code; [modifié par D. 25-03-2021] 
 
 
Docu 47237 
 
D. 28-03-2019  
5° conseiller et accompagner les directions, les enseignants, les équipes 
pédagogiques et les écoles pour lesquels soit l''Inspection lors d''une mission 
d''investigation et de contrôle ou d''audit diligentée à la demande du 
Gouvernement ou des Services du Gouvernement, soit le pouvoir organisateur 
a constaté des faiblesses ou des manquements, en tenant compte des constats 
posés, des observations relevées et, s''il échet, des pistes d''amélioration; 
6° apporter son appui aux écoles à faible taux d''occupation, ainsi qu''aux 
implantations d''écoles dont les performances présentent un écart significatif 
en dessous de la moyenne des écoles comparées, tels que visés aux articles 
1.5.2-13 à 1.5.2-22 du Code, au sens de l''article 7,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '4', '1', 'Article 4 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['inspection','spécialisé','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 4, 'Art. 4 § 1', '§ 1er/1, du décret du 16 
novembre 2007 relatif au programme prioritaire de travaux en faveur des 
bâtiments scolaires de l''enseignement fondamental ordinaire et spécialisé, de 
l''enseignement secondaire ordinaire, spécialisé et de promotion sociale, de 
l''enseignement artistique à horaire réduit, des centres psycho-médico-sociaux 
ainsi que des internats de l''enseignement fondamental et secondaire, ordinaire 
et spécialisé, organisés ou subventionnés par la Communauté française afin 
de mettre en place une stratégie de renforcement de leur attractivité; [modifié 
par D. 25-03-2021] 
7° conseiller, accompagner et soutenir les enseignants, les équipes 
pédagogiques et les écoles dans le déploiement d''une approche intégrée du 
numérique, conformément au présent décret; 
8° accompagner et soutenir les directions dans le développement du 
travail collaboratif, tel que visé par le décret du 14 mars 2019 portant diverses 
dispositions relatives à l''organisation du travail des membres du personnel de 
l''enseignement et octroyant plus de souplesse organisationnelle aux Pouvoirs 
organisateurs; 
9° soutenir les écoles dans la construction de leur projet d''établissement, 
en cohérence avec les projets éducatif et pédagogique de leur pouvoir 
organisateur, et de la fédération de pouvoirs organisateurs à laquelle ils 
adhèrent, et ce, conformément au Code; [modifié par D. 25-03-2021] 
10° mettre leur savoir et leur expérience pédagogiques au service des 
équipes éducatives et pédagogiques d''écoles ou de groupes d''écoles dans une 
perspective d''amélioration de la qualité de la formation assurée aux élèves; 
11° soutenir l''implantation des programmes et l''innovation pédagogique, 
notamment en informant les équipes éducatives et pédagogiques du contenu 
des réformes en matière d''enseignement; 
12° accompagner ou superviser des groupes d''enseignants qui 
construisent collectivement des démarches pédagogiques, des outils pour leurs 
cours; 
13° participer à l''analyse des besoins de formation des enseignants et 
faire des suggestions en vue d''élaborer le plan de formation de l''école; 
14° assister les écoles et les équipes pédagogiques dans le travail 
d''autoanalyse des résultats obtenus par leurs élèves lors des évaluations 
externes non certificatives; 
15° exercer toute autre mission qui est lui confiée par ou en vertu d''une 
disposition décrétale ou règlementaire ; 
16° offrir son appui à la mise en oeuvre du PECA en : 
a) conseillant, accompagnant, partageant son expertise et en soutenant 
les équipes pédagogiques et les écoles dans le déploiement d''une approche 
pluridisciplinaire du PECA, conformément au présent décret ; 
b) favorisant l''ouverture de chaque école aux représentants du monde 
culturel ; 
c) en étant un relais efficace entre le milieu scolaire et les représentants 
du monde culturel ; 
 
 
Docu 47237 
 
D. 28-03-2019  
d) collaborant et en se concertant notamment avec les référents culturels 
des autres réseaux et les représentants du monde culturel. [16° inséré par D. 25-
03-2021] 
 
Alinéa remplacé par D. 17-06-2021 
Le soutien et l''accompagnement des membres de l''équipe éducative des 
écoles et des membres du personnel de l''équipe pluridisciplinaire des Centres 
PMS s''inscrit dans un processus de développement professionnel de ceux-ci et 
dans une professionnalisation accrue. Dans le cadre des missions visées au 
présent article, les Cellules de soutien et d''accompagnement veillent à assurer 
l''implémentation 
des 
démarches 
entreprises 
pendant 
la 
formation 
professionnelle continue. 
 
Section II. - La composition des Cellules de soutien et 
d''accompagnement 
 
Modifié par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '4', '1', 'Article 4 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['discipline','évaluation','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 5, 'Art. 5', 'Article 5. - Chaque Cellule de soutien et d''accompagnement est 
composée : 
1° de Conseillers au soutien et à l''accompagnement parmi lesquels 
figurent des Conseillers techno-pédagogiques et des Référents culturels; 
[complété par D. 25-03-2021] 
2° d''au moins un Conseiller au soutien et à l''accompagnement 
coordonnateur; 
3° de Conseillers au soutien et à l''accompagnement chargés du soutien 
pédagogique des cours philosophiques. 
 
Les Conseillers techno-pédagogiques visés à l''alinéa 1er, 1°, sont affectés 
à la réalisation de la mission visée à l''article 4, alinéa 1er, 7°. 
 
Le Conseiller au soutien et à l''accompagnement coordonnateur visé à 
l''alinéa 1er, 2°, est chargé de la coordination de la Cellule de soutien et 
d''accompagnement. 
 
Les conseillers au soutien et à l''accompagnement visés à l''alinéa 1er, 3°, 
exercent exclusivement la mission visée à l''article 4, alinéa 1er, 5°, et ce, 
uniquement pour le cours de morale non confessionnelle ou de religion du culte 
dont ils relèvent. 
Inséré par D. 25-03-2021 
Les Référents culturels visés à l''alinéa 1er, 1°, sont affectés, d''une part, en 
appui à la réalisation des missions visées à l''article 4, alinéa 1er, 1° et 2°, et, 
d''autre part, à la réalisation de la mission visée à l''article 4, alinéa 1er, 16°. 
 
Les Cellules de soutien et d''accompagnement doivent comprendre un 
nombre minimum total de 370 Conseillers au soutien et à l''accompagnement 
visés à l''alinéa 1er, disposant d''un titre pédagogique. Tous les six ans, avant le 
renouvellement des contrats visés à l''article 14, le Gouvernement répartit 
proportionnellement ce nombre entre les différentes Cellules en fonction de la 
répartition établie en application de l''article 6, § 3, alinéa 2. 
 
Complété par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '5', NULL, 'Article 5 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 6, 'Art. 6 § 1', '§ 1er. Les membres du personnel des Cellules de soutien et 
d''accompagnement visés à l''article 5, alinéa 1er, 1°, sont : 
1° soit désignés par le Gouvernement, sur proposition de WBE ou de la 
fédération de pouvoirs organisateurs dont ils relèvent, dans le cadre d''un congé 
 
 
Docu 47237 
 
D. 28-03-2019  
pour mission en application de l''article 5 du décret du 24 juin 1996 portant 
règlementation des missions, des congés pour mission et des mises en 
disponibilité pour mission spéciale dans l''enseignement organisé ou 
subventionné par la Communauté française; 
2° soit désignés par le Gouvernement, sur proposition de WBE ou de la 
fédération de pouvoirs organisateurs, dans le cadre d''un congé pour mission en 
application de l''article 6 du décret du 24 juin 1996 précité; 
3° soit désignés par le Gouvernement, sur proposition de WBE ou de la 
fédération de pouvoirs organisateurs, dans le cadre d''un congé pour mission en 
application de l''article 6bis du décret du 24 juin 1996 précité; 
4° soit désignés par le Gouvernement, sur proposition de WBE ou de la 
fédération de pouvoirs organisateurs, dans le cadre d''un congé pour mission en 
application de l''article 7 du décret du 24 juin 1996 précité aux conditions fixées 
dans ce décret, à concurrence du nombre maximum de postes fixé par le 
Gouvernement. Le cas échéant, le poste octroyé dans le cadre des conventions 
régionales en application des dispositions de l''article 7 du décret du 24 juin 
1996 précité peut permettre l''engagement d''un membre du personnel dans une 
autre fonction que celle du membre du personnel mis en congé pour mission en 
vertu de l''article 7 précité. Dans ce cas, des périodes de NTPP peuvent être 
affectées totalement ou partiellement au remplacement du membre du 
personnel en congé pour mission. Elles ne peuvent donner lieu à nomination 
ou engagement à titre définitif; 
[4bis° soit désignés par le Gouvernement, sur proposition de WBE ou de 
la Fédération de Pouvoirs organisateurs, dans le cadre d''une disponibilité pour 
mission spéciale en application de l''article 21 du décret du 24 juin 1996 précité. 
Dans ce cas, le membre du personnel mis en disponibilité pour mission spéciale 
bénéficie d''un traitement d''attente ou d''une subvention-traitement d''attente 
et l''organisme au profit duquel la mission est exercée, rembourse 
trimestriellement ce traitement d''attente ou cette subvention-traitement 
d''attente augmenté(e) de toutes les allocations et indemnités éventuelles selon 
les modalités fixées à l''article 22 du même décret du 24 juin 1996.]1 
5° soit prélevés en application de l''article 21,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '1', 'Article 6 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 7, 'Art. 6 § 1', '§ 1er, du décret du 29 juillet 
1992 portant organisation de l''enseignement secondaire de plein exercice; 
6° soit engagés en application de l''article 18 du décret de la Région 
wallonne du 25 avril 2002 relatif aux aides visant à favoriser l''engagement de 
demandeurs d''emploi inoccupés par les pouvoirs locaux, régionaux et 
communautaires, et par certains employeurs du secteur non marchand, de 
l''enseignement et du secteur marchand ou en application de l''arrêté du 
Gouvernement de la Région de Bruxelles-Capitale du 28 novembre 2002 relatif 
au régime des contractuels subventionnés, à concurrence du nombre maximum 
de postes fixé par le Gouvernement; 
7° soit engagés par WBE ou les fédérations de pouvoirs organisateurs 
selon les règles qui leur sont propres. 
 
Les membres du personnel des Cellules de soutien et d''accompagnement 
désignés en application de l''alinéa 1er, 1°, 2° et 3°, le sont, parmi : 
1° les membres du personnel directeur et enseignant, du personnel 
auxiliaire d''éducation, du personnel paramédical, du personnel psychologique 
et du personnel social des écoles pour lesquelles la Cellule est compétente; 
2° les membres du personnel technique des Centres psycho-médico-
sociaux pour lesquels la Cellule est compétente; 
3° les membres du personnel directeur et enseignant et du personnel 
auxiliaire d''éducation des Hautes Ecoles. 
 
1Inséré par le D. 16-05-2024 
 
 
Docu 47237 
 
D. 28-03-2019  
Dans le cadre de l''application de l''alinéa 1er, 4°, lorsque des périodes de 
NTPP sont attribuées dans le cadre de charges partielles à un membre du 
personnel nommé ou engagé à titre définitif, les périodes de NTPP permettant 
son remplacement dans sa fonction d''origine ne peuvent donner lieu à 
nomination ou engagement à titre définitif.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '1', 'Article 6 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 8, 'Art. 6 § 2', '§ 2. Préalablement à la formulation d''une proposition de désignation au 
Gouvernement ou préalablement au recrutement d''un Conseiller au soutien et 
à l''accompagnement visé à l''article 5, alinéa 1er, 1°, WBE ou la fédération de 
pouvoirs organisateurs arrête le profil de la fonction à pourvoir et lance un 
appel aux candidats. 
 
Nul ne peut être désigné ou recruté en qualité de Conseiller au soutien et 
à l''accompagnement visé à l''article 5, alinéa 1er, 1°, s''il n''a pas répondu à l''appel 
aux candidats. 
 
WBE ou la fédération de pouvoirs organisateurs communique aux 
candidats les motifs de son choix au regard des critères du profil de fonction 
visé à l''alinéa 1er.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '2', 'Article 6 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 9, 'Art. 6 § 3', '§ 3. Le nombre total de postes de Conseillers au soutien et à 
l''accompagnement visés à l''article 5, alinéa 1er, 1°, dont WBE et chaque 
fédération de pouvoirs organisateurs peut bénéficier en application du 
paragraphe 1er, alinéa 1er, 1°, est fixé à 189. 
 
Tous les six ans, avant le renouvellement des contrats visés à l''article 14, 
le nombre de Conseillers au soutien et à l''accompagnement visé à l''alinéa 1er 
accordé à chaque Cellule est fixé par le Gouvernement, proportionnellement 
au nombre, exprimé en équivalents temps plein, de membres du personnel de 
l''équipe éducative qui prestent dans les écoles d''enseignement maternel, 
primaire, fondamental et secondaire de plein exercice et en alternance, 
ordinaire et spécialisé pour lesquelles la Cellule est compétente. 
 
Inséré par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '3', 'Article 6 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 10, 'Art. 6 § 4', '§ 4. Le nombre minimum total de postes de Conseillers techno-
pédagogiques visés à l''article 5, alinéa 1er, 1°, exprimés en équivalents temps 
plein, que WBE et les fédérations de pouvoirs organisateurs doivent pourvoir, 
est fixé à 41. 
 
Tous les six ans, avant le renouvellement des contrats visés à l''article 14, 
le nombre minimum de Conseillers techno-pédagogiques dont chaque Cellule 
de soutien et d''accompagnement doit disposer, est fixé par le gouvernement, 
proportionnellement au nombre, exprimé en équivalents temps plein, de 
membres du personnel de l''équipe éducative qui prestent dans les écoles 
d''enseignement maternel, primaire, fondamental et secondaire de plein 
exercice et en alternance, ordinaire et spécialisé pour lesquelles la Cellule est 
compétente. Chaque cellule dispose d''au moins un Conseiller techno-
pédagogique. 
 
Inséré par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '4', 'Article 6 § 4 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 11, 'Art. 6 § 5', '§ 5. Le nombre minimum total de postes de Référents culturels visés à 
l''article 5, alinéa 1er, 1°, exprimés en équivalents temps plein, que WBE et les 
fédérations de pouvoirs organisateurs doivent pourvoir, est fixé à 40. 
 
 
 
Docu 47237 
 
D. 28-03-2019  
Tous les six ans, avant le renouvellement des contrats visés à l''article 14, 
le nombre minimum de Référents culturels dont chaque Cellule de soutien et 
d''accompagnement 
doit 
disposer, 
est 
fixé 
par 
le 
gouvernement, 
proportionnellement au nombre, exprimé en équivalents temps plein, de 
membres du personnel de l''équipe éducative qui prestent dans les écoles 
d''enseignement maternel, primaire, fondamental et secondaire de plein 
exercice et en alternance, ordinaire et spécialisé pour lesquelles la Cellule est 
compétente. Chaque cellule dispose d''au moins un référent culturel. 
 
Les Cellules de soutien et d''accompagnement peuvent conclure une 
convention de collaboration visant à mutualiser les Référents culturels pour 
optimaliser la réponse aux besoins des écoles et la couverture des différentes 
zones d''enseignement.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '6', '5', 'Article 6 § 5 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 12, 'Art. 7 § 1', 'Article 7. - § 1er. Les Conseillers au soutien et à l''accompagnement 
coordonnateurs visés à l''article 5, alinéa 1er, 2°, sont désignés par le 
Gouvernement en application de l''article 6, § 1er, alinéa 1er, 1° et 7° sur 
proposition de WBE ou de la fédération de pouvoirs organisateurs. 
 
Nul ne peut être désigné en qualité de Conseiller au soutien et à 
l''accompagnement coordonnateur s''il ne remplit les conditions suivantes : 
1° avoir suivi une formation en gestion des ressources humaines de 30 
heures ou faire valoir une expérience équivalente; 
2° dans le cas d''un Conseiller au soutien et à l''accompagnement désigné 
sur la base de l''article 6, paragraphe 1er, alinéa 1er, 1°, être nommé ou engagé 
à titre définitif pour le nombre minimum d''heures ou de périodes requis pour 
la fonction à prestations complètes dont il est titulaire; 
3° avoir répondu à l''appel aux candidats visé au paragraphe 2. 
 
§ 2. Préalablement à la formulation d''une proposition de désignation d''un 
Conseiller au soutien et à l''accompagnement coordonnateur visés à l''article 5, 
alinéa 1er, 2°, WBE ou la fédération de pouvoirs organisateurs arrête le profil 
de la fonction à pourvoir et lance un appel aux candidats. 
 
WBE ou la fédération de pouvoirs organisateurs communique aux 
candidats les motifs de son choix au regard des critères du profil de fonction 
visé à l''alinéa 1er.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '7', '1', 'Article 7 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 13, 'Art. 8 § 1', '§ 1er. Les Conseillers au soutien et à l''accompagnement 
chargés du soutien pédagogique des cours philosophiques visés à l''article 5, 
alinéa 1er, 3°, sont désignés par le Gouvernement, sur proposition de WBE ou 
de la fédération de pouvoirs organisateurs concernée, dans le cadre d''un congé 
pour mission en application de l''article 5 du décret du 24 juin 1996 portant 
règlementation des missions, des congés pour mission et des mises en 
disponibilité pour mission spéciale dans l''enseignement organisé ou 
subventionné par la Communauté française parmi les maitres et professeurs 
de morale non confessionnelle, de religion des religions catholique, 
protestante, 
israélite, 
orthodoxe 
et 
islamique 
des 
établissements 
d''enseignement organisés ou subventionnés par la Communauté française. 
 
Nul ne peut être désigné en qualité de Conseiller au soutien et à 
l''accompagnement chargé du soutien pédagogique des cours philosophiques 
visé à l''article 5, alinéa 1er, 3°, s''il ne dispose pas du visa spécifique à cette 
fonction émanant de l''autorité du culte concerné ou de la morale non 
confessionnelle. En cas d''absence ou de vacance d''autorité d''un culte ou de la 
morale non confessionnelle, pour autant que cette absence ou cette vacance 
 
 
Docu 47237 
 
D. 28-03-2019  
soit démontrée, ce visa de l''autorité concernée ne sera pas requis. Le 
Gouvernement arrête le modèle et les modalités de délivrance du visa requis 
étant entendu que ce visa doit expressément porter sur l''accès éventuel du 
candidat à la fonction de Conseiller au soutien et à l''accompagnement et doit 
être délivré distinctement du visa requis pour l''accès du membre du personnel 
à ses fonctions d''enseignant.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '8', '1', 'Article 8 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 14, 'Art. 8 § 2', '§ 2. Préalablement à la formulation d''une proposition de désignation d''un 
Conseiller au soutien et à l''accompagnement des cours philosophiques visé à 
l''article 5, alinéa 1er, 3°, WBE ou la fédération de pouvoirs organisateurs arrête 
le profil de la fonction à pourvoir et lance un appel aux candidats. 
 
WBE ou la fédération de pouvoirs organisateurs communique aux 
candidats les motifs de son choix au regard des critères du profil de fonction 
visé à l''alinéa 1er.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '8', '2', 'Article 8 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 15, 'Art. 8 § 3', '§ 3. Le nombre total de postes de Conseillers au soutien et à 
l''accompagnement chargés du soutien pédagogique des cours philosophiques 
est fixé à 12. 
 
Tous les six ans, avant le renouvellement des contrats visés à l''article 14, 
le Gouvernement fixe : 
1° la répartition des douze postes entre les différents cours 
philosophiques proportionnellement au nombre, exprimé en équivalents temps 
plein, de maitres et professeurs de morale non confessionnelle, de religion des 
religions catholique, protestante, israélite, orthodoxe et islamique qui prestent 
dans les écoles d''enseignement maternel, primaire, fondamental et secondaire 
de plein exercice et en alternance, ordinaire et spécialisé. Un poste au moins 
est octroyé à chaque cours philosophique; 
2° le nombre ou la proportion d''un équivalent temps plein de Conseillers 
au soutien et à l''accompagnement visés à l''article 5, alinéa 1er, 3°, accordé à 
chaque Cellule proportionnellement au nombre, exprimé en équivalents temps 
plein, de maitres et professeurs de morale non confessionnelle, de religion des 
religions catholique, protestante, israélite, orthodoxe et islamique qui prestent 
dans les écoles d''enseignement maternel, primaire, fondamental et secondaire 
de plein exercice et en alternance, ordinaire et spécialisé, pour lesquelles la 
Cellule est compétente. 
 
Lorsque la répartition visée à l''alinéa 2 ne permet pas d''attribuer une 
charge complète (équivalent temps plein) à toutes les Cellules de soutien et 
d''accompagnement, une convention de collaboration est établie entre les 
Cellules concernées afin de permettre la désignation à temps plein d''un 
conseiller. Cette convention, transmise aux Services du Gouvernement 
préalablement à la formulation de la proposition de désignation du Conseiller 
au soutien et à l''accompagnement visé à l''article 5, alinéa 1er, 3°, concerné, fixe 
notamment : 
1° le choix sur la personne du candidat retenu, lequel est nécessairement 
sélectionné conformément à la procédure visée au paragraphe 2; 
2° les principales modalités organisationnelles relatives à la gestion et à 
la coordination du candidat retenu; 
3° les principales modalités organisationnelles relatives à la répartition 
du temps de travail du candidat retenu entre les différentes parties à la 
convention. 
 
 
Modifié par D. 25-03-2021 
 
 
Docu 47237 
 
D. 28-03-2019', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '8', '3', 'Article 8 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','personnel','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 16, 'Art. 9', 'Article 9. - Le Gouvernement peut : 
1° mettre fin de manière anticipée à la désignation d''un membre du 
personnel d''une Cellule de soutien et d''accompagnement visé à l''article 5, 
alinéa 1er, 1° et 3, et désigné conformément à l''article 6, § 1er, alinéa 1er, 1° à 
4°, sur proposition motivée de WBE ou de la fédération de pouvoirs 
organisateurs concernée, basée sur une évaluation négative réalisée, à la suite 
d''un entretien, par le Conseiller au soutien et à l''accompagnement 
coordonnateur visé à l''article 5, alinéa 1er, 2° ; 
2° mettre fin de manière anticipée à la désignation du Conseiller au 
soutien et à l''accompagnement coordonnateur visé à l''article 5, alinéa 1er, 2°, 
sur proposition motivée de WBE ou de la fédération de pouvoirs organisateurs 
concernée. 
 
Pour les membres du personnel d''une Cellule de soutien et 
d''accompagnement engagés sur la base de l''article 6, § 1er, alinéa 1er, 7°, WBE 
ou la fédération de pouvoirs organisateurs concernée peut mettre fin de 
manière anticipée à leur engagement dans le respect des règles qui lui sont 
propres. 
 
Modifié par D. 17-06-2021 ; D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '9', NULL, 'Article 9 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 17, 'Art. 10 § 1', '§ 1er. Tous les membres du personnel des Cellules de 
soutien et d''accompagnement sont tenus de suivre une formation initiale au 
cours des deux premières années de leur entrée en fonction, et une formation 
continue.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '1', 'Article 10 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 18, 'Art. 10 § 2', '§ 2. 
La 
formation 
initiale 
des 
conseillers 
au 
soutien 
et 
à 
l''accompagnement, en ce compris les conseillers techno-pédagogiques, visés à 
l''article 5, alinéa 1er, 1°, est de 80 heures. Elle comprend une formation initiale 
générale et une formation initiale spécifique. [Alinéa remplacé par D. 25-03-2021] 
 
Tous les deux ans, l''Institut interréseaux de la Formation professionnelle 
continue organise au moins une session de formation initiale générale d''une 
durée de 40 heures dont le contenu est fixé par le Gouvernement sur avis de 
l''Institut de la formation en cours de carrière. 
 
Cette formation vise à développer : 
1° les aptitudes relationnelles dans la gestion des relations personnelles, 
interpersonnelles et groupales entre adultes, en particulier dans les situations 
de communication orale et écrite, de prise de parole en public, d''animation de 
réunion, de travail en équipe, de supervision, de gestion de conflits, de 
médiation; 
2° la prise de conscience des changements de posture et d''identité 
professionnelle 
amenés 
par 
rapport 
aux 
aptitudes 
et 
compétences 
relationnelles des candidats; 
3° la compréhension des valeurs, du sens et de la portée de la notion de 
pilotage du système scolaire et des organisations scolaires, notamment en 
s''appropriant : 
a) les enjeux, les valeurs, les finalités et les fondements scientifiques de 
la gouvernance et du pilotage du système éducatif; 
b) les méthodes et processus d''évaluation des politiques scolaires et des 
réformes pédagogiques; 
c) l''organigramme et les missions de l''Administration générale de 
l''Enseignement, le rôle et les missions des différents acteurs du système 
scolaire. 
 
 
 
Docu 47237 
 
D. 28-03-2019  
L''Institut interréseaux de la Formation professionnelle continue délivre 
une attestation de fréquentation de cette formation. 
 
WBE ou la fédération de pouvoirs organisateurs concernée organise la 
formation initiale spécifique, d''une durée de 40 heures, destinée aux membres 
du personnel de sa Cellule. Les objectifs et les contenus de cette formation 
initiale spécifique sont transmis pour information à l''Institut interréseaux de 
la Formation professionnelle continue au plus tard dans le mois qui précède le 
début de celle-ci. 
 
WBE ou la fédération de pouvoirs organisateurs concernée délivre une 
attestation de fréquentation de cette formation. 
 
Inséré par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '2', 'Article 10 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','inspection','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 19, 'Art. 10 § 2', '§ 2/1. Par dérogation au paragraphe 2, la formation initiale des Référents 
culturels visés à l''article 5, alinéa 1er, 1°, est de 90 heures. Elle comprend une 
formation initiale générale, un volet culturel spécifique et une formation 
initiale spécifique. 
 
Tous les deux ans, l''Institut de la formation en cours de carrière organise 
au moins une session de formation initiale générale d''une durée de 30 heures 
dont le contenu est fixé par le gouvernement sur avis de l''Institut de de la 
formation en cours de carrière. Cette formation vise à développer : 
1° les aptitudes relationnelles dans la gestion des relations personnelles, 
interpersonnelles et groupales entre adultes, en particulier dans les situations 
de communication orale et écrite, de prise de parole en public, d''animation de 
réunion, de travail en équipe, de supervision, de gestion de conflits, de 
médiation ; 
2° la prise de conscience des changements de posture et d''identité 
professionnelle 
amenés 
par 
rapport 
aux 
aptitudes 
et 
compétences 
relationnelles des candidats ; 
3° la compréhension des valeurs, du sens et de la portée de la notion de 
pilotage du système scolaire et des organisations scolaires, notamment en 
s''appropriant : 
 a) les enjeux, les valeurs, les finalités et les fondements scientifiques de 
la gouvernance et du pilotage du système éducatif ; 
 b) les méthodes et processus d''évaluation des politiques scolaires et des 
réformes pédagogiques ; 
 c) l''organigramme et les missions de l''Administration générale de 
l''Enseignement, le rôle et les missions des différents acteurs du système 
scolaire. 
 
Certaines parties de la formation initiale générale des Référents culturels 
peuvent être communes avec la formation initiale générale des Conseillers au 
soutien et à l''accompagnement visée au paragraphe 2, alinéa 2. L''Institut de 
la formation en cours de carrière délivre une attestation de fréquentation de 
cette formation. 
 
Tous les deux ans, les services du gouvernement organisent au moins un 
volet culturel spécifique d''une durée de 30 heures qui consiste à : 
1° développer sa maitrise de l''accès et de l''utilisation du centre de 
ressources documentaires mis à disposition par les services du gouvernement; 
2° développer ses connaissances relatives aux ressources/services 
culturels et institutionnels mobilisables ou pouvant intervenir en soutien sur 
le plan local/interzonal. 
 
 
 
Docu 47237 
 
D. 28-03-2019  
Les services du gouvernement délivrent une attestation de fréquentation 
de cette formation. 
 
WBE ou la fédération de pouvoirs organisateurs concernée organise la 
formation initiale spécifique, d''une durée de 30 heures. Les objectifs et les 
contenus de cette formation initiale spécifique sont transmis pour information 
à l''Institut de la formation en cours de carrière et aux services du 
gouvernement au plus tard dans le mois qui précède le début de celle-ci. 
 
WBE ou la fédération de pouvoirs organisateurs concernée délivre une 
attestation de fréquentation de cette formation. 
 
Inséré par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '2', 'Article 10 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','inspection','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 20, 'Art. 10 § 2', '§ 2/2. Tous les deux ans, avant l''organisation de la formation initiale visée 
aux paragraphes 2 et 2/1, une concertation est organisée entre l''Institut de la 
formation en cours de carrière, les services du gouvernement, WBE et chaque 
fédération de pouvoirs organisateurs afin d''assurer la cohérence et la 
complémentarité des différentes parties de la formation initiale. 
 
Le gouvernement met fin d''office à la désignation des membres du 
personnel des Cellules de soutien et d''accompagnement désignés en 
application des articles 6,

§ 1er, alinéa 1er, qui n''ont pas suivi la formation 
initiale visée aux paragraphes 2 et 2/1 dans un délai de deux années suivant 
leur désignation.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '2', 'Article 10 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 21, 'Art. 10 § 3', '§ 3. Au-delà des deux premières années de leur fonction, les membres du 
personnel 
des 
Cellules 
de 
soutien 
et 
d''accompagnement 
suivent 
obligatoirement quatre jours de formation continue par an ou douze jours de 
formation continue répartis sur trois ans. Ils peuvent également suivre deux 
jours de formation continue facultative par an moyennant l''accord préalable 
du Conseiller coordonnateur de la Cellule de soutien et d''accompagnement 
concernée. 
 
Ces formations se déroulent durant le temps de travail des membres du 
personnel des Cellules de soutien et d''accompagnement. 
 
WBE et les fédérations de pouvoirs organisateurs veillent à la formation 
continue 
des 
membres 
du 
personnel 
des 
Cellules 
de 
soutien 
et 
d''accompagnement. 
 
Les formations dont bénéficient les Conseillers au soutien et à 
l''accompagnement visés à l''article 5, alinéa 1er, 1°, et les Conseillers au soutien 
et à l''accompagnement coordonnateurs visés à l''article 5, alinéa 1er, 2°, en vertu 
du Livre 6, Titre Ier, du Code de l''enseignement fondamental et de 
l''enseignement secondaire, doivent porter sur des matières en relation avec 
leurs missions. 
 
Les Conseillers au soutien et à l''accompagnement visés à l''article 5, 
alinéa 1er, 1°, et les Conseillers au soutien et à l''accompagnement 
coordonnateurs visés à l''article 5, alinéa 1er, 2°, non soumis aux décrets visés 
à l''alinéa 4 bénéficient des mêmes formations, organisées dans les mêmes 
conditions. 
Inséré par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '3', 'Article 10 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 22, 'Art. 10 § 3', '§ 3/1. Complémentairement à la formation continue visée au paragraphe 
3, les Référents culturels visés à l''article 5, alinéa 1er, 1°, suivent, chaque 
année, une formation continue organisée par les services du gouvernement. 
 
 
Docu 47237 
 
D. 28-03-2019  
Cette journée de rencontre rassemble les référents culturels et les 
représentants du monde culturel.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '3', 'Article 10 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 23, 'Art. 10 § 4', '§ 4. Sur demande motivée de WBE ou de la fédération de pouvoirs 
organisateurs concernée, le Gouvernement peut dispenser un membre du 
personnel d''une Cellule de soutien et d''accompagnement engagé en application 
de l''article 6,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '4', 'Article 10 § 4 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 24, 'Art. 10 § 1', '§ 1er, alinéa 1er 7°, de tout ou partie de la formation initiale visée 
au paragraphe 2 et/ou de la formation initiale visée aux paragraphes 2 et 2/1 
et/ou de la formation continue visée aux paragraphes 3 et 3/1. A défaut de 
réaction du Gouvernement dans un délai de deux mois, la dispense est réputée 
accordée.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '10', '1', 'Article 10 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 25, 'Art. 11', 'Article 11. - WBE et les fédérations de pouvoirs organisateurs 
transmettent chaque année aux Services du Gouvernement une liste 
actualisée des membres de leur Cellule de soutien et d''accompagnement. 
 
WBE et les fédérations de pouvoirs organisateurs transmettent aux 
Services du Gouvernement des données numériques conformément au décret 
du 25 avril 2019 relatif à la gouvernance numérique du système scolaire et à 
la transmission des données numériques statistiques dans l''enseignement 
obligatoire. 
 
Section III. - Les moyens financiers alloués à WBE et aux fédérations 
de pouvoirs organisateurs pour les Cellules de soutien et 
d''accompagnement 
 
Modifié par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '11', NULL, 'Article 11 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 26, 'Art. 12', 'Article 12. - WBE et les fédérations de pouvoirs organisateurs qui ont 
conclu le contrat visé à l''article 14 bénéficient d''une subvention annuelle 
destinée à couvrir les frais de personnel et de fonctionnement de leur Cellule 
de soutien et d''accompagnement visée à l''article 3. 
 
[Pour l''année scolaire 2025-2026, WBE ou chaque Fédération de Pouvoirs 
organisateurs peut décider d''utiliser une partie de sa dotation ou de sa 
subvention pour renforcer sa part du budget dédié à la formation 
professionnelle continue visé à l''article 6.1.8-1, §1er, alinéa 1er, 2°, du Code en 
l''affectant à l''organisation, pour le niveau réseau, de formations répondant à 
des besoins collectifs définie à l''article 6.1.3-8 du Code et de formations 
répondant à des besoins personnalisés définie à l''article 6.1.3-11 du Code. 
WBE ou la Fédération de Pouvoirs organisateurs communique aux Services du 
Gouvernement, selon les modalités fixées dans le contrat visé à l''article 14, le 
montant affecté au renforcement du budget dédié à la formation 
professionnelle continue, lequel ne peut pas excéder 10 pourcents de la 
subvention annuelle visée à l''alinéa 1er.]2 
 
Le montant total des subventions visées à l''alinéa 1er est de 16.933.915 
euros. Il est réparti entre WBE et chaque fédération de pouvoirs organisateurs, 
proportionnellement au nombre, exprimé en équivalents temps plein, de 
membres du personnel de l''équipe éducative qui prestent dans les écoles 
d''enseignement maternel, primaire, fondamental et secondaire de plein 
exercice et en alternance, ordinaire et spécialisé, qui relèvent de leur 
compétence respective. 
 
 
2Inséré par le D. 16-07-2025 
 
 
Docu 47237 
 
D. 28-03-2019  
Le montant visé [à l''alinéa 3]3 est indexé annuellement en le multipliant 
par l''estimation la plus récente du cout moyen d''un enseignant nommé 
disposant d''une ancienneté de dix années, divisé par le cout moyen pour 
l''année précédente d''un enseignant nommé disposant d''une ancienneté de dix 
années.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '12', NULL, 'Article 12 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 27, 'Art. 13 § 1', 'Article 13. - § 1er. Le Gouvernement détermine les modalités et les 
conditions d''octroi de la subvention visée à l''article 12, alinéa 1er. 
 
§ 2. Aux conditions et selon les modalités fixées par le Gouvernement, la 
subvention peut être réduite ou supprimée par le Gouvernement : 
1° en cas d''évaluation négative de la mise en oeuvre du contrat établi en 
application de l''article 16; 
2° si elle n''est pas utilisée aux fins pour lesquelles elle est accordée; 
3° si le rapport annuel visé à l''article 15 n''est pas communiqué; 
4° en cas de dysfonctionnement grave de la Cellule. 
 
En cas de réduction ou de suppression de la subvention, le Gouvernement 
peut adapter en conséquence le nombre de Conseillers au soutien et à 
l''accompagnement disposant d''un titre pédagogique que doit comprendre la 
Cellule de soutien et d''accompagnement concernée en application de l''article 
5, dernier alinéa. 
 
En outre, selon les modalités fixées par le Gouvernement, lorsqu''un ou 
plusieurs membres du personnel d''une Cellule engagés en application de 
l''article 6, § 1er, alinéa 1er, 7°, n''ont pas suivi la formation initiale visée à 
l''article 10 dans un délai de deux années suivant leur engagement, le 
Gouvernement peut réduire la subvention visée à l''article 12 à concurrence de 
maximum 5% jusqu''à ce que WBE ou la fédération de pouvoirs organisateurs 
démontre que le ou les Conseillers concernés ont effectivement suivi la 
formation initiale. 
 
Modifié par D. 25-03-2021 ; complété par D. 17-06-2021 ; modifié par D. 
17-06-2022', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '13', '1', 'Article 13 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 28, 'Art. 14 § 1', '§ 1er. WBE et les fédérations de pouvoirs organisateurs 
concluent avec le Gouvernement un contrat dont le modèle est arrêté par le 
Gouvernement, relatif aux services à prester et aux ressources à mobiliser par 
WBE et les fédérations de pouvoirs organisateurs aux fins d''assumer les 
missions de coordination, de soutien et d''accompagnement suivantes qui leur 
incombent : 
1° les missions de leurs Cellules de soutien et d''accompagnement visées 
à l''article 3, telles qu''énoncées à l''article 4; 
2° la désignation d''un manager de crise à la demande du Gouvernement, 
si WBE ou la fédération de pouvoirs organisateurs y est habilité par le pouvoir 
organisateur concerné, conformément à l''article 1.5.2-12,

§ 1er, ou à l''article 
1.5.2-21,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '14', '1', 'Article 14 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 29, 'Art. 14 § 1', '§ 1er du Code; 
3° faciliter la communication entre les pouvoirs organisateurs et les 
Services du Gouvernement, notamment avec les directeurs de zone et les 
délégués au contrat d''objectifs; 
4° assurer la formation des pouvoirs organisateurs, ou s''assurer de celle-
ci, 
et 
assurer 
leur 
accompagnement 
concernant 
le 
processus 
de 
contractualisation visé aux articles 1.5.2-1 à 1.5.2-22 du Code; 
 
3Remplacé par le D. 16-07-2025 
 
 
Docu 47237 
 
D. 28-03-2019  
5° assurer la formation des pouvoirs organisateurs, ou s''assurer de celle-
ci, et assurer leur accompagnement concernant la sélection et l''évaluation des 
directeurs; 
6° assurer la formation initiale et continue des directeurs conformément 
aux décrets en vigueur; 
7° assurer la formation professionnelle continue des membres du 
personnel conformément au Livre 6, Titre Ier, du Code de l''enseignement 
fondamental et secondaire; [remplacé par D. 17-06-2022] 
8° assurer le soutien rapproché et l''accompagnement collectif ou 
individualisé des équipes pédagogiques; 
9° assurer l''accompagnement des écoles dans le déploiement d''une 
approche intégrée du numérique; 
10° favoriser la collaboration entre les pouvoirs organisateurs, 
encourager la bonne utilisation et la mutualisation des ressources et moyens 
mis à leur disposition et les accompagner dans la conception et la réalisation 
de leur projet d''investissement; 
11° prendre en charge des missions spécifiques et supplémentaires de 
coordination, de soutien et d''accompagnement fixées dans le cadre du contrat 
visé au présent paragraphe ; 
12° assurer l''accompagnement des écoles dans le déploiement d''une 
approche pluridisciplinaire du PECA ; [Inséré par D. 25-03-2021] 
13° faciliter la création des pôles territoriaux visés au Livre 6, Titre 3, du 
Code, en étant notamment des facilitateurs pour une répartition géographique 
optimale des pôles et des écoles coopérantes, y compris, le cas échéant, dans 
une dynamique inter-réseaux ; [Inséré par D. 17-06-2021] 
14° conseiller et accompagner le coordonnateur et les membres de l''équipe 
pluridisciplinaire des pôles territoriaux, entre autres concernant la 
mutualisation des ressources. [Inséré par D. 17-06-2021] 
[15° conseiller et accompagner les écoles fortement touchées par le phénomène de l''absentéisme 
scolaire.]4

§ 2. Le contrat visé au paragraphe 1er, alinéa 1er, est renouvelé tous les 
six ans après que le Gouvernement a exécuté les articles 6,

§ 3, alinéa 2, et 
8,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '14', '1', 'Article 14 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['discipline','évaluation','obligation scolaire','parents','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 30, 'Art. 14 § 3', '§ 3, alinéa 2. 
 
Il comprend au moins les éléments suivants : 
1° la date de sa conclusion et de sa prise de cours, laquelle peut rétroagir; 
2° la description des missions et objectifs assignés pour la période 
couverte par le contrat; 
3° les moyens mis à disposition et les modalités d''octroi; 
4° les modalités et le calendrier de suivi et d''évaluation; 
5° les données communiquées aux Services du Gouvernement ainsi que 
les modalités de forme et de délais liés à cette communication; 
6° les conditions et les modalités de modification du contrat. 
 
Par «la description des missions et objectifs pour la période couverte par 
le contrat», on entend : 
1° la reproduction des missions de coordination, de soutien et 
d''accompagnement visées au paragraphe 1er; 
2° les objectifs transversaux et thématiques assignés à WBE ou à la 
fédération de pouvoirs organisateurs s''agissant de l''exécution des missions 
visées au 1° ; 
 
4Inséré par le D. 16-05-2024 et entrera en vigueur le 25-08-2025 
 
 
Docu 47237 
 
D. 28-03-2019  
3° les actions particulières que WBE ou la fédération de pouvoirs 
organisateurs mènent en vue d''atteindre les objectifs visés au 2°. 
 
Par «les moyens mis à disposition et les modalités d''octroi», on entend : 
1° le nombre de Conseillers au soutien et à l''accompagnement dont WBE 
ou la fédération de pouvoirs organisateurs pourra disposer, durant la période 
contractuelle, pour sa Cellule de soutien et d''accompagnement en exécution 
des articles 6,

§ 3, et 8,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '14', '3', 'Article 14 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 31, 'Art. 14 § 3', '§ 3, ainsi que le nombre de Conseillers au soutien et à 
l''accompagnement coordonnateurs visés à l''article 5, alinéa 1er, 2° ; 
2° le nombre de Conseillers techno-pédagogiques visés à l''article 5, alinéa 
1er, 1°, que WBE ou la fédération de pouvoirs organisateurs projette d''employer 
au sein de sa Cellule de soutien et d''accompagnement, ce nombre devant être 
suffisant pour la réalisation de la mission qui incombe à ces Conseillers en 
application de l''article 4, alinéa 1er, 7° ; 
2°/1 le nombre de Référents culturels visés à l''article 5, alinéa 1er, 1°, que 
WBE ou la fédération de pouvoirs organisateurs projette d''employer au sein de 
sa Cellule de soutien et d''accompagnement, ce nombre devant être suffisant 
pour la réalisation de la mission qui incombe à ces Référents culturels en 
application de l''article 5, alinéa 3. [Inséré par D. 25-03-2021] 
3° le montant annuel à indexer de la subvention dont WBE ou la 
fédération de pouvoirs organisateurs pourra bénéficier pour sa Cellule de 
soutien et d''accompagnement, étant entendu que le montant de la subvention 
pour la première et la dernière année civile du contrat pourra être fixé au 
prorata de la période couverte par le contrat; 
4° le nombre total de membres de personnel que WBE ou la fédération de 
pouvoirs organisateurs projette d''employer dans sa Cellule de soutien et 
d''accompagnement, les profils des fonctions et les modalités d''engagement 
projetés; 
5° une estimation annuelle des frais de fonctionnement de la Cellule de 
soutien et d''accompagnement; 
6° le cas échéant, la mention de la ou des fédérations de pouvoirs 
organisateurs avec laquelle/lesquelles WBE ou la fédération de pouvoirs 
organisateurs projette de conclure la convention visée à l''article 8,', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '14', '3', 'Article 14 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 32, 'Art. 14 § 3', '§ 3, alinéa 
3; 
7° un rappel des conditions et modalités de liquidation de la subvention 
telles qu''elles figurent à l''article 13; 
8° tout autre élément que les parties voudraient faire figurer dans le 
contrat à ce titre. 
 
Par «les modalités et le calendrier de suivi et d''évaluation», on entend : 
1° la reproduction de la procédure d''évaluation de la mise en oeuvre du 
contrat visée à l''article 16; 
2° la fixation de la date à laquelle les rapports de suivi annuels doivent 
être adressés au Gouvernement; 
3° la fixation des indicateurs de suivi de la mise en oeuvre du contrat par 
référence aux points 2° et 3°, de l''alinéa 2; 
4° tout autre élément que les parties voudraient faire figurer dans le 
contrat à ce titre. 
 
Par «les conditions et les modalités de modification du contrat», on entend 
les conditions et les modalités selon lesquelles les parties conviennent de 
modifier : 
1° les objectifs transversaux et thématiques visés à l''alinéa 3, 2° ; 
2° les actions particulières visées à l''alinéa 3, 3° ; 
3° le nombre total de membres de personnel visé à l''alinéa 4, 4° ; 
4° l''estimation des frais de fonctionnement visée à l''alinéa 4, 5° ; 
 
 
Docu 47237 
 
D. 28-03-2019  
5° toute modification de la ou des conventions visées à l''alinéa 4, 6° ; 
6° la date visée à l''alinéa 5, 2° ; 
7° les indicateurs de suivi visés à l''alinéa 5, 3° ; 
8° tout autre élément que les parties conviendraient de modifier. 
 
Les parties peuvent convenir de faire figurer d''autres dispositions dans 
le contrat visé au paragraphe 1er. Le Gouvernement ne peut imposer à WBE 
ou aux fédérations de pouvoirs organisateurs d''autres missions que celles 
visées au paragraphe 1er. WBE ou une fédération de pouvoirs organisateurs 
peut toutefois accepter de se voir confier d''autres missions dans le contrat visé 
au paragraphe 1er, sans augmentation du montant de la subvention visée à 
l''article 12.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '14', '3', 'Article 14 § 3 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 33, 'Art. 15 § 1', 'Article 15. - § 1er. Un rapport annuel relatif à la mise en oeuvre du 
contrat visé à l''article 14 est établi par WBE et les fédérations de pouvoirs 
organisateurs et communiqué au Gouvernement à la date fixée dans le contrat, 
laquelle est antérieure au 1er octobre. 
 
Le rapport visé à l''alinéa 1er contient un bilan, une description des 
moyens utilisés et des actions réalisées durant l''année d''exécution du contrat 
écoulée, ainsi qu''une analyse qualitative et quantitative de la réalisation des 
missions et objectifs visés à l''article 14, § 2, alinéa 2. 
 
Le rapport visé à l''alinéa 1er est accompagné des pièces justificatives de 
l''utilisation de la subvention pour l''année d''exécution du contrat écoulée. 
 
§ 2. Le Gouvernement fixe le modèle du rapport visé au paragraphe 1er.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '15', '1', 'Article 15 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 34, 'Art. 16', 'Article 16. - Sur la base des rapports visés à l''article 15, le 
Gouvernement procède à l''évaluation du contrat visé à l''article 14, à son 
échéance. 
 
Le Gouvernement peut également procéder à une évaluation 
intermédiaire du contrat visé à l''article 14 au terme de ses trois premières 
années d''exécution. 
 
CHAPITRE III. - Dispositions modificatives', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '16', NULL, 'Article 16 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 35, 'Art. 17 § 2', 'Article 17. - Dans l''article 5bis de la loi du 29 mai 1959 modifiant 
certaines dispositions de la législation de l''enseignement, les paragraphes 2 à 
4 sont remplacés par ce qui suit : 
 
«§ 2. Pour qu''un organe obtienne la reconnaissance du Gouvernement : 
1° il doit y avoir cohérence entre les projets éducatif et pédagogique d''un 
pouvoir organisateur qui adhère à cet organe et le projet éducatif et les axes 
majeurs du projet pédagogique de cet organe; 
2° l''organe : 
a) prévoit dans ses statuts que l''assemblée générale est constituée : 
- pour au moins 80 % de pouvoirs organisateurs affiliés ou de 
représentants élus en leur sein par plusieurs pouvoirs organisateurs; 
- pour un maximum de 20 % de membres cooptés par les premiers; 
b) prévoit dans ses statuts que ladite assemblée générale prend les 
décisions relatives aux modifications desdits statuts, à la définition du 
montant de la cotisation éventuelle prévue conformément à l''article 
 
 
Docu 47237 
 
D. 28-03-2019  
5quinquies et à la désignation du conseil d''administration, celui-ci étant 
désigné pour une durée maximale de six ans renouvelables; 
c) assure la publicité des informations destinées à ses membres ainsi 
que des règles d''adhésion à l''organe et d''accès aux activités, programmes et 
services offerts par celui-ci; 
d) transmet au Gouvernement, lors de sa demande de reconnaissance, 
une copie des résolutions d''adhésion des pouvoirs organisateurs affiliés, les 
noms et prénoms des membres des différentes instances le composant ainsi 
qu''une copie de ses statuts et règlements et, par la suite, dès qu''elle est 
adoptée, toute modification relative à ces divers éléments; 
3° le conseil d''administration de l''organe : 
a) est composé d''une majorité de membres choisis parmi ceux définis au 
2°, a), premier tiret; 
b) désigne, pour une durée maximale de six ans renouvelables, les 
personnes habilitées à signer, en son nom, les protocoles concluant les 
concertations visées à l''article 5. 
 
§ 3. La reconnaissance accordée vaut pour une durée indéterminée. 
 
§ 4. Le Gouvernement retire la reconnaissance aux organes de 
représentation et de coordination de pouvoirs organisateurs qui cessent de 
répondre aux conditions fixées aux paragraphes 1er et 2. 
 
Le Gouvernement arrête la procédure de reconnaissance, de refus de 
reconnaissance et de retrait de reconnaissance. 
 
La procédure visée à l''alinéa 2 prévoit au moins : 
1° que l''organe introduit une demande de reconnaissance auprès du 
Gouvernement au plus tard le 15 novembre de l''année qui précède la première 
année de l''entrée en application de cette reconnaissance; 
2° les modalités d''introduction de la demande de reconnaissance; 
3° la possibilité pour l''organe d''introduire un recours contre une décision 
de refus ou de retrait de reconnaissance ainsi que ses formes et délais; 
4° la possibilité pour l''organe d''être entendu lors d''un recours; 
5° les délais endéans lesquels doivent être prises les décisions d''octroi, de 
refus ou de retrait en matière de reconnaissance.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '17', '2', 'Article 17 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['recours','évaluation','personnel','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 36, 'Art. 18 § 1', 'Article 18. - Dans la même loi, l''article 5ter est remplacé par ce qui suit : 
«Article 5ter. § 1er. Chaque organe de représentation et de coordination 
visé à l''article 5bis est chargé d''une mission générale de représentation, de 
coordination, de soutien et d''accompagnement des pouvoirs organisateurs qu''il 
affilie ou avec lesquels il a conclu une convention, et ce, selon les termes fixés 
dans cette convention. 
 
Dans ce cadre, chaque organe de représentation et de coordination visé à 
l''article 5bis conclut avec le Gouvernement le contrat visé à l''article 14 du 
décret du 28 mars 2019 relatif aux cellules de soutien et d''accompagnement de 
l''enseignement organisé ou subventionné par la Communauté française et au 
statut des Conseillers au soutien et à l''accompagnement, et bénéficie de la 
subvention visée à l''article 12, alinéa 1er, du même décret, aux conditions et 
selon les modalités qu''il fixe.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '18', '1', 'Article 18 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 37, 'Art. 19', 'Article 19. - Dans la même loi, il est inséré un article 5quater rédigé 
comme suit : 
«Article 5quater. WBE est chargé d''une mission générale de 
représentation, de coordination, de soutien et d''accompagnement des écoles 
 
 
Docu 47237 
 
D. 28-03-2019  
qu''il organise et celles avec lesquelles il a conclu une convention en application 
de l''article 24, § 2, alinéa 2, 8°, et ce, selon les termes fixés dans cette 
convention. 
 
Dans ce cadre, WBE conclut avec le Gouvernement le contrat visé à 
l''article 14 du décret du 28 mars 2019 relatif aux cellules de soutien et 
d''accompagnement de l''enseignement organisé ou subventionné par la 
Communauté française et au statut des Conseillers au soutien et à 
l''accompagnement, et bénéficie de la subvention visée à l''article 12, alinéa 1er, 
du même décret, aux conditions et selon les modalités qu''il fixe.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '19', NULL, 'Article 19 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 38, 'Art. 20', 'Article 20. - Dans la même loi, il est inséré un article 5quinquies rédigé 
comme suit : 
«Article 5quinquies. Chaque pouvoir organisateur peut prélever sur les 
dotations ou subventions de fonctionnement des établissements qu''il organise 
le montant de la cotisation qu''il verse à un des organes de représentation et de 
coordination.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '20', NULL, 'Article 20 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 39, 'Art. 21', 'Article 21. - Dans l''article 8 de la loi du 29 mai 1959 modifiant certaines 
dispositions de la législation de l''enseignement, il est inséré un alinéa 4, rédigé 
comme suit : 
 
«Sur la proposition de l''autorité d''un culte ou de la morale non 
confessionnelle, et après avoir reçu l''avis de la Commission de pilotage créée 
par le décret du 27 mars 2002 relatif au pilotage du système éducatif de la 
Communauté française, le Gouvernement labélise les référentiels des cours de 
religion ou de morale non confessionnelle et les soumet à la confirmation du 
Parlement. En cas d''absence ou de vacance d''autorité d''un culte ou de la morale 
non confessionnelle, pour autant qu''elle soit démontrée, le Parlement désigne 
les membres d''un groupe technique chargé d''établir les référentiels du cours 
de religion ou de morale non confessionnelle concerné. Après s''être assuré de 
leur conformité aux référentiels labélisés du cours de religion ou de morale non 
confessionnelle concerné, le Gouvernement approuve les programmes des 
cours de religion ou de morale non confessionnelle conformément à tous les 
autres programmes de cours.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '21', NULL, 'Article 21 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 40, 'Art. 22 § 2', 'Article 22. - Dans l''article 24, § 2, alinéa 2, de la même loi, le 8° est 
remplacé par ce qui suit : 
«8° bénéficier, si l''école n''est pas affiliée à un organe de représentation et 
de coordination des pouvoirs organisateurs visé à l''article 5bis, de services de 
soutien et d''accompagnement externes, en vertu d''une convention passée au 
plus tard quatre mois après la création de l''établissement ou de la section 
d''établissement avec une des Cellules de soutien et d''accompagnement visées 
par le décret du 28 mars 2019 précité. Seule la Cellule de soutien et 
d''accompagnement de Wallonie-Bruxelles Enseignement ne peut pas refuser 
de signer la convention précitée.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '22', '2', 'Article 22 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 41, 'Art. 23', 'Article 23. - Dans l''article 15 de l''arrêté royal du 15 janvier 1974 pris en 
application de l''article 160 de l''arrêté royal du 22 mars 1969 fixant le statut 
des membres du personnel directeur et enseignant, du personnel auxiliaire 
d''éducation, du personnel paramédical des établissements d''enseignement 
gardien, primaire, spécialisé, moyen, technique, artistique et normal de l''Etat, 
des internats dépendant de ces établissements et des membres du personnel 
du service d''inspection chargé de la surveillance de ces établissements, les 
mots «du Titre III du décret du 8 mars 2007 relatif au Service général de 
l''Inspection, au Service de soutien et d''accompagnement pédagogiques de 
 
 
Docu 47237 
 
D. 28-03-2019  
l''enseignement organisé par la Communauté française, aux Cellules de soutien 
et d''accompagnement pédagogiques de l''enseignement subventionné par la 
Communauté française et aux statuts des membres du personnel du Service 
général» sont remplacés par les mots «du Chapitre III du décret du 28 mars 
