INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 42, 'Art. 24 § 1', 'Article 24. - Dans l''article 21, § 1er, alinéa 2, du décret du 29 juillet 1992 
