INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 43, 'Art. 25', 'Article 25. - Dans l''article 12 du décret du 14 mars 1995 relatif à la 
