INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 44, 'Art. 26', 'Article 26. - Dans l''article 5 du décret du 24 juin 1996 portant 
