INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 45, 'Art. 27', 'Article 27. - Dans l''article 6 du même décret, les modifications suivantes 
