INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 46, 'Art. 28', 'Article 28. - Dans l''article 6bis du même décret, tel qu''il a été inséré par 
