INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 47, 'Art. 29', 'Article 29. - Dans l''article 5 du décret du 24 juillet 1997 définissant les 
