INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 48, 'Art. 30 § 2', 'Article 30. - Dans les articles 35, § 2, alinéa 4, et 39bis, § 2, alinéa 2, du 
