INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 49, 'Art. 31', 'Article 31. - Dans l''article 67 du même décret, tel que remplacé par le 
