INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 50, 'Art. 32', 'Article 32. - Dans l''article 68 du même décret, tel que remplacé par le 
