INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 60, 'Art. 39 § 2', '§ 2. En ce qui concerne la transmission des résultats des élèves des 
établissements scolaires considérés un par un, la transmission à la Cellule de 
soutien et d''accompagnement de l''enseignement organisé par la Communauté 
française ou à la Cellule de soutien et d''accompagnement de l''enseignement 
subventionné par la Communauté française concernée, selon le cas, ne 
concerne que les établissements relevant, soit de l''enseignement organisé par 
la Communauté française, soit d''un pouvoir organisateur affilié à un organe 
de représentation et de coordination. Dans ce dernier cas, la transmission est 
subordonnée à l''accord donné par le pouvoir organisateur. Le Gouvernement 
définit les modalités selon lesquelles le pouvoir organisateur fait part de cet 
accord.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '39', '2', 'Article 39 § 2 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 61, 'Art. 40 § 1', 'Article 40. - Dans l''article 7bis, § 1er, du décret du 30 juin 2006 relatif à 
l''organisation pédagogique du 1er degré de l''enseignement secondaire, le 
dernier alinéa est remplacé par ce qui suit : 
«A titre informatif, les Services du Gouvernement mettent un répertoire 
de pratiques en matière de PIA et d''outils de gestion des PIA qui se sont avérés 
efficaces dans diverses écoles à la disposition des équipes éducatives ainsi que 
des Cellules de soutien et d''accompagnement visées par le décret du 28 mars 
2019 relatif aux Cellules de soutien et d''accompagnement de l''enseignement 
organisé ou subventionné par la Communauté française et au statut des 
Conseillers au soutien et à l''accompagnement.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '40', '1', 'Article 40 § 1 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 62, 'Art. 41', 'Article 41. - L''article 25 du décret du 2 février 2007 fixant le statut des 
directeurs est complété par un alinéa rédigé comme suit : 
«Le pouvoir organisateur de l''enseignement organisé par la Communauté 
française, chaque fédération de pouvoirs organisateurs qui serait tenu d''établir 
un rapport de suivi en application de de l''article 15 du décret du 28 mars 2019 
 
 
Docu 47237 
 
D. 28-03-2019  
relatif aux Cellules de soutien et d''accompagnement de l''enseignement 
organisé ou subventionné par la Communauté française et au statut des 
Conseillers au soutien et à l''accompagnement est dispensé, dans ce cas, 
d''établir et de transmettre le rapport d''évaluation visé à l''alinéa 1er.».', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '41', NULL, 'Article 41 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 63, 'Art. 42 § 8', 'Article 42. - Dans l''article 3, § 8, alinéa 2, c), du décret du 12 juillet 2012 
organisant la certification par unités d''acquis d''apprentissage (CPU) dans 
l''enseignement secondaire qualifiant et modifiant diverses dispositions 
relatives à l''enseignement secondaire, les mots «conseillers pédagogiques» sont 
remplacés par les mots «Conseillers au soutien et à l''accompagnement». 
 
CHAPITRE IV. - Dispositions abrogatoires', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '42', '8', 'Article 42 § 8 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 64, 'Art. 43', 'Article 43. - Dans le décret du 8 mars 2007 relatif au Service général de 
l''Inspection, au Service de conseil et de soutien pédagogiques de 
l''enseignement organisé par la Communauté française, aux Cellules de conseil 
et de soutien pédagogiques de l''enseignement subventionné par la 
Communauté française et aux statuts des membres du personnel du Service 
général de l''Inspection et des Conseillers pédagogiques, sont abrogés : 
1° l''article 4; 
2° dans le Titre Ier, les Chapitres III, VI et V comportant les articles 17 
à 25; 
3° le Titre III comportant les articles 149 à 156. 
 
 
CHAPITRE V. - Dispositions transitoires', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '43', NULL, 'Article 43 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 65, 'Art. 44', 'Article 44. - Les membres du personnel qui, à la veille de l''entrée en 
vigueur du présent décret, sont désignés en qualité de conseiller pédagogique 
en vertu du décret du 8 mars 2007 relatif au service général de l''inspection, au 
service de conseil et de soutien pédagogiques de l''enseignement organisé par 
la Communauté française, aux Cellules de conseil et de soutien pédagogiques 
de l''enseignement subventionné par la Communauté française et au statut des 
membres du personnel du service général de l''inspection et des conseillers 
pédagogiques conservent le bénéfice de leur désignation selon les mêmes 
conditions, avec la qualité de Conseillers au soutien et à l''accompagnement. 
 
Les Conseillers visés à l''alinéa 1er qui ont été désignés après le 1er 
septembre 2017 sont tenus de suivre la formation initiale visée à l''article 10 
dans un délai de trois années à dater de l''entrée en vigueur du présent décret.', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '44', NULL, 'Article 44 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['personnel','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 66, 'Art. 45', 'Article 45. - Sont réputés reconnus conformément au présent décret, à 
la date de l''entrée en vigueur fixée par l''article 50, les organes de 
représentation et de coordination de pouvoirs organisateurs reconnus 
conformément aux règles applicables avant son entrée en vigueur. 
 
[Article 45/1. - Par dérogation à l''article 14, §2, alinéa 1er, un nouveau 
contrat d''une durée d''un an est conclu respectivement par WBE et les 
fédérations de pouvoirs organisateurs avec le Gouvernement. Ce contrat 
couvre l''année scolaire 2025-2026. 
 
Par dérogation à l''article 14, §2, alinéa 3, pour le contrat couvrant l''année 
scolaire 2025-2026, par « la description des missions et objectifs pour la période 
couverte par le contrat », on entend : 
 
 
 
Docu 47237 
 
D. 28-03-2019  
1° la reproduction des missions de coordination, de soutien et 
d''accompagnement visées à l''article 14, §1er ; 
 
2° les objectifs assignés à WBE ou à la fédération de pouvoirs 
organisateurs s''agissant de l''exécution des missions visées au 1° ; 
 
3° les actions particulières que WBE ou la fédération de pouvoirs 
organisateurs mènent en vue d''atteindre les objectifs visés au 2°. 
 
Les moyens mis à disposition et les modalités d''octroi visé à l''article 14, 
§2, alinéa 4, octroyés dans le cadre du contrat visé à l''alinéa 1er couvrent 
uniquement l''année 2025-2026. 
 
Par dérogation aux articles 15 et 16, le Gouvernement procède à 
l''évaluation du contrat applicable durant l''année scolaire 2025-2026 à son 
échéance selon les éléments d''évaluation qu''il fixe dans le modèle de contrat.]5 
 
Remplacé par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '45', NULL, 'Article 45 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', ARRAY['évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 67, 'Art. 46', 'Article 46. - Par dérogation à l''article 12, alinéas 2 et 3, le montant total 
des subventions visées à l''article 12, alinéa 1er, est fixé de la manière suivante 
pour les années 2021 à 2027 : 
1° pour l''année 2021 : 12.780.259 euros ; 
2° pour l''année 2022 : 14.243.512 euros ; 
3° pour l''année 2023 : 14.663.712 euros ; 
4° pour l''année 2024 : 15.209.240 euros ; 
5° pour l''année 2025 : 15.747.535 euros ; 
6° pour l''année 2026 : 16.379.706 euros ; 
7° pour l''année 2027 : 16.933.915 euros. 
 
Modifié par D. 25-03-2021', 'Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement', 'Décret CSA', '46', NULL, 'Article 46 du Décret du 28 mars 2019 — Cellule de soutien et d''accompagnement (CDA 47237)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('47237', 68, 'Art. 47', 'Article 47. - Par dérogation à l''article 5, alinéa 6, pour la première 
