-- CDA 9547: Loi du 29 juin 1983 — Obligation scolaire (10 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 0, 'Art. 1er § 1', 'Article 1er. - § 1er. Le mineur est soumis à l''obligation scolaire 
pendant une période de treize années commençant avec l''année scolaire qui 
prend cours dans l''année où il atteint l''âge de cinq ans et se terminant à la 
fin de l''année scolaire, dans l''année au cours de laquelle il atteint l''âge de 
dix-huit ans. 
 
L''obligation scolaire est à temps plein jusqu''à l''âge de quinze ans et 
comporte au maximum sept années d''enseignement primaire et au moins les 
deux premières années de l''enseignement secondaire de plein exercice;  en 
aucun cas l''obligation scolaire à temps plein ne se prolonge au-delà de seize 
ans. Durant l''année scolaire 2022-2023, la possibilité de faire suivre une 
année complémentaire à un élève de 1e ou de 2e année de l''enseignement 
primaire est conditionnée par l''obtention préalable d''un accord écrit des 
parents, tels que définis à l''article 1.3.1-1, 45°, du Code de l''enseignement 
fondamental et de l''enseignement secondaire. Le pouvoir organisateur tient 
cet accord écrit à la disposition des services du Gouvernement. 
 
§ 2. […] Abrogé par D. 03-05-2019 (code). 
 
§ 3. Le mineur qui a terminé avec fruit l''enseignement secondaire de 
plein exercice n''est plus soumis à l''obligation scolaire. 
 
§ 4. […] Abrogé par D. 03-05-2019 (code). 
 
Complété par D. 11-04-2014 ;  D. 14-07-2015 ; modifié par D. 14-06-2018 
§ 4bis. Le ministre peut, selon les modalités que fixe le Gouvernement, 
autoriser un mineur : 
1° […] Abrogé par D. 03-05-2019 (code). 
2° à fréquenter l''enseignement primaire pendant huit années, auquel 
cas, il peut au cours de la huitième année être admis en sixième année; 
3° à fréquenter l''enseignement primaire pendant neuf années, dans des 
cas spécifiques, liés à une maladie de longue durée ; 
4° […] Abrogé par D. 03-05-2019 (code). 
 
§ 5, 6 et 7 […] Abrogés par D. 03-05-2019 (code). 
Fondamental 
 
III.A.02 
Lois 09547 
 
L. 29-06-1983 
mis à jour au 27-05-2022 
 
Modifié par D. 27-12-1993 ; D.13-01-2011 
Articles 2 à 6. - […] Abrogés par D. 03-05-2019 (code). 
 
Modifié par D. 07-12-2007', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '1er', '1', 'Article 1er § 1 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['inscription','redoublement','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 1, 'Art. 7', 'Article 7. - Le Roi détermine les certificats d''études et leur éventuelle 
équivalence avec d''autres diplômes ou certificats, délivrés après: 
- les deuxième et troisième degrés et les cycles inférieur et supérieur de 
l''enseignement secondaire professionnel;  
- certaines formes d''enseignement à horaire réduit.

Article 8. - […].abrogé par A.R. n° 413 du 29-04-1986', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '7', NULL, 'Article 7 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 2, 'Art. 9', 'Article 9. - L''article 14 de la loi du 6 juillet 1970 relative à 
l''enseignement spécialisé est remplacé par le texte suivant : 
"Article 14. - Les manuels scolaires et les fournitures scolaires sont 
distribués gratuitement dans l''enseignement spécial. 
L''Etat prend en charge le coût financier résultant de la gratuité des 
manuels scolaires et des fournitures scolaires pour les élèves de 
l''enseignement spécialisé subventionné. 
Le Roi fixe chaque année et forfaitairement le montant de l''intervention 
de l''Etat en tenant compte du niveau d''enseignement et de l''évolution du coût 
de la vie. 
Les sommes sont versées sur base des relevés certifiés sincères et 
véritables par le membre compétent du service de vérification."', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '9', NULL, 'Article 9 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['ROI','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 3, 'Art. 10 § 1', 'Article 10. - § 1er. L''article 6 de la loi du 16 mars 1971 sur le travail 
est remplacé par la disposition suivante : 
"Article 6. - Il est interdit de faire travailler des mineurs encore soumis 
à l''obligation scolaire à temps plein, ou de leur faire exercer un travail 
sortant du cadre de leur éducation ou de leur formation." 
 
§ 2. Le titre VI : "Le contrat d''occupation d''étudiants" de la loi du 3 
juillet 1978 relative aux contrats de travail est complété par un article 130bis 
libellé comme suit : 
"Article 130 bis. - Le Roi détermine les conditions et les modalités selon 
lesquelles des mineurs de quinze ans et plus peuvent conclure des contrats 
d''occupation d''étudiants."', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '10', '1', 'Article 10 § 1 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 4, 'Art. 11', 'Article 11. - L''article 6 de la loi du 24 février 1978 relative au contrat 
de travail du sportif rémunéré est remplacé par la disposition suivante : 
"Article 6. - Le contrat de travail du sportif rémunéré ne peut être 
conclu valablement, et au plus tôt, que lorsque le sportif a accompli 
entièrement sa scolarité obligatoire à temps plein". 
Après avis de la Commission paritaire nationale des Sports, le Roi peut, 
pour la pratique de certaines disciplines sportives, fixer une limite d''âge 
supérieure à celle qui marque la fin de la scolarité obligatoire à temps plein."', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '11', NULL, 'Article 11 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['discipline','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 5, 'Art. 12', 'Article 12. - L''article 19, premier alinéa 2°, de la loi du 5 juin 1928  
portant réglementation du contrat d''engagement maritime, est modifié 
comme suit : 
"2° l''âge auquel il a satisfait à l''obligation scolaire à temps plein pour 
tout autre service à bord." 
 
Fondamental 
 
III.A.02 
Lois 09547 
 
L. 29-06-1983 
mis à jour au 27-05-2022', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '12', NULL, 'Article 12 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 6, 'Art. 13 § 1', 'Article 13. - § 1er. L''article 2, premier alinéa, de la loi du 23 septembre 
1931 sur le recrutement du personnel de la pêche maritime est remplacé par 
la disposition suivante:  
"Pour l''application de la présente loi, on entend par apprenti-mousse les 
mineurs qui ont satisfait à l''obligation scolaire à temps plein et qui ont dix-
huit ans au maximum." 
 
§ 2. L''article 2, troisième alinéa, de la même loi est remplacé par la 
disposition suivante : 
"A défaut d''adolescents remplissant les conditions fixées à l''alinéa 
précédent, l''enrôlement devra se faire parmi les mineurs qui satisfont aux 
conditions d''âge fixées au premier alinéa de cet article."', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '13', '1', 'Article 13 § 1 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 7, 'Art. 14 § 1', 'Article 14. - § 1er Dans l''arrêté royal n°49 du 2 juillet 1982 relatif aux 
normes de création, de maintien et de dédoublement et au calcul de crédit 
d''heures de l''enseignement secondaire de type I, concernant la fusion 
d''établissements, ainsi que certains emplois du personnel des établissements 
d''enseignement secondaire de plein exercice de type I et II, les articles 4, § 1, 
a, premier, deuxième et troisième titres, et 10, 1, a, premier et deuxième 
tirets, sont complétés par les mots : "sauf pour une première création dans un 
centre d''enseignement". 
 
§ 2. Dans le même arrêté royal un article 24bis est inséré libellé comme 
suit : 
"Article 24 bis. - Les établissements d''enseignement secondaire peuvent 
utiliser librement après consultation du personnel enseignant, le nombre 
d''heures/professeurs résultant de l''application du présent arrêté aux élèves 
de la première année B et de l''enseignement secondaire professionnel pour 
l''ensemble de ces années d''études. A cette fin ils sont tenus de prouver : 
- qu''ils désignent par classe ou par groupe d''élèves du premier degré 
cinq professeurs au maximum pour l''ensemble des cours généraux, des cours 
techniques et de pratique professionnelle; 
- qu''ils adaptent l''horaire afin de permettre une intégration maximale 
des différents cours théoriques et pratiques. 
Dans ce cas, deux périodes hebdomadaires par classe doivent être 
réservées au recyclage des professeurs, dont une heure au maximum par 
professeur, dans l''année d''études où, pour la première fois, le nombre 
d''heures/professeurs est utilisé librement. En outre, à partir de l''année 
scolaire où le nombre d''heures/professeurs est utilisé librement dans un 
degré, deux périodes hebdomadaires par degré sont consacrées à la guidance 
pédagogique interne." 
 
CHAPITRE III - Dispositions abrogatoires 
 
Modifié par D. 27-12-1993', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '14', '1', 'Article 14 § 1 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['redoublement','ROI','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 8, 'Art. 15 § 1', 'Article 15. - § 1er. Les articles 1, 3 à 6, 11 et 69, § 1er, des lois sur 
l''enseignement primaire, coordonnées le 20 août 1957 et l''article 36, 5°, de la 
loi du 8 avril 1965 sur la protection de la jeunesse, sont abrogés. 
 
§ 2. Dans le cadre de l''application de l''article 3, § 2, le Gouvernement 
détermine lesquelles des dispositions des articles 8, 9 et 12 des lois sur 
l''enseignement primaire, coordonnées le 20 août 1957, sont abrogées. 
 
§ 3. Dans le cadre de l''application de l''article 3, § 3, alinéa 2, le 
Gouvernement détermine lesquelles des dispositions des articles 10 des lois 
sur l''enseignement primaire, coordonnées le 20 août 1957, sont abrogées. 
Fondamental 
 
III.A.02 
Lois 09547 
 
L. 29-06-1983 
mis à jour au 27-05-2022 
 
CHAPITRE IV. - Entrée en vigueur', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '15', '1', 'Article 15 § 1 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('9547', 9, 'Art. 16', 'Article 16. - A l''exception : 
1° de la nouvelle disposition fixée par l''article 8 en remplacement de 
l''article 12, troisième alinéa, de la loi du 29 mai 1959 et dont la date d''entrée 
en vigueur sera déterminée par arrêté royal délibéré en Conseil des 
Ministres; 
2° des avis visés à l''article 1er, § 4, qui sont requis à partir de l''année 
scolaire 1984-1985, 
la présente loi entre en vigueur le 1er septembre 1983. 
 
Cependant : 
1° les mineurs qui sont nés avant le 1er janvier 1968 ou qui ont déjà 
quitté l''école en 1982-1983, ne sont pas soumis aux dispositions de la 
présente loi; 
2° les mineurs qui sont nés en 1968 et qui n''ont pas encore quitté l''école 
en 1982-1983 sont soumis aux dispositions de la présente loi jusqu''au 
moment où ils auront terminé au moins deux années d''enseignement 
secondaire de plein exercice; 
3° les mineurs qui sont nés en 1969 sont soumis aux dispositions de la 
présente loi, jusqu''à la fin de l''année scolaire qui se termine au cours de 
l''année pendant laquelle ils atteignent l''âge de dix-sept ans, à moins que 
l''entrée en vigueur de cette disposition soit remise au 1er septembre 1985 par 
un arrêté royal, délibéré en Conseil des Ministres.', 'Loi du 29 juin 1983 — Obligation scolaire', 'Loi obligation scolaire', '16', NULL, 'Article 16 du Loi du 29 juin 1983 — Obligation scolaire (CDA 9547)', ARRAY['ROI'], 'commun');

-- CDA 23189: Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (38 chunks)
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 0, 'Art. 1er', 'Article 1er. - Le présent décret règle la formation en cours de carrière 
[et au mécanisme de soutien et de développement des compétences 
professionnelles]2 des membres du personnel directeur et enseignant et des 
membres du personnel auxiliaire d''éducation de l''enseignement secondaire 
artistique à horaire réduit subventionné par la Communauté française visés 
à l''article 49 du décret du 2 juin 1998 organisant l''enseignement secondaire 
artistique à horaire réduit subventionné par la Communauté française.', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '1er', NULL, 'Article 1er du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', NULL, 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 1, 'Art. 2 § 1', 'Article 2. - Pour l''application du présent décret, on entend par 
«formation en cours de carrière», toute activité de formation qui a pour objet 
l''entretien, [le développement,]3 le perfectionnement ou l''actualisation des 
compétences des membres du personnel visés à l''article 1er. 
 
La formation en cours de carrière comprend également des activités 
permettant aux membres du personnel dont la formation initiale ne répond 
pas ou plus aux exigences de la fonction ou à l''offre d''enseignement, [de 
développer ou]4 d''acquérir les compétences nécessaires soit à l''exercice de 
leur(s) fonction(s), soit à l''exercice d''une autre fonction dans l''enseignement, 
en ce compris les fonctions de sélection et de promotion. 
 
 
1 Intitulé remplacé par le décret du 20 juillet 2023 
2 Ajouté par le décret du 20 juillet 2023 
3Inséré par le D. 16-05-2024 
4Inséré par le D. 16-05-2024 
Artistique 
 
VIII.53 
Lois 23189 
 
D. 15-03-1999 
mis à jour au 30-10-2024 
[Article 2bis.]5 - §1er. Le bénéficiaire de formation peut consigner dans 
un dossier de développement professionnel intitulé « portfolio » les éléments 
de la formation en cours de carrière qui le concernent. 
 
Le portfolio est un outil de développement professionnel constitué sur 
base volontaire par le membre du personnel et qui lui est propre. 
 
Le portfolio est un outil formatif facilitant le soutien aux apprentissages 
et le développement d''une analyse réflexive. Le membre du personnel y 
consigne les traces utiles et pertinentes au sujet du cheminement de son 
développement professionnel. Le membre du personnel est responsable de 
son portfolio.', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '2', '1', 'Article 2 § 1 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['évaluation'], 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 2, 'Art. 2 § 2', '§2. Le portfolio est composé de trois parties, chacune de celles-ci ayant 
pour objectif de soutenir une posture réflexive : 
 
1° la première partie concerne le projet personnel de formation du 
membre du personnel. 
 
Elle comporte les volets suivants : 
 
a. les compétences professionnelles attendues en fonction de la charge 
occupée, et tout particulièrement celles qui sont visées dans le plan de 
développement des compétences professionnelles du membre du 
personnel ou dans le plan d''accompagnement individualisé et pour 
lesquelles des actions de formation sont nécessaires ; 
 
b. l''ensemble des formations, recueillies dans l''offre de formation en 
cours de carrière ouverte aux membres du personnel de l''enseignement 
secondaire artistique à horaire réduit prévue par le présent décret 
auxquelles le membre du personnel a participé ou participera, ainsi que 
les attestations de fréquentation des formations en cours de carrière ; 
 
c. l''ensemble des formations ou outils que le membre du personnel aura 
identifié seul ou avec le directeur ou son délégué, ou avec l''aide d''un 
collègue susceptibles de lui permettre de travailler les compétences 
professionnelles attendues identifiées au point a). L''ensemble des outils 
de formation ainsi constitué est organisé en un ensemble cohérent de 
parcours de formation au regard des compétences professionnelles 
attendues. 
 
2° la seconde partie concerne le cheminement du développement 
professionnel du membre du personnel. Cette partie permet au membre du 
personnel d''y consigner notamment les traces qu''il juge utiles et pertinentes 
relatives à sa trajectoire de développement des compétences professionnelles. 
 
3° la troisième partie reprend les traces expérientielles des compétences 
développées et acquises par le membre du personnel. Cette partie vise à 
valoriser les compétences développées tout au long du plan de développement 
des 
compétences 
professionnelles 
ou 
du 
plan 
d''accompagnement 
individualisé. 
 
 
5 Ajouté par le décret du 20 juillet 2023 
Artistique 
 
VIII.53 
Lois 23189 
 
D. 15-03-1999 
mis à jour au 30-10-2024', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '2', '2', 'Article 2 § 2 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['évaluation','obligation scolaire','ROI'], 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 3, 'Art. 2 § 3', '§3. Le membre du personnel décide d''utiliser ou de ne pas utiliser le 
portfolio comme support dans le cadre de son entretien de développement 
professionnel, 
de 
son 
plan 
de 
développement 
des 
compétences 
professionnelles, de son plan d''accompagnement individualisé, de son 
évaluation tels que prévus dans le cadre du mécanisme de soutien, de 
développement des compétences professionnelles et d''évaluation des 
membres du personnel de l''enseignement. La direction ou son délégué doit 
accepter le choix du membre du personnel d''utiliser ou non son portfolio lors 
de cet échange. 
 
Dans le cadre du développement de ses propres compétences 
professionnelles, la direction décide d''utiliser ou de ne pas utiliser son 
portfolio lors de ses échanges avec son pouvoir organisateur. Le pouvoir 
organisateur doit accepter le choix du directeur d''utiliser ou non son portfolio 
lors de cet échange.', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '2', '3', 'Article 2 § 3 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['évaluation'], 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 4, 'Art. 2 § 4', '§4. Le contenu du portfolio est adapté et remis à jour de manière 
régulière. 
 
Un seul portfolio est constitué par le membre du personnel et concerne 
l''ensemble de ses fonctions dans l''enseignement secondaire artistique à 
horaire réduit. 
 
Le membre du personnel peut utiliser son portfolio afin de constituer 
pour lui-même ou dans le cadre de ses visées professionnelles futures, un 
dossier témoignant de son parcours de développement de compétences 
professionnelles. 
 
[Article 2ter.]6 -', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '2', '4', 'Article 2 § 4 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', NULL, 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 5, 'Art. 2 § 1', '§1er. Ont le droit d''accéder en priorité et pour 
répondre à leurs besoins personnalisés à un maximum de cinq jours de 
formation en cours de carrière organisés par les fédérations de pouvoirs 
organisateurs : 
 
a) les membres du personnel de l''enseignement secondaire artistique à 
horaire réduit qui bénéficient d''un plan de développement des compétences 
professionnelles dans l''enseignement secondaire artistique à horaire réduit 
conformément aux articles : 
 
