INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 8, 'Art. 2 § 2', '§2. Le nombre de jours visé au paragraphe 1er est basé sur un temps 
plein et est réduit proportionnellement en fonction de l''horaire presté par le 
membre du personnel, en arrondissant au demi-jour supérieur. 
 
 
Modifié par D. 17-05-2018', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '2', '2', 'Article 2 § 2 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', NULL, 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 9, 'Art. 3', 'Article 3. - Les objectifs généraux de la formation en cours de carrière 
sont : 
1° la capacité de mettre en oeuvre les activités visées à l''article 2; 
2° l''acquisition des comportements propres à gérer efficacement les 
relations humaines; 
3° l''acquisition et la mise à jour des connaissances et des aptitudes 
professionnelles, notamment celles qui sont liées à l''application des 
dispositions fixées par le décret du 2 juin 1998 organisant l''enseignement 
secondaire artistique à horaire réduit subventionné par la Communauté 
française; 
4° l''étude et l''analyse des facteurs artistiques, sociaux, économiques et 
culturels qui influencent le comportement des personnes et les conditions 
d''exercice de la fonction d''enseignant dans l''enseignement secondaire 
artistique à horaire réduit subventionné par la Communauté française; 
5° le développement de la communication, du travail en équipe, de 
l''interdisciplinarité ainsi que l''émergence et le développement de projets au 
sein des établissements; 
6° 
la 
réorientation 
professionnelle, 
dans 
l''enseignement, 
des 
enseignants en disponibilité par défaut d''emploi; 
7° la formation spécifique pour les candidats à l''emploi de sélection visée 
à l''article 40, [alinéa 2, 10°,]7 du décret du 6 juin 1994 fixant le statut des 
membres du personnel subsidiés de l''enseignement officiel subventionné 
ainsi qu''à l''article 51, [alinéa 1er, 3°,]8 du décret du 1er février 1993 fixant le 
statut des membres du personnel subsidiés de l''enseignement libre 
subventionné. [remplacé par D. 17-05-2018] 
[8° le mécanisme de soutien et de développement des compétences 
professionnelles visé au Chapitre Ibis.]9 
 
Remplacé par D. 17-05-2018', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '3', NULL, 'Article 3 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['discipline','orientation','parents'], 'esahr');
