INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 11, 'Art. 5', 'Article 5. - Les activités de formation ne sont pas soumises [aux]11 
dispositions de l''article 5 de l''arrêté royal du 15 avril 1958 portant statut 
pécuniaire du personnel enseignant, scientifique et assimilé du ministère de 
l''Instruction publique, ni à celles de l''article 11 de l''arrêté du Gouvernement 
de la Communauté française du 25 octobre 1993 portant statut pécuniaire 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation de l''enseignement de Promotion sociale de la Communauté 
française, ni à celles de l''article 71 du décret du 2 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française.', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '5', NULL, 'Article 5 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', NULL, 'esahr');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 12, 'Art. 6', 'Article 6. - Les membres du personnel visés à l''article 1er auxquels est 
attribué un traitement d''activité ou une subvention-traitement d''activité et 
qui bénéficient d''une formation ou qui l''assurent sont réputés en activité de 
service pendant la durée de la formation. 
 
Les membres du personnel mis en disponibilité par défaut d''emploi 
peuvent assurer ou participer à une formation. La durée de celle-ci est 
assimilée à un rappel provisoire à l''activité de service ou à un rappel en 
service. 
 
Pour les membres du personnel désignés à titre temporaire, la durée de 
la formation suivie n''est prise en considération pour le calcul de l''ancienneté 
administrative et pécuniaire que si celle-ci est englobée dans les limites des 
prestations attribuées et pour la période de désignation ou d''engagement à 
titre temporaire. 
 
Modifié par D. 17-05-2018', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '6', NULL, 'Article 6 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['exclusion','personnel'], 'esahr');
