INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 17, 'Art. 8', 'Article 8/3. - Pour les directeurs, une formation relative aux 
