INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 32, 'Art. 10', 'Article 10. - Il est créé la «Commission de la formation en cours de 
carrière», ci-après dénommée «la Commission» chargée, […]15, de soumettre à 
l''approbation du Gouvernement dans le courant du premier trimestre de 
 
