INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 34, 'Art. 12 § 4', 'Article 12. Conformément [à l''article 6, §4, 3°, du décret du 10 janvier 
2019 précité]21, le service de l''inspection de l''enseignement artistique évalue 
annuellement la mise en application du présent décret et s''assure que la 
réalisation pédagogique des activités de formation en cours de carrière : 
[1°  est conforme aux objectifs visés à l''article 3 ;]22 
2° implique la participation et suscite l''intérêt des bénéficiaires; 
3° est menée dans un cadre répondant aux nécessités pédagogiques; 
4° compte un nombre de bénéficiaires en relation avec les inscriptions. 
 
Ce rapport d''évaluation est soumis au [Conseil général]23 de 
l''enseignement secondaire artistique à horaire réduit pour avis. Le rapport 
d''évaluation et l''avis du Conseil de perfectionnement sont transmis au 
Ministre qui a cet enseignement dans ses attributions.', 'Décret du 15 mars 1999 — Formation en cours de carrière ESAHR', 'Décret formation ESAHR', '12', '4', 'Article 12 § 4 du Décret du 15 mars 1999 — Formation en cours de carrière ESAHR (CDA 23189)', ARRAY['inscription','évaluation','inspection'], 'esahr');
