INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('23189', 36, 'Art. 14', 'Article 14. - Les crédits budgétaires affectés aux formations en cours de 
carrière, en ce compris les rémunérations correspondantes, s''élèvent au 
moins à 0,12 % des dépenses courantes que le budget du ministère de la 
Communauté française consacre à l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française. [Au moins 40 % 
de ces crédits sont consacrés à des formations basées sur des thèmes 
généraux communs de formation visés à l''article 10, alinéa 1er.]24 
 
[L''enveloppe telle que fixée à l''alinéa 1er est augmentée d''un montant 
de 45.000 euros en 2024 et d''un montant de 130.000 euros à partir de 2025. A 
partir de 2026, ce dernier montant est indexé annuellement en fonction du 
rapport entre l''indice général des prix à la consommation du mois de janvier 
de l''année en cours et celui du mois de janvier de l''année précédente.]25 
 
Ces crédits sont répartis entre les différents organes de représentation 
et de coordination des pouvoirs organisateurs au prorata du nombre total de 
périodes de cours attribuées au cours de l''année scolaire précédant celle de 
l''organisation des formations. 
 
Les frais de gestion et de secrétariat ne peuvent être supérieurs à [18 
%]26 du montant total des crédits accordés à la formation en cours de 
carrière. 
 
[…]27 
 
