INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 1, 'Art. 2', 'Article 2. - A l''article 6.1.1-1 du Code précité, les modifications suivantes 
