INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 6, 'Art. 6 § 1', 'Article 6.1.9-3. - §1er. Pour les directeurs, une formation relative aux 
mécanismes de soutien, de développement des compétences professionnelles et 
d''évaluation, est organisée dans le cadre de la formation initiale des directeurs 
visée au chapitre II du décret du 02 février 2007 fixant le statut des directeurs 
et directrices dans l''enseignement. Cette formation est organisée de manière 
complémentaire entre les niveaux de formation interréseaux et réseau visés à 
l''article 6.1.3-3 et comprend des modules répartis de manière égalitaire entre 
ces deux niveaux de formation. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
L''Institut de la Formation Professionnelle Continue d''une part et le 
pouvoir organisateur de l''enseignement organisé par la Communauté 
française ou chaque Fédération de pouvoirs organisateurs veillent à respecter 
la complémentarité des modules entre les niveaux interréseaux et réseau de 
manière à assurer la cohérence globale du dispositif de formation. 
 
§2. Le directeur suit la formation visée au paragraphe 1er.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '6', '1', 'Article 6 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 7, 'Art. 6 § 1', 'Article 6.1.9-4. - §1er. Dans l''enseignement secondaire, le délégué du 
directeur, visé dans le présent chapitre, doit être désigné parmi les membres 
du personnel suivants, à condition qu''il ait suivi la formation visée à l''article 
6.1.9-5 : 
 
1° les titulaires de la fonction de sélection de directeur adjoint ; 
 
2° le cas échéant, les enseignants expérimentés, tels que visé à l''article 
22 du décret du 14 mars 2019 portant diverses dispositions relatives à 
l''organisation du travail des membres du personnel de l''enseignement et 
octroyant plus de souplesse organisationnelle aux pouvoirs organisateurs. 
 
§2. Pour les fonctions de sélection ou de promotion, le directeur ne peut 
pas déléguer, à l''exception de la délégation au chef de travaux d''atelier en cas 
de soutien et de développement des compétences professionnelles d''un chef 
d''atelier. 
 
§3. Le délégué doit avoir un entretien de développement professionnel 
donnant lieu à un plan de développement des compétences professionnelles au 
cours de l''année scolaire durant laquelle la mission de délégué lui est confiée 
pour la première fois. 
 
§4. 
Le 
délégué 
visé 
au 
paragraphe 
1er exerce 
une 
mission 
d''accompagnateur du mécanisme de soutien et de développement des 
compétences professionnelles. 
 
Il fait, à la demande de la direction, des entretiens de développement 
professionnel. 
 
Il soutient, aide et accompagne le membre du personnel dans sa réflexion 
et dans la construction et l''élaboration de son plan de développement des 
compétences professionnelles. 
 
Il n''a pas de compétence de décision.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '6', '1', 'Article 6 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 8, 'Art. 6', 'Article 6.1.9-5. - Pour les délégués visés à l''article 6.1.9-4., une formation 
relative au mécanisme de soutien et de développement des compétences 
professionnelles, est organisée dans le cadre de la formation professionnelle 
continue. Cette formation est organisée de manière complémentaire entre les 
