INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 23, 'Art. 6', 'Article 6.1.9-10. - Dans le cadre des entretiens et échanges visés aux 
sections 3 et 4, le membre du personnel et le directeur ou son délégué sont 
tenus au respect des devoirs suivants : 
 
1° la discrétion ; 
 
2° le respect mutuel. 
 
En outre, le directeur ou son délégué est tenu de : 
 
1° 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ; 
 
2° soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
3° respecter les devoirs d''impartialité et d''objectivité. ». 
 
TITRE 2. - Dispositions insérant le mécanisme d''évaluation dans les 
différents statuts 
 
CHAPITRE 1. - Dispositions modifiant l''arrêté royal du 22 mars 1969 
fixant le statut des membres du personnel directeur et enseignant, 
du personnel auxiliaire d''éducation, du personnel paramédical des 
établissements d''enseignement gardien, primaire, spécial, moyen, 
technique, de promotion sociale et artistique de l''Etat, des internats 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
dépendant de ces établissements et des membres du personnel du 
service d''inspection chargé de la surveillance de ces établissements', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '6', NULL, 'Article 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 24, 'Art. 5', 'Article 5. - Il est ajouté un point 12° rédigé comme suit à l''article 18 de 
l''arrêté royal du 22 mars 1969 fixant le statut des membres du personnel 
directeur et enseignant, du personnel auxiliaire d''éducation, du personnel 
paramédical des établissements d''enseignement, gardien, primaire, spécial, 
moyen, technique, de promotion sociale et artistique de l''Etat, des internats 
dépendant de ces établissements et des membres du personnel du service 
d''inspection chargé de la surveillance de ces établissements : 
 
« 12° ne pas avoir fait l''objet dans la fonction considérée, pendant les deux 
dernières années scolaires, soit de deux rapports d''évaluation avec mention 
défavorable, soit de deux rapports sur la manière de servir avec mention 
défavorable tels que visés à l''article 27. ».

Article 6. - A l''article 20, §4, du même arrêté royal, les alinéas 1 à 4 sont 
abrogés.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '5', NULL, 'Article 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 25, 'Art. 7 § 1', 'Article 7. - A l''article 25, §1er, les modifications suivantes sont 
apportées : 
 
1° à l''alinéa 2 du même arrêté royal, les mots « sur la manière de servir » 
sont insérés entre le mot « rapport » et le mot « défavorable » ; 
 
2° un alinéa 4 rédigé comme suit est ajouté : 
 
« Les membres du personnel ayant fait l''objet d''un rapport d''évaluation 
portant la mention défavorable sont redésignés dans l''emploi qu''ils occupaient 
l''année scolaire précédente si cet emploi existe toujours au premier jour de 
l''année scolaire suivante et qu''il n''a pas fait l''objet d''une réaffectation, d''un 
rappel à l''activité de service, d''un changement d''affectation, d''une extension 
de nomination, d''une désignation d''un temporaire prioritaire ou de la 
désignation d''un membre du personnel mieux classé. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '7', '1', 'Article 7 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 26, 'Art. 8', 'Article 8. - L''article 27 du même arrêté royal est remplacé par l''article 
suivant : 
 
« Article 27 - Tout temporaire, temporaire prioritaire ou temporaire 
protégé est réputé s''être acquitté de sa tâche de manière satisfaisante aussi 
longtemps qu''un rapport d''évaluation avec mention défavorable ou qu''un 
rapport sur la manière de servir défavorable n''est pas rédigé à son sujet par le 
pouvoir organisateur. 
 
Par année scolaire, le membre du personnel ne peut faire l''objet que d''un 
rapport d''évaluation ou d''un rapport sur la manière de servir. 
 
En l''absence de rapport, tout membre du personnel est réputé bénéficier 
de la mention favorable. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 27, 'Art. 9 § 1', 'Article 9. - Un article 27bis rédigé comme suit est inséré dans le même 
arrêté royal : 
 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
« Article 27bis - §1er. Le cas échéant, le rapport sur la manière de servir 
est établi au plus tard à l''issue de chaque période d''activité, selon le modèle 
arrêté par le Gouvernement. 
 
Il doit être soumis au visa du temporaire, du temporaire prioritaire ou du 
temporaire protégé qu''il concerne et joint à son dossier personnel. 
 
La mention du rapport sur la manière de servir est motivée, à peine de 
nullité, sur la base d''au moins un fait favorable ou défavorable rédigé au 
moment de sa survenance. Ce fait doit être détaillé, daté et signé par le 
directeur et soumis au visa du membre du personnel pour réception. La 
procédure se poursuit valablement lorsque le membre du personnel refuse de 
viser le rapport. 
 
§2. Le membre du personnel a le droit d''introduire un recours, dans les 
dix jours ouvrables de la notification dudit rapport, devant la Chambre de 
recours visée au Chapitre IX, Section 2 du présent arrêté. Le membre du 
personnel qui fait usage de son droit de recours en notifie immédiatement une 
copie au pouvoir organisateur. Ce recours est suspensif. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '9', '1', 'Article 9 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','exclusion','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 28, 'Art. 10', 'Article 10. - A l''article 31, point 8°, du même arrêté royal, les 
modifications suivantes sont apportées : 
 
1° les mots « sur la manière de servir » sont insérés entre les mots « d''un 
rapport » et le mot « défavorable » ; 
 
2° les mots « ou d''un rapport d''évaluation avec mention défavorable du 
pouvoir organisateur » sont insérés après les mots « du chef d''établissement. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '10', NULL, 'Article 10 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 29, 'Art. 11', 'Article 11. - A l''article 31ter, point 8°, du même arrêté royal, les 
modifications suivantes sont apportées : 
 
1° les mots « sur la manière de servir » sont insérés entre les mots « d''un 
rapport » et le mot « défavorable » ; 
 
2° les mots « ou d''un rapport d''évaluation avec mention défavorable du 
pouvoir organisateur » sont insérés après les mots « du chef d''établissement. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '11', NULL, 'Article 11 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 30, 'Art. 12', 'Article 12. - A l''article 46bis, point 7°, du même arrêté royal, les 
modifications suivantes sont apportées : 
 
1° les mots « sur la manière de servir » sont insérés entre les mots « d''un 
rapport » et le mot « défavorable » ; 
 
2° les mots « ou d''un rapport d''évaluation avec mention défavorable du 
pouvoir 
organisateur 
» 
sont 
insérés 
après 
les 
mots 
« d''un 
chef 
d''établissement. ».

Article 13. - A l''article 83 du même arrêté royal, le point 5° est abrogé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '12', NULL, 'Article 12 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 31, 'Art. 14', 'Article 14. - A l''article 91 du même arrêté royal, les mots « leurs 
signalements » sont remplacés par les mots « leurs signalements ou leurs 
rapports d''évaluation ». 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023

Article 15. - Les articles 91sexies à 91novies du même arrêté royal sont 
abrogés.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '14', NULL, 'Article 14 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 32, 'Art. 16', 'Article 16. - Après l''article 121 du même arrêté royal, il est inséré un 
Chapitre VIIIbis, libellé comme suit : 
 
« Chapitre VIIIbis - De l''évaluation des membres du personnel.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '16', NULL, 'Article 16 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 33, 'Art. 121', 'Article 121/1. Le présent chapitre s''applique aux membres du personnel 
régis par le présent statut à l''exception des directeurs et des membres du 
personnel de l''Inspection. 
 
Section 1. - Du plan de développement des compétences professionnelles', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 34, 'Art. 121', 'Article 121/2. - Toute première évaluation doit être précédée d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture 
tels que prévus dans la section 3 du chapitre 9 du titre Ier du livre 6 du Code 
de l''enseignement fondamental et de l''enseignement secondaire et à la section 
3 du chapitre 1erbis du décret du 30 juin 1998 relatif à la formation en cours 
de carrière et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement de promotion sociale.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 35, 'Art. 121', 'Article 121/3. - Au plus tôt six mois après avoir communiqué le plan de 
développement des compétences professionnelles au membre du personnel, et 
pour autant que l''entretien de clôture visé aux articles 6.1.9-7, §5, et 6.1.9-9, 
§5, du Code de l''enseignement fondamental et de l''enseignement secondaire et 
aux articles 8.7, §5, et 8.9, §5, du décret du 30 juin 1998 relatif à la formation 
en cours de carrière et au mécanisme de soutien et de développement des 
compétences professionnelles des membres du personnel directeur et 
enseignant et du personnel auxiliaire d''éducation et des experts de 
l''enseignement de promotion sociale, ait eu lieu, en cas de mauvaise volonté 
manifeste en lien avec ledit plan ou de carence manifeste et répétée à atteindre 
les objectifs identifiés avec le membre du personnel dans le cadre du plan de 
développement des compétences professionnelles, le directeur rédige un 
rapport motivé à destination du pouvoir organisateur afin qu''il procède à une 
évaluation du membre du personnel. 
 
Section 2. - Du mécanisme d''évaluation', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 36, 'Art. 121 § 1', 'Article 121/4. - §1er. Sur la base du rapport du directeur visé à l''article 
121/3, le pouvoir organisateur peut mener une évaluation du membre du 
personnel concerné. 
 
Un entretien d''évaluation ne peut avoir lieu qu''une fois par année 
scolaire. 
 
§2. Préalablement à toute attribution de mention d''évaluation, le membre 
du personnel doit être entendu par le pouvoir organisateur. 
 
La convocation à cette audition doit lui être notifiée cinq jours ouvrables 
au moins avant la date fixée pour celle-ci. 
 
Lors de cette audition, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel d''un établissement de 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
l''enseignement organisé par la Communauté française, en activité de service 
ou retraité ou par un délégué d''une organisation syndicale agréée. 
 
§3. A l''issue de l''entretien d''évaluation, le pouvoir organisateur rédige un 
rapport d''évaluation. 
 
Il débouche sur une mention « favorable » ou « défavorable ». 
 
La mention d''évaluation est motivée sur la base des éléments : 
 
1° du rapport du directeur ; 
 
2° du plan de développement des compétences professionnelles ; 
 
3° de l''entretien d''évaluation. 
 
Le rapport est notifié au membre du personnel et soumis au visa de ce 
dernier. 
 
La procédure se poursuit lorsque le membre du personnel refuse de viser 
le rapport. 
 
A défaut de rapport d''évaluation, le membre du personnel est réputé 
bénéficier de la mention favorable.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 37, 'Art. 121 § 1', 'Article 121/5. - §1er. En cas d''évaluation débouchant sur la mention 
« défavorable », un entretien entre le pouvoir organisateur et/ou le directeur à 
qui il donne délégation et le membre du personnel est fixé afin de mettre en 
place un plan d''accompagnement individualisé. 
 
Le plan est basé sur les éléments évoqués lors de l''évaluation et 
détermine les objectifs que le membre du personnel doit atteindre pour obtenir 
une mention favorable lors de l''évaluation suivante. 
 
Un maximum de quatre objectifs peut être fixé. 
 
§2. La fin du plan d''accompagnement individualisé donne lieu à un 
entretien de clôture. 
 
Afin de permettre au membre du personnel de remédier aux carences 
constatées, l''entretien de clôture intervient au plus tôt après six mois 
d''exercice dans la fonction considérée et au plus tard deux ans après la 
notification du plan d''accompagnement individualisé. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 38, 'Art. 121 § 1', 'Article 121/6. - §1er. Après une évaluation avec mention défavorable, 
l''évaluation suivante doit intervenir dans un délai maximum de deux ans 
suivant la communication du plan d''accompagnement individualisé faisant 
suite à la précédente évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, la seconde évaluation peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée au §3. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
A défaut, le membre du personnel est réputé faire l''objet d''une évaluation 
favorable. 
 
§2. Préalablement à toute attribution de mention, le membre du 
personnel doit être entendu par le pouvoir organisateur. 
 
Un entretien d''évaluation ne peut avoir lieu qu''une fois par année 
scolaire. 
 
La convocation à cette audition doit lui être notifiée cinq jours ouvrables 
au moins avant la date fixée pour celle-ci. 
 
Lors de cette audition, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel d''un établissement de 
l''enseignement organisé par la Communauté française, en activité de service 
ou retraité ou par un délégué d''une organisation syndicale agréée. 
 
§3. A l''issue de l''entretien d''évaluation, le pouvoir organisateur rédige un 
rapport d''évaluation. 
 
Celui-ci débouche sur une mention « favorable », « défavorable » ou, en cas 
de commun accord entre le membre du personnel et le pouvoir organisateur, 
sur la prolongation du plan d''accompagnement individualisé. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum trois mois et de maximum un an. 
 
La 
mention 
d''évaluation 
est 
motivée 
sur 
la 
base 
du 
plan 
d''accompagnement individualisé visé à l''article 121/15. 
 
Le rapport d''évaluation est notifié au membre du personnel et soumis au 
visa de ce dernier. La procédure se poursuit lorsque le membre du personnel 
refuse de viser le rapport.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 39, 'Art. 121 § 1', 'Article 121/7. - §1er. En cas de seconde évaluation débouchant sur la 
prolongation du plan d''accompagnement individualisé, un entretien entre le 
pouvoir organisateur et/ou son délégué auquel il donne délégation et le 
membre du personnel est fixé afin de mettre en place un second plan 
d''accompagnement individualisé qui consiste en l''adaptation du premier plan 
d''accompagnement individualisé. 
 
Le plan est basé sur les éléments évoqués lors de l''évaluation et 
détermine les objectifs non atteints que le membre du personnel doit atteindre 
pour obtenir une mention favorable lors de l''évaluation suivante. 
 
Celui-ci reprend les objectifs du plan d''accompagnement individualisé 
précédent non atteints que le membre du personnel doit atteindre pour obtenir 
une mention favorable lors de l''évaluation suivante. Un maximum de quatre 
objectifs peut être fixé. 
 
§2. La fin du second plan d''accompagnement individualisé donne lieu à 
un entretien de clôture. 
 
Afin de permettre au membre du personnel de remédier aux carences 
constatées, l''entretien de clôture intervient au plus tôt après trois mois 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
d''exercice dans la fonction considérée et au plus tard un an après la notification 
du plan d''accompagnement individualisé adapté à la suite de la prolongation 
dudit plan d''accompagnement individualisé. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 40, 'Art. 121 § 1', 'Article 121/8. - §1er. Après l''entretien de clôture du second plan 
d''accompagnement individualisé et au plus tard un an après la notification du 
plan d''accompagnement, le pouvoir organisateur peut mener, en cas de 
prolongation du plan d''accompagnement individualisé, une troisième 
évaluation. 
 
A défaut, le membre du personnel est réputé faire l''objet d''une évaluation 
favorable. 
 
§2. Préalablement à toute attribution de mention, le membre du 
personnel doit être entendu par le pouvoir organisateur. 
 
Une évaluation ne peut avoir lieu qu''une fois par année scolaire. 
 
La convocation à cette audition doit lui être notifiée cinq jours ouvrables 
au moins avant la date fixée pour celle-ci. 
 
Lors de cette audition, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel d''un établissement de 
l''enseignement organisé par la Communauté française, en activité de service 
ou retraité ou par un délégué d''une organisation syndicale agréée. 
 
§3. A l''issue de l''entretien d''évaluation, le pouvoir organisateur rédige un 
rapport d''évaluation. 
 
Celui-ci débouche sur une mention « favorable » ou « défavorable ». 
 
La 
mention 
d''évaluation 
est 
motivée 
sur 
la 
base 
du 
plan 
d''accompagnement individualisé visé à l''article 121/7. 
 
Le rapport est notifié au membre du personnel et soumis au visa de ce 
dernier. La procédure se poursuit lorsque le membre du personnel refuse de 
viser le rapport.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 41, 'Art. 121', 'Article 121/9. - Pour pouvoir mener une évaluation, une des conditions 
suivantes doit être remplie : 
 
a. soit un membre du pouvoir organisateur est formé à cette fin via la 
formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement ; 
 
b. soit un membre du pouvoir organisateur est un expert en pédagogie ou 
en ressources humaines ; 
 
c. soit le pouvoir organisateur se fait assister par un expert en pédagogie 
ou en ressources humaines. 
 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 42, 'Art. 121', 'Article 121/10. - Dans le cadre des entretiens et évaluations précités, le 
membre du personnel et son évaluateur sont tenus au respect des devoirs 
suivants : 
 
1° la discrétion ; 
 
2° le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
1° 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
leurs 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
2° soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
3° respecter les devoirs d''impartialité et d''objectivité.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 43, 'Art. 121', 'Article 121/11. - Pour le calcul des délais visés aux articles 121/3, 121/5 
et 121/7, sont seuls pris en considération les services effectifs rendus, en ce 
compris : 
 
1° les vacances annuelles, à l''exclusion des vacances d''été ; 
 
2° les congés prévus aux articles 5, 5bis,6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 44, 'Art. 121', 'Article 121/12. - Toute notification de document, de décision ou de 
convocation se fait par courrier recommandé avec accusé de réception ou par 
une remise de la main à la main avec accusé de réception.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 45, 'Art. 121', 'Article 121/13. - En cas d''attribution d''une mention « défavorable » lors 
d''une évaluation, dans les dix jours ouvrables de la notification du rapport 
d''évaluation, le membre du personnel peut introduire, par courrier 
recommandé à la poste, un recours auprès de la chambre d''appel visée aux 
articles 121/16 à 121/24. Il en notifie immédiatement une copie au pouvoir 
organisateur. Ce recours est suspensif.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 46, 'Art. 121 § 1', 'Article 121/14. - §1er. Le pouvoir organisateur qui envisage une procédure 
pouvant conduire à l''attribution d''une mention d''évaluation « défavorable » à 
un délégué syndical dans le cadre de la procédure fixée aux articles 121/1 à 
121/12 doit, sous peine de nullité, en informer préalablement la délégation 
syndicale si celle-ci est composée de plusieurs délégués ainsi que l''organisation 
syndicale qui l''a désigné. Cette information se fait par lettre recommandée 
sortant ses effets le 3ème jour ouvrable suivant la date de son expédition. 
 
§2. L''organisation syndicale intéressée dispose d''un délai de 10 jours pour 
notifier par lettre recommandée au pouvoir organisateur qu''elle considère que 
la mesure envisagée est inspirée par des motifs inhérents à l''exercice du 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
mandat syndical et demander la réunion du Comité de concertation central 
visé à l''article 31/1 du décret spécial du 07 février 2019 portant création de 
l''organisme public chargé de la fonction de pouvoir organisateur de 
l''Enseignement organisé par la Communauté française. Le délai de 10 jours 
prend cours le jour où la lettre recommandée envoyée par le pouvoir 
organisateur sort ses effets. Toutefois, le délai de 10 jours est suspendu du 15 
juillet au 15 août. 
 
§3. L''absence de réaction de l''organisation syndicale concernée dans le 
délai imparti, signifie dans son chef qu''elle considère que la mesure envisagée 
n''est pas inspirée par des motifs inhérents à l''exercice du mandat syndical. 
 
§4. A l''expiration du délai de 10 jours, le pouvoir organisateur peut 
poursuivre 
la 
procédure 
d''attribution 
d''une 
mention 
d''évaluation 
« défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', '1', 'Article 121 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 47, 'Art. 121', 'Article 121/15. - Le Gouvernement arrête les modèles des rapports des 
directions à destination du pouvoir organisateur, des rapports d''évaluation et 
des plans d''accompagnement individualisé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 48, 'Art. 121', 'Article 121/16. - Après consultation du pouvoir organisateur et des 
organisations syndicales agréées, le Gouvernement institue des Chambres 
d''appel pour les évaluations, ci-après dénommées les Chambres d''appel, dont 
la compétence s''étend à un ou plusieurs degrés d''enseignement. 
 
Les Chambres d''appel sont uniquement compétentes pour traiter des 
recours prévus dans le cadre de la procédure d''évaluation visée au présent 
chapitre. 
 
Elles sont également compétentes pour traiter des recours prévus dans le 
cadre de la procédure d''évaluation des directeurs visés par le décret du 2 
février 2007 fixant le statut des directeurs et directrices dans l''enseignement. 
 
Chaque Chambre d''appel élabore son règlement d''ordre intérieur sous 
réserve d''approbation du Gouvernement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 49, 'Art. 121', 'Article 121/17. - Les Chambres d''appel sont composées : 
 
1° de trois représentants du pouvoir organisateur et de trois 
représentants des organisations syndicales agréées. Chacune de ces 
organisations syndicales dispose d''au moins un représentant ; 
 
2° d''un président et de deux présidents suppléants désignés par le 
Gouvernement parmi les magistrats en activité ou admis à la retraite ou parmi 
les fonctionnaires généraux du Ministère de la Communauté française en 
activité ou admis à la retraite ; 
 
3° d''un secrétaire et d''un secrétaire suppléant désignés par le 
Gouvernement. 
 
Le Gouvernement désigne les membres visés au 1° de l''alinéa précédent 
sur proposition du pouvoir organisateur et des organisations syndicales 
agréées. Il désigne, dans les mêmes conditions, deux membres suppléants pour 
chaque membre effectif. A défaut de proposition de membres suppléants, la 
Chambre d''appel est valablement composée. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Les membres d''une Chambre d''appel sont désignés pour un mandat de 
quatre ans. Leur mandat est renouvelable. 
 
Le remplaçant d''un membre achève le mandat de celui qu''il remplace. 
 
Les secrétaires et secrétaires suppléants d''une Chambre d''appel en 
assument le secrétariat. Ils n''ont pas voix délibérative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['inscription','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 50, 'Art. 121', 'Article 121/18. - Dès qu''un recours est introduit, le président communique 
au requérant et au pouvoir organisateur la liste des membres effectifs et 
suppléants. Dans les dix jours qui suivent la réception de cette liste, le membre 
du personnel ou le pouvoir organisateur peuvent demander la récusation de 
trois membres au maximum. Toutefois, ils ne peuvent récuser en même temps 
un membre effectif et ses deux suppléants. 
 
Un membre peut demander à être déchargé s''il estime avoir un intérêt 
moral en la cause ou s''il croit que l''on puisse douter de son impartialité. Le 
président décide de la suite à réserver à cette demande. Il peut aussi décharger 
un membre pour les mêmes motifs. 
 
Les présidents, présidents suppléants, les membres effectifs et les 
membres suppléants ne peuvent siéger dans une affaire concernant leur 
conjoint ou un parent ou un allié, jusqu''au quatrième degré inclusivement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 51, 'Art. 121', 'Article 121/19. - Aucun recours ne peut faire l''objet de délibérations de la 
Chambre d''appel si le requérant n''a été mis à même de faire valoir ses moyens 
de défense et si le dossier ne contient pas les éléments susceptibles de 
permettre à cette chambre d''émettre un avis en toute connaissance de cause, 
notamment le rapport du directeur et le ou les rapports d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 52, 'Art. 121', 'Article 121/20. - Les parties sont convoquées par le président dans les 
vingt jours suivant la réception du recours par courrier recommandé avec 
accusé de réception ou par une remise de la main à la main avec accusé de 
réception. 
 
Le membre du personnel et le pouvoir organisateur peuvent se faire 
assister ou représenter par un avocat, par un défenseur choisi parmi les 
membres du personnel des établissements d''enseignement organisé par la 
Communauté française, en activité de service ou pensionnés ou par un 
représentant d''une organisation syndicale agréée. 
 
En cas d''absence de l''une des parties régulièrement convoquées ou de son 
défenseur, la chambre d''appel statue valablement lors de sa deuxième séance. 
Les deux séances ne peuvent être espacées de moins de cinq jours. 
 
Lorsque la mention est liée, en tout ou en partie, à un objectif qui porte 
sur la compétence pédagogique du requérant, la Chambre d''appel peut faire 
appel au Service général de l''Inspection en sa qualité d''expert, sur des aspects 
techniques relatifs aux dimensions disciplinaires et/ou didactiques. 
 
Le président de la Chambre invite alors un représentant du Service 
général de l''Inspection, soit d''initiative, soit à la demande d''un ou plusieurs 
membres, soit à la demande du requérant. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023

Article 121/21. - Les délais visés à la présente section sont suspendus 
entre le 15 juillet et le 15 août.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','discipline','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 53, 'Art. 121', 'Article 121/22. - La Chambre d''appel ne peut remettre un avis que si au 
moins deux membres représentant le pouvoir organisateur et deux membres 
représentant les organisations syndicales agréées sont présents. Les membres 
représentant le pouvoir organisateur et les membres représentant les 
membres du personnel doivent être en nombre égal pour prendre part au vote. 
Le cas échéant, la parité est rétablie par l''élimination d''un ou de plusieurs 
membres après tirage au sort par le président. 
 
Si le quorum visé à l''alinéa précédent n''est pas atteint, le président 
convoque une nouvelle réunion endéans les quinze jours. Au cours de cette 
réunion, une décision pourra être prise quel que soit le nombre de membres 
présents. 
 
Le vote sur l''avis a lieu au scrutin secret. En cas d''unanimité ou de 
majorité simple des voix plus une, l''avis de la Chambre d''appel est 
contraignant. En cas de parité des voix uniquement, le président décide. Dans 
ce cas, l''avis de la Chambre d''appel n''est pas contraignant. 
 
La Chambre d''appel donne son avis au pouvoir organisateur dans un 
délai de 45 jours à partir de la date de réception du recours. Dans son avis, la 
Chambre d''appel indique si, sur base des éléments qui lui sont soumis, la 
mention attribuée au membre du personnel est justifiée ou ne l''est pas. L''avis 
de la Chambre d''appel ne propose pas d''alternative à la décision du pouvoir 
organisateur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 54, 'Art. 121', 'Article 121/23. - L''avis de la Chambre est signifié aux parties par courrier 
recommandé avec accusé de réception dans les cinq jours ouvrables qui suivent 
la réunion au cours de laquelle il a été donné. Il est motivé. 
 
Le pouvoir organisateur prend sa décision dans un délai de 30 jours à 
partir de la réception de l''avis visé à l''alinéa précédent et notifie sa décision à 
la Chambre d''appel et au membre du personnel. Le cas échéant, le pouvoir 
organisateur indique les raisons pour lesquelles l''avis de la Chambre d''appel 
n''a pas été suivi. 
 
Si l''avis de la Chambre d''appel est contraignant, le pouvoir organisateur 
modifie la mention du membre du personnel dans un délai de 30 jours à partir 
de la réception de l''avis visé au paragraphe précédent et notifie sa décision à 
la Chambre d''appel et au membre du personnel.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 55, 'Art. 121', 'Article 121/24. - Les frais de fonctionnement de la Chambre d''appel sont 
à charge de la Communauté française. 
 
Le Gouvernement détermine les indemnités pour frais de parcours et de 
séjour des membres des Chambres d''appels ainsi que les indemnités 
auxquelles le président et les présidents suppléants ont droit. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '121', NULL, 'Article 121 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 56, 'Art. 17', 'Article 17. - A l''article 168 du même arrêté royal, les modifications 
suivantes sont apportées : 
 
1° à l''alinéa 1er, un point 10° libellé comme suit est inséré :  
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
«  10° s''ils ont fait l''objet dans la fonction considérée, de deux rapports 
d''évaluation avec mention « défavorable » consécutifs sur deux années 
scolaires distinctes, devenues définitives après épuisement des procédures 
devant la chambre d''appel, telles que visées à l''article 121/13; ». 
 
2° à l''alinéa 2, le mot « 10° » est inséré entre les mots « 7° » et « perd ». ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '17', NULL, 'Article 17 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 57, 'Art. 18', 'Article 18. - A l''alinéa 1er de l''article 169 du même arrêté royal, un point 
5° libellé comme suit est inséré : 
 
« 5° une deuxième évaluation avec mention « défavorable » telle que 
mentionnées à l''article 28septies du décret du 04 janvier 1999 relatif aux 
fonctions de sélection et de promotion et à l''article 42 du décret du 02 février 
2007 fixant le statut des directeurs et directrices dans l''enseignement. ». 
 
CHAPITRE 2. - Disposition modifiant l''arrêté royal du 22 juillet 1969 
