INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 58, 'Art. 19', 'Article 19. - A l''article 4bis de l''arrêté royal du 22 juillet 1969 fixant les 
