INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 59, 'Art. 20', 'Article 20. - Il est ajouté un point 11° rédigé comme suit à l''article 4 de 
l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres et des professeurs 
de religion des religions catholique, protestante, israélite, orthodoxe et 
islamique des établissements d''enseignement de la Communauté française : 
 
« 11°. ne pas avoir fait l''objet dans la fonction considérée, au cours des 
deux dernières années scolaires, de deux rapports sur la manière de servir 
défavorable ou de deux rapports d''évaluation avec mention défavorable tels 
que visés à l''article 7. ».

Article 21. - A l''article 5 du même arrêté royal, les alinéas 1 à 4 du §4 
sont abrogés.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '20', NULL, 'Article 20 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 60, 'Art. 22 § 4', 'Article 22. - A l''article 6, §4 du même arrêté royal est inséré un troisième 
alinéa rédigé comme suit : 
 
« Le temporaire visés par à l''article 5 quater, qui a fait l''objet d''un rapport 
d''évaluation portant la mention défavorable est désigné à nouveau dans 
l''établissement où il était affecté l''année scolaire précédente sous réserve de 
l''application de la priorité à la désignation d''un candidat mieux classé. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '22', '4', 'Article 22 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 61, 'Art. 23', 'Article 23. - L''article 7 du même arrêté royal est remplacé par l''article 
suivant : 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
« Article 7. - Un maître de religion ou un professeur de religion temporaire 
est réputé s''être acquitté de sa tâche de manière satisfaisante aussi longtemps 
qu''un rapport sur la manière de servir défavorable ou un rapport d''évaluation 
avec mention défavorable n''est pas rédigé à son sujet par le pouvoir 
organisateur. 
 
Le rapport sur la manière de servir peut faire l''objet d''une des mentions 
suivantes : « favorable » ou « défavorable ». 
 
Le rapport d''évaluation peut faire l''objet d''une des mentions suivantes : 
« favorable » ou « défavorable ». 
 
En l''absence de rapport, tout membre du personnel est réputé bénéficier 
de la mention favorable. 
 
Par année scolaire, le membre du personnel ne peut recevoir qu''un 
rapport d''évaluation ou qu''un rapport sur la manière de servir. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '23', NULL, 'Article 23 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 62, 'Art. 24 § 1', 'Article 24. - Un article 7bis rédigé comme suit est inséré dans le même 
arrêté royal : 
 
« Article 7bis. - §1er. Le cas échéant, le rapport sur la manière de servir 
est établi au plus tard à l''issue de chaque période d''activité, selon le modèle 
arrêté par le Gouvernement. 
 
Il doit être soumis au visa du membre du personnel qu''il concerne. 
 
La mention du rapport sur la manière de servir est motivée, à peine de 
nullité, sur la base d''au moins un fait favorable ou défavorable rédigé au 
moment de sa survenance. Ce fait doit être détaillé, daté et signé par le 
directeur et le membre du personnel et soumis au visa de ce dernier pour 
réception. La procédure se poursuit lorsque le membre du personnel refuse de 
viser le rapport. 
 
§2. Le membre du personnel a le droit d''introduire un recours, dans les 
dix jours ouvrables de la notification dudit rapport devant la Chambre de 
recours visée à la section 2 du chapitre VIII du présent arrêté. Le membre du 
personnel qui fait usage de son droit de recours en notifie immédiatement une 
copie au pouvoir organisateur. Ce recours est suspensif. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '24', '1', 'Article 24 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 63, 'Art. 25', 'Article 25. - A l''article 12 du même arrêté royal, le point 8° est remplacé 
par le point 8° suivant : 
 
« 8° Ne pas avoir fait l''objet, dans la fonction à conférer, pendant les deux 
dernières années scolaires et avant la date de l''appel aux candidats, d''un 
rapport sur la manière de servir ou d''un rapport d''évaluation portant la 
mention défavorable. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '25', NULL, 'Article 25 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 64, 'Art. 26 § 2', 'Article 26. - A l''article 16, §2 du même arrêté royal, les mots « ou de 
