INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 65, 'Art. 27', 'Article 27. - A l''article 17, l''alinéa 1er du même arrêté royal est remplacé 
par l''alinéa 1er rédigé comme suit :  
 
 
 
Docu 51683 
 
