INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 68, 'Art. 30', 'Article 30. - Après l''article 26 du même arrêté royal, il est inséré un 
