INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 69, 'Art. 26', 'Article 26/1. - Le Chapitre VIIIbis relatif à l''évaluation des membres du 
