INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 73, 'Art. 35 § 3', 'Article 35. - A l''article 34quater, §3, du décret du 1er février 1993 fixant 
le statut des membres du personnel subsidiés de l''enseignement libre 
subventionné, le 6ème et dernier alinéa est complété d''un 6° rédigé comme 
suit : 
 
« 6° le membre du personnel se voit attribuer par le pouvoir organisateur 
au sein duquel cette affectation a lieu, deux mentions « défavorable » 
consécutives, sur deux années scolaires distinctes, devenue définitives après 
épuisement des procédures devant la chambre de recours, telles que visées à 
l''article 47ter/5 pour la fonction concernée au sein d''un pouvoir organisateur 
de l''enseignement libre subventionné de même caractère. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '35', '3', 'Article 35 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 74, 'Art. 36 § 3', 'Article 36. - A l''article 42, §3, du même décret, les modifications 
suivantes sont insérées : 
 
1° à l''alinéa 1er, après les termes « au visa de l''intéressé. », la phrase 
suivante est insérée comme suit :  
 
« A défaut d''un accord en Commission paritaire centrale dans un délai de 
quatre mois, le Gouvernement statue en lieu et place de cette dernière. » ; 
 
2° un alinéa 13 est inséré comme suit :  
 
« L''attribution d''une première mention « défavorable » définitive lors de 
l''évaluation visée à la section 4 du présent chapitre équivaut à un rapport 
« défavorable » à l''évaluation précédant l''engagement à titre définitif, tel que 
visé au présent paragraphe. Par année scolaire, le membre du personnel ne 
peut pas faire l''objet à la fois d''un rapport d''évaluation visé dans la section 4 
du présent chapitre et d''un rapport à l''évaluation précédant l''engagement à 
titre définitif tel que visé au précédent paragraphe. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '3', 'Article 36 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 75, 'Art. 37', 'Article 37. - Une nouvelle section 4 est introduite après la section 3 du 
chapitre III du même décret, intitulée comme suit : 
 
« Section 4. - Du mécanisme d''évaluation ». 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '37', NULL, 'Article 37 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 76, 'Art. 38 § 1', 'Article 38. - Dans la section 4 du même décret, insérée par l''article 37, 
les dispositions suivantes sont insérées : 
 
« Article 47ter. - §1er. Une évaluation ne peut avoir lieu qu''une fois par 
année scolaire. 
 
§2. Toute première évaluation doit être précédée d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture 
tels que visés à la section 3 du Chapitre 9 du titre Ier du livre 6 du Code de 
l''enseignement fondamental et de l''enseignement secondaire, à la section 3 du 
chapitre Ibis du décret du 30 juin 1998 relatif à la formation en cours de 
carrière et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement de promotion sociale ou à 
la section 3 du chapitre Ibis du décret du 15 mars 1999 relatif à la formation 
en cours de carrière et au mécanisme de soutien et de développement des 
compétences professionnelles des membres du personnel directeur et 
enseignant et du personnel auxiliaire d''éducation de l''enseignement 
secondaire artistique à horaire réduit subventionné par la Communauté 
française. 
 
§3. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au membre du personnel et 
pour autant que l''entretien de clôture visé à l''article 6.1.9-7, §5, du Code de 
l''enseignement fondamental et de l''enseignement secondaire, à l''article 8.7, §5, 
du décret du 30 juin 1998 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation et des experts de l''enseignement de promotion sociale et à l''article 
8/6, §5, du décret du 15 mars 1999 relatif à la formation en cours de carrière 
et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française ait eu lieu, en cas 
de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste 
et répétée à atteindre les objectifs identifiés avec le membre du personnel dans 
le cadre du plan de développement des compétences professionnelles, le 
directeur rédige un rapport motivé à destination du pouvoir organisateur afin 
qu''il procède à une évaluation du membre du personnel. 
 
Pour le calcul de la période de six mois visée à l''alinéa précédent, sont 
seuls pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
1° les vacances annuelles, à l''exclusion des vacances d''été ; 
 
2° les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '38', '1', 'Article 38 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 77, 'Art. 47ter § 1', 'Article 47ter/1. - §1er. Cette évaluation est menée par le pouvoir 
organisateur sur la base du rapport du directeur, visé à l''article 47ter, §3. 
 
Pour mener l''évaluation, une des conditions suivantes doit être remplie 
par le pouvoir organisateur : 
 
1° soit un membre du pouvoir organisateur a été formé à cette fin via la 
formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement ; 
 
2° soit un membre du pouvoir organisateur est un expert en pédagogie ou 
en ressources humaines ; 
 
3° soit le pouvoir organisateur se fait assister par un expert en pédagogie 
ou en ressources humaines. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel des établissements 
d''enseignement libre subventionné, en activité de service ou pensionnés, ou 
par un représentant d''une organisation syndicale représentative. 
 
§2. A l''issue de l''évaluation, le pouvoir organisateur rédige un rapport 
d''évaluation, qui débouche sur une mention « favorable » ou « défavorable » et 
est formalisée selon le document visé à l''article 47ter/3 ainsi que notifié au 
membre du personnel. 
 
La mention d''évaluation est motivée sur la base des éléments : 
 
1° du rapport du directeur ; 
 
2° du plan de développement des compétences professionnelles ; 
 
3° de l''entretien d''évaluation. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
§3. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le 
membre du personnel doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '1', 'Article 47ter § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 78, 'Art. 47ter § 1', '§1er. Après un délai de minimum six mois d''exercice de 
la fonction suite à la communication au membre du personnel du plan 
d''accompagnement individualisé convenu lors de l''évaluation précédente, une 
nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées. 
 
Toutefois, après une évaluation avec mention défavorable, l''évaluation 
suivante doit intervenir dans un délai maximum de deux ans suivant la 
communication du plan d''accompagnement individualisé faisant suite à la 
précédente évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée au paragraphe 3.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '1', 'Article 47ter § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 79, 'Art. 47ter § 2', '§2. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
1° les vacances annuelles, à l''exclusion des vacances d''été ; 
 
2° les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '2', 'Article 47ter § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 80, 'Art. 47ter § 3', '§3. Le rapport d''évaluation faisant suite à une première évaluation avec 
mention « défavorable » définitive est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable », ou « défavorable » ou, en cas d''un 
commun accord entre le membre du personnel et le pouvoir organisateur sur 
la prolongation du plan d''accompagnement individualisé. Le rapport 
d''évaluation est formalisé selon le document visé à l''article 47ter/3 ainsi que 
notifié au membre du personnel. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel des établissements 
d''enseignement libre subventionné, en activité de service ou pensionnés, ou 
par un représentant d''une organisation syndicale représentative. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '3', 'Article 47ter § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 81, 'Art. 47ter § 4', '§4. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan 
d''accompagnement individualisé précédent que le membre du personnel doit 
atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un 
maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '4', 'Article 47ter § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 82, 'Art. 47ter § 5', '§5. Après une prolongation de plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé. 
 
A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '5', 'Article 47ter § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 83, 'Art. 47ter § 6', '§6. Pour le calcul des délais de trois mois et un an précités, sont seuls pris 
en considération les services effectifs rendus pendant l''exercice de la fonction, 
en ce compris : 
 
1° les vacances annuelles, à l''exclusion des vacances d''été ; 
 
2° les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '47ter', '6', 'Article 47ter § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 84, 'Art. 47ter § 7', '§7. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
