INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 110, 'Art. 48 § 1', 'Article 48. - A l''article 72, §1er du même décret, un 12° est introduit 
