INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 111, 'Art. 49 § 1', 'Article 49. - A l''article 30, §1er du décret du 06 juin 1994 fixant le statut 
des membres du personnel subsidiés de l''enseignement officiel subventionné, 
un alinéa 5 est inséré comme suit : 
 
« L''attribution d''une première mention « défavorable » définitive lors de 
l''évaluation visée à la section 4 du présent chapitre équivaut à un rapport 
« défavorable » précédant la nomination. Par année scolaire, le membre du 
personnel ne peut pas faire l''objet à la fois d''une mention lors de l''évaluation 
visée dans la section 4 du présent chapitre et d''un rapport précédant la 
nomination à titre définitif tel que visé au précédent paragraphe. ». 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '49', '1', 'Article 49 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 112, 'Art. 50', 'Article 50. - A l''article 35 du même décret, un paragraphe 3 est inséré 
comme suit : 
 
« En cas de démission d''office conformément à l''article 58, 11°, le membre 
du personnel perd la priorité acquise auprès du pouvoir concerné. Il la recouvre 
néanmoins si, après cette démission, il est engagé à nouveau par ce pouvoir 
organisateur. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '50', NULL, 'Article 50 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 113, 'Art. 51', 'Article 51. - Une nouvelle section 4 est introduite après la section 3 du 
chapitre III du même décret, intitulée comme suit : 
 
« Section 4. - Du mécanisme d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '51', NULL, 'Article 51 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 114, 'Art. 52 § 1', 'Article 52. - Les dispositions suivantes sont insérées dans la section 4 du 
chapitre III du même décret : 
 
« Article 36duodecies/1. - §1er. Dans la présente section, pour les membres 
du personnel temporaires, il y a lieu d''entendre par « pouvoir organisateur », 
les autorités visées à l''article 27bis. 
 
Pour les membres du personnel définitifs, le pouvoir organisateur visé 
dans la présente section est l''autorité qui exerce le pouvoir de nomination. 
 
§2. Dans la présente section, toute notification de document, de décision 
ou de convocation se fait par courrier recommandé avec accusé de réception ou 
par une remise de la main à la main avec accusé de réception.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52', '1', 'Article 52 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 115, 'Art. 36duodecies § 1', 'Article 36duodecies/2. - §1er. Une évaluation ne peut avoir lieu qu''une fois 
par année scolaire. 
 
§2. Toute première évaluation doit être précédée d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture 
tels que visés à la section 3 du Chapitre 9 du titre Ier du livre 6 du Code de 
l''enseignement fondamental et de l''enseignement secondaire et à la section 3 
du chapitre Ibis du décret du 30 juin 1998 relatif à la formation en cours de 
carrière et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement de promotion sociale ou à 
la section 3 du chapitre Ibis du décret du 15 mars 1999 relatif à la formation 
en cours de carrière et au mécanisme de soutien et de développement des 
compétences professionnelles des membres du personnel directeur et 
enseignant et du personnel auxiliaire d''éducation de l''enseignement 
secondaire artistique à horaire réduit subventionné par la Communauté 
française. 
 
§3. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au membre du personnel et 
pour autant que l''entretien de clôture visé à l''article 6.1.9-7, § 5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire, à l''article 8.7, §5 
du décret du 30 juin 1998 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation et des experts de l''enseignement de promotion sociale et à l''article 
8/6, §5 du décret du 15 mars 1999 relatif à la formation en cours de carrière et 
au 
mécanisme 
de 
soutien 
et 
de 
développement 
des 
compétences 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française ait eu lieu, en cas 
de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste 
et répétée à atteindre les objectifs identifiés avec le membre du personnel dans 
le cadre du plan de développement des compétences professionnelles, le 
directeur rédige un rapport motivé à destination du pouvoir organisateur afin 
qu''il procède à une évaluation du membre du personnel. 
 
Pour le calcul du délai de 6 mois précité, sont seuls pris en considération 
les services effectifs rendus pendant l''exercice de la fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '1', 'Article 36duodecies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 116, 'Art. 36duodecies § 1', 'Article 36duodecies/3. - §1er. Cette évaluation est menée par le pouvoir 
organisateur sur la base du rapport du directeur visé à l''article 36duodecies/2, 
§3. 
 
Pour mener l''évaluation, une des conditions suivantes doit être remplie 
par le pouvoir organisateur : 
 
a. soit un membre du pouvoir organisateur est formé à cette fin via la 
formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement ; 
 
b. soit un membre du pouvoir organisateur est un expert en pédagogie ou 
en ressources humaines ; 
 
c. soit le pouvoir organisateur se fait assister par un expert en pédagogie 
ou en ressources humaines. 
 
§2. Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation, par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel en activité de service ou 
pensionnés de l''enseignement officiel subventionné ou par un représentant 
d''une organisation syndicale représentative. 
 
§3. A l''issue de l''évaluation, le pouvoir organisateur rédige un rapport 
d''évaluation, qui débouche sur une mention « favorable » ou « défavorable » et 
est formalisé selon le document visé à l''article 36duodecies/5 ainsi que notifié 
au membre du personnel. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
La mention d''évaluation est motivée sur la base des éléments : 
 
- du rapport du directeur ; 
 
- du plan de développement des compétences professionnelles ; 
 
- de l''entretien d''évaluation. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
§4. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le 
membre du personnel doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '1', 'Article 36duodecies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 117, 'Art. 36duodecies § 1', '§1er. Après un délai de minimum six mois 
d''exercice de la fonction entre la communication au membre du personnel du 
plan d''accompagnement individualisé convenu lors de l''évaluation avec 
mention défavorable précédente, une nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées. 
 
Après une évaluation avec mention « défavorable », l''évaluation suivante 
doit intervenir dans un délai maximum de deux ans suivant la communication 
du plan d''accompagnement individualisé faisant suite à la précédente 
évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée au paragraphe 3.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '1', 'Article 36duodecies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 118, 'Art. 36duodecies § 2', '§2. Pour le calcul des délais de six mois et de deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '2', 'Article 36duodecies § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 119, 'Art. 36duodecies § 3', '§3. A l''issue de l''évaluation, le pouvoir organisateur rédige un rapport 
d''évaluation, qui débouche sur une mention « favorable » ou « défavorable » ou, 
en cas d''un commun accord entre le membre du personnel et le pouvoir 
organisateur sur la prolongation du plan d''accompagnement individualisé. Le 
rapport d''évaluation est formalisé selon le document visé à l''article 
36duodecies/5 ainsi que notifié au membre du personnel. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation, par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel en activité de service ou 
pensionnés de l''enseignement officiel subventionné ou par un représentant 
d''une organisation syndicale représentative. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé.

§4. En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '3', 'Article 36duodecies § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 120, 'Art. 36duodecies § 5', '§5. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan 
d''accompagnement individualisé précédent que le membre du personnel doit 
atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un 
maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '5', 'Article 36duodecies § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 121, 'Art. 36duodecies § 6', '§6. Après une prolongation de plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé.  
 
A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées dans le cadre de l''évaluation précédente.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '6', 'Article 36duodecies § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 122, 'Art. 36duodecies § 7', '§7. Pour le calcul des délais de trois mois et un an précités, sont seuls pris 
en considération les services effectifs rendus pendant l''exercice de la fonction, 
en ce compris : 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '7', 'Article 36duodecies § 7 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 123, 'Art. 36duodecies § 8', '§8. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 36duodecies/5 ainsi que notifié au membre du 
personnel. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel des établissements 
d''enseignement officiel subventionné, en activité de service ou pensionnés, ou 
par un représentant d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '8', 'Article 36duodecies § 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 124, 'Art. 36duodecies', 'Article 36duodecies/5. - Le Gouvernement fixe le modèle de rapport de la 
direction à destination du pouvoir organisateur, de plan d''accompagnement 
individualisé et de rapport d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', NULL, 'Article 36duodecies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 125, 'Art. 36duodecies', 'Article 36duodecies/6. - La répétition de deux mentions « défavorable » 
consécutives sur deux années scolaires distinctes, et devenues définitives 
après épuisement des procédures devant la chambre de recours, telles que 
visées à l''article 36duodecies/7, a pour conséquence : 
 
- la fin de fonction d''office dans la fonction considérée ; 
 
- la perte de priorité pour tout nouvel emploi dans la fonction considérée 
au sein du même pouvoir organisateur au cours de la même année scolaire et 
lors des années scolaires suivantes. Il la recouvre néanmoins s''il est recruté à 
nouveau ultérieurement par ce même pouvoir organisateur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', NULL, 'Article 36duodecies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 126, 'Art. 36duodecies § 1', 'Article 36duodecies/7. - §1er. Le membre du personnel qui se voit attribuer 
une mention « défavorable » peut, dans les dix jours ouvrables qui suivent la 
réception de ce rapport, introduire, un recours devant la Chambre de recours 
visée au chapitre X. Le membre du personnel qui fait usage de son droit de 
recours en notifie immédiatement une copie à son pouvoir organisateur. Ce 
recours est suspensif. 
 
§2. Lorsque la mention défavorable est liée, en tout ou en partie, à un 
objectif qui porte sur la compétence pédagogique du membre du personnel, la 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
chambre de recours peut faire appel au Service général de l''Inspection en sa 
qualité d''expert, sur des aspects techniques relatifs aux dimensions 
disciplinaires et/ou didactiques. 
 
Le président de la Chambre invite alors un représentant du Service 
général de l''Inspection, soit d''initiative, soit à la demande d''un ou plusieurs 
membres, soit à la demande du membre du personnel concerné par le recours. 
 
§3. Lors de l''audition, le membre du personnel peut se faire assister par 
un avocat, par un défenseur choisi parmi les membres du personnel des 
établissements d''enseignement officiel subventionné, en activité de service ou 
pensionnés, 
ou 
par 
un 
représentant 
d''une 
organisation 
syndicale 
représentative. 
 
L''audition fait l''objet d''un procès-verbal. 
 
La procédure se poursuit valablement lorsque le membre du personnel 
dûment convoqué ne se présente pas à l''audition. 
 
§4. L''avis est donné après un vote secret. En cas d''avis rendu à 
l''unanimité ou à la majorité simple des voix plus une, l''avis de la Chambre de 
recours est contraignant. En cas de parité des voix uniquement, le président 
décide. Dans ce cas, l''avis de la chambre de recours n''est pas contraignant. 
 
La Chambre de recours donne son avis au pouvoir organisateur dans un 
délai de 45 jours à partir de la date de réception du recours. L''avis de la 
Chambre de recours doit indiquer si, sur base des éléments qui lui sont soumis, 
la mention attribuée au membre du personnel est justifiée ou ne l''est pas. 
L''avis de la Chambre de recours ne propose pas d''alternative à la décision du 
pouvoir organisateur. 
 
§5. Le pouvoir organisateur prend sa décision dans un délai de 30 jours à 
partir de la réception de l''avis visé à l''alinéa précédent et notifie sa décision à 
la Chambre de recours et au membre du personnel. Le cas échéant, le pouvoir 
organisateur indique les raisons pour lesquelles l''avis de la Chambre de 
recours n''a pas été suivi.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '1', 'Article 36duodecies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','discipline','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 127, 'Art. 36duodecies § 1', 'Article 36duodecies /8. - §1er. Le pouvoir organisateur qui envisage une 
procédure pouvant conduire à l''attribution d''une mention d''évaluation 
« défavorable » à un délégué syndical dans le cadre de la procédure fixée dans 
la présente section doit, sous peine de nullité, en informer préalablement la 
délégation syndicale si celle-ci est composée de plusieurs délégués, ainsi que 
l''organisation syndicale qui l''a désigné. Cette information se fait par lettre 
recommandée sortant ses effets le 3ème jour ouvrable suivante la date de son 
expédition. 
 
§2. L''organisation syndicale intéressée dispose d''un délai de 10 jours pour 
notifier conformément à l''article 36duodecies/1, §2 au pouvoir organisateur, 
avec copie au président de la Commission paritaire centrale compétente, 
qu''elle considère que la mesure envisagée est inspirée par des motifs inhérents 
à l''exercice du mandat syndical et peut demander la tenue d''un bureau de 
conciliation. Le délai de 10 jours prend cours le jour où la lettre recommandée 
envoyée par le pouvoir organisateur sort ses effets. Toutefois, le délai de 10 
jours est suspendu du 15 juillet au 15 août. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§3. L''absence de réaction de l''organisation syndicale concernée dans le 
délai imparti, signifie dans son chef qu''elle considère que la mesure envisagée 
n''est pas inspirée par des motifs inhérents à l''exercice du mandat syndical. 
 
§4. A l''expiration du délai de 10 jours, le pouvoir organisateur peut 
poursuivre 
la 
procédure 
d''attribution 
d''une 
mention 
d''évaluation 
« défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', '1', 'Article 36duodecies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 128, 'Art. 36duodecies', 'Article 36duodecies/9. - Dans le cadre des entretiens et évaluations visés 
à la présente section, le membre du personnel et son évaluateur sont tenus au 
respect des devoirs suivants : 
 
a) la discrétion ; 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
a) 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36duodecies', NULL, 'Article 36duodecies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 129, 'Art. 53 § 6', 'Article 53. - A l''article 44sexies du même décret, un paragraphe 6 est 
inséré comme suit : 
 
« §6. Les coordonnateurs de centre de technologies avancées nommés à 
titre définitif sont évalués selon les dispositions prévues à la section II du 
Chapitre Vbis du présent titre, applicables mutatis mutandis. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '53', '6', 'Article 53 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 130, 'Art. 54', 'Article 54. - A l''article 44decies/2 du même décret, un alinéa 3 est inséré 
comme suit : 
 
« Les coordonnateurs de pôles territoriaux nommés à titre définitif sont 
évalués selon les dispositions prévues à la section II du Chapitre Vbis du 
présent titre, applicables mutatis mutandis. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '54', NULL, 'Article 54 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 131, 'Art. 55 § 1', 'Article 55. - A l''article 52quinquies du même décret, les modifications 
suivantes sont apportées au §1er : 
 
1° à l''alinéa 1er, les termes « et 5, §3, 1° et 2° du décret du 04 janvier 1999 » 
sont remplacés par les termes « et 5, §3 du décret du 04 janvier 1999 » ; 
 
2° à l''alinéa 3, les mots « A l''exception de la section Iter relative à la lettre 
de mission, » sont abrogés.

Article 56. - L''intitulé de la section 2 du Chapitre Vbis du même décret 
est remplacé par : 
 
« Section 2. - Du mécanisme d''évaluation ».

Article 57. - L''article 52novies alinéa 2 du même décret est abrogé. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '55', '1', 'Article 55 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 132, 'Art. 58 § 1', 'Article 58. - Les dispositions suivantes sont insérées dans la section 2 du 
Chapitre Vbis du même décret : 
 
« Article 52novies/1. - §1er. Pour les membres du personnel nommés à titre 
définitif, le pouvoir organisateur visé dans la présente section est l''autorité qui 
exerce le pouvoir de nomination. 
 
§2. Dans la présente section, toute notification de document, de décision 
ou de convocation se fait par courrier recommandé avec accusé de réception ou 
par une remise de la main à la main avec accusé de réception.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '58', '1', 'Article 58 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 133, 'Art. 52novies § 1', 'Article 52novies/2. - §1er. Une évaluation ne peut avoir lieu qu''une fois 
par année scolaire. 
 
§2. Toute première évaluation doit être précédée d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture 
tels que visés à la section 4 du Chapitre 9 du titre Ier du livre 6 du Code de 
l''enseignement fondamental et de l''enseignement secondaire et à la section 4 
du chapitre Ibis du décret du 30 juin 1998 relatif à la formation en cours de 
carrière et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement de promotion sociale ou à 
la section 4 du chapitre Ibis du décret du 15 mars 1999 relatif à la formation 
en cours de carrière et au mécanisme de soutien et de développement des 
compétences professionnelles des membres du personnel directeur et 
enseignant et du personnel auxiliaire d''éducation de l''enseignement 
secondaire artistique à horaire réduit subventionné par la Communauté 
française. 
 
§3. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au membre du personnel et 
pour autant que l''entretien de clôture visé à l''article 6.1.9-9, §5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire, à l''article 8.9, §5 
du décret du 30 juin 1998 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation et des experts de l''enseignement de promotion sociale et à l''article 
8/8, §5 du décret du 15 mars 1999 relatif à la formation en cours de carrière et 
au 
mécanisme 
de 
soutien 
et 
de 
développement 
des 
compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française ait eu lieu, en cas 
de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste 
et répétée à atteindre les objectifs identifiés avec le membre du personnel dans 
le cadre du plan de développement des compétences professionnelles, le 
directeur rédige un rapport motivé à destination du pouvoir organisateur afin 
qu''il procède à une évaluation du membre du personnel. 
 
§4. Pour le calcul du délai de 6 mois précité, sont seuls pris en 
considération les services effectifs rendus pendant l''exercice de la fonction, en 
ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '1', 'Article 52novies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 134, 'Art. 52novies § 1', 'Article 52novies/3. - §1er. Cette évaluation est menée par le pouvoir 
organisateur sur la base du rapport du directeur visé à l''article 52novies/2, §3. 
 
Pour mener l''évaluation, une des conditions suivantes doit être remplie 
par le pouvoir organisateur : 
 
a. soit un membre du pouvoir organisateur est formé à cette fin via la 
formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement ; 
 
b. soit un membre du pouvoir organisateur est un expert en pédagogie ou 
en ressources humaines ; 
 
c. soit le pouvoir organisateur se fait assister par un expert en pédagogie 
ou en ressources humaines. 
 
§2. Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation, par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel en activité de service ou 
pensionnés de l''enseignement officiel subventionné ou par un représentant 
d''une organisation syndicale représentative. 
 
§3. A l''issue de cette évaluation, le pouvoir organisateur rédige un rapport 
d''évaluation, comportant l''une des mentions suivantes « favorable » ou 
« défavorable ». L''évaluation est formalisée selon le document visé à l''article 
52novies/5 et notifiée au membre du personnel. 
 
La mention d''évaluation est motivée sur la base des éléments : 
 
- du rapport du directeur ; 
 
- du plan de développement des compétences professionnelles ; 
 
- de l''entretien d''évaluation. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
§4. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
mettre en place un nouveau plan d''accompagnement individualisé, basé sur 
les éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que 
le membre du personnel doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '1', 'Article 52novies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 135, 'Art. 52novies § 1', '§1er. Après un délai de minimum six mois d''exercice 
de la fonction suite à la communication au membre du personnel du plan 
d''accompagnement individualisé convenu lors de l''évaluation avec mention 
défavorable qui précède, une nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées. 
 
Après une évaluation avec mention « défavorable », l''évaluation suivante 
doit intervenir dans un délai maximum de deux ans suivant la communication 
du plan d''accompagnement individualisé faisant suite à la précédente 
évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée au paragraphe 3.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '1', 'Article 52novies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 136, 'Art. 52novies § 2', '§2. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '2', 'Article 52novies § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 137, 'Art. 52novies § 3', '§3. 
Lors 
de 
l''évaluation 
suivant 
l''attribution 
d''une 
mention 
« défavorable » définitive, le pouvoir organisateur rédige un rapport 
d''évaluation, qui débouche sur une mention « favorable » ou « défavorable » ou, 
en cas d''un commun accord entre le membre du personnel et le pouvoir 
organisateur sur la prolongation du plan d''accompagnement individualisé. Le 
rapport d''évaluation est formalisé selon le document visé à l''article 52novies/5 
ainsi que notifié au membre du personnel. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation, par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel en activité de service ou 
pensionnés de l''enseignement officiel subventionné ou par un représentant 
d''une organisation syndicale représentative.

§4. En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '3', 'Article 52novies § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 138, 'Art. 52novies § 5', '§5. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan 
d''accompagnement individualisé précédent que le membre du personnel doit 
atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un 
maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '5', 'Article 52novies § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 139, 'Art. 52novies § 6', '§6. Après une prolongation du plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé convenu lors 
de l''évaluation précédente. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées. 
 
A défaut, elle est réputée favorable.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '6', 'Article 52novies § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 140, 'Art. 52novies § 7', '§7. Pour le calcul des délais de trois mois et un an précités, sont seuls pris 
en considération les services effectifs rendus pendant l''exercice de la fonction, 
en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '7', 'Article 52novies § 7 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 141, 'Art. 52novies § 8', '§8. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 52novies/5 ainsi que notifié au membre du 
personnel. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel des établissements 
d''enseignement officiel subventionné, en activité de service ou pensionnés, ou 
par un représentant d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '8', 'Article 52novies § 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 142, 'Art. 52novies', 'Article 52novies/5. - Le Gouvernement fixe le modèle de rapport de la 
direction à destination du pouvoir organisateur, de plan d''accompagnement 
individualisé et le rapport d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', NULL, 'Article 52novies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 143, 'Art. 52novies', 'Article 52novies/6. - La répétition de deux mentions « défavorable » 
consécutives sur deux années scolaires distinctes, devenues définitives après 
épuisement des procédures devant la chambre de recours, telles que visées à 
l''article 52novies/7, a pour conséquence la fin de fonction d''office, 
conformément à l''article 58.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', NULL, 'Article 52novies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 144, 'Art. 52novies § 1', 'Article 52novies/7. - §1er. Le membre du personnel qui se voit attribuer 
une mention « défavorable » peut, dans les dix jours ouvrables qui suivent la 
réception de ce rapport, introduire, un recours devant la Chambre de recours 
visée au chapitre X. Le membre du personnel qui fait usage de son droit de 
recours en notifie immédiatement une copie à son pouvoir organisateur. Ce 
recours est suspensif. 
 
§2. Lorsque la mention défavorable est liée, en tout ou en partie, à un 
objectif qui porte sur la compétence pédagogique du membre du personnel, la 
chambre de recours peut faire appel au Service général de l''Inspection en sa 
qualité d''expert, sur des aspects techniques relatifs aux dimensions 
disciplinaires et/ou didactiques. 
 
Le Président de la chambre invite alors un représentant du Service 
général de l''Inspection, soit d''initiative, soit à la demande d''un ou plusieurs 
membres, soit à la demande du membre du personnel concerné par le recours. 
 
§3. Lors de l''audition, le membre du personnel peut se faire assister par 
un avocat, par un défenseur choisi parmi les membres du personnel des 
établissements d''enseignement officiel subventionné, en activité de service ou 
pensionnés, 
ou 
par 
un 
représentant 
d''une 
organisation 
syndicale 
représentative. 
 
L''audition fait l''objet d''un procès-verbal. 
 
La procédure se poursuit valablement lorsque le membre du personnel 
dûment convoqué ne se présente pas à l''audition. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§4. L''avis est donné après un vote secret. En cas d''avis rendu à 
l''unanimité ou à la majorité simple des voix plus une, l''avis de la Chambre de 
recours est contraignant. En cas de parité des voix uniquement, le président 
décide. Dans ce cas, l''avis de la chambre de recours n''est pas contraignant. 
 
La Chambre de recours donne son avis au pouvoir organisateur dans un 
délai de 45 jours à partir de la date de réception du recours. L''avis de la 
Chambre de recours doit indiquer si, sur base des éléments qui lui sont soumis, 
la mention attribuée au membre du personnel est justifiée ou ne l''est pas. 
L''avis de la Chambre de recours ne propose pas d''alternative à la décision du 
pouvoir organisateur. 
 
§5. Le pouvoir organisateur prend sa décision dans un délai de 30 jours à 
partir de la réception de l''avis visé à l''alinéa précédent et notifie sa décision à 
la Chambre de recours et au membre du personnel. Le cas échéant, le pouvoir 
organisateur indique les raisons pour lesquelles l''avis de la Chambre de 
recours n''a pas été suivi.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', '1', 'Article 52novies § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','discipline','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 145, 'Art. 52novies', 'Article 52novies/8. - Le pouvoir organisateur qui envisage une procédure 
pouvant conduire à l''attribution d''une mention d''évaluation « défavorable » à 
un délégué syndical dans le cadre de la procédure fixée dans la présente section 
doit, sous peine de nullité, en informer préalablement la délégation syndicale 
si celle-ci est composée de plusieurs délégués, ainsi que l''organisation 
syndicale qui l''a désigné. Cette information se fait par lettre recommandée 
sortant ses effets le 3ème jour ouvrable suivante la date de son expédition. 
 
§2. L''organisation syndicale intéressée dispose d''un délai de 10 jours pour 
notifier par lettre recommandée au pouvoir organisateur, avec copie au 
président de la Commission paritaire centrale compétente, qu''elle considère 
que la mesure envisagée est inspirée par des motifs inhérents à l''exercice du 
mandat syndical et peut demander la tenue d''un bureau de conciliation. Le 
délai de 10 jours prend cours le jour où la lettre recommandée envoyée par le 
pouvoir organisateur sort ses effets. Toutefois, le délai de 10 jours est suspendu 
du 15 juillet au 15 août. 
 
§3. L''absence de réaction de l''organisation syndicale concernée dans le 
délai imparti, signifie dans son chef qu''elle considère que la mesure envisagée 
n''est pas inspirée par des motifs inhérents à l''exercice du mandat syndical. 
 
§4. A l''expiration du délai de 10 jours, le pouvoir organisateur peut 
poursuivre 
la 
procédure 
d''attribution 
d''une 
mention 
d''évaluation 
« défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', NULL, 'Article 52novies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 146, 'Art. 52novies', 'Article 52novies/9. - Dans le cadre des entretiens et évaluations visés à la 
présente section, le membre du personnel et son évaluateur sont tenus au 
respect des devoirs suivants : 
 
a) la discrétion ; 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
a) 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ».

Article 59. - Les articles 52decies à 52duodecies du même décret sont 
abrogés.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '52novies', NULL, 'Article 52novies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
