INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 148, 'Art. 61', 'Article 61. - A l''article 58 du même décret, un 11° est introduit comme 
