INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 149, 'Art. 62 § 1', 'Article 62. - L''article 28bis, §1er du décret du 04 janvier 1999 relatif aux 
