INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 150, 'Art. 63', 'Article 63. - Les mots « Section II. - De l''évaluation formative » sont 
