INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 151, 'Art. 64', 'Article 64. - L''article 28septies du même décret est remplacé par ce qui 
