INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 152, 'Art. 65', 'Article 65. - L''article 28octies du même décret est remplacé par ce qui 
suit : 
 
« Article 28octies. - Pour les membres du personnel visés à l''article 28bis 
du même décret, un entretien de développement professionnel doit avoir lieu 
dans la mesure du possible une fois par an, et, au minimum, une fois tous les 
trois ans. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Cet entretien de développement professionnel se fonde : 
 
- sur la lettre de mission ; 
 
- sur les compétences professionnelles mentionnées dans l''appel à 
candidatures ; 
 
- sur la mise en œuvre du contrat d''objectifs. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', NULL, 'Article 65 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI','pilotage'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 153, 'Art. 66', 'Article 66. - L''article 28novies du présent décret est abrogé. 
 
