INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 154, 'Art. 67 § 1', 'Article 67. - A l''article 24, §1er du décret du 10 mars 2006 relatif aux 
