INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 155, 'Art. 68 § 1', 'Article 68. - A l''article 31, §1er du même décret, un nouvel alinéa 5 est 
inséré comme suit : 
 
« L''attribution d''une première mention « défavorable » définitive lors de 
l''évaluation visée à la section V du présent chapitre équivaut à un rapport 
« défavorable » précédant la nomination. Par année scolaire, le membre du 
personnel ne peut pas faire l''objet à la fois d''une mention lors de l''évaluation 
visée dans la section V du présent chapitre et d''un rapport à l''évaluation 
précédant la nomination à titre définitif tel que visé au précédent 
paragraphe. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '68', '1', 'Article 68 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 156, 'Art. 69', 'Article 69. - Une nouvelle section V est insérée après la section IV du 
chapitre III du titre Ier du même décret, intitulée comme suit : 
 
« Section V. - Du mécanisme d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '69', NULL, 'Article 69 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 157, 'Art. 70 § 1', 'Article 70. - Les dispositions suivantes sont insérées dans la section V 
précitée du même décret : 
 
« Article 36/1. - §1er. Dans la présente section, pour les membres du 
personnel temporaires, il y a lieu d''entendre par « pouvoir organisateur », les 
autorités visées à l''article 19. 
 
Pour les membres du personnel définitifs, le pouvoir organisateur visé 
dans la présente section est l''autorité qui exerce le pouvoir de nomination. 
 
§2. Dans la présente section, toute notification de document, de décision 
ou de convocation se fait par courrier recommandé avec accusé de réception ou 
par une remise de la main à la main avec accusé de réception.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '70', '1', 'Article 70 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 158, 'Art. 36 § 1', 'Article 36/2. - §1er. Une évaluation ne peut avoir lieu qu''une fois par année 
scolaire. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§2. A l''exception de l''évaluation précédant la nomination à titre définitif, 
l''évaluation doit être précédée d''un plan de développement des compétences 
professionnelles tel que visés à la section 3 du Chapitre 9 du titre Ier du livre 6 
du Code de l''enseignement fondamental et de l''enseignement secondaire et 
d''un entretien de clôture. 
 
§3. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au membre du personnel et 
pour autant que l''entretien de clôture visé à l''article 6.1.9-7, §5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire, à l''article 8.7, §5 
du décret du 30 juin 1998 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation et des experts de l''enseignement de promotion sociale et à l''article 
8/6, §5 du décret du 15 mars 1999 relatif à la formation en cours de carrière et 
au 
mécanisme 
de 
soutien 
et 
de 
développement 
des 
compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française ait eu lieu, en cas 
de mauvaise volonté manifeste en lien avec ledit plan ou de carence manifeste 
et répétée à atteindre les objectifs identifiés avec le membre du personnel dans 
le cadre du plan de développement des compétences professionnelles, le 
directeur rédige un rapport motivé à destination du pouvoir organisateur afin 
qu''il procède à une évaluation du membre du personnel. 
 
Pour le calcul du délai de six mois précité, sont seuls pris en considération 
les services effectifs rendus pendant l''exercice de la fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '1', 'Article 36 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 159, 'Art. 36 § 1', 'Article 36/3. - §1er. Cette évaluation est menée par le pouvoir organisateur 
sur la base du rapport du directeur visé à l''article 36/2, §3. 
 
Pour mener l''évaluation, une des conditions suivantes doit être remplie 
par le pouvoir organisateur : 
 
a. soit un membre du pouvoir organisateur est formé à cette fin via la 
formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement ; 
 
b. soit un membre du pouvoir organisateur est un expert en pédagogie ou 
en ressources humaines ; 
 
c. soit le pouvoir organisateur se fait assister par un expert en pédagogie 
ou en ressources humaines. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§2. Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation, par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel en activité de service ou 
pensionnés de l''enseignement officiel subventionné ou par un représentant 
d''une organisation syndicale représentative. 
 
§3. A l''issue de l''évaluation, le pouvoir organisateur rédige un rapport 
d''évaluation, qui débouche sur une mention « favorable » ou « défavorable » et 
est formalisé selon le document visé à l''article 36/5 ainsi que notifié au membre 
du personnel. 
 
La mention d''évaluation est motivée sur la base des éléments : 
 
- du rapport du directeur ; 
 
- du plan de développement des compétences professionnelles ; 
 
- de l''entretien d''évaluation. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
Le rapport d''évaluation vise uniquement l''action éducative, la tenue, la 
présentation, le sens des responsabilités. Il reprend à son compte le contenu 
d''un éventuel rapport d''inspection individuel portant sur les aptitudes 
pédagogiques. 
 
§4. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est, ensuite, fixé 
afin de mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le 
membre du personnel doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '1', 'Article 36 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 160, 'Art. 36 § 1', '§1er. Après un délai de minimum six mois d''exercice de la 
fonction entre la communication au membre du personnel du plan 
d''accompagnement individualisé convenu lors de l''évaluation avec mention 
défavorable précédente, une nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées. 
 
Après une évaluation avec mention « défavorable », l''évaluation suivante 
doit intervenir dans un délai, maximum, de deux ans suivant la 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
communication du plan d''accompagnement individualisé faisant suite à la 
précédente évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée au paragraphe 3.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '1', 'Article 36 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 161, 'Art. 36 § 2', '§2. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
