INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 163, 'Art. 36 § 4', '§4. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et/ou le directeur à qui il 
donne délégation et, d''autre part, le membre du personnel est fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci reprend les objectifs du plan 
d''accompagnement individualisé précédent que le membre du personnel doit 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
atteindre pour obtenir une mention favorable lors de l''évaluation suivante. Un 
maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '4', 'Article 36 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 164, 'Art. 36 § 5', '§5. Après une prolongation de plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé. 
 
A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au membre du personnel de remédier aux 
carences constatées.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '5', 'Article 36 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
