INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 166, 'Art. 36 § 7', '§7. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 36/5 ainsi que notifié au membre du personnel. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le membre du personnel doit avoir été entendu préalablement à 
l''attribution de sa mention d''évaluation par le pouvoir organisateur. La 
convocation doit lui être notifiée cinq jours ouvrables au moins avant 
l''audition, soit par lettre recommandée à la poste avec accusé de réception, soit 
par la remise d''une lettre de la main à la main avec accusé de réception. Lors 
de l''entretien d''évaluation, le membre du personnel peut se faire assister par 
un défenseur choisi parmi les membres du personnel des établissements 
d''enseignement officiel subventionné, en activité de service ou pensionnés, ou 
par un représentant d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '7', 'Article 36 § 7 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 167, 'Art. 36', 'Article 36/5. - Le Gouvernement fixe le modèle de rapport de la direction 
à destination du pouvoir organisateur, de plan d''accompagnement 
individualisé et de rapport d''évaluation. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', NULL, 'Article 36 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 168, 'Art. 36', 'Article 36/6. - La répétition de deux mentions « défavorable » consécutives 
sur deux années scolaires distinctes, devenues définitives après épuisement 
des procédures devant la chambre de recours, telles que visées à l''article 36/7, 
a pour conséquence : 
 
a) la fin de fonction d''office dans la fonction considérée ; 
 
b) la perte de priorité pour tout nouvel emploi dans la fonction considérée 
au sein du même pouvoir organisateur au cours de la même année scolaire et 
lors des années scolaires suivantes. Il la recouvre néanmoins s''il est recruté à 
nouveau ultérieurement par ce même pouvoir organisateur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', NULL, 'Article 36 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 169, 'Art. 36 § 1', 'Article 36/7. - §1er. Le membre du personnel qui se voit attribuer une 
mention « défavorable » peut, dans les dix jours ouvrables qui suivent la 
réception de ce rapport, introduire, un recours devant la Chambre de recours 
visée au Chapitre V du Titre Ier. Le membre du personnel qui fait usage de son 
droit de recours en notifie immédiatement une copie à son pouvoir 
organisateur. Ce recours est suspensif. 
 
§2. Lorsque la mention défavorable est liée, en tout ou en partie, à un 
objectif qui porte sur la compétence pédagogique du membre du personnel, la 
chambre de recours peut faire appel au Service général de l''Inspection en sa 
qualité d''expert, sur des aspects techniques relatifs aux dimensions 
disciplinaires et/ou didactiques. 
 
Le président de la Chambre invite alors un représentant du Service 
général de l''Inspection, soit d''initiative, soit à la demande d''un ou plusieurs 
membres, soit à la demande du membre du personnel concerné par le recours. 
 
§3. Lors de l''audition, le membre du personnel peut se faire assister par 
un avocat, par un défenseur choisi parmi les membres du personnel des 
établissements d''enseignement officiel subventionné, en activité de service ou 
pensionnés, 
ou 
par 
un 
représentant 
d''une 
organisation 
syndicale 
représentative. 
 
L''audition fait l''objet d''un procès-verbal. 
 
La procédure se poursuit valablement lorsque le membre du personnel 
dûment convoqué ne se présente pas à l''audition. 
 
§4. L''avis est donné après un vote secret. En cas d''avis rendu à 
l''unanimité ou à la majorité simple des voix plus une, l''avis de la Chambre de 
recours est contraignant. En cas de parité des voix uniquement, le président 
décide. Dans ce cas, l''avis de la chambre de recours n''est pas contraignant. 
 
La Chambre de recours donne son avis au pouvoir organisateur dans un 
délai de 45 jours à partir de la date de réception du recours. L''avis de la 
Chambre de recours doit indiquer si, sur base des éléments qui lui sont soumis, 
la mention attribuée au membre du personnel est justifiée ou ne l''est pas. 
L''avis de la Chambre de recours ne propose pas d''alternative à la décision du 
pouvoir organisateur. 
 
§5. Le pouvoir organisateur prend sa décision dans un délai de 30 jours à 
partir de la réception de l''avis visé à l''alinéa précédent et notifie sa décision à 
la Chambre de recours et au membre du personnel. Le cas échéant, le pouvoir 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
organisateur indique les raisons pour lesquelles l''avis de la Chambre de 
recours n''a pas été suivi.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '1', 'Article 36 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','discipline','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 170, 'Art. 36 § 1', 'Article 36/8. - §1er. Le pouvoir organisateur qui envisage une procédure 
pouvant conduire à l''attribution d''une mention d''évaluation « défavorable » à 
un délégué syndical dans le cadre de la procédure fixée dans cette section V 
doit, sous peine de nullité, en informer préalablement la délégation syndicale 
si celle-ci est composée de plusieurs délégués, ainsi que l''organisation 
syndicale qui l''a désigné. Cette information se fait par lettre recommandée 
sortant ses effets le 3ème jour ouvrable suivante la date de son expédition. 
 
§2. L''organisation syndicale intéressée dispose d''un délai de 10 jours pour 
notifier par lettre recommandée au pouvoir organisateur, avec copie au 
président de la Commission paritaire centrale compétente, qu''elle considère 
que la mesure envisagée est inspirée par des motifs inhérents à l''exercice du 
mandat syndical et peut demander la tenue d''un bureau de conciliation. Le 
délai de 10 jours prend cours le jour où la lettre recommandée envoyée par le 
pouvoir organisateur sort ses effets. Toutefois, le délai de 10 jours est suspendu 
du 15 juillet au 15 août. 
 
§3. L''absence de réaction de l''organisation syndicale concernée dans le 
délai imparti, signifie dans son chef qu''elle considère que la mesure envisagée 
n''est pas inspirée par des motifs inhérents à l''exercice du mandat syndical. 
 
§4. A l''expiration du délai de 10 jours, le pouvoir organisateur peut 
poursuivre 
la 
procédure 
d''attribution 
d''une 
mention 
d''évaluation 
« défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', '1', 'Article 36 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','obligation scolaire','parents'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 171, 'Art. 36', 'Article 36/9. - Dans le cadre des entretiens et évaluations, le membre du 
personnel et son évaluateur sont tenus au respect des devoirs suivants : 
 
a) la discrétion ; 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
a) 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '36', NULL, 'Article 36 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 172, 'Art. 71', 'Article 71. - A l''article 110 du même décret, un 13° est inséré comme 
