INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 175, 'Art. 74', 'Article 74. - L''article 46 du même décret est remplacé par ce qui suit : 
 
