INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 176, 'Art. 75', 'Article 75. - Un article 46bis est inséré dans le même décret, rédigé 
