INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 179, 'Art. 78', 'Article 78. - L''intitulé de la section III du chapitre I du Titre III du même 
décret est remplacé par ce qui suit :  
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
« Des mécanismes de soutien, de développement des compétences 
professionnelles et d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '78', NULL, 'Article 78 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 180, 'Art. 79', 'Article 79. - L''article 39 du même décret est remplacé par ce qui suit : 
 
« Article 39. - Cette section s''applique aux directeurs nommés à titre 
définitif. 
 
Elle s''applique également au membre du personnel désigné à titre 
temporaire dans la fonction de directeur pour une durée égale ou supérieure à 
un an. La dénomination « directeur » visée à la présente section vise également 
ce membre du personnel. 
 
Les membres du pouvoir organisateur chargés de l''évaluation ont accès à 
la formation visée à l''article 132 du décret du 20 juillet 2023 relatif au soutien, 
au développement des compétences professionnelles et à l''évaluation des 
personnels de l''enseignement. 
 
Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en 
ressources humaines pour procéder aux entretiens et/ou évaluations visés à la 
sous-section II. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '79', NULL, 'Article 79 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 181, 'Art. 80', 'Article 80. - Une sous-section I est insérée dans la section III du chapitre 
I du Titre III, à la suite de l''article 39, du même décret, intitulée comme suit : 
 
« Sous-section I. - Du mécanisme de soutien et de développement des 
compétences professionnelles ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '80', NULL, 'Article 80 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 182, 'Art. 81 § 1', 'Article 81. - Les articles 40 et 41 sont remplacés comme suit et insérés 
dans la sous-section I précitée du même décret : 
 
« Article 40 - §1er. Le mécanisme de soutien et de développement des 
compétences professionnelles est composé, notamment, d''entretiens de 
développement professionnel entre le directeur et son pouvoir organisateur ou 
son délégué et d''un plan de développement des compétences professionnelles 
et d''un entretien de clôture. Ces entretiens de développement professionnel 
sont organisés à l''initiative du pouvoir organisateur mais peuvent également 
être demandés par le directeur à tout moment de l''année. 
 
Un délai de minimum cinq jours ouvrables doit être garanti entre la 
convocation à l''entretien de développement professionnel et la date de 
l''entretien de développement professionnel. 
 
L''entretien de développement professionnel doit faire l''objet d''un compte-
rendu. 
 
Un entretien de développement professionnel doit avoir lieu dans la 
mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. 
L''entretien de développement professionnel porte sur l''exécution de la lettre 
de mission visée au chapitre III du Titre 1er et sur la mise en œuvre du contrat 
d''objectifs, quand celui-ci existe. 
 
Dans le cadre de l''entretien de développement professionnel, il est tenu 
compte du contexte global dans lequel est amené à évoluer le directeur et des 
moyens mis à sa disposition. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Dans ce cadre, le pouvoir organisateur ou son délégué prend en 
considération : 
 
a) dans l''enseignement maternel et dans l''enseignement obligatoire, les 
dispositions relatives aux projets éducatif et pédagogique du pouvoir 
organisateur et au projet d''établissement visés au titre 5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire; 
 
b) dans l''enseignement de promotion sociale, les dispositions relatives au 
projet pédagogique visé à l''article 36ter, du décret du 16 avril 1991 précité.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '1', 'Article 81 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 183, 'Art. 81 § 2', '§2. A la suite du premier entretien de développement professionnel ou à 
la demande du pouvoir organisateur ou du directeur, un plan de 
développement des compétences professionnelles est mis en place. 
 
Ce plan de développement des compétences professionnelles est élaboré 
par le pouvoir organisateur ou son délégué en concertation avec le directeur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '2', 'Article 81 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 184, 'Art. 81 § 3', '§3. Ce plan de développement des compétences professionnelles est 
formalisé dans un document cosigné par le directeur et le pouvoir organisateur 
ou son délégué, tel que visé à l''article 41 et contient des engagements mutuels 
des deux parties tels que des objectifs individualisés, spécifiques, réalistes et 
adaptés au directeur ainsi que les moyens mis à sa disposition pour les 
atteindre. Un maximum de quatre objectifs peut être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le pouvoir organisateur ou son délégué fait la preuve que la 
demande de signature pour prise de connaissance a été adressée au membre 
du personnel. 
 
En cas de refus de signature du directeur, la procédure suit normalement 
son cours dans la mise en œuvre du plan de développement des compétences 
professionnelles. 
 
Ce document peut, le cas échéant, servir de base à la rédaction du rapport 
d''évaluation visé à l''article 42.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '3', 'Article 81 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 185, 'Art. 81 § 4', '§4. Sa périodicité est adaptée de manière à permettre au directeur de 
mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par année scolaire. 
 
Toutefois, durant une même année scolaire, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention « défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '4', 'Article 81 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 186, 'Art. 81 § 5', '§5. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements à l''initiative du pouvoir organisateur ou son délégué ou à 
la demande du directeur. Ces ajustements sont cosignés par le directeur et le 
membre du personnel. En cas de refus de signature du membre du personnel, 
la procédure de mise en œuvre du plan de développement des compétences 
professionnelles se poursuit valablement. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '5', 'Article 81 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 187, 'Art. 81 § 6', '§6. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le pouvoir organisateur ou son 
délégué. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '6', 'Article 81 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 188, 'Art. 81 § 7', '§7. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '81', '7', 'Article 81 § 7 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 189, 'Art. 41', 'Article 41. - Le Gouvernement fixe le modèle de plan de développement 
des compétences professionnelles pouvant servir de base à l''évaluation visée 
dans la sous-section II. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '41', NULL, 'Article 41 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 190, 'Art. 82', 'Article 82. - Une sous-section II est insérée dans la section III du 
chapitre I du Titre III, à la suite de l''article 41, du même décret, intitulée 
comme suit : 
 
« Sous-section II. - Du mécanisme d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '82', NULL, 'Article 82 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 191, 'Art. 83 § 1', 'Article 83. - L''article 42 est remplacé comme suit et inséré dans la sous-
section II précitée du même décret : 
 
« Article 42. - §1er. Une évaluation ne peut avoir lieu qu''une fois par année 
scolaire. 
 
§2. Toute première évaluation doit être précédée d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture 
tels que visés à la sous-section I. 
 
§3. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au directeur et pour autant 
que l''entretien de clôture visé à l''article 40, §6 ait eu lieu, en cas de mauvaise 
volonté manifeste en lien avec ledit plan ou de carence manifeste et répétée à 
atteindre les objectifs identifiés avec le directeur dans le cadre du plan de 
développement des compétences professionnelles, le pouvoir organisateur peut 
procéder à une évaluation de celui-ci. Ce délai est calculé conformément à 
l''article 42bis. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§4. Le directeur doit avoir été entendu préalablement à l''attribution de la 
mention d''évaluation, par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel en activité de service ou retraités de l''enseignement 
organisé par la Communauté française ou par un représentant d''une 
organisation syndicale représentative. 
 
§5. L''évaluation débouche sur une mention « favorable » ou 
« défavorable ». Elle est formalisée selon le document visé à l''article 
42quinquies et notifiée au membre du personnel. 
 
La mention d''évaluation est motivée sur base du plan de développement 
des compétences professionnelles. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
§6. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre le directeur et le pouvoir organisateur ou son délégué est, 
ensuite, fixé afin de mettre en place un plan d''accompagnement individualisé, 
basé sur les éléments évoqués lors de l''évaluation et prenant en compte le plan 
de développement des compétences professionnelles. Celui-ci détermine les 
objectifs que le directeur doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu, préalablement à 
toute nouvelle évaluation. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '83', '1', 'Article 83 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 192, 'Art. 84 § 1', 'Article 84. - Les dispositions suivantes sont insérées dans la sous-
section II précitée du même décret : 
 
« Article 42bis - §1er. Après un délai de minimum six mois d''exercice de la 
fonction entre la communication au directeur du plan d''accompagnement 
individualisé convenu lors de l''évaluation avec mention défavorable qui 
précède, une nouvelle évaluation peut avoir lieu. 
 
Toutefois, après une évaluation avec mention « défavorable », l''évaluation 
suivante doit intervenir dans un délai maximum de deux ans suivant la 
communication du plan d''accompagnement individualisé faisant suite à la 
précédente évaluation. A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au directeur de remédier aux carences constatées. 
 
Une évaluation ne peut avoir lieu qu''une fois par année scolaire. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée à l''article 42ter. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§2. Pour le calcul des délais de six mois et deux ans visés au §1er, sont 
seuls pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '84', '1', 'Article 84 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','parents','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 193, 'Art. 42ter § 1', '§1er. Le rapport d''évaluation faisant suite à une première 
évaluation définitive avec mention « défavorable » est rédigé par le pouvoir 
organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, 
en cas d''un commun accord entre le membre du personnel et le pouvoir 
organisateur sur la prolongation du plan d''accompagnement individualisé. Le 
rapport d''évaluation est formalisé selon le document visé à l''article 
42quinquies ainsi que notifié au directeur. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum trois mois et de maximum un an. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le membre du personnel peut se faire assister par un défenseur 
choisi parmi les membres du personnel de l''enseignement organisé par la 
Communauté française, en activité de service ou pensionnés, ou par un 
représentant d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42ter', '1', 'Article 42ter § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 194, 'Art. 42ter § 2', '§2. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et, d''autre part, le 
directeur est fixé afin de mettre en place un plan d''accompagnement 
individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci 
reprend les objectifs du plan d''accompagnement individualisé précédent que le 
directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation 
suivante. Un maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42ter', '2', 'Article 42ter § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 195, 'Art. 42ter § 3', '§3. Après prolongation du plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé. Ce délai doit 
permettre au directeur de remédier aux carences constatées. 
 
A défaut, elle est réputée favorable.

§4. Pour le calcul des délais de trois mois et un an visés au', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42ter', '3', 'Article 42ter § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 196, 'Art. 42ter § 4', '§4, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42ter', '4', 'Article 42ter § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 197, 'Art. 42ter § 5', '§5. Le rapport d''évaluation faisant suite à une prolongation du plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 42quinquies ainsi que notifié au directeur. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le membre du personnel peut se faire assister par un défenseur 
choisi parmi les membres du personnel de l''enseignement organisé par la 
Communauté française, en activité de service ou pensionnés, ou par un 
représentant d''une organisation syndicale représentative. Une évaluation ne 
peut avoir lieu qu''une fois par année scolaire.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42ter', '5', 'Article 42ter § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 198, 'Art. 42quater § 1', 'Article 42quater. - §1er. En cas d''évaluation avec mention « défavorable », 
le directeur peut, dans les 10 jours ouvrables, introduire un recours 
conformément aux modalités décrites aux articles 121/16 à 121/24 de l''arrêté 
royal du 22 mars 1969 fixant le statut des membres du personnel directeur et 
enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des 
établissements d''enseignement gardien, primaire, spécial, moyen, technique, 
de promotion sociale et artistique de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé de 
la surveillance de ces établissements, applicables mutatis mutandis. Le 
directeur qui fait usage de son droit de recours en notifie immédiatement une 
copie à son pouvoir organisateur. Ce recours est suspensif. 
 
§2. Il est mis fin d''office aux fonctions du directeur qui fait l''objet deux 
mentions « défavorable » consécutives sur deux années scolaires distinctes 
conformément à l''article 169, alinéa 1er, 5° de l''arrêté royal du 22 mars 1969 
précité, et devenues définitives après épuisement des procédures devant la 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
chambre d''appel, telles que visées à l''article 121/13 de l''arrêté royal du 22 mars 
1969 précité.

Article 42quinquies. - Le Gouvernement fixe les modèles de plan 
d''accompagnement individualisé et de rapport d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42quater', '1', 'Article 42quater § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 199, 'Art. 42sexies', 'Article 42sexies. - Toute notification de document, de décision ou de 
convocation mentionnée dans la présente sous-section se fait par courrier 
recommandé avec accusé de réception ou par une remise de la main à la main 
avec accusé de réception. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '42sexies', NULL, 'Article 42sexies du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 200, 'Art. 85', 'Article 85. - Une sous-section III est insérée dans la section II du 
chapitre II du Titre III, à la suite de l''article 42sexies, du même décret, 
intitulée comme suit : 
 
« Sous-section III. - Des règles de déontologie ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '85', NULL, 'Article 85 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 201, 'Art. 86', 'Article 86. - Le nouvel article 42septies est inséré dans la sous-section 3 
précitée du même décret : 
 
« Article 42septies. - Dans le cadre des entretiens et évaluations visés à 
la présente section, le membre du personnel et son évaluateur sont tenus au 
respect des devoirs suivants : 
 
a) la discrétion ; 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
a) motiver, de manière adéquate et constructive, ses instructions, conseils 
et échanges avec le membre du personnel ainsi que la mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '86', NULL, 'Article 86 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 202, 'Art. 87', 'Article 87. - L''intitulé de la Section III du chapitre II du Titre III du 
même décret est remplacé par ce qui suit :  
 
« Des mécanismes de soutien, de développement des compétences 
professionnelles et d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '87', NULL, 'Article 87 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 203, 'Art. 88', 'Article 88. - L''article 63 du même décret est remplacé par ce qui suit : 
 
« Article 63. - Les membres du pouvoir organisateur chargés de cette 
évaluation sont soutenus par leur fédération de pouvoir organisateur qui leur 
apporte notamment, une éventuelle expertise technique spécialisée. Par 
ailleurs, ils ont accès à la formation visée à l''article 132 du décret du 20 juillet 
2023 relatif au soutien, au développement des compétences professionnelles et 
à l''évaluation des personnels de l''enseignement. 
 
Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en 
ressources humaines pour procéder aux entretiens et/ou évaluations visés à la 
sous-section II. ». 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', NULL, 'Article 88 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 204, 'Art. 89', 'Article 89. - Une sous-section 1 est insérée dans la section III du 
chapitre II du Titre III, à la suite de l''article 63, du même décret, intitulée 
comme suit : 
 
« Sous-section 1. - Du mécanisme de soutien et de développement des 
compétences professionnelles ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '89', NULL, 'Article 89 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 205, 'Art. 90 § 1', 'Article 90. - Les articles 64 et 65 sont remplacés comme suit et insérés 
dans la sous-section 1 précitée du même décret : 
 
« Article 64. - §1er. Le mécanisme de soutien et de développement des 
compétences professionnelles est composé, notamment, d''entretiens de 
développement professionnel entre le directeur et son pouvoir organisateur et 
d''un plan de développement des compétences professionnelles et d''un entretien 
de clôture. Ces entretiens de développement professionnel sont organisés à 
l''initiative du pouvoir organisateur mais peuvent également être demandés 
par le directeur. 
 
Un délai de minimum cinq jours ouvrables doit être garanti entre la 
convocation à l''entretien de développement professionnel et la date de 
l''entretien de développement professionnel. 
 
L''entretien de développement professionnel doit faire l''objet d''un compte-
rendu. 
 
Un entretien de développement professionnel doit avoir lieu dans la 
mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. 
L''entretien de développement professionnel porte sur l''exécution de la lettre 
de mission visée au chapitre III du Titre 1er et sur la mise en œuvre du contrat 
d''objectifs, quand celui-ci existe. 
 
Dans le cadre de l''entretien de développement professionnel, il est tenu 
compte du contexte global dans lequel est amené à évoluer le directeur et des 
moyens mis à sa disposition. 
 
Dans ce cadre, le pouvoir organisateur prend en considération : 
 
a) dans l''enseignement maternel et dans l''enseignement obligatoire, les 
dispositions relatives aux projets éducatif et pédagogique du pouvoir 
organisateur et au projet d''établissement visés au titre 5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire ; 
 
b) dans l''enseignement de promotion sociale, les dispositions relatives au 
projet pédagogique visé à l''article 36,', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '1', 'Article 90 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 206, 'Art. 90 § 2', '§2, du décret du 16 avril 1991 précité; 
 
c) dans l''enseignement secondaire artistique à horaire réduit, les 
dispositions relatives au projet éducatif et au projet pédagogique du pouvoir 
organisateur visés à l''article 1er du décret du 02 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française et les dispositions relatives au projet pédagogique et 
artistique d''établissement visé à l''article 3bis du même décret.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '2', 'Article 90 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 207, 'Art. 90 § 2', '§2. A la suite du premier entretien de développement professionnel ou à 
la demande du pouvoir organisateur ou du directeur, un plan de 
développement des compétences professionnelles est mis en place. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Ce plan de développement des compétences professionnelles est élaboré 
par le pouvoir organisateur en concertation avec le directeur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '2', 'Article 90 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 208, 'Art. 90 § 3', '§3. Ce plan de développement des compétences professionnelles est 
formalisé dans un document cosigné, tel que visé à l''article 65 et contient des 
engagements mutuels des deux parties tels que des objectifs individualisés, 
spécifiques, réalistes et adaptés au directeur ainsi que les moyens mis à sa 
disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le pouvoir organisateur ou son délégué fait la preuve que la 
demande de signature pour prise de connaissance a été adressée au membre 
du personnel. 
 
En cas de refus de signature du directeur, la procédure de mise en œuvre 
du plan de développement des compétences professionnelles se poursuit 
valablement. 
 
Ce document peut, le cas échéant, servir de base à la rédaction du rapport 
d''évaluation visé à l''article 65/1.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '3', 'Article 90 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 209, 'Art. 90 § 4', '§4. Sa périodicité est adaptée de manière à permettre au directeur de 
mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par année scolaire par membre du personnel. 
 
Toutefois, durant une même année scolaire, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention « défavorable ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '4', 'Article 90 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 210, 'Art. 90 § 5', '§5. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements à l''initiative du pouvoir organisateur ou à la demande du 
directeur. Ces ajustements sont cosignés par les deux parties. En cas de refus 
de signature du membre du personnel, la procédure de mise en œuvre du plan 
de développement des compétences professionnelles se poursuit valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '5', 'Article 90 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 211, 'Art. 90 § 6', '§6. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le pouvoir organisateur ou son 
délégué. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '6', 'Article 90 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 212, 'Art. 90 § 6', '§6. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '90', '6', 'Article 90 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 213, 'Art. 65', 'Article 65. - Le Gouvernement fixe le modèle de plan de développement 
des compétences professionnelles, pouvant servir de base à l''évaluation visée 
dans la sous-section 2. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', NULL, 'Article 65 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 214, 'Art. 91', 'Article 91. - Une sous-section 2 est insérée dans la section III du 
chapitre II du Titre III, à la suite de l''article 65 du même décret, intitulée 
comme suit : 
 
« Sous-section 2. - Du mécanisme d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '91', NULL, 'Article 91 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 215, 'Art. 92 § 1', 'Article 92. - Les dispositions suivantes sont insérées dans la sous-
section 2 précitée du même décret : 
 
« Article 65/1. - §1er. En cas de mauvaise volonté manifeste en lien avec 
ledit plan ou de carence manifeste et répétée à atteindre les objectifs identifiés 
avec le directeur dans le cadre du plan de développement des compétences 
professionnelles, une procédure d''évaluation peut être engagée par le pouvoir 
organisateur. 
 
L''évaluation est précédée d''un plan de développement des compétences 
professionnelles. 
 
§2. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au directeur et pour autant 
que l''entretien de clôture visé à l''article 64, §6 ait eu lieu, le pouvoir 
organisateur peut procéder à une évaluation de celui-ci. Ce délai est calculé 
conformément à l''article 65/2, §2. 
 
§3. Le directeur doit être entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel en activité de service ou pensionnés de 
l''enseignement officiel subventionné ou par un représentant d''une 
organisation syndicale représentative. 
 
§4. L''évaluation débouche sur une mention « favorable » ou 
« défavorable ». Elle est formalisée selon le document visé à l''article 65/5 et 
notifié au membre du personnel. 
 
La mention d''évaluation est motivée sur la base du plan de 
développement des compétences professionnelles. 
 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§5. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre le directeur et le pouvoir organisateur est, ensuite, fixé afin de 
mettre en place un plan d''accompagnement individualisé, basé sur les 
éléments évoqués lors de l''évaluation. Celui-ci détermine les objectifs que le 
directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation 
suivante. Un maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '92', '1', 'Article 92 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 216, 'Art. 65 § 1', 'Article 65/2. - §1er. Après un délai de minimum six mois d''exercice de la 
fonction entre la communication au directeur du plan d''accompagnement 
individualisé convenu lors de l''évaluation avec mention « défavorable » qui 
précède, une nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au directeur de remédier aux carences constatées. 
 
Toutefois, après une évaluation avec mention « défavorable », l''évaluation 
suivante doit intervenir dans un délai maximum de deux ans suivant la 
communication du plan d''accompagnement individualisé faisant suite à la 
précédente évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée à l''article 65/3. 
 
§2. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '1', 'Article 65 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','parents','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 217, 'Art. 65 § 1', '§1er. Le rapport d''évaluation faisant suite à une première 
évaluation définitive avec mention « défavorable » est rédigé par le pouvoir 
organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, 
en cas d''un commun accord entre le membre du personnel et le pouvoir 
organisateur sur la prolongation du plan d''accompagnement individualisé. Le 
rapport d''évaluation est formalisé selon le document visé à l''article 65/5 ainsi 
que notifié au directeur. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel des établissements d''enseignement officiel 
subventionné, en activité de service ou pensionnés, ou par un représentant 
d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '1', 'Article 65 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 218, 'Art. 65 § 2', '§2. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et, d''autre part, le 
directeur est fixé afin de mettre en place un plan d''accompagnement 
individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci 
reprend les objectifs du plan d''accompagnement individualisé précédent que le 
directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation 
suivante. Un maximum de 4 objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '2', 'Article 65 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 219, 'Art. 65 § 3', '§3. Après une prolongation du plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé. 
 
A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au directeur de remédier aux carences constatées.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '3', 'Article 65 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 220, 'Art. 65 § 4', '§4. Pour le calcul des délais de trois mois et un an précités, sont seuls pris 
en considération les services effectifs rendus pendant l''exercice de la fonction, 
en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '4', 'Article 65 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 221, 'Art. 65 § 5', '§5. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 65/5 ainsi que notifié au directeur. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel des établissements d''enseignement officiel 
subventionné, en activité de service ou pensionnés, ou par un représentant 
d''une organisation syndicale représentative. 
 
Une évaluation ne peut avoir lieu qu''une fois par année scolaire.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '5', 'Article 65 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 222, 'Art. 65 § 1', 'Article 65/4. - §1er. En cas d''évaluation avec mention « défavorable », le 
directeur peut, dans les 10 jours ouvrables qui suivent la réception du rapport, 
introduire un recours conformément aux modalités décrites au chapitre Vbis 
du décret du 06 juin 1994 fixant le statut des membres du personnel subsidiés 
de l''enseignement officiel subventionné, applicables mutatis mutandis. Le 
directeur qui fait usage de son droit de recours en notifie immédiatement une 
copie à son pouvoir organisateur. Ce recours est suspensif. 
 
§2. La répétition de deux mentions « défavorable » consécutives sur deux 
années scolaires distinctes, devenues définitives après épuisement des 
procédures devant la chambre de recours, telles que visées à l''article 
52novies/7 du décret du 6 juin 1994 précité, a pour conséquence de mettre fin 
d''office aux fonctions du directeur conformément à l''article 58 du décret du 06 
juin 1994 précité.

Article 65/5. - Le Gouvernement fixe le modèle de plan d''accompagnement 
individualisé et de rapport d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', '1', 'Article 65 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 223, 'Art. 65', 'Article 65/6. - Toute notification de document, de décision ou de 
convocation mentionnée dans la présente sous-section se fait par courrier 
recommandé avec accusé de réception ou par une remise de la main à la main 
avec accusé de réception. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '65', NULL, 'Article 65 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 224, 'Art. 93', 'Article 93. - Une sous-section 3 est insérée dans la section III du 
chapitre II du Titre III, à la suite de l''article 65/6, du même décret, intitulée 
comme suit : 
 
« Sous-section 3. - Des règles de déontologie ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '93', NULL, 'Article 93 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 225, 'Art. 94', 'Article 94. - La disposition suivante est insérée dans la sous-section 3 
précitée du même décret : 
 
« Article 65/7. - Dans le cadre des entretiens et évaluations visés à la 
présente section, le membre du personnel et son évaluateur sont tenus au 
respect des devoirs suivants : 
 
a) la discrétion ; 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
a) 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '94', NULL, 'Article 94 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 226, 'Art. 95', 'Article 95. - L''intitulé de la Section III du chapitre III du Titre III du 
même décret est remplacé par ce qui suit :  
 
«  Des mécanismes de soutien et de développement des compétences 
professionnelles et d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '95', NULL, 'Article 95 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 227, 'Art. 96', 'Article 96. - L''article 86 du même décret est remplacé par ce qui suit : 
 
« Article 86. - Les membres du pouvoir organisateur chargés de cette 
évaluation sont soutenus par leur fédération de pouvoir organisateur qui leur 
apporte notamment, une éventuelle expertise technique spécialisée. Par 
ailleurs, ils ont accès à la formation visée à l''article 132 du décret du 20 juillet 
2023 relatif au soutien, au développement des compétences professionnelles et 
à l''évaluation des personnels de l''enseignement. 
 
Le pouvoir organisateur peut s''entourer d''experts en pédagogie ou en 
ressources humaines pour procéder aux entretiens et/ou évaluations visés à la 
sous-section II. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '96', NULL, 'Article 96 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','spécialisé'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 228, 'Art. 97', 'Article 97. - Une sous-section 1 est insérée dans la section III du 
chapitre III du Titre III, à la suite de l''article 86, du même décret, intitulée 
comme suit : 
 
« Sous-section 1. - Du mécanisme de soutien et de développement des 
compétences professionnelles ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '97', NULL, 'Article 97 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 229, 'Art. 98 § 1', 'Article 98. - Les articles 87 et 88 sont remplacés comme suit et insérés 
dans la sous-section 1 précitée du même décret : 
 
« Article 87. - §1er. Le mécanisme de soutien et de développement des 
compétences professionnelles est composé, notamment, d''entretiens de 
développement professionnel entre le directeur et son pouvoir organisateur et 
d''un plan de développement des compétences professionnelles et d''un entretien 
de clôture. Ces entretiens de développement professionnel sont organisés à 
l''initiative du pouvoir organisateur mais peuvent également être demandés 
par le directeur. 
 
Un délai de minimum cinq jours ouvrables doit être garanti entre la 
convocation à l''entretien de développement professionnel et la date de 
l''entretien de développement professionnel. 
 
L''entretien de développement professionnel doit faire l''objet d''un compte-
rendu. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Un entretien de développement professionnel doit avoir lieu dans la 
mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. 
L''entretien de développement professionnel porte sur l''exécution de la lettre 
de mission visée au chapitre III du Titre 1er et sur la mise en oeuvre du contrat 
d''objectifs, quand celui-ci existe. 
 
Dans le cadre de l''entretien de développement professionnel, il est tenu 
compte du contexte global dans lequel est amené à évoluer le directeur et des 
moyens mis à sa disposition. 
 
Dans ce cadre, le pouvoir organisateur prend en considération : 
 
a) dans l''enseignement maternel et dans l''enseignement obligatoire, les 
dispositions relatives aux projets éducatif et pédagogique du pouvoir 
organisateur et au projet d''établissement visés au titre 5 du Code de 
l''enseignement fondamental et de l''enseignement secondaire ; 
 
b) dans l''enseignement de promotion sociale, les dispositions relatives au 
projet pédagogique visé à l''article 36,', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '1', 'Article 98 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 230, 'Art. 98 § 2', '§2, du décret du 16 avril 1991 précité ; 
 
c) dans l''enseignement secondaire artistique à horaire réduit, les 
dispositions relatives au projet artistique et au projet pédagogique du pouvoir 
organisateur visés à l''article 1er, 7° et 8° du décret du 02 juin 1998 organisant 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française et les dispositions relatives au projet éducatif et 
artistique d''établissement visé à l''article 3bis du même décret.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '2', 'Article 98 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 231, 'Art. 98 § 2', '§2. A la suite de cet entretien et à la demande du pouvoir organisateur ou 
du directeur, un plan de développement des compétences professionnelles est 
mis en place. 
 
Ce plan de développement des compétences professionnelles est élaboré 
par le pouvoir organisateur ou son délégué en concertation avec le directeur.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '2', 'Article 98 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 232, 'Art. 98 § 3', '§3. Ce plan de développement des compétences professionnelles est 
formalisé dans un document cosigné, tel que visé à l''article 88 et contient des 
engagements mutuels des deux parties tels que des objectifs individualisés, 
spécifiques, réalistes et adaptés au directeur ainsi que les moyens mis à sa 
disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le pouvoir organisateur ou son délégué fait la preuve que la 
demande de signature pour prise de connaissance a été adressée au membre 
du personnel. 
 
En cas de refus de signature du directeur, la procédure de mise en œuvre 
du plan de développement des compétences professionnelles se poursuit 
valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '3', 'Article 98 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 233, 'Art. 98 § 4', '§4. Sa périodicité est adaptée de manière à permettre au directeur de 
mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par année scolaire. 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Toutefois, durant une même année scolaire, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention défavorable.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '4', 'Article 98 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 234, 'Art. 98 § 5', '§5. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements à l''initiative du pouvoir organisateur ou à la demande du 
directeur. Ils sont cosignés par les deux parties.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '5', 'Article 98 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 235, 'Art. 98 § 6', '§6. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le pouvoir organisateur ou son 
délégué. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '6', 'Article 98 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 236, 'Art. 98 § 7', '§7. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '98', '7', 'Article 98 § 7 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 237, 'Art. 88', 'Article 88. - Le Gouvernement fixe le modèle de plan de développement 
des compétences professionnelles, pouvant servir de base à l''évaluation visée 
dans la sous-section 2. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', NULL, 'Article 88 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 238, 'Art. 99', 'Article 99. - Une sous-section 2 est insérée dans la section III du 
chapitre III du Titre III, à la suite de l''article 88 du même décret, intitulée 
comme suit : 
 
« Sous-section 2. - Du mécanisme d''évaluation ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '99', NULL, 'Article 99 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 239, 'Art. 100 § 1', 'Article 100. - Les dispositions suivantes sont insérées dans la sous-
section 2 précitée du même décret : 
 
« Article 88/1. - §1er. En cas de mauvaise volonté manifeste en lien avec 
ledit plan ou de carence manifeste et répétée à atteindre les objectifs identifiés 
avec le directeur dans le cadre du plan de développement des compétences 
professionnelles, une procédure d''évaluation peut être engagée par pouvoir 
organisateur. 
 
Toute première évaluation est précédée d''un plan de développement des 
compétences professionnelles et d''un entretien de clôture. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Une évaluation ne peut avoir lieu qu''une fois par année scolaire. 
 
§2. Au plus tôt six mois après avoir communiqué ce plan de 
développement des compétences professionnelles au directeur et pour autant 
que l''entretien de clôture visé à l''article 87, §6 ait eu lieu, le pouvoir 
organisateur peut procéder à une évaluation de celui-ci. Ce délai est calculé 
conformément à l''article 88/2, §2. 
 
§3. Le directeur doit être entendu préalablement à toute attribution d''une 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel des établissements d''enseignement libre 
subventionné, en activité de service ou pensionnés, ou par un représentant 
d''une organisation syndicale représentative. 
 
§4. L''évaluation débouche sur une mention « favorable » ou 
« défavorable ». Elle est formalisée selon le document visé à l''article 88/5 et 
notifiée au membre du personnel. 
 
La mention d''évaluation est motivée sur la base des éléments du plan de 
développement des compétences professionnelles, pour la première évaluation. 
En l''absence de rapport d''évaluation, tout membre du personnel est 
réputé bénéficier de la mention « favorable ». 
 
§5. En cas d''évaluation débouchant sur la mention « défavorable », un 
entretien entre le directeur et le pouvoir organisateur ou son délégué est, 
ensuite, fixé afin de mettre en place un plan d''accompagnement individualisé, 
basé sur les éléments évoqués lors de l''évaluation. Celui-ci détermine les 
objectifs que le directeur doit atteindre pour obtenir une mention favorable lors 
de l''évaluation suivante. Un maximum de 4 objectifs peut être fixé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '100', '1', 'Article 100 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection','obligation scolaire'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 240, 'Art. 88 § 1', 'Article 88/2. - §1er. Après un délai de minimum six mois d''exercice de la 
fonction entre la communication au directeur du plan d''accompagnement 
individualisé convenu lors de l''évaluation avec mention « défavorable » qui 
précède, une nouvelle évaluation peut avoir lieu. 
 
Ce délai doit permettre au directeur de remédier aux carences constatées. 
 
Toutefois, après une évaluation avec mention « défavorable », l''évaluation 
suivante doit intervenir dans un délai maximum de deux ans suivant la 
communication du plan d''accompagnement individualisé faisant suite à la 
précédente évaluation. A défaut, elle est réputée favorable. 
 
Par dérogation à l''alinéa précédent, l''évaluation suivante peut intervenir 
dans un délai plus long en cas de prolongation du plan d''accompagnement 
individualisé telle que visée à l''article 88/3. 
 
§2. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '1', 'Article 88 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','parents','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 241, 'Art. 88 § 1', '§1er. Le rapport d''évaluation faisant suite à une première 
évaluation définitive avec mention « défavorable » est rédigé par le pouvoir 
organisateur. Il débouche sur une mention « favorable » ou « défavorable » ou, 
en cas d''un commun accord entre le membre du personnel et le pouvoir 
organisateur sur la prolongation du plan d''accompagnement individualisé. Le 
rapport d''évaluation est formalisé selon le document visé à l''article 88/5 ainsi 
que notifié au directeur. 
 
La prolongation du plan d''accompagnement individualisé est de 
minimum 3 mois et de maximum un an. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel des établissements d''enseignement libre 
subventionné, en activité de service ou pensionnés, ou par un représentant 
d''une organisation syndicale représentative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '1', 'Article 88 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 242, 'Art. 88 § 3', '§3. En cas de prolongation du plan d''accompagnement individualisé, un 
entretien entre, d''une part, le pouvoir organisateur et, d''autre part, le 
directeur est fixé afin de mettre en place un plan d''accompagnement 
individualisé, basé sur les éléments évoqués lors de l''évaluation. Celui-ci 
reprend les objectifs du plan d''accompagnement individualisé précédent que le 
directeur doit atteindre pour obtenir une mention favorable lors de l''évaluation 
suivante. Un maximum de quatre objectifs peut être fixé. 
 
Le plan d''accompagnement individualisé donne lieu à un entretien de 
clôture. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '3', 'Article 88 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 243, 'Art. 88 § 4', '§4. Après prolongation du plan d''accompagnement individualisé, une 
nouvelle évaluation a lieu endéans un délai de minimum trois mois et un délai 
maximum d''un an d''exercice de la fonction à partir de la communication au 
membre du personnel du plan d''accompagnement individualisé adapté à la 
suite de la prolongation du plan d''accompagnement individualisé. 
 
A défaut, elle est réputée favorable. 
 
Ce délai doit permettre au directeur de remédier aux carences constatées. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '4', 'Article 88 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','parents','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 244, 'Art. 88 § 5', '§5. Pour le calcul des délais de trois mois et un an précités, sont seuls pris 
en considération les services effectifs rendus pendant l''exercice de la fonction, 
en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '5', 'Article 88 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 245, 'Art. 88 § 6', '§6. Le rapport d''évaluation faisant suite à une prolongation de plan 
d''accompagnement individualisé est rédigé par le pouvoir organisateur. Il 
débouche sur une mention « favorable » ou « défavorable » et est formalisé selon 
le document visé à l''article 88/5 ainsi que notifié au directeur. 
 
La mention d''évaluation est motivée sur la base des éléments du plan 
d''accompagnement individualisé. 
 
Le directeur doit avoir été entendu préalablement à l''attribution de sa 
mention d''évaluation par le pouvoir organisateur. La convocation doit lui être 
notifiée cinq jours ouvrables au moins avant l''audition, soit par lettre 
recommandée à la poste avec accusé de réception, soit par la remise d''une 
lettre de la main à la main avec accusé de réception. Lors de l''entretien 
d''évaluation, le directeur peut se faire assister par un défenseur choisi parmi 
les membres du personnel des établissements d''enseignement libre 
subventionné, en activité de service ou pensionnés, ou par un représentant 
d''une organisation syndicale représentative. 
 
Une évaluation ne peut avoir lieu qu''une fois par année scolaire.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '6', 'Article 88 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','inspection'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 246, 'Art. 88 § 1', 'Article 88/4. - §1er. En cas d''évaluation avec mention « défavorable », le 
directeur peut, dans les 10 jours ouvrables qui suivent la réception du rapport, 
introduire un recours conformément aux modalités décrites au chapitre Vbis 
du décret du 1er février 1993 fixant le statut des membres du personnel 
subsidiés de l''enseignement libre subventionné, applicables mutatis mutandis. 
Le directeur qui fait usage de son droit de recours en notifie immédiatement 
une copie à son pouvoir organisateur. Ce recours est suspensif. 
 
§2. La répétition de deux mentions « défavorable » consécutives sur deux 
années scolaires distinctes, devenues définitives après épuisement des 
procédures devant la chambre de recours, telles que visées à l''article 61decies/6 
du décret du 1er février 1993 précité, a pour conséquence de mettre fin d''office 
aux fonctions du directeur en application de l''article 72, §1er, 12° du décret du 
1er février 1993 précité.

Article 88/5. - Le Gouvernement fixe le modèle de plan d''accompagnement 
individualisé et de rapport d''évaluation.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '88', '1', 'Article 88 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['recours','évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 247, 'Art. 88', 'Article 88/6. - Toute notification de document, de décision ou de 
convocation mentionnée dans la présente sous-section se fait par courrier 
 
 
