INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 249, 'Art. 102', 'Article 102. - Les dispositions suivantes sont insérées dans la sous-
section 3 précitée du même décret : 
 
« Article 88/7. - Dans le cadre des entretiens et évaluations visées à la 
présente section, le membre du personnel et son évaluateur sont tenus au 
respect des devoirs suivants : 
 
a) la discrétion ; 
 
b) le respect mutuel. 
 
En outre, l''évaluateur est tenu de : 
 
a) 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ainsi que la 
mention d''évaluation ; 
 
b) soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
c) respecter les devoirs d''impartialité et d''objectivité. ». 
 
TITRE 3. - DISPOSITION MODIFIANT LE DECRET DU 14 MARS 
2019 PORTANT DIVERSES DISPOSITIONS RELATIVES A 
L''ORGANISATION DU TRAVAIL DES MEMBRES DU PERSONNEL 
DE L''ENSEIGNEMENT ET OCTROYANT PLUS DE SOUPLESSE 
ORGANISATIONNELLE AUX POUVOIRS ORGANISATEURS', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '102', NULL, 'Article 102 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 250, 'Art. 103', 'Article 103. - A l''article 9 du décret du 14 mars 2019 portant diverses 
dispositions relatives à l''organisation du travail des membres du personnel de 
l''enseignement et octroyant plus de souplesse organisationnelle aux pouvoirs 
organisateurs, les modifications suivantes sont apportées : 
 
1° au §1er, un 17. rédigé comme suit est inséré : 
 
« 17. délégué en charge du mécanisme de soutien et de développement des 
compétences professionnelles des membres du personnel » ; 
 
2° un nouveau §2bis rédigé comme suit est inséré : 
 
« §2bis. La mission au §1er, point 17. requière que l''enseignant 
expérimenté à qui la mission est confiée ait suivi la formation préalable aux 
mécanismes de soutien et de développement des compétences professionnelles 
ainsi que d''évaluation visée à l''article 6.1.9-5 du Code de l''enseignement 
fondamental et de l''enseignement secondaire. ». 
 
3° un alinéa 3 est ajouté au §4, rédigé comme suit : 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
« Le présent paragraphe ne s''applique pas à la mission prévue à l''article 
9, §1er, 17° ». 
 
TITRE 4. - DISPOSITIONS INSERANT LA DEFINITION D''EQUIPE 
EDUCATIVE DANS LE DECRET DU 16 AVRIL 1991 ORGANISANT 
L''ENSEIGNEMENT DE PROMOTION SOCIALE', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '103', NULL, 'Article 103 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 251, 'Art. 104', 'Article 104. - A l''article 5 bis du décret du 16 avril 1991 organisant 
l''enseignement de promotion sociale, un point 29° est ajouté, rédigé comme 
suit : 
 
« 29° équipe éducative : le personnel directeur et enseignant, le personnel 
