INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 252, 'Art. 105 § 2', 'Article 105. - Au §2 de l''article 36 bis de ce même décret, un point 6° est 
