INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 263, 'Art. 8', 'Article 8.1. - Le mécanisme de soutien et de développement des 
compétences professionnelles s''inscrit dans un processus de développement 
professionnel et dans une professionnalisation accrue. 
 
Il s''applique aux membres du personnel de l''enseignement de promotion 
sociale soumis aux règles statutaires désignés ou engagés, à titre temporaire 
ou définitif, dans des périodes organiques. 
 
Le champ d''application de l''article 8.11 est étendu à l''ensemble de 
l''équipe éducative.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 264, 'Art. 8', 'Article 8.2. - Le Gouvernement fixe les modèles de rapport de la direction 
à destination du pouvoir organisateur et de plan de développement des 
compétences professionnelles visé aux sections 3 et 4 du présent chapitre. 
 
Section 2 - La formation au mécanisme de soutien et de développement 
des compétences professionnelles et les délégués de la direction', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 265, 'Art. 8 § 1', 'Article 8.3. - §1er. Pour les directeurs, une formation relative aux 
mécanismes de soutien, de développement des compétences professionnelles et 
d''évaluation est organisée de manière complémentaire entre les niveaux de 
formation interréseaux et réseau et comprend des modules répartis de manière 
égalitaire entre ces deux niveaux de formation. 
 
L''Institut de la Formation Professionnelle Continue et le pouvoir 
organisateur de l''enseignement organisé par la Communauté française ou 
chaque Fédération de pouvoirs organisateurs veillent à respecter la 
complémentarité des modules entre les niveaux interréseaux et réseau de 
manière à assurer la cohérence globale du dispositif de formation. 
 
§2. Le directeur suit la formation visée au paragraphe 1er dans le cadre 
de la formation initiale des directeurs visée au chapitre II du décret du 2 
février 2007 fixant le statut des directeurs et directrice dans l''enseignement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 266, 'Art. 8 § 1', 'Article 8.4. - §1er. Le délégué du directeur, visé dans le présent chapitre, 
doit être désigné parmi les titulaires d''une fonction de sélection de directeur 
adjoint et doit avoir suivi la formation visée à l''article 8.5. 
 
§2. Pour les fonctions de sélection, le directeur ne peut pas déléguer. 
 
§3. Le délégué doit avoir un entretien de développement professionnel 
donnant lieu à un plan de développement des compétences professionnelles au 
cours de l''année académique durant laquelle la mission de délégué lui est 
confiée pour la première fois. 
 
§4. Le délégué visé au §1er exerce une mission d''accompagnateur du 
mécanisme de soutien et de développement des compétences professionnelles. 
 
Il fait, à la demande de la direction, des entretiens de développement 
professionnel. 
 
Il soutient, aide et accompagne le membre du personnel dans sa réflexion 
et dans la construction et l''élaboration de son plan de développement des 
compétences professionnelles. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Il n''a pas de compétence de décision.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
