INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 268, 'Art. 8', 'Article 8.6. - Le mécanisme de soutien et de développement des compétences professionnelles est composé, notamment, d''entretiens de développement professionnel menés par le directeur ou son délégué et, le cas échéant, d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Ces entretiens de développement professionnel sont organisés à l''initiative du directeur mais peuvent également être demandés par le membre du personnel. Un délai de minimum cinq jours ouvrables doit être garanti entre la convocation à l''entretien de développement professionnel et la date de celui-ci. L''entretien de développement professionnel fait l''objet d''un compte- rendu. Un entretien de développement professionnel doit avoir lieu dans la mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. A partir de la rentrée académique 2024-2025, les enseignants qui sont dans une de leurs cinq premières années d''exercice dans l''enseignement en Communauté française, ont un entretien de développement professionnel par année académique. L''entretien de développement professionnel peut en fonction de la charge occupée, s''appuyer sur les compétences professionnelles attendues suivantes : - les compétences professionnelles visées par les objectifs généraux de la formation en cours de carrière tels que visés à l''article 3 du présent décret ; - les compétences professionnelles utiles à la participation du membre du personnel au Conseil des études tel que défini à l''article 31 du décret du 16 avril 1991 organisant l''enseignement de promotion sociale ; - les compétences professionnelles découlant de l''application des arrêtés du Gouvernement de la Communauté française du 02 septembre 2015 portant règlement général des études de l''enseignement secondaire et supérieur de promotion sociale; Docu 51683 D. 20-07-2023 Version initiale au 22/11/2023 - les compétences professionnelles qui relèvent de la mise en œuvre des dossiers pédagogiques et de ses activités d''enseignement telles que définies à l''article 5bis 2° du décret du 16 avril 1991 précité ; - les compétences professionnelles nécessaires pour la mise en œuvre d''activités d''enseignement ou d''activités de développement de compétences organisées en hybridation telles que visées à l''article 5 de l''arrêté du Gouvernement de la Communauté française fixant les conditions d''organisation d''un enseignement hybride dans l''enseignement de promotion sociale du 21 décembre 2022 ; - les compétences professionnelles nécessaires pour concevoir et mettre en œuvre des méthodes didactiques adaptées à un public adulte telles que prévues à l''article 26 du décret du 16 avril 1991 précité ; - les compétences professionnelles nécessaires pour prendre en compte les acquis de l''expérience conformément à l''article 8 du décret du 16 avril 1991 précité ; - les compétences professionnelles nécessaires pour mettre en œuvre en concertation avec les Conseils des études les dispositions prévues à l''article 36 ter, §3 du décret du 16 avril 1991 précité ; - les compétences professionnelles nécessaires pour concevoir et mettre en œuvre les pratiques de différenciation pédagogique, de suivi pédagogique tel que défini à la section 5 du décret du 16 avril 1991 précité et d''accompagnement des étudiants, et les aménagements raisonnables tels que définis par le décret du 30 juin 2016 relatif à l''enseignement de promotion sociale inclusif ; - les compétences professionnelles relatives au praticien réflexif, à savoir : a) savoir lire de manière critique les résultats de recherches scientifiques en éducation et en didactique et s''en inspirer pour son action d''enseignement ainsi que s''appuyer sur diverses disciplines des sciences humaines pour analyser et agir en situation professionnelle ; b) mener, individuellement et avec ses pairs, une observation et une analyse critique et rigoureuse de ses propres pratiques et de leur impact sur les étudiants afin de réguler son enseignement et d''en faire évoluer les stra', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['discipline','évaluation','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 269, 'Art. 8', 'et conditions de mise en œuvre dans une perspective d''efficacité et d''équité. c) construire progressivement son identité professionnelle, notamment en mobilisant des outils de développement professionnel personnel tel que le portfolio ; - les compétences professionnelles collectives ou personnalisées qui sont susceptibles de rencontrer les objectifs spécifiques définis dans le projet de l''établissement, dans son plan d''accompagnement ou dans son règlement d''ordre intérieur, s''il échet. Dans le cadre de l''entretien de développement professionnel, il est tenu compte du contexte global dans lequel est amené à évoluer le membre du personnel et des moyens mis à sa disposition. Docu 51683 D. 20-07-2023 Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 270, 'Art. 8 § 1', '§1er. A la suite d''un entretien de développement 
professionnel, à la demande du membre du personnel ou du directeur, un plan 
de développement des compétences professionnelles peut être mis en place. 
 
Pour pouvoir mettre en place un plan de développement des compétences 
professionnelles, les conditions suivantes doivent être réunies : 
 
1° le membre du personnel doit avoir eu, au minimum, un entretien de 
développement professionnel avec le directeur ou son délégué ; 
 
2° le membre du personnel ne peut pas avoir déjà eu un plan de 
développement des compétences professionnelles au cours de la même année 
académique au sein du pouvoir organisateur, conformément au', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 271, 'Art. 8 § 3', '§3 ; 
 
3° le directeur doit être formé via la formation visée à l''article 8.3. 
 
La mise en place d''un plan de développement des compétences 
professionnelles est obligatoire pour les membres du personnel qui sont dans 
leur première année d''exercice d''une fonction dans l''enseignement en 
Communauté française, pour autant que la durée de désignation initiale soit 
d''au moins neuf mois au sein du pouvoir organisateur et qu''ils soient désignés 
pour plus d''une demi-charge organique au sein du pouvoir organisateur pour 
l''année académique. 
 
Ce plan de développement des compétences professionnelles est élaboré 
par le directeur ou son délégué en concertation avec le membre du personnel.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '3', 'Article 8 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 272, 'Art. 8 § 2', '§2. Celui-ci est formalisé dans un document cosigné par le membre du 
personnel et le directeur, tel que visé à l''article 8.2. et contient des 
engagements mutuels des deux parties tels que des objectifs individualisés, 
spécifiques, réalistes et adaptés au membre du personnel ainsi que les moyens 
mis à sa disposition pour les atteindre. Un maximum de quatre objectifs peut 
être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le directeur fait la preuve que la demande de signature pour prise 
de connaissance a été adressée au membre du personnel. 
 
En cas de refus de signature du membre du personnel, la procédure de 
mise en œuvre du plan de développement des compétences professionnelles se 
poursuit valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '2', 'Article 8 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 273, 'Art. 8 § 3', '§3. Sa périodicité est adaptée de manière à permettre au membre du 
personnel de mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par membre du personnel par année 
académique au sein du pouvoir organisateur. 
 
Toutefois, durant une même année académique, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention défavorable.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '3', 'Article 8 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 274, 'Art. 8 § 4', '§4. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements en cours d''année académique et ce, sur l''initiative du 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
directeur ou à la demande du membre du personnel. Ces ajustements sont 
cosignés par le directeur et le membre du personnel. En cas de refus de 
signature du membre du personnel, la procédure de mise en œuvre du plan de 
développement des compétences professionnelles se poursuit valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '4', 'Article 8 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 275, 'Art. 8 § 5', '§5. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le directeur. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '5', 'Article 8 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 276, 'Art. 8 § 6', '§6. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
Section 4. - Déroulement du mécanisme de soutien et de développement 
des compétences professionnelles pour les fonctions de sélection', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '6', 'Article 8 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 277, 'Art. 8', 'Article 8.8. - Le mécanisme de soutien et de développement des 
compétences professionnelles est composé, notamment, d''entretiens de 
développement professionnel avec le directeur ou son délégué et, le cas 
échéant, d''un plan de développement des compétences professionnelles et d''un 
entretien de clôture. 
 
Ces entretiens de développement professionnel sont organisés à 
l''initiative du directeur mais peuvent également être demandés par le membre 
du personnel. 
 
Un délai de minimum cinq jours ouvrables doit être garanti entre la 
convocation à l''entretien de développement professionnel et la date de celui-ci. 
 
L''entretien de développement professionnel doit faire l''objet d''un compte-
rendu. 
 
Un entretien de développement professionnel doit avoir lieu dans la 
mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. 
 
L''entretien de développement professionnel se fonde sur : 
 
- l''exécution de la lettre de mission ; 
 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
- la mise en pratique des compétences acquises dans le cadre des 
formations spécifiques requises en vue d''une nomination/engagement à titre 
définitif. 
 
Dans le cadre de l''entretien de développement professionnel, il est tenu 
compte du contexte global dans lequel est amené à évoluer le membre du 
personnel et des moyens mis à sa disposition.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 278, 'Art. 8 § 1', 'Article 8.9. - §1er. A la suite d''un entretien de développement 
professionnel, un plan de développement des compétences professionnelles 
peut être mis en place. 
 
Le plan de développement des compétences professionnelles est élaboré 
par le directeur, et, le cas échéant, son délégué lorsqu''il concerne un chef 
d''atelier, en concertation avec le membre du personnel. 
 
Préalablement à tout plan de développement des compétences 
professionnelles, le membre du personnel doit avoir eu, au minimum, un 
entretien de développement professionnel avec le directeur, et son délégué 
lorsqu''il concerne un chef d''atelier. 
 
§2. Celui-ci est formalisé dans un document cosigné par le membre du 
personnel et le directeur, tel que visé à l''article 8.2. et contient des 
engagements mutuels des deux parties tels que des objectifs individualisés, 
spécifiques, réalistes et adaptés au membre du personnel ainsi que les moyens 
mis à sa disposition pour les atteindre. Un maximum de quatre objectifs peut 
être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le directeur fait la preuve que la demande de signature pour prise 
de connaissance a été adressée au membre du personnel. 
 
En cas de refus de signature du membre du personnel, la procédure de 
mise en œuvre du plan de développement des compétences professionnelles se 
poursuit valablement. 
 
§3. Sa périodicité est adaptée de manière à mettre en place les conseils 
dispensés ou de suivre les formations recommandées. Ainsi, il ne peut être 
élaboré plus d''un plan de développement des compétences professionnelles par 
membre du personnel par année académique au sein du pouvoir organisateur. 
 
Toutefois, durant une même année académique, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention « défavorable ». 
 
§4. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements et ce, sur l''initiative du directeur ou à la demande du 
membre du personnel. Ces ajustements sont cosignés par le directeur et le 
membre du personnel. En cas de refus de signature du membre du personnel, 
la procédure de mise en œuvre du plan de développement des compétences 
professionnelles se poursuit valablement. 
 
§5. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le directeur. 
 
L''entretien de clôture fait l''objet d''un compte-rendu. 
 
§6. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
Section 5. - Les règles de déontologie', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','surveillance'], 'commun');
