INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 282, 'Art. 114', 'Article 114. - A l''article 10 du même décret, les modifications suivantes 
