INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 284, 'Art. 116', 'Article 116. - L''article 11 du même décret est remplacé ce qui suit : 
 
