INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 285, 'Art. 119', 'Article 119. - A l''article 13 du même décret, les modifications suivantes 
