INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 287, 'Art. 121', 'Article 121. - Dans l''intitulé du CHAPITRE VIbis du même décret, les 
mots « Institut de la Formation en cours de carrière (IFC) créé à l''article 25 du 
décret du 11 juillet 2002 relatif à la formation en cours de carrière dans 
l''enseignement spécial, l''enseignement secondaire ordinaire et les centres 
