INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 290, 'Art. 124', 'Article 124. - A l''article 27, alinéa 2, du décret du 11 juillet 2002 relatif 
à l''Institut interréseaux de la Formation professionnelle continue (IFPC), les 
mots « L''organisation » sont remplacés par les mots « Excepté en ce qui 
concerne les formations visées à l''article 15.3 du décret du 30 juin 1998 relatif 
à la formation en cours de carrière et au mécanisme de soutien et de 
développement des compétences professionnelles des membres du personnel 
directeur et enseignant et du personnel auxiliaire d''éducation et des experts 
de l''enseignement de promotion sociale, l''organisation ». 
 
TITRE 7. - DISPOSITIONS MODIFIANT LE DECRET DU 15 MARS 
1999 RELATIF A LA FORMATION EN COURS DE CARRIERE DES 
MEMBRES DU PERSONNEL DIRECTEUR ET ENSEIGNANT ET DU 
PERSONNEL AUXILIAIRE D''EDUCATION DE L''ENSEIGNEMENT 
SECONDAIRE ARTISTIQUE A HORAIRE REDUIT SUBVENTIONNE 
PAR LA COMMUNAUTE FRANÇAISE', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '124', NULL, 'Article 124 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 291, 'Art. 125', 'Article 125. - L''intitulé du décret du 15 mars 1999 relatif à la formation 
en cours de carrière des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation de l''enseignement secondaire artistique à 
horaire réduit subventionné par la Communauté française est remplacé par 
l''intitulé suivant :  
 
« Décret relatif à la formation en cours de carrière et au mécanisme de 
soutien et de développement des compétences professionnelles des membres 
du personnel directeur et enseignant et du personnel auxiliaire d''éducation de 
l''enseignement secondaire artistique à horaire réduit subventionné par la 
Communauté française ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '125', NULL, 'Article 125 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 292, 'Art. 126', 'Article 126. - A l''article 1er du décret précité, les mots « et au mécanisme 
de soutien et de développement des compétences professionnelles » sont 
insérés entre les mots « formation en cours de carrière » et les mots « des 
membres du personnel ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '126', NULL, 'Article 126 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 293, 'Art. 127 § 1', 'Article 127. - Un nouvel article 2bis est inséré dans le décret précité, 
rédigé comme suit : 
 
« Article 2bis. - §1er. Le bénéficiaire de formation peut consigner dans un 
dossier de développement professionnel intitulé « portfolio » les éléments de la 
formation en cours de carrière qui le concernent. 
 
Le portfolio est un outil de développement professionnel constitué sur 
base volontaire par le membre du personnel et qui lui est propre. 
 
Le portfolio est un outil formatif facilitant le soutien aux apprentissages 
et le développement d''une analyse réflexive. Le membre du personnel y 
consigne les traces utiles et pertinentes au sujet du cheminement de son 
développement professionnel. Le membre du personnel est responsable de son 
portfolio. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '127', '1', 'Article 127 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 294, 'Art. 127 § 2', '§2. Le portfolio est composé de trois parties, chacune de celles-ci ayant 
pour objectif de soutenir une posture réflexive : 
 
1° la première partie concerne le projet personnel de formation du 
membre du personnel. 
 
Elle comporte les volets suivants : 
 
a. les compétences professionnelles attendues en fonction de la charge 
occupée, et tout particulièrement celles qui sont visées dans le plan de 
développement des compétences professionnelles du membre du 
personnel ou dans le plan d''accompagnement individualisé et pour 
lesquelles des actions de formation sont nécessaires ; 
 
b. l''ensemble des formations, recueillies dans l''offre de formation en cours 
de carrière ouverte aux membres du personnel de l''enseignement 
secondaire artistique à horaire réduit prévue par le présent décret 
auxquelles le membre du personnel a participé ou participera, ainsi que 
les attestations de fréquentation des formations en cours de carrière ; 
 
c. l''ensemble des formations ou outils que le membre du personnel aura 
identifié seul ou avec le directeur ou son délégué, ou avec l''aide d''un 
collègue susceptibles de lui permettre de travailler les compétences 
professionnelles attendues identifiées au point a). L''ensemble des outils 
de formation ainsi constitué est organisé en un ensemble cohérent de 
parcours de formation au regard des compétences professionnelles 
attendues. 
 
2° la seconde partie concerne le cheminement du développement 
professionnel du membre du personnel. Cette partie permet au membre du 
personnel d''y consigner notamment les traces qu''il juge utiles et pertinentes 
relatives à sa trajectoire de développement des compétences professionnelles. 
 
3° la troisième partie reprend les traces expérientielles des compétences 
développées et acquises par le membre du personnel. Cette partie vise à 
valoriser les compétences développées tout au long du plan de développement 
des compétences professionnelles ou du plan d''accompagnement individualisé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '127', '2', 'Article 127 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation','obligation scolaire','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 295, 'Art. 127 § 3', '§3. Le membre du personnel décide d''utiliser ou de ne pas utiliser le 
portfolio comme support dans le cadre de son entretien de développement 
professionnel, de son plan de développement des compétences professionnelles, 
de son plan d''accompagnement individualisé, de son évaluation tels que prévus 
dans le cadre du mécanisme de soutien, de développement des compétences 
professionnelles et d''évaluation des membres du personnel de l''enseignement. 
La direction ou son délégué doit accepter le choix du membre du personnel 
d''utiliser ou non son portfolio lors de cet échange. 
 
Dans le cadre du développement de ses propres compétences 
professionnelles, la direction décide d''utiliser ou de ne pas utiliser son portfolio 
lors de ses échanges avec son pouvoir organisateur. Le pouvoir organisateur 
doit accepter le choix du directeur d''utiliser ou non son portfolio lors de cet 
échange.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '127', '3', 'Article 127 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 296, 'Art. 127 § 4', '§4. Le contenu du portfolio est adapté et remis à jour de manière 
régulière. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Un seul portfolio est constitué par le membre du personnel et concerne 
l''ensemble de ses fonctions dans l''enseignement secondaire artistique à 
horaire réduit. 
 
Le membre du personnel peut utiliser son portfolio afin de constituer pour 
lui-même ou dans le cadre de ses visées professionnelles futures, un dossier 
témoignant 
de 
son 
parcours 
de 
développement 
de 
compétences 
professionnelles. »', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '127', '4', 'Article 127 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 297, 'Art. 128 § 1', 'Article 128. - Un nouvel article 2ter rédigé comme suit est inséré dans 
le décret précité : 
 
« Article 2ter. - §1er. Ont le droit d''accéder en priorité et pour répondre à 
leurs besoins personnalisés à un maximum de cinq jours de formation en cours 
de carrière organisés par les fédérations de pouvoirs organisateurs : 
 
a) les membres du personnel de l''enseignement secondaire artistique à 
horaire réduit qui bénéficient d''un plan de développement des compétences 
professionnelles dans l''enseignement secondaire artistique à horaire réduit 
conformément aux articles : 
 
- 47ter, §2 décret du 1er février 1993 fixant le statut des membres du 
personnel subsidiés de l''enseignement libre subventionné ; 
 
- 61decies/1, §2 décret du 1er février 1993 précité ; 
 
- 36duodecies/2, §2 du décret du 06 juin 1994 fixant le statut des membres 
du personnel subsidiés de l''enseignement officiel subventionné ; 
 
- 52novies/2, §2 du décret du 06 juin 1994 précité. 
 
b) les membres du personnel de l''enseignement secondaire artistique à 
horaire réduit qui sont soumis à un Plan d''Accompagnement Individualisé 
conformément aux articles : 
 
- 47ter/1, §3 du décret du 1er février 1993 précité ; 
 
- 61decies/2, §4 du décret du 1er février 1993 précité ; 
 
- 36duodecies/3, §4 du décret du 06 juin 1994 précité ; 
 
- 52novies/3, §4 du décret du 06 juin 1994 précité. 
 
c) les membres du personnel qui ont été soumis à l''appréciation de leur 
aptitude pédagogique, telle que prévue à l''article 6, §3, du décret du 10 janvier 
2019 relatif au Service général de l''Inspection. 
 
§2. Le nombre de jours visé au paragraphe 1er est basé sur un temps plein 
et est réduit proportionnellement en fonction de l''horaire presté par le membre 
du personnel, en arrondissant au demi-jour supérieur. ».', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '128', '1', 'Article 128 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['inspection','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 298, 'Art. 129', 'Article 129. - Dans le même décret, un chapitre Ibis intitulé 
