INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 300, 'Art. 8', 'Article 8/2. - Le Gouvernement fixe les modèles de rapport de la direction 
à destination du pouvoir organisateur et de plan de développement des 
compétences professionnelles visé aux sections 3 et 4 du présent chapitre. 
 
Section II. - La formation au mécanisme de soutien et de développement 
des compétences professionnelles et les délégués à la direction', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 301, 'Art. 8', 'Article 8/3. - Pour les directeurs, une formation relative aux mécanismes 
de soutien, de développement des compétences professionnelles et d''évaluation 
est organisée. Il s''agit de la formation visée à l''article 6.1.9-3 du Code de 
l''enseignement fondamental et de l''enseignement secondaire.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 302, 'Art. 8 § 1', 'Article 8/4. - §1er. Le délégué du directeur, visé dans le présent chapitre, 
doit être désigné parmi les titulaires d''une fonction de sélection de directeur 
adjoint et doit avoir suivi la formation visée à l''article 6.1.9-5. du Code de 
l''enseignement fondamental et de l''enseignement secondaire. 
 
§2. Concernant la réalisation du mécanisme de soutien et de 
développement des compétences professionnelles pour les fonctions de 
sélection, le directeur ne peut pas déléguer sa mission. 
 
§3. Le délégué doit participer à un entretien de développement 
professionnel donnant lieu, le cas échéant, à un plan de développement des 
compétences professionnelles au cours de l''année scolaire durant laquelle la 
mission de délégué lui est confiée pour la première fois. 
 
§4. Le délégué visé au §1er exerce une mission d''accompagnateur du 
mécanisme de soutien et de développement des compétences professionnelles. 
Il réalise, à la demande de la direction, des entretiens de développement 
professionnel au cours desquels il soutient, aide et accompagne le membre du 
personnel dans sa réflexion et, le cas échéant, dans la construction et 
l''élaboration de son plan de développement des compétences professionnelles. 
 
Il n''a pas de compétence de décision. 
 
Section III. - Déroulement du mécanisme de soutien et de développement 
des compétences professionnelles pour les fonctions de recrutement', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 303, 'Art. 8', 'Article 8.5. - Le mécanisme de soutien et de développement des compétences professionnelles est composé, notamment, d''entretiens de développement professionnel menés par le directeur ou son délégué et, le cas échéant, d''un plan de développement des compétences professionnelles et d''un entretien de clôture. Ces entretiens de développement professionnel sont organisés à l''initiative du directeur mais peuvent également être demandés par le membre du personnel. Docu 51683 D. 20-07-2023 Version initiale au 22/11/2023 Un délai de minimum cinq jours ouvrables doit être garanti entre la convocation à l''entretien de développement professionnel et la date de celui-ci. L''entretien de développement professionnel fait l''objet d''un compte- rendu. Un entretien de développement professionnel doit avoir lieu dans la mesure du possible une fois par an, et, au minimum, une fois tous les trois ans pour les membres du personnel qui prestent plus d''une demi-charge dans un même pouvoir organisateur. A partir de la rentrée scolaire 2024-2025, les enseignants qui sont dans leurs cinq premières années d''exercice dans l''enseignement en Communauté française, ont un entretien de développement professionnel par année scolaire s''ils prestent plus de 6 périodes par semaine dans l''établissement. L''entretien de développement professionnel peut en fonction de la fonction occupée, s''appuyer sur les compétences professionnelles attendues suivantes : 1° la capacité d''agir comme acteur pédagogique, social, culturel au sein de l''établissement et de la société, y compris dans leur transformation, d''intégrer la diversité et de développer des pratiques citoyennes pour plus de cohésion sociale ; 2° la disposition à se positionner face à des enjeux éthiques et à respecter les cadres déontologiques et réglementaires de la profession dans une perspective démocratique et de responsabilité ; 3° la capacité d''analyser l''environnement organisationnel et institutionnel du système éducatif et d''agir en son sein notamment en interagissant avec les collègues, les parents et d''autres acteurs afin de : - faire de la classe et de l''établissement un lieu où les élèves apprennent et se forment dans un climat positif, et non un lieu de sélection ; 4° la capacité de s''appuyer sur diverses disciplines des sciences humaines pour analyser et agir en situation professionnelle ; 5° la maîtrise des contenus disciplinaires, en ce compris les concepts à enseigner, de leurs fondements épistémologiques, de leur didactique et de la méthodologie de leur enseignement ; 6° la capacité de lire de manière critique les résultats de recherches scientifiques en éducation et en didactique et de s''en inspirer pour son action d''enseignement ; 7° la connaissance et la capacité de mise en œuvre des programmes de cours en vigueur dans l''établissement ; 8° la capacité d''agir comme pédagogue au sein de la classe et, dans une perspective collective, au sein de l''établissement, notamment : - à travers la conception et la mise en œuvre d''une démarche d''enseignement comprenant des pratiques variées et différenciées et Docu 51683 D. 20-07-2023 Version initiale au 22/11/2023 assurant la motivation et la promotion de la confiance en soi des élèves, de la créativité et de l''esprit d''initiative et de coopération dans le souci de l''intérêt général ; - à travers la conception, le choix et l''utilisation de supports didactiques et d''outils pédagogiques au sein des établissements ; - à travers la construction et l''utilisation de supports d''observation et d''évaluation spécifiquement diagnostique et formative favorisant la responsabilisation et la participation de l''élève dans ses apprentissages ; 9° la capacité de mener, individuellement et avec ses pairs, une observation et une analyse critique et rigoureuse de ses propres pratiques et de leur impact sur les élèves afin de réguler son enseignement et d''en faire évoluer les stratégies et conditions de mise en œuvre dans une perspective d''efficacité et d''équité. Cette analyse int', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['discipline','évaluation','parents','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 304, 'Art. 8', 'la dimension de genre ; 10° le développement de capacités : - relationnelles à l''égard des élèves, en ce compris leur entourage notamment familial s''il échet, et à l''égard des collègues ; - de gestion de groupes en situation éducative et pédagogique, s''il échet ; 11° la capacité d''identifier ses besoins de formation individuelle ; 12° la capacité de développer des compétences personnelles liées aux exigences de la profession, notamment les exigences relatives à la gestion du groupe classe s''il échet ; 13° la capacité de s''insérer dans le système éducatif en y respectant les codes et fonctionnement notamment hiérarchiques ; 14° la maîtrise de sa situation administrative et le suivi de son dossier administratif personnel. Dans le cadre de l''entretien de développement professionnel, il est tenu compte du contexte global dans lequel est amené à évoluer le membre du personnel et des moyens mis à sa disposition.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 305, 'Art. 8 § 1', '§1er. A la suite d''un entretien de développement 
professionnel, à la demande du membre du personnel ou du directeur, un plan 
de développement des compétences professionnelles peut être mis en place. 
 
Pour pouvoir mettre en place un plan de développement des compétences 
professionnelles, les conditions suivantes doivent être réunies : 
 
1° le membre du personnel doit avoir eu, au minimum, un entretien de 
développement professionnel avec le directeur ou son délégué ; 
 
2° le membre du personnel ne peut pas avoir déjà eu un plan de 
développement des compétences professionnelles au cours de la même année 
scolaire au sein du pouvoir organisateur, conformément au', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 306, 'Art. 8 § 3', '§3. 
 
3° le directeur doit être formé via la formation visée à l''article 6.1.9-3. du 
Code de l''enseignement fondamental et de l''enseignement secondaire. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
La mise en place d''un plan de développement des compétences 
professionnelles est obligatoire pour les membres du personnel qui sont dans 
leur première année d''exercice d''une fonction dans l''enseignement en 
Communauté française, pour autant que la durée de désignation initiale soit 
d''au moins neuf mois au sein du pouvoir organisateur et qu''ils soient désignés 
pour plus d''une demi-charge au sein du pouvoir organisateur pour l''année 
scolaire. 
 
Ce plan de développement des compétences professionnelles est élaboré 
par le directeur ou son délégué en concertation avec le membre du personnel.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '3', 'Article 8 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['personnel'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 307, 'Art. 8 § 2', '§2. Celui-ci est formalisé dans un document cosigné par le membre du 
personnel et le directeur, tel que visé à l''article 8/2 et contient des engagements 
mutuels des deux parties tels que des objectifs individualisés, spécifiques, 
réalistes et adaptés au membre du personnel ainsi que les moyens mis à sa 
disposition pour les atteindre. Un maximum de quatre objectifs peut être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le directeur fait la preuve que la demande de signature pour prise 
de connaissance a été adressée au membre du personnel. 
 
En cas de refus de signature du membre du personnel, la procédure de 
mise en œuvre du plan de développement des compétences professionnelles se 
poursuit valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '2', 'Article 8 § 2 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 308, 'Art. 8 § 3', '§3. Sa périodicité est adaptée de manière à permettre au membre du 
personnel de mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par membre du personnel par année scolaire 
au sein du pouvoir organisateur. 
 
Toutefois, durant une même année scolaire, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention défavorable.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '3', 'Article 8 § 3 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 309, 'Art. 8 § 4', '§4. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements en cours d''année académique et ce, sur l''initiative du 
directeur ou à la demande du membre du personnel. Ces ajustements sont 
cosignés par le directeur et le membre du personnel. En cas de refus de 
signature du membre du personnel, la procédure de mise en œuvre du plan de 
développement des compétences professionnelles se poursuit valablement.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '4', 'Article 8 § 4 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 310, 'Art. 8 § 5', '§5. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt 6 mois après 
la mise en place du plan de développement des compétences professionnelles 
et au plus tard 2 ans après celle-ci. 
 
L''entretien de clôture est mené par le directeur. 
 
L''entretien de clôture fait l''objet d''un compte-rendu.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '5', 'Article 8 § 5 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 311, 'Art. 8 § 6', '§6. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
Section IV. - Déroulement du mécanisme de soutien et de développement 
des compétences professionnelles pour les fonctions de sélection', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '6', 'Article 8 § 6 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 312, 'Art. 8', 'Article 8/7. - Le mécanisme de soutien et de développement des 
compétences professionnelles est composé, notamment, d''entretiens de 
développement professionnel avec le directeur et, le cas échéant, d''un plan de 
développement des compétences professionnelles et d''un entretien de clôture. 
 
Ces entretiens de développement professionnel sont organisés à 
l''initiative du directeur mais peuvent également être demandés par le membre 
du personnel. 
 
Un délai de minimum cinq jours ouvrables doit être garanti entre la 
convocation à l''entretien de développement professionnel et la date de celui-ci. 
 
L''entretien de développement professionnel doit faire l''objet d''un compte-
rendu. 
 
Un entretien de développement professionnel doit avoir lieu dans la 
mesure du possible une fois par an, et, au minimum, une fois tous les trois ans. 
 
L''entretien de développement professionnel se fonde sur : 
 
- l''exécution de la lettre de mission ; 
 
- la mise en pratique des compétences acquises dans le cadre de la 
formation spécifique requise en vue d''une nomination/engagement à titre 
définitif. 
 
Dans le cadre de l''entretien de développement professionnel, il est tenu 
compte du contexte global dans lequel est amené à évoluer le membre du 
personnel et des moyens mis à sa disposition.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','personnel','ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 313, 'Art. 8 § 1', 'Article 8/8. - §1er. A la suite d''un entretien de développement 
professionnel, un plan de développement des compétences professionnelles 
peut être mis en place. 
 
Le plan de développement des compétences professionnelles est élaboré 
par le directeur en concertation avec le membre du personnel. 
 
Préalablement à tout plan de développement des compétences 
professionnelles, le membre du personnel doit avoir eu, au minimum, un 
entretien de développement professionnel avec le directeur. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§2. Celui-ci est formalisé dans un document cosigné par le membre du 
personnel et le directeur, tel que visé à l''article 8/2 et contient des engagements 
mutuels des deux parties tels que des objectifs individualisés, spécifiques, 
réalistes et adaptés au membre du personnel ainsi que les moyens mis à sa 
disposition pour les atteindre. Un maximum de 4 objectifs peut être fixé. 
 
L''obligation de co-signature visée à l''alinéa précédent est réputée remplie 
dès lors que le directeur fait la preuve que la demande de signature pour prise 
de connaissance a été adressée au membre du personnel. 
 
En cas de refus de signature du membre du personnel, la procédure de 
mise en œuvre du plan de développement des compétences professionnelles se 
poursuit valablement. 
 
§3. Sa périodicité est adaptée de manière à permettre au membre du 
personnel de mettre en place les conseils dispensés ou de suivre les formations 
recommandées. Ainsi, il ne peut être élaboré plus d''un plan de développement 
des compétences professionnelles par membre du personnel par année scolaire 
au sein du pouvoir organisateur. 
 
Toutefois, durant une même année scolaire, un membre du personnel 
faisant l''objet d''un plan de développement des compétences professionnelles 
peut également être amené à avoir un plan d''accompagnement individualisé 
élaboré suite à une première évaluation avec mention défavorable. 
 
§4. Le plan de développement des compétences professionnelles peut faire 
l''objet d''ajustements et ce, sur l''initiative du directeur ou à la demande du 
membre du personnel. Ces ajustements sont cosignés par le directeur et le 
membre du personnel. 
 
En cas de refus de signature du membre du personnel, la procédure de 
mise en œuvre du plan de développement des compétences professionnelles se 
poursuit valablement. 
 
§5. Le plan de développement des compétences professionnelles donne 
lieu à un entretien de clôture. Cet entretien intervient au plus tôt six mois 
après la mise en place du plan de développement des compétences 
professionnelles et au plus tard deux ans après celle-ci. 
 
L''entretien de clôture est mené par le directeur. 
 
L''entretien de clôture fait l''objet d''un compte-rendu. 
 
§6. Pour le calcul des délais de six mois et deux ans précités, sont seuls 
pris en considération les services effectifs rendus pendant l''exercice de la 
fonction, en ce compris : 
 
- les vacances annuelles, à l''exclusion des vacances d''été ; 
 
- les congés prévus aux articles 5, 5bis, 6 et 7 de l''arrêté royal du 15 
janvier 1974 pris en application de l''article 160 de l''arrêté royal du 22 mars 
1969 fixant le statut des membres du personnel directeur et enseignant, du 
personnel auxiliaire d''éducation, du personnel paramédical des établissements 
d''enseignement gardien, primaire, spécial, moyen, technique, artistique et 
normal de l''Etat, des internats dépendant de ces établissements et des 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
membres du personnel du service d''inspection chargé de la surveillance de ces 
établissements. 
 
Section V. - Règles de déontologie', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', '1', 'Article 8 § 1 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['exclusion','évaluation','inspection','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 314, 'Art. 8', 'Article 8/9. - Dans le cadre des entretiens et échanges visés aux sections 
3 et 4, le membre du personnel et le directeur ou son délégué sont tenus au 
respect des devoirs suivants : 
 
- la discrétion ; 
 
- le respect mutuel. 
 
En outre, le directeur est tenu de : 
 
- 
motiver, 
de 
manière 
adéquate 
et 
constructive, 
ses 
instructions/conseils/échanges avec le membre du personnel ; 
 
- soutenir le membre du personnel dans l''atteinte de ses objectifs ; 
 
- respecter les devoirs d''impartialité et d''objectivité. »

Article 130. - A l''article 10 du même décret, le deuxième alinéa est 
supprimé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '8', NULL, 'Article 8 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 315, 'Art. 131', 'Article 131. - A l''article 14 du même décret, les modifications suivantes 
sont apportées : 
 
1° un nouvel alinéa est inséré entre les alinéas 1er et 2, rédigé comme 
suit : 
 
 « En supplément des budgets visés à l''alinéa 1er, pour l''organisation des 
formations visées à l''article 2bis, les crédits budgétaires alloués sont fixés pour 
l''année civile 2024 à un minimum de 45.000 euros et à partir de l''année civile 
2025 à un minimum de 130.000 euros indexés, chaque année civile à partir de 
2026, sur l''indice général des prix à la consommation fixé à la date du 
1er janvier 2013. » ; 
 
2° un alinéa 5 est inséré, rédigé comme suit :  
 
« A la demande motivée d''une Fédération de pouvoirs organisateurs, le 
Gouvernement peut autoriser, selon les modalités qu''il détermine, le report 
des soldes éventuels relatifs à une année sur l''année suivante pour les budgets 
visés à l''alinéa 1er ». 
 
TITRE 8. - DISPOSITION RELATIVE A LA FORMATION DES 
POUVOIRS ORGANISATEURS', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '131', NULL, 'Article 131 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 316, 'Art. 132', 'Article 132. - A partir de la rentrée 2026-2027, une formation relative 
aux 
mécanismes 
de 
soutien, 
de 
développement 
des 
compétences 
professionnelles et d''évaluation, est organisée pour les pouvoirs organisateurs 
et les directions, dans le cadre de la formation professionnelle continue. 
 
Cette formation est organisée de manière complémentaire entre les 
niveaux de formation interréseaux et réseau visés à l''article 6.1.3-3 du Code 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
de l''enseignement fondamental et de l''enseignement secondaire et comprend 
des modules répartis de manière égalitaire entre ces deux niveaux de 
formation. 
 
L''Institut de la Formation Professionnelle Continue d''une part et le 
pouvoir organisateur de l''enseignement organisé par la Communauté 
française ou chaque Fédération de pouvoirs organisateurs veillent à respecter 
la complémentarité des modules entre les niveaux interréseaux et réseau de 
manière à assurer la cohérence globale du dispositif de formation. 
 
Cette formation est réputée être équivalente à la formation visée aux 
articles 6.1.9-3 du Code de l''enseignement fondamental et de l''enseignement 
secondaire, 8.3 du décret 30 juin 1998 relatif à la formation en cours de carrière 
et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation et des experts de l''enseignement de promotion 
sociale et 8/3 du 15 mars 1999 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation de l''enseignement secondaire artistique à horaire réduit 
subventionné par la Communauté française. 
 
TITRE 9. - DISPOSITION RELATIVE A LA MISE EN PLACE D''UN 
MONITORING', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '132', NULL, 'Article 132 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['évaluation'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 317, 'Art. 133', 'Article 133. - Dès le 1er janvier 2024 et jusqu''à la rentrée scolaire 2030-
2031, un monitoring de la mise en œuvre du mécanisme porté par le présent 
décret est réalisé annuellement par le Gouvernement. 
 
TITRE 10. - DISPOSITIONS TRANSITOIRES', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '133', NULL, 'Article 133 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', NULL, 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 318, 'Art. 134', 'Article 134. - Pour les membres du personnel soumis à l''arrêté royal du 
22 mars 1969 fixant le statut des membres du personnel directeur et 
enseignant, du personnel auxiliaire d''éducation, du personnel paramédical des 
établissements d''enseignement gardien, primaire, spécial, moyen, technique, 
de promotion sociale et artistique de l''Etat, des internats dépendant de ces 
établissements et des membres du personnel du service d''inspection chargé de 
la surveillance de ces établissements, il n''est plus possible de rédiger un 
bulletin de signalement à partir de la rentrée scolaire 2026-2027 en application 
du mécanisme existant repris au Chapitre VI du même arrêté royal. 
 
Par dérogation à l''alinéa 1er, pour les membres du personnel ayant fait 
l''objet de deux bulletins de signalement avec mention défavorable à la veille 
de la rentrée scolaire 2026-2027, la possibilité de rédiger un troisième bulletin 
de signalement durant la période du premier jour de l''année scolaire 2026-
2027 au 31 décembre 2027 subsiste en application du mécanisme existant 
repris au Chapitre VI de l''arrêté royal du 22 mars 1969 susvisé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '134', NULL, 'Article 134 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['inspection','ROI','surveillance'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 319, 'Art. 135', 'Article 135. - Pour les maîtres et professeurs de religion soumis à 
l''arrêté royal du 25 octobre 1971 fixant le statut des maîtres de religion, des 
professeurs de religion et des inspecteurs de religion des religions catholique, 
protestante, israélite et orthodoxe des établissements d''enseignement de 
l''Etat, il n''est plus possible de rédiger un bulletin de signalement à partir de 
la rentrée scolaire 2026-2027 en application du mécanisme existant repris au 
Chapitre VI du même arrêté royal. 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
Par dérogation à l''alinéa 1er, pour les maîtres et professeurs de religion 
ayant fait l''objet de deux bulletins de signalement avec mention défavorable à 
la veille de la rentrée scolaire 2026-2027, la possibilité de rédiger un troisième 
bulletin de signalement durant la période du premier jour de l''année scolaire 
2026-2027 au 31 décembre 2027 subsiste en application du mécanisme 
existant repris au Chapitre VI de l''arrêté royal du 25 octobre 1971 susvisé.', 'Décret relatif au soutien et à l''évaluation des personnels', 'Décret évaluation personnels', '135', NULL, 'Article 135 du Décret relatif au soutien et à l''évaluation des personnels (CDA 51683)', ARRAY['ROI'], 'commun');
INSERT INTO public.legal_chunks (cda_code, chunk_index, chunk_title, content, source_title, source_short_title, article_number, paragraph, citation_display, topics, education_level) VALUES ('51683', 320, 'Art. 136 § 1', 'Article 136. - §1er. Jusqu''à l''année scolaire 2026-2027, une formation 
obligatoire relative aux mécanismes de soutien, de développement des 
compétences professionnelles et d''évaluation, est organisée pour les directeurs, 
dans le cadre de la formation professionnelle continue. 
 
Cette formation est organisée de manière complémentaire entre les 
niveaux de formation interréseaux et réseau visés à l''article 6.1.3-3 et 
comprend des modules répartis de manière égalitaire entre ces deux niveaux 
de formation. 
 
L''Institut de la Formation Professionnelle Continue et le pouvoir 
organisateur de l''enseignement organisé par la Communauté française ou 
chaque Fédération de pouvoirs organisateurs veillent à respecter la 
complémentarité des modules entre les niveaux interréseaux et réseau de 
manière à assurer la cohérence globale du dispositif de formation. 
 
Cette formation est réputée être équivalente à la formation visée aux 
articles 6.1.9-3 du Code de l''enseignement fondamental et de l''enseignement 
secondaire, 8.3 du décret 30 juin 1998 relatif à la formation en cours de carrière 
et au mécanisme de soutien et de développement des compétences 
professionnelles des membres du personnel directeur et enseignant et du 
personnel auxiliaire d''éducation et des experts de l''enseignement de promotion 
sociale et 8/3 du 15 mars 1999 relatif à la formation en cours de carrière et au 
mécanisme de soutien et de développement des compétences professionnelles 
des membres du personnel directeur et enseignant et du personnel auxiliaire 
d''éducation de l''enseignement secondaire artistique à horaire réduit 
subventionné par la Communauté française. 
 
§2. Jusqu''à l''année scolaire 2026-2027, les directions n''ayant pas suivi la 
formation visée au paragraphe 1er, peuvent mener des entretiens de 
développement des compétences professionnelles et mettre en place des plans 
de développement des compétences professionnelles pour les membres du 
personnel dépendant de leur établissement scolaire. 
 
§3. Dès le 1er janvier 2024, les pouvoirs organisateurs peuvent suivre la 
formation visée au §1er. 
 
Le suivi de cette formation est équivalent au suivi de la formation prévue 
à l''article 132. 
 
§4. Jusqu''à l''année scolaire 2026-2027, la mise en place d''un plan de 
développement des compétences professionnelles prévue respectivement à 
l''article 6.1.9-7 du Code de l''enseignement, à l''article 8.7 du décret du 30 juin 
1998 précité et à l''article 8/6 du décret du 15 mars 1999 précité, pour les 
membres du personnel dans leur première année d''exercice est obligatoire 
mais peut être réalisé dans l''année qui suit l''entretien de développement des 
compétences professionnelles. 
 
 
 
Docu 51683 
 
D. 20-07-2023  
Version initiale au 22/11/2023 
 
§5. Jusqu''à l''année scolaire 2026-2027 l''obligation d''un entretien de 
développement professionnel au minimum tous les 3 ans ne s''applique pas, par 
dérogation aux articles : 
 
A) 6.1.9-8, §2, alinéa 4 du Code de l''enseignement fondamental et de 
l''enseignement secondaire ; 
 
B) 8.6, alinéa 4 et 8.8, alinéa 5 du décret du 30 juin 1998 précité ; 
 
C) 8/5, alinéa 4 et 8/7, alinéa 5 du décret du 15 mars 1999 précité; 
 
D) 28octies, alinéa 1er du décret du 04 janvier 1999 relatif aux fonctions 
de promotion et de sélection ; 
 
E) 40, §1er, alinéa 4 ; 64, §1er, alinéa 4 et 87, §1er, alinéa 4 du décret du 02 
février 2007 fixant le statut des directeurs et directrices dans l''enseignement. 
 
§6. Les entretiens de développement professionnel menés avant la 
rentrée scolaire 2026-2027 sont considérés comme ayant été menés durant 
l''année scolaire 2026-2027 et peuvent donc répondre à l''obligation citée au 
paragraphe 4. 
 
